Future<void> main() async {
  WidgetsFlutterBinding.ensureInitialized();
  tz.initializeTimeZones();

  final cfg = await _loadSupabaseConfig();
  if (cfg != null) {
    await _initSupabase(cfg);
  }

  runApp(const AtalaiaApp());
}

SupabaseClient? _trySupabaseClient() {
  try {
    return Supabase.instance.client;
  } catch (_) {
    return null;
  }
}

bool _supportsLocalNotifications() {
  if (kIsWeb) return false;
  return defaultTargetPlatform == TargetPlatform.android || defaultTargetPlatform == TargetPlatform.iOS;
}

String _authErrorText(BuildContext context, String? codeOrMessage, {String? fallback}) {
  final l10n = t(context);
  final v = codeOrMessage?.trim();
  if (v == null || v.isEmpty) return fallback ?? l10n.authErrorInvalidCredentials;
  if (v == DemoRepository._authErrNoConnection) return l10n.commonNoConnection;
  if (v == DemoRepository._authErrInvalidCredentials) return l10n.authErrorInvalidCredentials;
  if (v == DemoRepository._authErrLoginFailed) return l10n.authErrorLoginFailed;
  if (v == DemoRepository._authErrCreateAccountFailed) return l10n.authErrorCreateAccountFailed;
  if (v == DemoRepository._authErrAccountCreatedNoSession) return l10n.authErrorAccountCreatedNoSession;
  if (v == DemoRepository._authErrRateLimit) return l10n.authErrorRateLimit;
  if (v == DemoRepository._authErrEmailAlreadyRegistered) return l10n.authErrorEmailAlreadyRegistered;
  if (v == DemoRepository._authErrUsernameUnavailable) return l10n.authErrorUsernameUnavailable;
  if (v == DemoRepository._authErrSupabaseNotConfigured) return l10n.authSupabaseNotConfigured;
  return v;
}

String _profileDisplayLabel(ProfileModel p, {String userFallback = ''}) {
  final name = _displayNameForProfile(p, userFallback: userFallback).trim();
  final username = _usernameForProfile(p, userId: p.userId).trim();
  if (name.isEmpty && username.isEmpty) return userFallback;
  if (username.isEmpty) return name;
  if (name.isEmpty) return '@$username';
  if (name == username || name == '@$username') return name;
  return '$name (@$username)';
}

int _fnv1a32(String input) {
  var hash = 0x811c9dc5;
  for (var i = 0; i < input.length; i++) {
    hash ^= input.codeUnitAt(i);
    hash = (hash * 0x01000193) & 0xffffffff;
  }
  return hash & 0x7fffffff;
}

String _shortSupabaseError(Object e) {
  if (e is PostgrestException) {
    final parts = <String>[
      e.message,
      if ((e.code ?? '').toString().trim().isNotEmpty) 'code=${e.code}',
      if ((e.details ?? '').toString().trim().isNotEmpty) 'details=${e.details}',
      if ((e.hint ?? '').toString().trim().isNotEmpty) 'hint=${e.hint}',
    ];
    return parts.where((p) => p.trim().isNotEmpty).join(' • ');
  }
  if (e is AuthException) return e.message;
  if (e is StorageException) return e.message;
  return e.toString();
}

bool _isStoriesCommunityIdMissing(Object e) {
  if (e is! PostgrestException) return false;
  final code = (e.code ?? '').toString().trim().toUpperCase();
  final message = '${e.message} ${e.details} ${e.hint}'.toLowerCase();
  if (code == 'PGRST204' && message.contains('community_id')) return true;
  if (message.contains("could not find the 'community_id'")) return true;
  return false;
}

bool _isStoriesCityIdNotNullViolation(Object e) {
  if (e is! PostgrestException) return false;
  final code = (e.code ?? '').toString().trim().toUpperCase();
  if (code != '23502') return false;
  final message = '${e.message} ${e.details} ${e.hint}'.toLowerCase();
  if (!message.contains('stories')) return false;
  return message.contains('city_id') && message.contains('null') && message.contains('not-null');
}

final class _LocalNotifications {
  _LocalNotifications._();

  static final _LocalNotifications instance = _LocalNotifications._();

  final FlutterLocalNotificationsPlugin plugin = FlutterLocalNotificationsPlugin();
  var _initialized = false;

  Future<void> init() async {
    if (_initialized) return;
    if (!_supportsLocalNotifications()) return;
    final android = const AndroidInitializationSettings('@mipmap/ic_launcher');
    final ios = const DarwinInitializationSettings();
    await plugin.initialize(InitializationSettings(android: android, iOS: ios));
    _initialized = true;
  }

  Future<bool> ensurePermission() async {
    if (!_supportsLocalNotifications()) return false;
    await init();

    var allowed = true;
    final android = plugin.resolvePlatformSpecificImplementation<AndroidFlutterLocalNotificationsPlugin>();
    if (android != null) {
      final a = await android.requestNotificationsPermission();
      allowed = allowed && (a ?? true);
    }
    final ios = plugin.resolvePlatformSpecificImplementation<IOSFlutterLocalNotificationsPlugin>();
    if (ios != null) {
      final i = await ios.requestPermissions(alert: true, badge: true, sound: true);
      allowed = allowed && (i ?? true);
    }
    return allowed;
  }

  NotificationDetails inboxDetails() {
    const android = AndroidNotificationDetails(
      'inbox_notifications',
      'Notificações',
      channelDescription: 'Notificações do Atalaia Social',
      importance: Importance.max,
      priority: Priority.high,
    );
    const ios = DarwinNotificationDetails(presentAlert: true, presentSound: true);
    return const NotificationDetails(android: android, iOS: ios);
  }

  NotificationDetails reminderDetails(AppLocalizations l10n) {
    final android = AndroidNotificationDetails(
      'prayer_run_reminders',
      l10n.notificationChannelPrayerRunsName,
      channelDescription: l10n.notificationChannelPrayerRunsDescription,
      importance: Importance.max,
      priority: Priority.high,
    );
    const ios = DarwinNotificationDetails(presentAlert: true, presentSound: true);
    return NotificationDetails(android: android, iOS: ios);
  }
}

final ValueNotifier<int> _supabaseConfigVersion = ValueNotifier<int>(0);

bool _allowManualSupabaseSetup() {
  return false;
}

const _bundledSupabaseUrl = 'https://ofvfygksjylwyxtlmrvn.supabase.co';
const _bundledSupabaseAnonKey = 'sb_publishable_amJpGBTWnSxqmZICFOyZVQ_2WpQj-Xb';

final class _SupabaseConfig {
  const _SupabaseConfig({required this.url, required this.anonKey});

  final String url;
  final String anonKey;
}

Future<_SupabaseConfig?> _loadSupabaseConfig() async {
  final expectedHost = Uri.tryParse(_bundledSupabaseUrl)?.host ?? '';
  final envUrl = const String.fromEnvironment('SUPABASE_URL').trim();
  final envKey = const String.fromEnvironment('SUPABASE_ANON_KEY').trim();
  if (envUrl.isNotEmpty && envKey.isNotEmpty) {
    final host = Uri.tryParse(envUrl)?.host ?? '';
    if (expectedHost.isNotEmpty && host != expectedHost) {
      debugPrint('[supabase] droppedEnvHost=$host expectedHost=$expectedHost');
    } else {
    final anonPrefix = envKey.substring(0, math.min(12, envKey.length));
    debugPrint('[supabase] configSource=env');
    debugPrint('[supabase] loadedUrl=$envUrl');
    debugPrint('[supabase] host=$host');
    debugPrint('[supabase] loadedAnonPrefix=$anonPrefix');
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('supabase_url', envUrl);
      await prefs.setString('supabase_anon_key', envKey);
      debugPrint('[supabase] persistedConfigSource=env');
    } catch (_) {}
    return _SupabaseConfig(url: envUrl, anonKey: envKey);
    }
  }

  if (_bundledSupabaseUrl.isNotEmpty && _bundledSupabaseAnonKey.isNotEmpty) {
    final host = Uri.tryParse(_bundledSupabaseUrl)?.host ?? '';
    final anonPrefix = _bundledSupabaseAnonKey.substring(0, math.min(12, _bundledSupabaseAnonKey.length));
    debugPrint('[supabase] configSource=bundled_default');
    debugPrint('[supabase] loadedUrl=$_bundledSupabaseUrl');
    debugPrint('[supabase] host=$host');
    debugPrint('[supabase] loadedAnonPrefix=$anonPrefix');
    try {
      final prefs = await SharedPreferences.getInstance();
      await prefs.setString('supabase_url', _bundledSupabaseUrl);
      await prefs.setString('supabase_anon_key', _bundledSupabaseAnonKey);
      debugPrint('[supabase] persistedConfigSource=bundled_default');
    } catch (_) {}
    return const _SupabaseConfig(url: _bundledSupabaseUrl, anonKey: _bundledSupabaseAnonKey);
  }

  try {
    final prefs = await SharedPreferences.getInstance();
    final url = (prefs.getString('supabase_url') ?? '').trim();
    final key = (prefs.getString('supabase_anon_key') ?? '').trim();
    if (url.isNotEmpty && key.isNotEmpty) {
      final host = Uri.tryParse(url)?.host ?? '';
      if (host == 'ofvfgksxjlwyxtlrvmn.supabase.co') {
        await prefs.remove('supabase_url');
        await prefs.remove('supabase_anon_key');
        debugPrint('[supabase] droppedInvalidHost=$host');
      } else if (expectedHost.isNotEmpty && host != expectedHost) {
        await prefs.remove('supabase_url');
        await prefs.remove('supabase_anon_key');
        debugPrint('[supabase] droppedUnexpectedHost=$host expectedHost=$expectedHost');
      } else {
        final anonPrefix = key.substring(0, math.min(12, key.length));
        debugPrint('[supabase] configSource=shared_preferences');
        debugPrint('[supabase] loadedUrl=$url');
        debugPrint('[supabase] host=$host');
        debugPrint('[supabase] loadedAnonPrefix=$anonPrefix');
        return _SupabaseConfig(url: url, anonKey: key);
      }
    }
  } catch (_) {}

  debugPrint('[supabase] configSource=none');
  return null;
}

Future<void> _initSupabase(_SupabaseConfig cfg) async {
  final host = Uri.tryParse(cfg.url)?.host;
  final anonPrefix = cfg.anonKey.substring(0, math.min(12, cfg.anonKey.length));
  debugPrint('[supabase] url=${cfg.url}');
  debugPrint('[supabase] host=${host ?? ''}');
  debugPrint('[supabase] anonKeyPrefix=$anonPrefix');

  try {
    Supabase.instance.client;
    debugPrint('[supabase] already_initialized=true');
    return;
  } catch (_) {}

  try {
    await Supabase.initialize(
      url: cfg.url,
      anonKey: cfg.anonKey,
      authOptions: const FlutterAuthClientOptions(
        autoRefreshToken: true,
      ),
    );
    assert(() {
      debugPrint('[supabase] initialized');
      return true;
    }());
  } catch (e) {
    debugPrint('[supabase] initialize_failed=$e');
  }
}

Future<void> showSupabaseSetupDialog(BuildContext context) async {
  final prefs = await SharedPreferences.getInstance();
  final urlController = TextEditingController(text: prefs.getString('supabase_url') ?? '');
  final keyController = TextEditingController(text: prefs.getString('supabase_anon_key') ?? '');

  final action = await showDialog<String>(
    context: context,
    builder: (context) {
      return AlertDialog(
        title: Text(t(context).supabaseSetupTitle),
        content: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            TextField(
              controller: urlController,
              decoration: const InputDecoration(labelText: 'SUPABASE_URL'),
            ),
            const SizedBox(height: 10),
            TextField(
              controller: keyController,
              decoration: const InputDecoration(labelText: 'SUPABASE_ANON_KEY'),
            ),
          ],
        ),
        actions: [
          AtalaiaTextButton(
            label: t(context).commonCancel,
            onPressed: () => Navigator.of(context).pop('cancel'),
          ),
          AtalaiaTextButton(
            label: t(context).commonReset,
            onPressed: () => Navigator.of(context).pop('reset'),
          ),
          PrimaryButton(
            label: t(context).commonSave,
            onPressed: () => Navigator.of(context).pop('save'),
          ),
        ],
      );
    },
  );

  final url = urlController.text.trim();
  final key = keyController.text.trim();
  urlController.dispose();
  keyController.dispose();

  if (action == 'reset') {
    await prefs.remove('supabase_url');
    await prefs.remove('supabase_anon_key');
    debugPrint('[supabase] local config cleared');
    _supabaseConfigVersion.value++;
    if (!context.mounted) return;
    showAtalaiaSnackBar(
      context,
      t(context).supabaseSetupResetLocalConfigSnack,
      kind: AtalaiaSnackKind.warning,
    );
    return;
  }

  if (action != 'save') return;
  if (url.isEmpty || key.isEmpty) {
    if (!context.mounted) return;
    showAtalaiaSnackBar(context, t(context).supabaseSetupMissingUrlKeySnack, kind: AtalaiaSnackKind.warning);
    return;
  }

  await prefs.setString('supabase_url', url);
  await prefs.setString('supabase_anon_key', key);
  await _initSupabase(_SupabaseConfig(url: url, anonKey: key));
  _supabaseConfigVersion.value++;
  if (!context.mounted) return;
  showAtalaiaSnackBar(context, t(context).supabaseSetupConfiguredSnack, kind: AtalaiaSnackKind.success);
}

