      timezoneName: timezoneName ?? this.timezoneName,
      countryCode: countryCode ?? this.countryCode,
      receiveGlobalContent: receiveGlobalContent ?? this.receiveGlobalContent,
    );
  }
}

class UserLocalePrefsScope extends InheritedNotifier<ValueNotifier<UserLocalePrefs>> {
  const UserLocalePrefsScope({required ValueNotifier<UserLocalePrefs> notifier, required super.child, super.key})
      : super(notifier: notifier);

  static ValueNotifier<UserLocalePrefs> of(BuildContext context) {
    final scope = context.dependOnInheritedWidgetOfExactType<UserLocalePrefsScope>();
    if (scope == null) throw StateError('UserLocalePrefsScope not found');
    return scope.notifier!;
  }
}

DateTime _toUserTime(DateTime dt, String? timezoneName) {
  final tzName = timezoneName?.trim();
  final utc = dt.isUtc ? dt : dt.toUtc();
  if (tzName == null || tzName.isEmpty) return utc.toLocal();
  try {
    final loc = tz.getLocation(tzName);
    return tz.TZDateTime.from(utc, loc);
  } catch (_) {
    return utc.toLocal();
  }
}

DateTime _userWallTimeToUtc(DateTime wallTime, String? timezoneName) {
  final tzName = timezoneName?.trim();
  if (tzName == null || tzName.isEmpty) return wallTime.toUtc();
  try {
    final loc = tz.getLocation(tzName);
    return tz.TZDateTime(
      loc,
      wallTime.year,
      wallTime.month,
      wallTime.day,
      wallTime.hour,
      wallTime.minute,
      wallTime.second,
      wallTime.millisecond,
      wallTime.microsecond,
    ).toUtc();
  } catch (_) {
    return wallTime.toUtc();
  }
}

String _formatRelativeTimeForUser(BuildContext context, DateTime dt) {
  final prefs = UserLocalePrefsScope.of(context).value;
  final local = _toUserTime(dt, prefs.timezoneName);
  final now = _toUserTime(DateTime.now(), prefs.timezoneName);
  final diff = now.difference(local);
  if (diff.inSeconds.abs() <= 10) return t(context).timeNow;
  if (diff.isNegative) return _formatTimestamp(local);
  if (diff.inMinutes < 60) return t(context).timeAgoMinutes(diff.inMinutes);
  if (diff.inHours < 24) return t(context).timeAgoHours(diff.inHours);
  if (diff.inDays < 7) return t(context).timeAgoDays(diff.inDays);
  return _formatTimestamp(local);
}

