enum PostVisibility { public, followers, church }

enum PostKind { request, testimony }

enum PostType { normal, alert, prayer, storyRef, event }

enum CampaignCategory { medical, emergency, social, church, mission, education, disaster, communityProject }

enum CampaignStatus { draft, active, closed, cancelled }

enum DonationStatus { pending, succeeded, failed, refunded }

enum PaymentMethod { pix, card }

PostVisibility _parsePostVisibility(String? value) {
  return switch (value) {
    'followers' => PostVisibility.followers,
    'church' => PostVisibility.church,
    _ => PostVisibility.public,
  };
}

PostKind _parsePostKind(String? value) {
  return switch (value) {
    'testimony' => PostKind.testimony,
    _ => PostKind.request,
  };
}

PostType _parsePostType(String? value, {PostKind? fallbackKind}) {
  return switch (value) {
    'alert' => PostType.alert,
    'prayer' => PostType.prayer,
    'story_ref' => PostType.storyRef,
    'event' => PostType.event,
    'normal' => PostType.normal,
    _ => switch (fallbackKind) {
        PostKind.request => PostType.prayer,
        PostKind.testimony => PostType.normal,
        _ => PostType.normal,
      },
  };
}

