bool _looksLikeUuid(String? value) {
  final v = value?.trim();
  if (v == null || v.isEmpty) return false;
  return RegExp(r'^[0-9a-fA-F]{8}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{4}-[0-9a-fA-F]{12}$').hasMatch(v);
}

String _uuidV4() {
  final rnd = math.Random.secure();
  final bytes = List<int>.generate(16, (_) => rnd.nextInt(256), growable: false);
  bytes[6] = (bytes[6] & 0x0f) | 0x40;
  bytes[8] = (bytes[8] & 0x3f) | 0x80;
  String hex(int b) => b.toRadixString(16).padLeft(2, '0');
  final s = bytes.map(hex).join();
  return '${s.substring(0, 8)}-${s.substring(8, 12)}-${s.substring(12, 16)}-${s.substring(16, 20)}-${s.substring(20)}';
}

bool _looksLikeEmail(String? value) {
  final v = value?.trim();
  if (v == null || v.isEmpty) return false;
  if (!v.contains('@')) return false;
  final parts = v.split('@');
  if (parts.length != 2) return false;
  if (parts.first.trim().isEmpty) return false;
  final domain = parts.last.trim();
  if (domain.isEmpty) return false;
  if (!domain.contains('.')) return false;
  return true;
}

String _normalizeDisplayUsername(String? value, {String fallback = ''}) {
  final v = value?.trim() ?? '';
  if (v.isEmpty) return fallback.trim();
  if (_looksLikeEmail(v)) return fallback.trim();
  return v;
}

String _displayNameForProfile(ProfileModel profile, {String userFallback = ''}) {
  final displayName = profile.name.trim();
  if (displayName.isNotEmpty && !_looksLikeEmail(displayName)) return displayName;
  final fullName = profile.fullName.trim();
  if (fullName.isNotEmpty && !_looksLikeEmail(fullName)) return fullName;
  return userFallback;
}

String _fallbackUsernameForUserId(String userId) {
  final id = userId.trim();
  if (id.isEmpty) return 'user';
  if (_looksLikeUuid(id)) return 'user${id.substring(0, 8)}';
  final cleaned = id.replaceAll(RegExp(r'[^a-zA-Z0-9._-]'), '');
  if (cleaned.isEmpty) return 'user';
  return cleaned;
}

String _usernameForProfile(ProfileModel? profile, {required String userId}) {
  final u = profile?.username.trim() ?? '';
  if (u.isEmpty) return _fallbackUsernameForUserId(userId);
  if (_looksLikeEmail(u)) return _fallbackUsernameForUserId(userId);
  return u;
}

({String displayName, String username, String avatarName, String? avatarUrl, bool isVerified}) _identityForUserId(
  DemoRepository repo,
  String userId, {
  bool legacyVerified = false,
  String userFallback = '',
}) {
  final profile = repo.profileForUserId(userId);
  final displayName = profile == null ? userFallback : _displayNameForProfile(profile, userFallback: userFallback);
  final username = _usernameForProfile(profile, userId: userId);
  final avatarName = displayName;
  final avatarUrl = profile?.avatarUrl;
  final isVerified = profile?.isVerified ?? legacyVerified;
  return (
    displayName: displayName,
    username: username,
    avatarName: avatarName,
    avatarUrl: avatarUrl,
    isVerified: isVerified,
  );
}

bool _postgrestMissingColumn(PostgrestException e, String column) {
  final c = column.trim().toLowerCase();
  if (c.isEmpty) return false;
  final msg = [
    e.message,
    (e.details ?? '').toString(),
    (e.hint ?? '').toString(),
  ].join(' ').toLowerCase();
  if (!msg.contains(c)) return false;
  return msg.contains('schema cache') ||
      msg.contains('does not exist') ||
      msg.contains('could not find') ||
      msg.contains('unknown column') ||
      msg.contains('column');
}

String? _normalizeSupabaseMediaPublicUrl(String? url) {
  final v = url?.trim();
  if (v == null || v.isEmpty) return null;
  const needle = '/storage/v1/object/media/';
  const replacement = '/storage/v1/object/public/media/';
  if (v.contains(replacement)) return v;
  if (v.contains(needle)) return v.replaceFirst(needle, replacement);
  return v;
}

double _numToDouble(Object? value, {double fallback = 0}) {
  if (value is num) return value.toDouble();
  if (value is String) return double.tryParse(value.replaceAll(',', '.')) ?? fallback;
  return fallback;
}

int _numToInt(Object? value, {int fallback = 0}) {
  if (value is int) return value;
  if (value is num) return value.toInt();
  if (value is String) return int.tryParse(value) ?? fallback;
  return fallback;
}

String _formatCompactInt(int value) {
  final v = value.abs();
  if (v >= 1000000) return '${(value / 1000000).toStringAsFixed(value % 1000000 == 0 ? 0 : 1)}M';
  if (v >= 1000) return '${(value / 1000).toStringAsFixed(value % 1000 == 0 ? 0 : 1)}k';
  return '$value';
}

String _formatBrl(double amount) {
  final clamped = amount.isFinite ? amount : 0;
  final parts = clamped.toStringAsFixed(2).split('.');
  final whole = parts[0];
  final cents = parts.length > 1 ? parts[1] : '00';
  final buf = StringBuffer();
  for (var i = 0; i < whole.length; i++) {
    final left = whole.length - i;
    buf.write(whole[i]);
    if (left > 1 && left % 3 == 1) buf.write('.');
  }
  return 'R\$ ${buf.toString()},$cents';
}

String _formatHoursFromSeconds(int seconds) {
  final s = seconds < 0 ? 0 : seconds;
  if (s <= 0) return '0h';
  final hours = s ~/ 3600;
  final mins = (s % 3600) ~/ 60;
  if (hours <= 0) return '${mins}min';
  if (mins <= 0) return '${hours}h';
  return '${hours}h ${mins}min';
}

double _distanceKm(LatLng a, LatLng b) {
  const r = 6371.0;
  final dLat = (b.latitude - a.latitude) * (math.pi / 180);
  final dLng = (b.longitude - a.longitude) * (math.pi / 180);
  final lat1 = a.latitude * (math.pi / 180);
  final lat2 = b.latitude * (math.pi / 180);
  final h =
      math.sin(dLat / 2) * math.sin(dLat / 2) + math.cos(lat1) * math.cos(lat2) * math.sin(dLng / 2) * math.sin(dLng / 2);
  return 2 * r * math.asin(math.sqrt(h.clamp(0, 1)));
}

