final class _AnalyticsOnce extends StatefulWidget {
  const _AnalyticsOnce({
    required this.eventName,
    required this.fieldsBuilder,
    required this.child,
  });

  final String eventName;
  final Map<String, Object?> Function(BuildContext context) fieldsBuilder;
  final Widget child;

  @override
  State<_AnalyticsOnce> createState() => _AnalyticsOnceState();
}

class _AnalyticsOnceState extends State<_AnalyticsOnce> {
  var _fired = false;

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();
    if (_fired) return;
    _fired = true;
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      final repo = RepoScope.of(context);
      repo.trackEvent(widget.eventName, widget.fieldsBuilder(context));
    });
  }

  @override
  Widget build(BuildContext context) => widget.child;
}

