final class PrayerChallengeModel {
  const PrayerChallengeModel({
    required this.id,
    required this.title,
    required this.description,
    required this.imageUrl,
    required this.targetRegion,
    required this.targetLocationId,
    required this.targetLocationName,
    required this.communityId,
    required this.communityName,
    required this.startDate,
    required this.endDate,
    required this.goalParticipants,
    required this.goalPrayerMinutes,
    required this.status,
    required this.createdAt,
    required this.participantsCount,
    required this.viewerJoined,
    required this.totalDurationSeconds,
    required this.centerLat,
    required this.centerLng,
  });

  final String id;
  final String title;
  final String description;
  final String? imageUrl;

  final String targetRegion;
  final String? targetLocationId;
  final String? targetLocationName;
  final String? communityId;
  final String? communityName;

  final DateTime startDate;
  final DateTime endDate;
  final int goalParticipants;
  final int goalPrayerMinutes;
  final PrayerChallengeStatus status;
  final DateTime createdAt;

  final int participantsCount;
  final bool viewerJoined;
  final int totalDurationSeconds;

  final double? centerLat;
  final double? centerLng;

  bool get isActiveNow {
    final now = DateTime.now().toUtc();
    if (status != PrayerChallengeStatus.active) return false;
    return !now.isBefore(startDate.toUtc()) && !now.isAfter(endDate.toUtc());
  }

  double get participantsProgress {
    final goal = goalParticipants;
    if (goal <= 0) return 0;
    return (participantsCount / goal).clamp(0, 1);
  }

  double get prayerProgress {
    final goalSeconds = goalPrayerMinutes * 60;
    if (goalSeconds <= 0) return 0;
    return (totalDurationSeconds / goalSeconds).clamp(0, 1);
  }
}

