  if (v.isEmpty) return null;
  return switch (v) {
    'follow' || 'followed' => NotificationType.follow,
    'reaction' || 'liked' => NotificationType.reaction,
    'comment' || 'commented' => NotificationType.comment,
    'prayed' => NotificationType.prayed,
    'post_new' => NotificationType.postNew,
    'story_new' => NotificationType.storyNew,
    'alert_new' => NotificationType.alertNew,
    'prayer_request' => NotificationType.prayerRequest,
    'scale_reminder_24h' => NotificationType.scaleReminder24h,
    'scale_reminder_1h' => NotificationType.scaleReminder1h,
    _ => null,
  };
}

