final class _AdSlotRecord {
  const _AdSlotRecord._({
    required this.slotId,
    required this.placement,
    required this.status,
    required this.startedAt,
    required this.creative,
  });

  factory _AdSlotRecord.loading({
    required String slotId,
    required String placement,
    required DateTime startedAt,
    required AdCreative creative,
  }) {
    return _AdSlotRecord._(
      slotId: slotId,
      placement: placement,
      status: _AdSlotStatus.loading,
      startedAt: startedAt,
      creative: creative,
    );
  }

  final String slotId;
  final String placement;
  final _AdSlotStatus status;
  final DateTime startedAt;
  final AdCreative creative;

  _AdSlotRecord toReady(AdCreative creative) {
    if (status == _AdSlotStatus.ready && identical(this.creative, creative)) return this;
    return _AdSlotRecord._(
      slotId: slotId,
      placement: placement,
      status: _AdSlotStatus.ready,
      startedAt: startedAt,
      creative: creative,
    );
  }

  _AdSlotRecord toFallback(AdCreative creative) {
    return _AdSlotRecord._(
      slotId: slotId,
      placement: placement,
      status: _AdSlotStatus.fallback,
      startedAt: startedAt,
      creative: creative,
    );
  }
}

