  void setActiveCommunityFilterId(String? communityId) {
    final next = _looksLikeUuid(communityId) ? communityId : null;
    if (_activeCommunityFilterId == next) return;
    _activeCommunityFilterId = next;
    if (supabase != null && !isOffline) {
      unawaited(
        refreshFeedForCurrentSession(
          scope: next == null ? 'world' : 'community',
          locationPath: _lastFeedLocationPath,
          locationId: _lastFeedLocationId,
          communityId: next,
          postTypes: _lastFeedPostTypes,
          sort: _lastFeedSort,
          lat: _lastFeedLat,
          lng: _lastFeedLng,
        ),
      );
    }
    notifyListeners();
  }

  bool _isRpcUnavailable(Object error, String rpcName) {
    if (error is! PostgrestException) return false;
    final code = (error.code ?? '').trim().toUpperCase();
    if (code == 'PGRST202') return true;
    final message = '${error.message} ${error.details} ${error.hint}'.toLowerCase();
    if (message.contains('could not find the function')) return true;
    if (message.contains('public.$rpcName'.toLowerCase())) return true;
    return false;
  }

