  void _schedulePersistDirect() {
    if (supabase == null) return;
    if (_viewerSessionKey == 'anon') return;
    _directPersistDebounce?.cancel();
    _directPersistDebounce = Timer(const Duration(milliseconds: 300), () {
      unawaited(_saveDirectCache());
    });
  }

  Future<void> _loadDirectCacheIfNeeded() async {
    if (supabase == null) return;
    if (_viewerSessionKey == 'anon') return;
    if (_directCacheLoadedForSessionKey == _viewerSessionKey) return;
    _directCacheLoadedForSessionKey = _viewerSessionKey;
    try {
      final sp = await SharedPreferences.getInstance();
      final raw = sp.getString('direct_cache_v1:$_viewerSessionKey');
      if (raw == null || raw.trim().isEmpty) return;
      final decoded = jsonDecode(raw);
      if (decoded is! Map) return;

      final threadsRaw = decoded['threads'];
      final messagesRaw = decoded['messagesByThread'];
      final restrictedRaw = decoded['restrictedUserIds'];
      final blockedRaw = decoded['blockedUserIds'];
      final nicknamesRaw = decoded['directNicknames'];

      final nextThreads = <ThreadModel>[];
      if (threadsRaw is List) {
        for (final item in threadsRaw) {
          final t = _threadFromJson(item);
          if (t != null) nextThreads.add(t);
        }
      }
      final nextMessages = <String, List<MessageModel>>{};
      if (messagesRaw is Map) {
        for (final entry in messagesRaw.entries) {
          final threadId = entry.key?.toString();
          if (threadId == null || threadId.isEmpty) continue;
          final listRaw = entry.value;
          if (listRaw is! List) continue;
          final list = <MessageModel>[];
          for (final item in listRaw) {
            final m = _messageFromJson(item);
            if (m != null) list.add(m);
          }
          nextMessages[threadId] = List.unmodifiable(list);
        }
      }

      if (nextThreads.isNotEmpty) {
        final byId = <String, ThreadModel>{for (final t in _threads) t.id: t};
        for (final t in nextThreads) {
          byId.putIfAbsent(t.id, () => t);
        }
        final list = byId.values.toList(growable: false)..sort((a, b) => b.lastAt.compareTo(a.lastAt));
        _threads = List.unmodifiable(list);
      }
      if (nextMessages.isNotEmpty) {
        for (final entry in nextMessages.entries) {
          _messagesByThread.putIfAbsent(entry.key, () => entry.value);
        }
      }
      if (restrictedRaw is List) {
        for (final item in restrictedRaw) {
          final id = item?.toString().trim() ?? '';
          if (id.isEmpty) continue;
          _restrictedDirectUserIds.add(id);
        }
      }
      if (blockedRaw is List) {
        for (final item in blockedRaw) {
          final id = item?.toString().trim() ?? '';
          if (id.isEmpty) continue;
          _blockedDirectUserIds.add(id);
        }
      }
      if (nicknamesRaw is Map) {
        for (final entry in nicknamesRaw.entries) {
          final key = entry.key?.toString().trim() ?? '';
          final value = entry.value?.toString().trim() ?? '';
          if (key.isEmpty || value.isEmpty) continue;
          _directNicknamesByThreadUserKey[key] = value;
        }
      }
      notifyListeners();
    } catch (_) {}
  }

  Future<void> _saveDirectCache() async {
    if (supabase == null) return;
    if (_viewerSessionKey == 'anon') return;
    try {
      final sp = await SharedPreferences.getInstance();
      final data = <String, Object?>{
        'threads': _threads.map(_threadToJson).toList(growable: false),
        'messagesByThread': <String, Object?>{
          for (final entry in _messagesByThread.entries)
            entry.key: entry.value.map(_messageToJson).toList(growable: false),
        },
        'restrictedUserIds': _restrictedDirectUserIds.toList(growable: false),
        'blockedUserIds': _blockedDirectUserIds.toList(growable: false),
        'directNicknames': <String, String>{
          for (final entry in _directNicknamesByThreadUserKey.entries) entry.key: entry.value,
        },
      };
      await sp.setString('direct_cache_v1:$_viewerSessionKey', jsonEncode(data));
    } catch (_) {}
  }

  void _schedulePersistMediaLibrary() {
    final key = _mediaLibraryCacheKey();
    if (key == null) return;
    _mediaLibraryPersistDebounce?.cancel();
    _mediaLibraryPersistDebounce = Timer(const Duration(milliseconds: 300), () {
      unawaited(_saveMediaLibraryCache());
    });
  }

  String? _mediaLibraryCacheKey() {
    final viewerId = _viewerUserId.trim();
    if (viewerId.isEmpty) return null;
    final sessionKey = _viewerSessionKey.trim();
    if (sessionKey.isEmpty) return null;
    return 'media_library_v1:$sessionKey:$viewerId';
  }

  Future<void> _loadMediaLibraryCacheIfNeeded() async {
    final key = _mediaLibraryCacheKey();
    if (key == null) return;
    if (_mediaLibraryCacheLoadedForSessionKey == key) return;
    _mediaLibraryCacheLoadedForSessionKey = key;
    final viewerId = _viewerUserId.trim();
    if (viewerId.isEmpty) return;
    try {
      final sp = await SharedPreferences.getInstance();
      final raw = sp.getString(key);
      if (raw == null || raw.trim().isEmpty) return;
      final decoded = jsonDecode(raw);
      if (decoded is! List) return;
      final loaded = <MediaLibraryItemModel>[];
      for (final item in decoded) {
        final m = _mediaLibraryItemFromJson(item);
        if (m == null) continue;
        if (m.ownerId != viewerId) continue;
        loaded.add(m);
      }
      if (loaded.isEmpty) return;

      final kept = _mediaLibraryItems.where((i) => i.ownerId != viewerId).toList(growable: true);
      final byId = <String, MediaLibraryItemModel>{};
      for (final m in loaded) {
        byId[m.id] = m;
      }
      kept.addAll(byId.values);
      kept.sort((a, b) => b.updatedAt.compareTo(a.updatedAt));
      _mediaLibraryItems = List.unmodifiable(kept);
      notifyListeners();
    } catch (_) {}
  }

  Future<void> _saveMediaLibraryCache() async {
    final key = _mediaLibraryCacheKey();
    if (key == null) return;
    final viewerId = _viewerUserId.trim();
    if (viewerId.isEmpty) return;
    try {
      final sp = await SharedPreferences.getInstance();
      final owned = _mediaLibraryItems.where((i) => i.ownerId == viewerId).toList(growable: false);
      owned.sort((a, b) => b.updatedAt.compareTo(a.updatedAt));
      final data = owned.map(_mediaLibraryItemToJson).toList(growable: false);
      await sp.setString(key, jsonEncode(data));
    } catch (_) {}
  }

  Map<String, Object?> _mediaLibraryItemToJson(MediaLibraryItemModel item) {
    return <String, Object?>{
      'id': item.id,
      'ownerId': item.ownerId,
      'title': item.title,
      'subtitle': item.subtitle,
      'type': item.type.name,
      'mediaUrl': item.mediaUrl,
      'thumbnailUrl': item.thumbnailUrl,
      'durationSeconds': item.durationSeconds,
      'createdAt': item.createdAt.toIso8601String(),
      'updatedAt': item.updatedAt.toIso8601String(),
    };
  }

  MediaLibraryItemModel? _mediaLibraryItemFromJson(Object? raw) {
    if (raw is! Map) return null;
    final id = raw['id']?.toString() ?? '';
    final ownerId = raw['ownerId']?.toString() ?? '';
    final title = raw['title']?.toString() ?? '';
    final mediaUrl = raw['mediaUrl']?.toString() ?? '';
    final createdAt = DateTime.tryParse(raw['createdAt']?.toString() ?? '')?.toLocal();
    final updatedAt = DateTime.tryParse(raw['updatedAt']?.toString() ?? '')?.toLocal();
    if (id.isEmpty || ownerId.isEmpty || title.isEmpty || mediaUrl.isEmpty || createdAt == null || updatedAt == null) {
      return null;
    }
    final typeRaw = raw['type']?.toString() ?? '';
    final type = PlaylistItemType.values.firstWhere((t) => t.name == typeRaw, orElse: () => PlaylistItemType.audio);
    return MediaLibraryItemModel(
      id: id,
      ownerId: ownerId,
      title: title,
      subtitle: raw['subtitle']?.toString(),
      type: type,
      mediaUrl: mediaUrl,
      thumbnailUrl: raw['thumbnailUrl']?.toString(),
      durationSeconds: (raw['durationSeconds'] as num?)?.toInt(),
      createdAt: createdAt,
      updatedAt: updatedAt,
    );
  }

  Map<String, Object?> _threadToJson(ThreadModel t) {
    return <String, Object?>{
      'id': t.id,
      'peerUserId': t.peerUserId,
      'peerName': t.peerName,
      'peerUsername': t.peerUsername,
      'peerIsVerified': t.peerIsVerified,
      'lastMessage': t.lastMessage,
      'lastAt': t.lastAt.toIso8601String(),
      'isGroup': t.isGroup,
      'communityId': t.communityId,
      'unreadCount': t.unreadCount,
      'isMuted': t.isMuted,
      'themeKey': t.themeKey,
      'ephemeralHours': t.ephemeralHours,
    };
  }

  ThreadModel? _threadFromJson(Object? raw) {
    if (raw is! Map) return null;
    final id = raw['id']?.toString() ?? '';
    final peerUserId = raw['peerUserId']?.toString() ?? '';
    final peerName = raw['peerName']?.toString() ?? '';
    final peerUsername = raw['peerUsername']?.toString() ?? '';
    final lastMessage = raw['lastMessage']?.toString() ?? '';
    final lastAt = DateTime.tryParse(raw['lastAt']?.toString() ?? '')?.toLocal();
    if (id.isEmpty || peerUserId.isEmpty || peerName.isEmpty || peerUsername.isEmpty || lastAt == null) return null;
    return ThreadModel(
      id: id,
      peerUserId: peerUserId,
      peerName: peerName,
      peerUsername: peerUsername,
      peerIsVerified: raw['peerIsVerified'] == true,
      lastMessage: lastMessage,
      lastAt: lastAt,
      isGroup: raw['isGroup'] == true,
      communityId: raw['communityId']?.toString(),
      unreadCount: int.tryParse(raw['unreadCount']?.toString() ?? '') ?? 0,
      isMuted: raw['isMuted'] == true,
      themeKey: (raw['themeKey']?.toString().trim().isEmpty ?? true) ? 'default' : raw['themeKey'].toString().trim(),
      ephemeralHours: (int.tryParse(raw['ephemeralHours']?.toString() ?? '') ?? 0).clamp(0, 24 * 7),
    );
  }

  Map<String, Object?> _messageToJson(MessageModel m) {
    return <String, Object?>{
      'id': m.id,
      'threadId': m.threadId,
      'senderId': m.senderId,
      'kind': m.kind.name,
      'sentAt': m.sentAt.toIso8601String(),
      'sendStatus': m.sendStatus.name,
      'text': m.text,
      'imageToken': m.imageToken,
      'postId': m.post?.id,
    };
  }

  MessageModel? _messageFromJson(Object? raw) {
    if (raw is! Map) return null;
    final id = raw['id']?.toString() ?? '';
    final threadId = raw['threadId']?.toString() ?? '';
    final senderId = raw['senderId']?.toString() ?? '';
    final kindRaw = raw['kind']?.toString() ?? '';
    final statusRaw = raw['sendStatus']?.toString() ?? '';
    final sentAt = DateTime.tryParse(raw['sentAt']?.toString() ?? '')?.toLocal();
    if (id.isEmpty || threadId.isEmpty || senderId.isEmpty || sentAt == null) return null;
    final kind = MessageKind.values.firstWhere((k) => k.name == kindRaw, orElse: () => MessageKind.text);
    final status =
        MessageSendStatus.values.firstWhere((s) => s.name == statusRaw, orElse: () => MessageSendStatus.sent);
    final postId = raw['postId']?.toString();
    final post = postId == null || postId.isEmpty ? null : findPost(postId);
    return MessageModel(
      id: id,
      threadId: threadId,
      senderId: senderId,
      kind: kind,
      sentAt: sentAt,
      sendStatus: status,
      text: raw['text']?.toString(),
      imageToken: raw['imageToken']?.toString(),
      post: post,
    );
  }

  Future<AuthSession?> sessionFromSupabaseAuth() async {
    final sb = supabase;
    if (sb == null) return null;
    final user = sb.auth.currentUser ?? sb.auth.currentSession?.user;
    if (user == null) return null;

    Map<String, dynamic>? row;
    try {
      row = await sb
          .from('profiles')
          .select(
            'username,display_name,full_name,bio,church_id,is_verified,avatar_url,is_active,deactivated_at,deleted_at',
          )
          .eq('id', user.id)
          .maybeSingle();
    } on PostgrestException catch (e) {
      if (_postgrestMissingColumn(e, 'is_active') || _postgrestMissingColumn(e, 'deleted_at') || _postgrestMissingColumn(e, 'deactivated_at')) {
        try {
          row = await sb
              .from('profiles')
              .select(
                'username,display_name,full_name,bio,church_id,is_verified,avatar_url',
              )
              .eq('id', user.id)
              .maybeSingle();
        } catch (_) {
          row = null;
        }
      } else
      if (_postgrestMissingColumn(e, 'full_name')) {
        try {
          row = await sb
              .from('profiles')
              .select('username,display_name,bio,church_id,is_verified,avatar_url,is_active,deactivated_at,deleted_at')
              .eq('id', user.id)
              .maybeSingle();
        } catch (_) {
          row = null;
        }
      } else {
        row = null;
      }
    } catch (_) {
      row = null;
    }
    final isActive = row?['is_active'];
    final deletedAt = DateTime.tryParse(row?['deleted_at']?.toString() ?? '')?.toLocal();
    if (isActive == false || deletedAt != null) {
      _lastAuthError = 'Conta desativada.';
      try {
        await sb.auth.signOut();
      } catch (_) {}
      return null;
    }
    final username = (row?['username'] as String?)?.trim() ?? '';
    final displayName = (row?['display_name'] as String?)?.trim() ?? '';
    final fullName = (row?['full_name'] as String?)?.trim() ?? '';
    final resolvedUsername = username.isEmpty ? _fallbackUsernameForUserId(user.id) : username;

    _upsertProfile(
      ProfileModel(
        userId: user.id,
        name: displayName,
        fullName: fullName,
        username: username,
        isVerified: row?['is_verified'] == true,
        reputationScore: (row?['reputation_score'] as num?)?.toInt() ?? 0,
        reputationLevel: _parseReputationLevel(row?['reputation_level']?.toString()),
        verificationType: _parseVerificationType(row?['verification_type']?.toString()),
        suspendedUntil: DateTime.tryParse(row?['suspended_until']?.toString() ?? '')?.toLocal(),
        avatarUrl: _normalizeSupabaseMediaPublicUrl((row?['avatar_url'] as String?)?.trim()),
        bio: (row?['bio'] as String?) ?? '',
        churchName: null,
      ),
    );

    return AuthSession(
      userId: user.id,
      username: resolvedUsername,
      churchId: row?['church_id']?.toString(),
    );
  }

  Future<Map<String, ProfileModel>> _fetchProfilesByIds(Set<String> ids) async {
    final sb = supabase;
    if (sb == null) return const <String, ProfileModel>{};
    if (ids.isEmpty) return const <String, ProfileModel>{};
    List<dynamic> rows = const <dynamic>[];
    try {
      final select = 'id,username,display_name,bio,is_verified,avatar_url';
      if (ids.length == 1) {
        final only = ids.first;
        rows = await sb.from('profiles').select(select).eq('id', only);
      } else {
        rows = await sb.from('profiles').select(select).inFilter('id', ids.toList(growable: false));
      }
    } catch (_) {}
    final map = <String, ProfileModel>{};
    for (final raw in rows) {
      final r = raw as Map<String, dynamic>;
      final id = r['id']?.toString();
      if (id == null || id.isEmpty) continue;
      final username = (r['username'] as String?)?.trim() ?? '';
      final displayName = (r['display_name'] as String?)?.trim() ?? '';
      final fullName = (r['full_name'] as String?)?.trim() ?? '';
      final p = ProfileModel(
        userId: id,
        name: displayName,
        fullName: fullName,
        username: username,
        isVerified: r['is_verified'] == true,
        reputationScore: (r['reputation_score'] as num?)?.toInt() ?? 0,
        reputationLevel: _parseReputationLevel(r['reputation_level']?.toString()),
        verificationType: _parseVerificationType(r['verification_type']?.toString()),
        suspendedUntil: DateTime.tryParse(r['suspended_until']?.toString() ?? '')?.toLocal(),
        avatarUrl: _normalizeSupabaseMediaPublicUrl((r['avatar_url'] as String?)?.trim()),
        bio: (r['bio'] as String?) ?? '',
        churchName: null,
      );
      map[id] = p;
      _upsertProfile(p);
    }
    return map;
  }

  Future<Map<String, Map<String, String?>>> _fetchFirstMediaByPostIds(Set<String> postIds) async {
    final sb = supabase;
    if (sb == null) return const <String, Map<String, String?>>{};
    if (postIds.isEmpty) return const <String, Map<String, String?>>{};
    final rows = await sb
        .from('post_media')
        .select('post_id,kind,provider,storage_key,external_id,order_index')
        .inFilter('post_id', postIds.toList(growable: false))
        .order('order_index', ascending: true);
    final map = <String, Map<String, String?>>{};
    for (final raw in (rows as List<dynamic>)) {
      final r = raw as Map<String, dynamic>;
      final postId = r['post_id']?.toString();
      if (postId == null || postId.isEmpty) continue;
      if (map.containsKey(postId)) continue;
      final provider = r['provider']?.toString();
      final kind = r['kind']?.toString();
      final storageKey = r['storage_key']?.toString();
      final externalId = r['external_id']?.toString();
      final url = switch (provider) {
        'external' => _normalizeSupabaseMediaPublicUrl(externalId),
        _ => storageKey == null ? null : _normalizeSupabaseMediaPublicUrl(sb.storage.from('media').getPublicUrl(storageKey)),
      };
      map[postId] = <String, String?>{'kind': kind, 'url': url};
    }
    return map;
  }

  Future<Set<String>> _fetchViewerPostIds({
