  Future<String?> locationIdByPath(String path) async {
    final p = path.trim();
    if (p.isEmpty) return null;
    final cached = _locationIdByPathCache[p];
    if (cached != null) return cached;
    if (_locationPathMisses.contains(p) && p != 'world') return null;
    final sb = supabase;
    if (sb == null) return null;
    if (isOffline) return null;
    try {
      final row = await sb.from('locations').select('id').eq('path', p).maybeSingle();
      final id = row?['id']?.toString();
      if (id == null || id.isEmpty) {
        if (p == 'world') {
          final fallback = await sb.from('locations').select('id').eq('level', 'world').maybeSingle();
          final fallbackId = fallback?['id']?.toString();
          if (fallbackId != null && fallbackId.isNotEmpty) {
            _locationPathMisses.remove(p);
            _locationIdByPathCache[p] = fallbackId;
            return fallbackId;
          }
        }
        _locationPathMisses.add(p);
        return null;
      }
      if (p == 'world') _locationPathMisses.remove(p);
      _locationIdByPathCache[p] = id;
      return id;
    } catch (_) {
      return null;
    }
  }

  Future<String?> locationNameById(String id) async {
    final key = id.trim();
