      final name = row?['name']?.toString();
      if (name == null || name.isEmpty) {
        _locationNameMisses.add(key);
        return null;
      }
      _locationNameByIdCache[key] = name;
      return name;
    } catch (_) {
      return null;
    }
  }

  Future<Map<String, String>?> locationMetaById(String id) async {
    final key = id.trim();
