    }
  }

  Future<String> createPrayerSession({
    required String locationId,
    required String locationLevel,
    String? challengeId,
    String? communityId,
    String? scheduleRunId,
    DateTime? startedAt,
  }) async {
    final sb = supabase;
    if (sb == null) throw StateError('Supabase indisponível');
    if (isOffline) throw StateError('Sem conexão');
    final uid = sb.auth.currentUser?.id;
    if (uid == null) throw StateError('Sem sessão');
    if (!_looksLikeUuid(locationId)) throw StateError('Local inválido');
    final remoteChallengeId = _looksLikeUuid(challengeId) ? challengeId : null;
    final remoteCommunityId = _looksLikeUuid(communityId) ? communityId : null;
    final remoteScheduleRunId = _looksLikeUuid(scheduleRunId) ? scheduleRunId : null;
    final now = (startedAt ?? DateTime.now()).toUtc();
    try {
      final base = <String, Object?>{
        'user_id': uid,
        'location_id': locationId,
        'location_level': locationLevel,
        'challenge_id': remoteChallengeId,
        'community_id': remoteCommunityId,
        'schedule_run_id': remoteScheduleRunId,
        'started_at': now.toIso8601String(),
        'status': 'active',
      };
      final row = await sb.from('prayer_sessions').insert(base).select('id').single();
      final id = row['id']?.toString();
      if (id == null || id.isEmpty) throw StateError('Sessão inválida');
      return id;
    } on PostgrestException catch (e) {
      if (e.code == 'PGRST205' || e.message.contains("Could not find the table 'public.prayer_sessions'")) {
        throw StateError('Banco incompleto: rode a migration "phase15_prayer_challenges" (cria a tabela prayer_sessions e policies RLS)');
      }
      if (_postgrestMissingColumn(e, 'community_id') || _postgrestMissingColumn(e, 'schedule_run_id')) {
        final row = await sb
            .from('prayer_sessions')
            .insert(<String, Object?>{
              'user_id': uid,
              'location_id': locationId,
              'location_level': locationLevel,
              'challenge_id': remoteChallengeId,
              'started_at': now.toIso8601String(),
              'status': 'active',
            })
            .select('id')
            .single();
        final id = row['id']?.toString();
        if (id == null || id.isEmpty) throw StateError('Sessão inválida');
        return id;
      }
      rethrow;
    }
  }

