  Future<void> finishPrayerSession({
    required String sessionId,
    required DateTime endedAt,
    required int durationSeconds,
    required String status,
    String? prayerRecordText,
    String? prayerRecordType,
  }) async {
    final sb = supabase;
    if (sb == null) throw StateError('Supabase indisponível');
    if (isOffline) throw StateError('Sem conexão');
    if (!_looksLikeUuid(sessionId)) throw StateError('Sessão inválida');
    try {
      final t = prayerRecordText?.trim();
      final k = prayerRecordType?.trim();
      final payload = <String, Object?>{
        'ended_at': endedAt.toUtc().toIso8601String(),
        'duration_seconds': durationSeconds,
        'status': status,
        if (t != null && t.isNotEmpty) 'prayer_record': t,
        if (t != null && t.isNotEmpty && k != null && k.isNotEmpty) 'prayer_record_type': k,
      };
      await sb.from('prayer_sessions').update(payload).eq('id', sessionId);
    } on PostgrestException catch (e) {
      if (e.code == 'PGRST205' || e.message.contains("Could not find the table 'public.prayer_sessions'")) {
        throw StateError('Banco incompleto: rode a migration "phase15_prayer_challenges" (cria a tabela prayer_sessions e policies RLS)');
      }
      if (_postgrestMissingColumn(e, 'prayer_record') || _postgrestMissingColumn(e, 'prayer_record_type')) {
        final t = prayerRecordText?.trim();
        final k = prayerRecordType?.trim();
        String? legacyColumn;
        if (t != null && t.isNotEmpty) {
          legacyColumn = switch (k) {
            'revelation' => 'revelations',
            'testimony' => 'observations',
            _ => 'notes',
          };
        }
        await sb.from('prayer_sessions').update(<String, Object?>{
          'ended_at': endedAt.toUtc().toIso8601String(),
          'duration_seconds': durationSeconds,
          'status': status,
          if (legacyColumn != null && t != null && t.isNotEmpty) legacyColumn: t,
        }).eq('id', sessionId);
        return;
      }
      rethrow;
    }
  }

  Future<void> refreshFeedForCurrentSession({
    String scope = 'world',
    String locationPath = 'world',
    String? locationId,
    String? communityId,
    List<String>? postTypes,
    String sort = 'recent',
    double? lat,
    double? lng,
  }) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final now = DateTime.now();
    String? nextFeedKey;
    String? resolvedLocationId;
    final remoteCommunityId = _looksLikeUuid(communityId) ? communityId : null;
    final usesCommunity = scope == 'community' && remoteCommunityId != null;
    try {
      resolvedLocationId = _looksLikeUuid(locationId) ? locationId : await locationIdByPath(locationPath);
      final viewerId = sb.auth.currentUser?.id;
      final followedIds = <String>{};
      if (!usesCommunity && viewerId != null) {
        await _refreshViewerFollowing(viewerId);
        followedIds.addAll(_followingByUserId[viewerId] ?? const <String>{});
      }
      final authorIds = <String>{if (viewerId != null) viewerId, ...followedIds};

      nextFeedKey = [
        _viewerSessionKey,
        usesCommunity ? 'community' : 'following',
        usesCommunity ? remoteCommunityId : '',
        if (!usesCommunity) ...authorIds.toList(growable: false)..sort(),
        (postTypes ?? const <String>[]).join(','),
        sort,
      ].join('|');
      if (_feedLoadedKey == nextFeedKey &&
          _feedLoadedAt != null &&
          now.difference(_feedLoadedAt!) < const Duration(seconds: 10)) {
        return;
      }

      _lastFeedScope = usesCommunity ? 'community' : scope;
      _lastFeedLocationPath = locationPath;
      _lastFeedLocationId = resolvedLocationId;
      _lastFeedCommunityId = usesCommunity ? remoteCommunityId : null;
      _lastFeedPostTypes = postTypes;
      _lastFeedSort = sort;
      _lastFeedLat = lat;
      _lastFeedLng = lng;
      if (usesCommunity) {
        unawaited(
          refreshAlertsForCurrentFeed(
            locationPath: locationPath,
            locationId: resolvedLocationId,
            communityId: remoteCommunityId,
          ),
        );
        unawaited(
          refreshCampaignsForCurrentFeed(
            locationPath: locationPath,
            locationId: resolvedLocationId,
            communityId: remoteCommunityId,
            lat: lat,
            lng: lng,
          ),
