        viewerHasLiked: likedIds.contains(id),
        viewerHasPrayed: prayedIds.contains(id),
        viewerHasSaved: false,
      );

      final existing = _posts.indexWhere((p) => p.id == id);
      if (existing >= 0) {
        final list = _posts.toList(growable: true);
        list[existing] = post;
        _posts = List.unmodifiable(list);
      } else {
        _posts = List.unmodifiable([post, ..._posts.where((p) => p.id != id)]);
      }
      notifyListeners();
      return true;
    } catch (_) {
      return false;
    }
  }

