            summary: eventRaw['summary']?.toString(),
            category: eventRaw['category']?.toString() ?? 'other',
            urgencyLevel: eventRaw['urgency_level']?.toString() ?? 'low',
            occurredAt: DateTime.tryParse(eventRaw['occurred_at']?.toString() ?? ''),
            lastSeenAt: lastSeenAt,
            locationId: eventRaw['location_id']?.toString(),
            locationPath: eventRaw['location_path']?.toString(),
            locationName: eventRaw['location_name']?.toString(),
            prayerPostId: eventRaw['prayer_post_id']?.toString(),
            itemsCount: 0,
          );
        }
      }

      final items = <NewsItemModel>[];
      for (final rawItem in itemsRaw) {
        final m = rawItem is Map ? rawItem.cast<String, dynamic>() : null;
        if (m == null) continue;
        final id = m['id']?.toString();
        final title = m['title']?.toString();
        if (id == null || id.isEmpty) continue;
        if (title == null || title.trim().isEmpty) continue;
        items.add(
          NewsItemModel(
            id: id,
            title: title,
            url: m['url']?.toString(),
            publishedAt: DateTime.tryParse(m['published_at']?.toString() ?? ''),
            sourceId: m['source_id']?.toString(),
          ),
        );
      }

      return (event: event, items: List<NewsItemModel>.unmodifiable(items));
    } catch (_) {
      return (event: null, items: const <NewsItemModel>[]);
    }
