  Future<void> refreshGlobalExpansionConfig({required String? countryCode, bool force = false}) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;

    final cc = (countryCode ?? '').trim().toUpperCase();
    final now = DateTime.now();
    final isFresh = _globalExpansionLoadedAt != null && now.difference(_globalExpansionLoadedAt!).inMinutes < 10;
    if (!force && isFresh && _globalExpansionLoadedForCountryCode == cc) return;

    String? regionId;
    if (!_rpcResolveAppRegionUnavailable) {
      try {
        final rawRegion = await sb.rpc('resolve_app_region', params: <String, Object?>{'p_country_code': cc});
        final s = rawRegion?.toString().trim();
        regionId = (s == null || s.isEmpty) ? null : s;
      } on PostgrestException catch (e) {
        if (_isRpcUnavailable(e, 'resolve_app_region')) {
          _rpcResolveAppRegionUnavailable = true;
        }
        regionId = null;
      } catch (_) {
        regionId = null;
      }
    }

    final configs = <String, Object?>{};
    if (!_rpcGetEnabledFeatureRolloutsUnavailable) {
      try {
        final rows = await sb.rpc('get_enabled_feature_rollouts', params: <String, Object?>{'p_region_id': regionId});
        if (rows is List) {
          for (final raw in rows) {
            final r = raw is Map ? raw.cast<String, dynamic>() : null;
            final key = r?['feature_key']?.toString().trim();
            if (key == null || key.isEmpty) continue;
            configs[key] = r?['config'];
          }
        }
      } on PostgrestException catch (e) {
        if (_isRpcUnavailable(e, 'get_enabled_feature_rollouts')) {
          _rpcGetEnabledFeatureRolloutsUnavailable = true;
        }
      }
    }

    final changed = _appRegionId != regionId || !_mapEquals(_enabledFeatureConfigsByKey, configs);
    _appRegionId = regionId;
    _enabledFeatureConfigsByKey = configs;
    _globalExpansionLoadedForCountryCode = cc;
    _globalExpansionLoadedAt = now;
    if (changed) notifyListeners();
  }

  bool _mapEquals(Map<String, Object?> a, Map<String, Object?> b) {
    if (identical(a, b)) return true;
    if (a.length != b.length) return false;
    for (final e in a.entries) {
      if (!b.containsKey(e.key)) return false;
      final av = e.value;
      final bv = b[e.key];
      if (av is Map && bv is Map) {
        final am = av.cast<String, dynamic>();
        final bm = bv.cast<String, dynamic>();
        if (jsonEncode(am) != jsonEncode(bm)) return false;
      } else if (av is List && bv is List) {
        if (jsonEncode(av) != jsonEncode(bv)) return false;
      } else if (av != bv) {
        return false;
      }
    }
    return true;
  }

  Future<List<PostModel>> fetchCommunityFeedPosts(
    String communityId, {
    DateTime? cursorCreatedAt,
    int limit = 24,
    PostKind? kind,
  }) async {
    final sb = supabase;
    if (sb == null) return const [];
    if (isOffline) return const [];
    if (!_looksLikeUuid(communityId)) return const [];
    try {
      final postTypes = switch (kind) {
        null => null,
        PostKind.request => <String>['prayer'],
        PostKind.testimony => <String>['normal'],
      };
      late final List<Map<String, dynamic>> postRows;
      Future<List<Map<String, dynamic>>> fetchDirect({required bool legacy}) async {
        final select = legacy
            ? 'id,user_id,kind,visibility,body,church_id,community_id,created_at,like_count,comment_count,prayer_count,location_id,location:locations(path,name)'
            : 'id,user_id,kind,post_type,visibility,body,church_id,community_id,created_at,like_count,comment_count,prayer_count,location_id,location:locations(path,name)';
        var q = sb.from('posts').select(select).eq('community_id', communityId);
        if (cursorCreatedAt != null) q = q.lt('created_at', cursorCreatedAt.toIso8601String());
        if (kind != null) q = q.eq('kind', kind == PostKind.request ? 'request' : 'testimony');
        final rows = await q.order('created_at', ascending: false).limit(limit);
        return (rows as List<dynamic>).cast<Map<String, dynamic>>();
      }
      if (_rpcGetFeedByScopeUnavailable) {
        try {
          postRows = await fetchDirect(legacy: false);
        } on PostgrestException catch (e) {
          if (_postgrestMissingColumn(e, 'post_type') || _postgrestMissingColumn(e, 'media_type')) {
            postRows = await fetchDirect(legacy: true);
          } else {
            rethrow;
          }
        }
      } else {
        try {
          final rows = await sb.rpc(
            'get_feed_by_scope',
            params: <String, Object?>{
              'p_scope': 'community',
              'p_location_id': null,
              'p_community_id': communityId,
              'p_post_types': postTypes,
              'p_sort': 'recent',
              'p_cursor_created_at': cursorCreatedAt?.toUtc().toIso8601String(),
              'p_limit': limit,
              'p_lat': null,
              'p_lng': null,
            },
          );
          postRows = (rows as List<dynamic>).cast<Map<String, dynamic>>();
        } on PostgrestException catch (e) {
          if (!_isRpcUnavailable(e, 'get_feed_by_scope')) rethrow;
          _rpcGetFeedByScopeUnavailable = true;
          try {
            postRows = await fetchDirect(legacy: false);
          } on PostgrestException catch (e) {
            if (_postgrestMissingColumn(e, 'post_type') || _postgrestMissingColumn(e, 'media_type')) {
              postRows = await fetchDirect(legacy: true);
            } else {
              rethrow;
            }
          }
        }
      }
      final userIds = postRows.map((r) => r['user_id']?.toString()).whereType<String>().toSet();
      final postIds = postRows.map((r) => r['id']?.toString()).whereType<String>().toSet();

      final profilesById = await _fetchProfilesByIds(userIds);
      final mediaByPostId = await _fetchFirstMediaByPostIds(postIds);

      final viewerId = sb.auth.currentUser?.id;
      final likedIds =
          viewerId == null ? const <String>{} : await _fetchViewerPostIds(table: 'reactions', viewerId: viewerId, postIds: postIds);
      final prayedIds =
          viewerId == null ? const <String>{} : await _fetchViewerPostIds(table: 'prayers', viewerId: viewerId, postIds: postIds);

      final next = <PostModel>[];
      for (final r in postRows) {
        final id = r['id']?.toString();
        final userId = r['user_id']?.toString();
        if (id == null || userId == null) continue;
        if (_hiddenPostIds.contains(id)) continue;

        final profile = profilesById[userId];
        final media = mediaByPostId[id];
        final location = r['location'] is Map ? (r['location'] as Map).cast<String, dynamic>() : null;
        final kind = _parsePostKind(r['kind']?.toString());
        next.add(
          PostModel(
            id: id,
            userId: userId,
            username: profile?.username ?? userId,
            isVerified: profile?.isVerified ?? false,
            kind: kind,
            postType: _parsePostType(r['post_type']?.toString(), fallbackKind: kind),
            visibility: _parsePostVisibility(r['visibility']?.toString()),
            body: (r['body'] as String?) ?? '',
            createdAt: DateTime.tryParse(r['created_at']?.toString() ?? '') ?? DateTime.now(),
            regionPath: r['location_path']?.toString() ?? location?['path']?.toString() ?? 'world',
            location: r['location_name']?.toString() ?? location?['name']?.toString(),
            churchId: r['church_id']?.toString(),
            communityId: r['community_id']?.toString(),
            mediaKind: media?['kind'],
            mediaUrl: media?['url'],
            commentCount: (r['comment_count'] as int?) ?? 0,
            likeCount: (r['like_count'] as int?) ?? 0,
            prayerCount: (r['prayer_count'] as int?) ?? 0,
            viewerHasLiked: likedIds.contains(id),
            viewerHasPrayed: prayedIds.contains(id),
            viewerHasSaved: false,
          ),
        );
      }
      return List.unmodifiable(next);
    } catch (_) {
      return const [];
    }
  }

