  _AdSlotRecord adSlotFor({required String slotId, required String placement}) {
    final cached = _adSlotsById[slotId];
    if (cached != null) return cached;

    final sb = supabase;
    if (sb != null && !isOffline) {
      final now = DateTime.now();
      final token = _adSessionToken;
      final record = _AdSlotRecord.loading(
        slotId: slotId,
        placement: placement,
        startedAt: now,
        creative: _internalPromoCreative(slotId: slotId, placement: placement),
      );
      _adSlotsById[slotId] = record;
      unawaited(_loadAdSlotFromRemote(slotId: slotId, placement: placement, token: token));
      return record;
    }

    final now = DateTime.now();
    final token = _adSessionToken;
    final hash = slotId.hashCode ^ _viewerSessionKey.hashCode;
    final slow = hash.abs() % 5 == 0;
    final fail = hash.abs() % 11 == 0;
    final loadMs = slow ? 1300 : 520 + (hash.abs() % 420);
    final creative = _pickAdCreative(slotId: slotId, placement: placement);

    final record = _AdSlotRecord.loading(
      slotId: slotId,
      placement: placement,
      startedAt: now,
      creative: creative,
    );
    _adSlotsById[slotId] = record;

    Future<void>.delayed(Duration(milliseconds: loadMs)).then((_) {
      if (_adSessionToken != token) return;
      final current = _adSlotsById[slotId];
      if (current == null || current.status != _AdSlotStatus.loading) return;
      if (fail) {
        _adSlotsById[slotId] = current.toFallback(_internalPromoCreative(slotId: slotId, placement: placement));
      } else {
        _adSlotsById[slotId] = current.toReady(current.creative);
      }
      notifyListeners();
    });

    Future<void>.delayed(const Duration(milliseconds: 1000)).then((_) {
      if (_adSessionToken != token) return;
      final current = _adSlotsById[slotId];
      if (current == null || current.status != _AdSlotStatus.loading) return;
      _adSlotsById[slotId] = current.toFallback(_internalPromoCreative(slotId: slotId, placement: placement));
      notifyListeners();
    });

    return record;
  }

  Future<void> _loadAdSlotFromRemote({
    required String slotId,
    required String placement,
    required int token,
  }) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    if (_adSessionToken != token) return;

    try {
      final remotePlacement = placement.trim().isEmpty ? 'feed' : placement.trim().toLowerCase();
      final scope = _lastFeedScope.trim().isEmpty ? 'world' : _lastFeedScope.trim();

      final rows = await sb.rpc(
        'ads_select_feed_candidates',
        params: <String, Object?>{
          'p_scope': scope,
          'p_location_id': _lastFeedLocationId,
          'p_community_id': _lastFeedCommunityId,
          'p_placement': remotePlacement,
          'p_limit': 12,
        },
      );

      if (_adSessionToken != token) return;
      final list = (rows as List<dynamic>).cast<Map<String, dynamic>>();
      if (list.isEmpty) {
        final current = _adSlotsById[slotId];
        if (current == null || current.status != _AdSlotStatus.loading) return;
        _adSlotsById[slotId] = current.toFallback(_internalPromoCreative(slotId: slotId, placement: placement));
        notifyListeners();
        return;
      }

      final preferred = <Map<String, dynamic>>[];
      final fallback = <Map<String, dynamic>>[];
      for (final r in list) {
        final creativeId = r['creative_id']?.toString();
        if (creativeId == null || creativeId.isEmpty) continue;
        if (_usedAdCreativeIds.contains(creativeId)) {
          fallback.add(r);
        } else {
          preferred.add(r);
        }
      }
      final pool = preferred.isNotEmpty ? preferred : fallback;
      if (pool.isEmpty) return;

      final hash = slotId.hashCode ^ _viewerSessionKey.hashCode;
      final chosen = pool[hash.abs() % pool.length];

      final campaignId = chosen['campaign_id']?.toString();
      final creativeId = chosen['creative_id']?.toString();
      final advertiserName = (chosen['advertiser_name'] as String?)?.trim();
      final headline = (chosen['headline'] as String?)?.trim();
      final targetUrl = (chosen['target_url'] as String?)?.trim();

      if (campaignId == null || campaignId.isEmpty) return;
      if (creativeId == null || creativeId.isEmpty) return;
      if (targetUrl == null || targetUrl.isEmpty) return;

      final creative = AdCreative(
        id: creativeId,
        provider: 'atalaia_ads',
        campaignId: campaignId,
        advertiserName: advertiserName?.isEmpty ?? true ? 'Patrocinado' : advertiserName!,
        headline: headline?.isEmpty ?? true ? 'Patrocinado' : headline!,
        destinationUrl: targetUrl,
        seed: creativeId.hashCode ^ campaignId.hashCode,
      );

      _usedAdCreativeIds.add(creativeId);
      final current = _adSlotsById[slotId];
      if (current == null || current.status != _AdSlotStatus.loading) return;
      _adSlotsById[slotId] = current.toReady(creative);
      notifyListeners();
    } catch (_) {
      final current = _adSlotsById[slotId];
      if (current == null || current.status != _AdSlotStatus.loading) return;
      _adSlotsById[slotId] = current.toFallback(_internalPromoCreative(slotId: slotId, placement: placement));
      notifyListeners();
    }
  }

