  AdCreative _pickAdCreative({required String slotId, required String placement}) {
    final pool = <AdCreative>[
      const AdCreative(
        id: 'admob_1',
        provider: 'admob',
        advertiserName: 'Livraria Ebenézer',
        headline: 'Bíblias, devocionais e presentes',
        destinationUrl: 'https://atalaia.app/promo/livraria',
        seed: 11,
      ),
      const AdCreative(
        id: 'meta_1',
        provider: 'meta',
        advertiserName: 'Conferência Vida',
        headline: 'Ingressos com desconto por tempo limitado',
        destinationUrl: 'https://atalaia.app/promo/conferencia',
        seed: 23,
      ),
      const AdCreative(
        id: 'admob_2',
        provider: 'admob',
        advertiserName: 'Apoie uma missão',
        headline: 'Doe e acompanhe o impacto',
        destinationUrl: 'https://atalaia.app/promo/missao',
        seed: 37,
      ),
    ];

    final h = (slotId.hashCode ^ placement.hashCode ^ _viewerSessionKey.hashCode).abs();
    final i = h % pool.length;
    final base = pool[i];
    return AdCreative(
      id: base.id,
      provider: base.provider,
      advertiserName: base.advertiserName,
      headline: base.headline,
      destinationUrl: base.destinationUrl,
      seed: base.seed ^ h,
    );
  }

  AdCreative _internalPromoCreative({required String slotId, required String placement}) {
    final h = (slotId.hashCode ^ placement.hashCode ^ _viewerSessionKey.hashCode).abs();
    return AdCreative(
      id: 'internal_promo',
      provider: 'custom',
      advertiserName: 'Atalaia',
      headline: 'Conheça comunidades perto de você',
      destinationUrl: 'https://atalaia.app/promo/comunidades',
      seed: 101 ^ h,
    );
  }

