  void activateVerificationForViewer({required String planLabel}) {
    final userId = _viewerUserId;
    _verificationPlanByUserId[userId] = planLabel;
    _verificationStartedAtByUserId[userId] = DateTime.now();
    final i = _profiles.indexWhere((p) => p.userId == userId);
    if (i >= 0) {
      _profiles[i] = _profiles[i].copyWith(isVerified: true);
