  Future<AuthSession?> signInWithEmail({required String email, required String password}) async {
    var debugMode = false;
    assert(() {
      debugMode = true;
      return true;
    }());
    _lastAuthError = null;
    final sb = supabase;
    if (sb != null) {
      if (isOffline) {
        _lastAuthError = _authErrNoConnection;
        return null;
      }
      try {
        final e = email.trim().toLowerCase();
        final res = await sb.auth.signInWithPassword(email: e, password: password);
        if (res.user == null) {
          _lastAuthError = _authErrInvalidCredentials;
          return null;
        }
        final user = res.user!;
        var session = AuthSession(userId: user.id, username: user.id, churchId: null);
        try {
          final enriched = await sessionFromSupabaseAuth();
          if (enriched == null) return null;
          session = enriched;
        } catch (e) {
          assert(() {
            debugPrint('[auth] sessionFromSupabaseAuth error=$e');
            return true;
          }());
        }
        if (profileForUserId(session.userId) == null) {
          _upsertProfile(
            ProfileModel(
              userId: session.userId,
              name: session.username,
              username: session.username,
              isVerified: false,
            ),
          );
        }
        return session;
      } on AuthException catch (e) {
        assert(() {
          debugPrint('[auth] signIn AuthException message=${e.message}');
          return true;
        }());
        final raw = e.message.trim();
        if (debugMode && raw.isNotEmpty) {
          _lastAuthError = raw;
          return null;
        }
        _lastAuthError = _authErrInvalidCredentials;
        return null;
      } catch (e) {
        assert(() {
          debugPrint('[auth] signIn error=$e');
          return true;
        }());
        _lastAuthError = debugMode ? e.toString() : _authErrLoginFailed;
        return null;
      }
    }

    final a = _authByEmail[email.trim().toLowerCase()];
    if (a == null) return null;
    if (a.password != password) return null;
    final profile = profileForUserId(a.userId);
    return AuthSession(
      userId: a.userId,
      username: profile?.username ?? a.userId,
      churchId: _churchIdByUserId[a.userId],
    );
  }

  Future<AuthSession?> createAccount({
    required String name,
    required String username,
    required String email,
    required String password,
  }) async {
    var debugMode = false;
    assert(() {
      debugMode = true;
      return true;
    }());
    _lastAuthError = null;
    final sb = supabase;
    if (sb != null) {
      if (isOffline) {
        _lastAuthError = _authErrNoConnection;
        return null;
      }
      final e = email.trim().toLowerCase();
      final u = username.trim().toLowerCase();
      if (e.isEmpty || u.isEmpty) return null;
      if (password.length < 8) return null;
      try {
        final res = await sb.auth.signUp(email: e, password: password);
        final user = res.user;
        if (user == null) {
          _lastAuthError = _authErrCreateAccountFailed;
          return null;
        }
        var session = res.session ?? sb.auth.currentSession;
        if (session == null) {
          try {
            await sb.auth.signInWithPassword(email: e, password: password);
          } catch (e) {
            assert(() {
              debugPrint('[auth] post-signUp signIn error=$e');
              return true;
            }());
          }
          session = sb.auth.currentSession;
        }
        if (session == null) {
          _lastAuthError =
              'Conta criada, mas o Supabase está exigindo confirmação por e-mail. Desative a confirmação de e-mail em Authentication → Providers → Email para entrar automaticamente.';
          return null;
        }

        try {
          await sb.from('profiles').upsert(<String, Object?>{
            'id': user.id,
            'username': u,
            'display_name': name.trim(),
            'bio': '',
          });
        } catch (e) {
          final short = _shortSupabaseError(e).trim();
          _lastAuthError = short.isEmpty
              ? 'Falha ao criar perfil. Verifique a policy de INSERT da tabela profiles (RLS) permitindo auth.uid() = id.'
              : 'Falha ao criar perfil: $short';
          return null;
        }

        final enriched = await sessionFromSupabaseAuth();
        return enriched ?? AuthSession(userId: user.id, username: u, churchId: null);
      } on AuthException catch (e) {
        assert(() {
          debugPrint('[auth] signUp AuthException message=${e.message}');
          return true;
        }());
        final raw = e.message.trim();
        final lower = raw.toLowerCase();
        if (lower.contains('rate limit')) {
          _lastAuthError = _authErrRateLimit;
          return null;
        }
        if (debugMode && raw.isNotEmpty) {
          _lastAuthError = raw;
          return null;
        }
        _lastAuthError = lower.contains('already') ? _authErrEmailAlreadyRegistered : _authErrCreateAccountFailed;
        return null;
      } on PostgrestException catch (e) {
        assert(() {
          debugPrint('[auth] signUp PostgrestException message=${e.message} code=${e.code} details=${e.details} hint=${e.hint}');
          return true;
        }());
        final parts = <String>[
          e.message,
          if ((e.code ?? '').toString().trim().isNotEmpty) 'code=${e.code}',
          if ((e.details ?? '').toString().trim().isNotEmpty) 'details=${e.details}',
          if ((e.hint ?? '').toString().trim().isNotEmpty) 'hint=${e.hint}',
        ];
        final short = parts.where((p) => p.trim().isNotEmpty).join(' • ');
        if (debugMode && short.trim().isNotEmpty) {
          _lastAuthError = short;
          return null;
        }
        final msg = e.message.toLowerCase();
        _lastAuthError = msg.contains('username') ? _authErrUsernameUnavailable : _authErrCreateAccountFailed;
        return null;
      } catch (e) {
        assert(() {
          debugPrint('[auth] signUp error=$e');
          return true;
        }());
        _lastAuthError = debugMode ? e.toString() : _authErrCreateAccountFailed;
        return null;
      }
    }

    final e = email.trim().toLowerCase();
    if (e.isEmpty) return null;
    if (isEmailTaken(e)) return null;
    final u = username.trim().toLowerCase();
    if (isUsernameTaken(u)) return null;
    if (password.length < 8) return null;
    final nextId = 'u${_profiles.length + 1}';
    _profiles.add(ProfileModel(userId: nextId, name: name.trim(), username: u, isVerified: false));
    _followersByUserId[nextId] = <String>{};
    _followingByUserId[nextId] = <String>{};
    _authByEmail[e] = _EmailAuthAccount(userId: nextId, password: password);
    notifyListeners();
    return AuthSession(userId: nextId, username: u, churchId: _churchIdByUserId[nextId]);
  }

