    return List.unmodifiable(list);
  }

  void updateProfile(
    String userId, {
    required String name,
    required String bio,
    String? username,
    String? churchName,
    String? avatarUrl,
  }) {
    final i = _profiles.indexWhere((p) => p.userId == userId);
    if (i < 0) return;
    final p = _profiles[i];
    final nextUsernameRaw = (username ?? '').trim();
    final nextUsername = nextUsernameRaw.isEmpty ? null : nextUsernameRaw.toLowerCase();
    _profiles[i] = p.copyWith(
      name: name,
      username: nextUsername,
      bio: bio,
      churchName: churchName,
      avatarUrl: avatarUrl,
    );
    notifyListeners();
    if (supabase != null) {
      unawaited(
        _updateProfileSupabase(
          userId: userId,
          name: name,
          username: nextUsername,
          bio: bio,
          avatarUrl: avatarUrl,
        ),
      );
    }
  }

  Future<bool> updateCommunity(
    String communityId, {
    required String name,
    required String description,
    required List<String> rules,
  }) async {
    final i = _communities.indexWhere((c) => c.id == communityId);
    if (i < 0) return false;
    final c = _communities[i];
    _lastCommunityUpdateError = null;
    final next = c.copyWith(
      name: name.trim(),
      description: description.trim(),
      rules: rules,
    );

    if (supabase != null) {
      final ok = await _updateCommunitySupabase(
        communityId: communityId,
        name: name,
        description: description,
        rules: rules,
      );
      if (!ok) return false;
    }

    _communities[i] = next;
    notifyListeners();
    return true;
  }

