  Future<String?> uploadCommunityAvatar({
    required String communityId,
    required Uint8List jpegBytes,
  }) async {
    final sb = supabase;
    if (sb == null) return null;
    if (isOffline) return null;
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null) return null;
    _lastCommunityAvatarError = null;

    final c = findCommunity(communityId);
    if (c == null) return null;
    final role = (c.viewerRole ?? '').trim().toLowerCase();
    final canEdit = c.ownerId == viewerId || role == 'admin' || role == 'moderator' || role == 'founder';
    if (!canEdit) return null;

    final path = 'communities/$communityId/${DateTime.now().millisecondsSinceEpoch}.jpg';
    await sb.storage.from('media').uploadBinary(
          path,
          jpegBytes,
          fileOptions: const FileOptions(
            contentType: 'image/jpeg',
            upsert: true,
          ),
        );

    final url = sb.storage.from('media').getPublicUrl(path);

    try {
      await sb.from('media_files').insert(<String, Object?>{
        'user_id': viewerId,
        'type': 'community_photo',
        'url': url,
        'thumbnail': null,
        'size': jpegBytes.lengthInBytes,
        'duration': null,
      });
    } catch (_) {}

    try {
      await sb.from('communities').update(<String, Object?>{'image_url': url}).eq('id', communityId);
    } on PostgrestException catch (e) {
      if (_postgrestMissingColumn(e, 'image_url')) {
        _lastCommunityAvatarError = 'Seu banco ainda não tem a coluna image_url em communities (migração pendente).';
      } else {
        final code = (e.code ?? '').toString().trim();
        final details = (e.details ?? '').toString().trim();
        final hint = (e.hint ?? '').toString().trim();
        final parts = <String>[
          'Falha ao atualizar a foto da comunidade',
          e.message,
          if (code.isNotEmpty) 'code=$code',
          if (details.isNotEmpty) 'details=$details',
          if (hint.isNotEmpty) 'hint=$hint',
        ];
        _lastCommunityAvatarError = parts.join(' • ');
      }
      return null;
    } catch (e) {
      _lastCommunityAvatarError = 'Falha ao atualizar a foto da comunidade • ${e.toString()}';
      return null;
    }

    final i = _communities.indexWhere((x) => x.id == communityId);
    if (i >= 0) {
      _communities[i] = _communities[i].copyWith(imageUrl: url);
      notifyListeners();
    } else {
      unawaited(refreshCommunitiesForViewer(force: true));
    }
    return url;
  }

