  void _pruneExpiredStories() {
    if (_stories.isEmpty) {
      _rescheduleStoryExpiryTimer();
      return;
    }
    final now = DateTime.now();
    final next = _stories.where((s) => s.expiresAt.isAfter(now)).toList(growable: false);
    if (next.length != _stories.length) _stories = next;
    _rescheduleStoryExpiryTimer();
  }

  void _rescheduleStoryExpiryTimer() {
    if (_stories.isEmpty) {
      _storyExpiryTimer?.cancel();
      _storyExpiryTimer = null;
      _nextStoryExpiryAt = null;
      return;
    }

    DateTime? nextExpiry;
    for (final s in _stories) {
      final e = s.expiresAt;
      if (nextExpiry == null || e.isBefore(nextExpiry)) nextExpiry = e;
    }

    if (nextExpiry == null) {
      _storyExpiryTimer?.cancel();
      _storyExpiryTimer = null;
      _nextStoryExpiryAt = null;
      return;
    }

    if (_storyExpiryTimer != null && _nextStoryExpiryAt != null && nextExpiry.isAtSameMomentAs(_nextStoryExpiryAt!)) {
      return;
    }
    _storyExpiryTimer?.cancel();
    _storyExpiryTimer = null;
    _nextStoryExpiryAt = nextExpiry;

    final now = DateTime.now();
    final delay = nextExpiry.difference(now) + const Duration(seconds: 1);
    if (delay.isNegative || delay == Duration.zero) {
      _storyExpiryTimer = Timer(const Duration(milliseconds: 20), () {
        final before = _stories.length;
        _pruneExpiredStories();
        if (_stories.length != before) notifyListeners();
      });
      return;
    }

    _storyExpiryTimer = Timer(delay, () {
      final before = _stories.length;
      _pruneExpiredStories();
      if (_stories.length != before) notifyListeners();
    });
  }

  List<StoryModel> storiesForHomeSocial() {
    _pruneExpiredStories();
    final list = _stories.where((s) => s.communityId == null).toList(growable: false);
    list.sort((a, b) => b.createdAt.compareTo(a.createdAt));
    return List.unmodifiable(list);
  }

