  Future<StoryModel?> createStory({
    required AuthSession session,
    String? cityId,
    required String mediaType,
    String? communityId,
    String? text,
    Uint8List? mediaBytes,
    String? contentType,
    String? fileExtension,
  }) async {
    _lastStoryCreateError = null;
    final now = DateTime.now();
    final trimmed = text?.trim();
    final expiresAt = now.add(const Duration(hours: 24));
    final communityKey = _looksLikeUuid(communityId) ? communityId : null;
    final initialCityId = (cityId == null || cityId.trim().isEmpty) ? null : cityId.trim();
    var effectiveCityId = initialCityId;

    final sb = supabase;
    if (sb == null || isOffline) {
      final local = StoryModel(
        id: now.microsecondsSinceEpoch.toString(),
        userId: session.userId,
        cityId: effectiveCityId,
        communityId: _storiesHasCommunityIdColumn == false ? null : communityKey,
        mediaUrl: null,
        mediaType: mediaType,
        text: trimmed?.isEmpty == true ? null : trimmed,
        expiresAt: expiresAt,
        createdAt: now,
      );
      _stories = [..._stories, local];
      _pruneExpiredStories();
      notifyListeners();
      return local;
    }

    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null || viewerId != session.userId) return null;

    String? url;
    try {
      if (mediaBytes != null && mediaBytes.isNotEmpty) {
        final ext = (fileExtension ?? '').trim().isEmpty ? 'bin' : fileExtension!.trim();
        final prefix = mediaType == 'video' ? 'stories/videos' : 'stories/images';
        final path = '$prefix/${session.userId}/${DateTime.now().millisecondsSinceEpoch}.$ext';
        await sb.storage.from('stories').uploadBinary(
              path,
              mediaBytes,
              fileOptions: FileOptions(
                contentType: (contentType ?? '').trim().isEmpty ? null : contentType,
                upsert: true,
              ),
            );
        url = sb.storage.from('stories').getPublicUrl(path);
      }
    } catch (e) {
      final short = _shortSupabaseError(e);
      _lastStoryCreateError = short.isEmpty ? 'Falha ao enviar mídia' : 'Falha ao enviar mídia: $short';
      debugPrint('[story:create] upload_failed=${_lastStoryCreateError}');
      return null;
    }

    final payload = <String, Object?>{
      'user_id': session.userId,
      if (effectiveCityId != null && effectiveCityId.trim().isNotEmpty) 'city_id': effectiveCityId,
      if (_storiesHasCommunityIdColumn != false && communityKey != null) 'community_id': communityKey,
      'media_url': url,
      'media_type': mediaType,
      'text': trimmed?.isEmpty == true ? null : trimmed,
      'expires_at': expiresAt.toUtc().toIso8601String(),
    };

    try {
      Map<String, dynamic>? inserted;
      final insertPayload = Map<String, Object?>.of(payload);
      Object? lastInsertError;
      for (var attempt = 0; attempt < 3; attempt++) {
        try {
          inserted = await sb.from('stories').insert(insertPayload).select('id,created_at').single();
          lastInsertError = null;
          break;
        } catch (e) {
          lastInsertError = e;
          if (_isStoriesCommunityIdMissing(e) && insertPayload.containsKey('community_id')) {
            _storiesHasCommunityIdColumn = false;
            insertPayload.remove('community_id');
            continue;
          }
          if (_isStoriesCityIdNotNullViolation(e) && !insertPayload.containsKey('city_id')) {
            String? inferred;
            final p = _lastFeedLocationPath.trim();
            if (p.startsWith('world/')) {
              final parts = p.split('/').where((v) => v.trim().isNotEmpty).toList(growable: false);
              if (parts.length >= 5) {
                inferred = await locationIdByPath(parts.take(5).join('/'));
              }
            }
            inferred ??= _lastFeedLocationId;
            inferred ??= await locationIdByPath('world');
            final normalized = (inferred ?? '').trim();
            if (normalized.isNotEmpty) {
              effectiveCityId = normalized;
              insertPayload['city_id'] = normalized;
              continue;
            }
          }
          break;
        }
      }
      if (lastInsertError != null) throw lastInsertError;
      if (inserted == null) return null;

      final insertedRow = inserted;
      final id = insertedRow['id']?.toString() ?? '';
      final createdAtRaw = insertedRow['created_at']?.toString();
      final createdAt = createdAtRaw == null ? now : DateTime.parse(createdAtRaw).toLocal();
      final story = StoryModel(
        id: id.isEmpty ? now.microsecondsSinceEpoch.toString() : id,
        userId: session.userId,
        cityId: effectiveCityId,
        communityId: _storiesHasCommunityIdColumn == false ? null : communityKey,
        mediaUrl: url,
        mediaType: mediaType,
        text: trimmed?.isEmpty == true ? null : trimmed,
        expiresAt: expiresAt,
        createdAt: createdAt,
      );

      _stories = [
        ..._stories.where((s) => s.id != story.id),
        story,
      ];
      _pruneExpiredStories();
      notifyListeners();
      return story;
    } catch (e) {
      final short = _shortSupabaseError(e);
      _lastStoryCreateError = short.isEmpty ? 'Falha ao publicar story' : 'Falha ao publicar story: $short';
      debugPrint('[story:create] insert_failed=${_lastStoryCreateError}');
      try {
        final safePayload = _storiesHasCommunityIdColumn == false ? (Map<String, Object?>.of(payload)..remove('community_id')) : payload;
        await sb.from('stories').insert(safePayload);
        final effective = effectiveCityId;
        if (effective != null && effective.trim().isNotEmpty) {
          final refreshed = communityKey == null ? await fetchStoriesForCity(effective) : await fetchStoriesForCityInCommunity(cityId: effective, communityId: communityKey);
          final match = refreshed.where((s) => s.userId == session.userId).where((s) {
            if (url != null && url.trim().isNotEmpty) return s.mediaUrl == url;
            final t = (trimmed ?? '').trim();
            return t.isNotEmpty && (s.text ?? '').trim() == t;
          }).toList(growable: false);
          if (match.isNotEmpty) {
            _lastStoryCreateError = null;
            return match.last;
          }
        }
        _lastStoryCreateError = null;
        return StoryModel(
          id: now.microsecondsSinceEpoch.toString(),
          userId: session.userId,
          cityId: effectiveCityId,
          communityId: _storiesHasCommunityIdColumn == false ? null : communityKey,
          mediaUrl: url,
          mediaType: mediaType,
          text: trimmed?.isEmpty == true ? null : trimmed,
          expiresAt: expiresAt,
          createdAt: now,
        );
      } catch (e2) {
        final short2 = _shortSupabaseError(e2);
        _lastStoryCreateError = short2.isEmpty ? _lastStoryCreateError : 'Falha ao publicar story: $short2';
        debugPrint('[story:create] insert_fallback_failed=${_lastStoryCreateError}');
        return null;
      }
    }
  }

  Future<bool> updateStoryCityId({
    required AuthSession session,
    required String storyId,
    required String cityId,
  }) async {
    final id = storyId.trim();
    final c = cityId.trim();
    if (id.isEmpty || c.isEmpty) return false;
    final sb = supabase;
    if (sb == null || isOffline) return false;
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null || viewerId != session.userId) return false;

    try {
      await sb.from('stories').update(<String, Object?>{'city_id': c}).eq('id', id).eq('user_id', session.userId);
      final i = _stories.indexWhere((s) => s.id == id);
      if (i >= 0) {
        final s = _stories[i];
        _stories = [
          ..._stories.sublist(0, i),
          StoryModel(
            id: s.id,
            userId: s.userId,
            cityId: c,
            communityId: s.communityId,
            mediaUrl: s.mediaUrl,
            mediaType: s.mediaType,
            text: s.text,
            expiresAt: s.expiresAt,
            createdAt: s.createdAt,
          ),
          ..._stories.sublist(i + 1),
        ];
        notifyListeners();
      }
      return true;
    } catch (_) {
      return false;
    }
  }

  List<NotificationModel> notificationsFor(String viewerId) {
    if (supabase != null &&
        (_notificationsRealtimeChannel == null || _notificationsRealtimeViewerId != viewerId)) {
      unawaited(_ensureNotificationsSubscribed(viewerId));
    }
    if (supabase != null && _notificationsLoadedForViewerId != viewerId) {
      unawaited(refreshNotificationsForViewer(viewerId, force: true));
    }
    final list = _notifications
        .where((n) => n.userId == viewerId && !_hiddenNotificationIds.contains(n.id))
        .toList(growable: false);
    list.sort((a, b) => b.createdAt.compareTo(a.createdAt));
    return List.unmodifiable(list);
  }

  int unreadNotificationCount(String viewerId) {
    if (supabase != null &&
        (_notificationsRealtimeChannel == null || _notificationsRealtimeViewerId != viewerId)) {
      unawaited(_ensureNotificationsSubscribed(viewerId));
    }
    if (supabase != null && _notificationsLoadedForViewerId != viewerId) {
      unawaited(refreshNotificationsForViewer(viewerId, force: true));
    }
    var count = 0;
    for (final n in _notifications) {
      if (n.userId != viewerId) continue;
      if (_hiddenNotificationIds.contains(n.id)) continue;
      if (!n.isRead) count += 1;
    }
    return count;
  }

  Future<void> refreshNotificationsForViewer(String viewerId, {bool force = false}) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final v = viewerId.trim();
    if (v.isEmpty) return;
    final localVersionAtStart = _notificationsLocalVersion;
    final refreshVersion = ++_notificationsRefreshVersion;
    if (!force && _notificationsLoadedForViewerId == viewerId && _notifications.isNotEmpty) return;
    try {
      late final dynamic rows;
      try {
        final selectKind = _notificationsHasKindColumn != false;
        final selectReadAt = _notificationsHasReadAtColumn != false;
        final cols = [
          'id',
          'user_id',
          'actor_id',
          'type',
          if (selectKind) 'kind',
          'title',
          'body',
          'entity_id',
          'entity_type',
          'location_id',
          'is_read',
          if (selectReadAt) 'read_at',
          'created_at',
        ].join(',');
        rows = await sb
            .from('notifications')
            .select(cols)
            .eq('user_id', v)
            .order('created_at', ascending: false)
            .limit(60);
      } on PostgrestException catch (e) {
        final msg = '${e.message} ${e.details} ${e.hint}'.toLowerCase();
        if (msg.contains('kind')) _notificationsHasKindColumn = false;
        if (msg.contains('read_at')) _notificationsHasReadAtColumn = false;
        final selectKind = _notificationsHasKindColumn != false;
        final selectReadAt = _notificationsHasReadAtColumn != false;
        final cols = [
          'id',
          'user_id',
          'actor_id',
          'type',
          if (selectKind) 'kind',
          'title',
          'body',
          'entity_id',
          'entity_type',
          'location_id',
          'is_read',
          if (selectReadAt) 'read_at',
          'created_at',
        ].join(',');
        rows = await sb
            .from('notifications')
            .select(cols)
            .eq('user_id', v)
            .order('created_at', ascending: false)
            .limit(60);
      }

      final rawList = (rows as List<dynamic>).cast<Map<String, dynamic>>();
      final actorIds = rawList.map((r) => r['actor_id']?.toString()).whereType<String>().where((v) => v.isNotEmpty).toSet();
      await _fetchProfilesByIds(actorIds);

      final list = <NotificationModel>[];
      for (final r in rawList) {
        final n = _notificationFromRawRecord(r);
        if (n == null) continue;
        list.add(n);
      }

      if (refreshVersion != _notificationsRefreshVersion) return;
      _notificationsLoadedForViewerId = v;
      if (localVersionAtStart == _notificationsLocalVersion) {
        _notifications = List.unmodifiable(list);
      } else {
        final localById = <String, NotificationModel>{for (final n in _notifications) n.id: n};
        final merged = <NotificationModel>[];
        final seenIds = <String>{};
        for (final s in list) {
          if (_notificationsLocallyRemovedIds.contains(s.id)) continue;
          final local = localById[s.id];
          final effective = (local != null && local.isRead && !s.isRead) ? s.copyWith(isRead: true) : s;
          merged.add(effective);
          seenIds.add(s.id);
        }
        for (final e in localById.entries) {
          if (seenIds.contains(e.key)) continue;
          if (_notificationsLocallyRemovedIds.contains(e.key)) continue;
          merged.add(e.value);
        }
        merged.sort((a, b) => b.createdAt.compareTo(a.createdAt));
        _notifications = List.unmodifiable(merged);
      }
      notifyListeners();
    } catch (_) {}
  }

  void markNotificationRead(String notificationId, {required String viewerId}) {
    final i = _notifications.indexWhere((n) => n.id == notificationId);
    if (i < 0) return;
    final current = _notifications[i];
    if (current.userId != viewerId) return;
    if (current.isRead) return;
    _notificationsLocalVersion++;
    final list = _notifications.toList(growable: true);
    list[i] = current.copyWith(isRead: true);
    _notifications = List.unmodifiable(list);
    notifyListeners();
    if (supabase != null) {
      unawaited(_markNotificationReadSupabase(notificationId, viewerId: viewerId));
    }
  }

  Future<void> _markNotificationReadSupabase(String notificationId, {required String viewerId}) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    try {
      final payload = <String, Object?>{'is_read': true};
      if (_notificationsHasReadAtColumn != false) {
        payload['read_at'] = DateTime.now().toIso8601String();
      }
      try {
        await sb.from('notifications').update(payload).eq('id', notificationId).eq('user_id', viewerId);
      } on PostgrestException catch (e) {
        final msg = '${e.message} ${e.details} ${e.hint}'.toLowerCase();
        if (msg.contains('read_at')) {
          _notificationsHasReadAtColumn = false;
          await sb
              .from('notifications')
              .update(<String, Object?>{'is_read': true})
              .eq('id', notificationId)
              .eq('user_id', viewerId);
        } else {
          rethrow;
        }
      }
    } catch (_) {}
  }

  void markAllNotificationsRead(String viewerId) {
    var changed = false;
    final list = _notifications.toList(growable: true);
    for (var i = 0; i < list.length; i++) {
      final n = list[i];
      if (n.userId != viewerId) continue;
      if (n.isRead) continue;
      list[i] = n.copyWith(isRead: true);
      changed = true;
    }
    if (changed) {
      _notificationsLocalVersion++;
      _notifications = List.unmodifiable(list);
      notifyListeners();
    }
    if (supabase != null) {
      unawaited(_markAllNotificationsReadSupabase(viewerId));
    }
  }

  Future<void> _markAllNotificationsReadSupabase(String viewerId) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    try {
      final payload = <String, Object?>{'is_read': true};
      if (_notificationsHasReadAtColumn != false) {
        payload['read_at'] = DateTime.now().toIso8601String();
      }
      try {
        await sb.from('notifications').update(payload).eq('user_id', viewerId).eq('is_read', false);
      } on PostgrestException catch (e) {
        final msg = '${e.message} ${e.details} ${e.hint}'.toLowerCase();
        if (msg.contains('read_at')) {
          _notificationsHasReadAtColumn = false;
          await sb.from('notifications').update(<String, Object?>{'is_read': true}).eq('user_id', viewerId).eq('is_read', false);
        } else {
          rethrow;
        }
      }
    } catch (_) {}
    unawaited(refreshNotificationsForViewer(viewerId, force: true));
  }

  void hideNotification(String notificationId, {required String viewerId}) {
    final exists = _notifications.any((n) => n.id == notificationId && n.userId == viewerId);
    if (!exists) return;
    if (_hiddenNotificationIds.add(notificationId)) notifyListeners();
  }

  List<ProfileModel> searchProfiles(String query) {
    final q = query.trim().toLowerCase();
    if (q.isEmpty) return const [];
    if (supabase != null) {
      if (_profileSearchQuery != q) {
        _profileSearchQuery = q;
        unawaited(_refreshProfileSearch(q));
      }
      return _profileSearchResults;
    }
    final list = _profiles.where((p) {
      return p.name.toLowerCase().contains(q) || p.username.toLowerCase().contains(q);
    }).toList(growable: false);
    return List.unmodifiable(list);
  }

  Future<void> _refreshProfileSearch(String q) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    try {
      final rows = await sb
          .from('profiles')
          .select('id,username,display_name,bio,is_verified')
          .or('username.ilike.%$q%,display_name.ilike.%$q%')
          .limit(20);
      final ids = <String>{};
      final list = <ProfileModel>[];
      for (final raw in (rows as List<dynamic>)) {
        final r = raw as Map<String, dynamic>;
        final id = r['id']?.toString();
        if (id == null || id.isEmpty) continue;
        if (!ids.add(id)) continue;
        final username = (r['username'] as String?)?.trim();
        final displayName = (r['display_name'] as String?)?.trim();
        final resolvedUsername = (username == null || username.isEmpty) ? id : username;
        final p = ProfileModel(
          userId: id,
          name: (displayName == null || displayName.isEmpty) ? resolvedUsername : displayName,
          username: resolvedUsername,
          isVerified: r['is_verified'] == true,
          bio: (r['bio'] as String?) ?? '',
          churchName: null,
        );
        list.add(p);
        _upsertProfile(p);
      }
      if (_profileSearchQuery != q) return;
      _profileSearchResults = List.unmodifiable(list);
      notifyListeners();
    } catch (_) {}
  }

  List<PostModel> searchPosts(SessionState session, String query) {
    final q = query.trim().toLowerCase();
    if (q.isEmpty) return const [];
    final visible = visiblePostsFor(session);
    final list = visible.where((p) {
      final hay = '${p.body} ${p.username}'.toLowerCase();
      return hay.contains(q);
    }).toList(growable: false);
    return List.unmodifiable(list);
  }

