  void setOffline(bool value) {
    if (_isOffline == value) return;
    _isOffline = value;
    if (_isOffline) {
      unawaited(_alertsRealtimeChannel?.unsubscribe() ?? Future<void>.value());
      _alertsRealtimeChannel = null;
    } else {
      if (supabase != null) {
        unawaited(
          refreshFeedForCurrentSession(
            scope: _lastFeedScope,
            locationPath: _lastFeedLocationPath,
            locationId: _lastFeedLocationId,
            communityId: _lastFeedCommunityId,
            postTypes: _lastFeedPostTypes,
            sort: _lastFeedSort,
            lat: _lastFeedLat,
            lng: _lastFeedLng,
          ),
        );
      }
    }
    notifyListeners();
  }

  void setDirectLoading(bool value) {
    if (_directIsLoading == value) return;
    _directIsLoading = value;
    notifyListeners();
  }

  List<PostModel> visiblePostsFor(SessionState session) {
    if (supabase != null) {
      return _posts.where((p) => !_hiddenPostIds.contains(p.id)).toList(growable: false);
    }
    if (session is AuthSession) {
      final uid = session.userId;
      return _posts.where((p) {
        if (_hiddenPostIds.contains(p.id)) return false;
        if (p.communityId != null) {
          if (uid == _u2.userId && session.userId == _u2.userId) {
            return true;
          }
          final viewerApproved = _communities
              .where((c) => c.id == p.communityId)
              .any((c) => c.viewerStatus == CommunityViewerStatus.approved);
          if (!viewerApproved && uid != _u2.userId) return false;
        }

        if (p.userId == uid) return true;
        return switch (p.visibility) {
          PostVisibility.public => true,
          PostVisibility.followers =>
            (_followersByUserId[p.userId] ?? const <String>{}).contains(uid),
          PostVisibility.church =>
            (p.churchId != null && p.churchId == session.churchId),
        };
      }).toList(growable: false);
    }

    return _posts
        .where((p) => p.visibility == PostVisibility.public)
        .where((p) => p.communityId == null)
        .where((p) => !_hiddenPostIds.contains(p.id))
        .toList(growable: false);
  }

  List<AlertModel> visibleAlertsFor(SessionState session) {
    if (supabase != null) {
      return _alerts.toList(growable: false);
    }
    if (session is AuthSession) {
      final uid = session.userId;
      return _alerts.where((a) {
        if (a.communityId == null) return true;
        final viewerApproved = _communities.where((c) => c.id == a.communityId).any((c) => c.viewerStatus == CommunityViewerStatus.approved);
        if (!viewerApproved && uid != _u2.userId) return false;
        return true;
      }).toList(growable: false);
    }
    return _alerts.where((a) => a.communityId == null).toList(growable: false);
  }

