    final visible = visibleAlertsFor(session);
    return visible
        .where((a) => a.communityId == communityId)
        .where((a) {
          if (regionPath == 'world') return true;
          return a.locationPath == regionPath || a.locationPath.startsWith('$regionPath/');
        })
        .toList(growable: false);
  }

  bool _viewerCanViewCommunity(SessionState session, String communityId) {
    if (!session.isAuthenticated) return false;
    final viewerId = session is AuthSession ? session.userId : null;
    if (viewerId == null || viewerId.isEmpty) return false;
    final c = findCommunity(communityId);
    if (c == null) return false;
    if (c.ownerId == viewerId) return true;
    if (_communityModeratorsById[communityId]?.contains(viewerId) ?? false) return true;
    if (_communityMembersById[communityId]?.contains(viewerId) ?? false) return true;
    return c.viewerStatus == CommunityViewerStatus.approved;
  }

  List<CampaignModel> visibleCampaignsFor(SessionState session) {
    final viewerId = session is AuthSession ? session.userId : null;
    return _campaigns
        .where((c) {
          if (c.status == CampaignStatus.draft) return viewerId != null && c.creatorId == viewerId;
          final communityId = c.communityId;
          if (communityId == null) return true;
          if (viewerId != null && c.creatorId == viewerId) return true;
          return _viewerCanViewCommunity(session, communityId);
        })
        .toList(growable: false);
  }

  List<PrayerChallengeModel> visiblePrayerChallengesFor(
    SessionState session, {
    bool onlyActive = true,
    String? communityId,
  }) {
    final now = DateTime.now().toUtc();
    final filterCommunityId = communityId?.trim().isEmpty ?? true ? null : communityId!.trim();
    return _prayerChallenges
        .where((c) => filterCommunityId == null ? true : c.communityId == filterCommunityId)
        .where((c) {
          if (c.communityId == null) return true;
          return _viewerCanViewCommunity(session, c.communityId!);
        })
        .where((c) {
          if (!onlyActive) return true;
          if (c.status != PrayerChallengeStatus.active) return false;
          return !now.isBefore(c.startDate.toUtc()) && !now.isAfter(c.endDate.toUtc());
        })
        .toList(growable: false);
  }

