  Future<void> refreshAlertsForCurrentFeed({
    required String locationPath,
    String? locationId,
    String? communityId,
    bool force = false,
  }) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;

    final resolvedLocationId = _looksLikeUuid(locationId) ? locationId : await locationIdByPath(locationPath);
    if (resolvedLocationId == null) return;
    final remoteCommunityId = _looksLikeUuid(communityId) ? communityId : null;
    final usesCommunity = remoteCommunityId != null;

    final nextKey = '${resolvedLocationId}|${remoteCommunityId ?? ''}';
    if (!force && _alertsLoadedKey == nextKey) return;

    if (_rpcFeedAlertsByLocationUnavailable) {
      _alertsLoadedKey = nextKey;
      if (_alerts.isNotEmpty) {
        _alerts = const <AlertModel>[];
        notifyListeners();
      }
      return;
    }

    try {
      if (_alertsRealtimeChannel != null) {
        unawaited(_alertsRealtimeChannel!.unsubscribe());
        _alertsRealtimeChannel = null;
      }

      final channel = sb.channel('realtime:alerts:$nextKey');
      channel.onPostgresChanges(
        event: PostgresChangeEvent.all,
        schema: 'public',
        table: 'alerts',
        filter: PostgresChangeFilter(
          type: PostgresChangeFilterType.eq,
          column: 'location_id',
          value: resolvedLocationId,
        ),
        callback: (payload) {
          if (isOffline) return;
          unawaited(
            refreshAlertsForCurrentFeed(
              locationPath: _lastFeedLocationPath,
              locationId: _lastFeedLocationId ?? resolvedLocationId,
              communityId: _lastFeedCommunityId ?? remoteCommunityId,
              force: true,
            ),
          );
        },
      );
      channel.subscribe();
      _alertsRealtimeChannel = channel;

      late final List<dynamic> rows;
      try {
        final rpcRows = await sb.rpc(
          'feed_alerts_by_location',
          params: <String, Object?>{
            'p_location_id': resolvedLocationId,
            'p_community_id': usesCommunity ? remoteCommunityId : null,
            'p_cursor_created_at': null,
            'p_limit': 24,
          },
        );
        rows = (rpcRows as List<dynamic>);
      } on PostgrestException catch (e) {
        if (!_isRpcUnavailable(e, 'feed_alerts_by_location')) rethrow;
        _rpcFeedAlertsByLocationUnavailable = true;
        _alertsLoadedKey = nextKey;
        if (_alerts.isNotEmpty) {
          _alerts = const <AlertModel>[];
          notifyListeners();
        }
        return;
      }

      final rawList = rows.cast<Map<String, dynamic>>();
      final userIds = rawList.map((r) => r['user_id']?.toString()).whereType<String>().where((v) => v.isNotEmpty).toSet();
      final profilesById = await _fetchProfilesByIds(userIds);

      final viewerId = sb.auth.currentUser?.id;
      final alertIds = rawList.map((r) => r['id']?.toString()).whereType<String>().where((v) => v.isNotEmpty).toSet();
      final followed = viewerId == null ? const <String>{} : await _fetchViewerAlertIds(viewerId: viewerId, alertIds: alertIds);
      _followedAlertIds
        ..clear()
        ..addAll(followed);

      final list = <AlertModel>[];
      for (final r in rawList) {
        final id = r['id']?.toString();
        final userId = r['user_id']?.toString();
        if (id == null || id.isEmpty) continue;
        if (userId == null || userId.isEmpty) continue;

        final profile = profilesById[userId];
        final locId = r['location_id']?.toString();
        final locPath = r['location_path']?.toString();
        final locName = r['location_name']?.toString();
        if (locId == null || locId.isEmpty) continue;
        if (locPath == null || locPath.isEmpty) continue;
        if (locName == null || locName.isEmpty) continue;

        list.add(
          AlertModel(
            id: id,
            userId: userId,
            username: profile?.username ?? userId,
            isVerified: profile?.isVerified ?? false,
            title: (r['title'] as String?) ?? '',
            description: (r['description'] as String?) ?? '',
            category: _parseAlertCategory(r['category']?.toString()),
            urgency: _parseAlertUrgency(r['urgency']?.toString()),
            status: _parseAlertStatus(r['status']?.toString()),
            expiresAt: DateTime.tryParse(r['expires_at']?.toString() ?? '') ?? DateTime.now().add(const Duration(hours: 6)),
            createdAt: DateTime.tryParse(r['created_at']?.toString() ?? '') ?? DateTime.now(),
            updatedAt: DateTime.tryParse(r['updated_at']?.toString() ?? '') ?? DateTime.now(),
            locationId: locId,
            locationPath: locPath,
            locationName: locName,
            communityId: r['community_id']?.toString(),
            mediaUrl: _normalizeSupabaseMediaPublicUrl((r['media_url'] as String?)?.trim()),
            mediaType: _parseAlertMediaType(r['media_type']?.toString()),
            viewerIsFollowing: _followedAlertIds.contains(id),
          ),
        );
      }

      _alertsLoadedKey = nextKey;
      _alerts = List.unmodifiable(list);
      notifyListeners();
    } catch (_) {}
  }

  Future<void> refreshCampaignsForCurrentFeed({
    required String locationPath,
    String? locationId,
    String? communityId,
    double? lat,
    double? lng,
    bool force = false,
  }) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final resolvedLocationId = _looksLikeUuid(locationId) ? locationId : await locationIdByPath(locationPath);
    if (resolvedLocationId == null) return;
    final remoteCommunityId = _looksLikeUuid(communityId) ? communityId : null;
    final nextKey = '${resolvedLocationId}|${remoteCommunityId ?? ''}';
    if (!force && _campaignsLoadedKey == nextKey) return;

    if (_rpcCampaignsByLocationUnavailable) {
      final localFallback = campaignsForRegion(
        sb.auth.currentUser == null ? const AnonSession() : AuthSession(userId: sb.auth.currentUser!.id, username: '', churchId: null),
        locationPath,
        communityId: remoteCommunityId,
      );
      _campaignsLoadedKey = nextKey;
      _campaigns = List.unmodifiable(localFallback);
      _campaignById = <String, CampaignModel>{for (final c in _campaigns) c.id: c};
      notifyListeners();
      return;
    }

    try {
      late final List<dynamic> rows;
      try {
        final rpcRows = await sb.rpc(
          'campaigns_by_location',
          params: <String, Object?>{
            'p_location_id': resolvedLocationId,
            'p_community_id': remoteCommunityId,
            'p_cursor_created_at': null,
            'p_limit': 24,
          },
        );
        rows = (rpcRows as List<dynamic>);
      } on PostgrestException catch (e) {
        if (!_isRpcUnavailable(e, 'campaigns_by_location')) rethrow;
        _rpcCampaignsByLocationUnavailable = true;
        final localFallback = campaignsForRegion(
          sb.auth.currentUser == null ? const AnonSession() : AuthSession(userId: sb.auth.currentUser!.id, username: '', churchId: null),
          locationPath,
          communityId: remoteCommunityId,
        );
        _campaignsLoadedKey = nextKey;
        _campaigns = List.unmodifiable(localFallback);
        _campaignById = <String, CampaignModel>{for (final c in _campaigns) c.id: c};
        notifyListeners();
        return;
      }

      final rawList = rows.cast<Map<String, dynamic>>();
      final next = <CampaignModel>[];
      for (final r in rawList) {
        final id = r['id']?.toString();
        final creatorId = r['creator_id']?.toString();
        final locId = r['location_id']?.toString();
        final locPath = r['location_path']?.toString();
        final locName = r['location_name']?.toString();
        if (id == null || id.isEmpty) continue;
        if (creatorId == null || creatorId.isEmpty) continue;
        if (locId == null || locId.isEmpty) continue;
        if (locPath == null || locPath.isEmpty) continue;
        if (locName == null || locName.isEmpty) continue;

        next.add(
          CampaignModel(
            id: id,
            creatorId: creatorId,
            title: (r['title'] as String?) ?? '',
            description: (r['description'] as String?) ?? '',
            imageUrl: _normalizeSupabaseMediaPublicUrl((r['image_url'] as String?)?.trim()),
            goalAmount: _numToDouble(r['goal_amount']),
            raisedAmount: _numToDouble(r['raised_amount']),
            currency: (r['currency'] as String?) ?? 'BRL',
            category: _parseCampaignCategory(r['category']?.toString()),
            status: _parseCampaignStatus(r['status']?.toString()),
            deadline: DateTime.tryParse(r['deadline']?.toString() ?? ''),
            createdAt: DateTime.tryParse(r['created_at']?.toString() ?? '') ?? DateTime.now(),
            updatedAt: DateTime.tryParse(r['updated_at']?.toString() ?? '') ?? DateTime.now(),
            locationId: locId,
            locationPath: locPath,
            locationName: locName,
            communityId: r['community_id']?.toString(),
            donationsCount: (r['donations_count'] as num?)?.toInt() ?? 0,
            centerLat: (r['center_lat'] as num?)?.toDouble(),
            centerLng: (r['center_lng'] as num?)?.toDouble(),
          ),
        );
      }

      _campaignsLoadedKey = nextKey;
      _campaigns = List.unmodifiable(next);
      _campaignById = <String, CampaignModel>{for (final c in _campaigns) c.id: c};
      notifyListeners();
    } catch (_) {
      final localFallback = campaignsForRegion(
        sb.auth.currentUser == null ? const AnonSession() : AuthSession(userId: sb.auth.currentUser!.id, username: '', churchId: null),
        locationPath,
        communityId: remoteCommunityId,
      );
      _campaignsLoadedKey = nextKey;
      _campaigns = List.unmodifiable(localFallback);
      _campaignById = <String, CampaignModel>{for (final c in _campaigns) c.id: c};
      notifyListeners();
    }
  }

