    final remoteCommunityId = _looksLikeUuid(communityId) ? communityId : null;
    final nextKey = '${_viewerSessionKey}|${remoteCommunityId ?? ''}';
    final now = DateTime.now();
    if (!force &&
        _prayerChallengePinsLoadedKey == nextKey &&
        _prayerChallengePinsLoadedAt != null &&
        now.difference(_prayerChallengePinsLoadedAt!) < const Duration(seconds: 20)) {
      return;
    }
    try {
      final rows = await sb.rpc(
        'cached_prayer_challenges_for_map',
        params: <String, Object?>{
          'p_community_id': remoteCommunityId,
          'p_limit': 60,
          'p_ttl_seconds': 30,
