            centerLng: lng,
            startDate: DateTime.tryParse(r['start_date']?.toString() ?? '') ?? DateTime.now().toUtc(),
            endDate: DateTime.tryParse(r['end_date']?.toString() ?? '') ?? DateTime.now().toUtc(),
            goalParticipants: _numToInt(r['goal_participants']),
            participantsCount: _numToInt(r['participants_count']),
          ),
        );
      }
      _prayerChallengePinsLoadedKey = nextKey;
      _prayerChallengePinsLoadedAt = now;
      _prayerChallengePins = List.unmodifiable(next);
      notifyListeners();
    } catch (_) {}
  }

