  Future<bool> joinPrayerChallenge(String challengeId) async {
    final v = challengeId.trim();
    if (v.isEmpty) return false;
    if (supabase == null) {
      if (_joinedPrayerChallengeIds.add(v)) {
        final current = findPrayerChallenge(v);
        if (current != null) {
          _prayerChallengeById[v] = PrayerChallengeModel(
            id: current.id,
            title: current.title,
            description: current.description,
            imageUrl: current.imageUrl,
            targetRegion: current.targetRegion,
            targetLocationId: current.targetLocationId,
            targetLocationName: current.targetLocationName,
            communityId: current.communityId,
            communityName: current.communityName,
            startDate: current.startDate,
            endDate: current.endDate,
            goalParticipants: current.goalParticipants,
            goalPrayerMinutes: current.goalPrayerMinutes,
            status: current.status,
            createdAt: current.createdAt,
            participantsCount: current.participantsCount + 1,
            viewerJoined: true,
            totalDurationSeconds: current.totalDurationSeconds,
            centerLat: current.centerLat,
            centerLng: current.centerLng,
          );
          _prayerChallenges = List.unmodifiable(_prayerChallenges.map((c) => c.id == v ? _prayerChallengeById[v]! : c));
        }
        notifyListeners();
        return true;
      }
      return false;
    }
    if (isOffline) return false;
    if (!_looksLikeUuid(v)) return false;
    try {
      final ok = await supabase!.rpc('join_prayer_challenge', params: <String, Object?>{'p_challenge_id': v});
      if (ok == true) {
        await refreshPrayerChallenges(force: true, onlyActive: false);
        await refreshPrayerChallengePinsForMap(force: true);
      }
      return ok == true;
    } catch (_) {
      return false;
    }
  }

  Future<bool> leavePrayerChallenge(String challengeId) async {
    final v = challengeId.trim();
    if (v.isEmpty) return false;
    if (supabase == null) {
      if (_joinedPrayerChallengeIds.remove(v)) {
        final current = findPrayerChallenge(v);
        if (current != null) {
          _prayerChallengeById[v] = PrayerChallengeModel(
            id: current.id,
            title: current.title,
            description: current.description,
            imageUrl: current.imageUrl,
            targetRegion: current.targetRegion,
            targetLocationId: current.targetLocationId,
            targetLocationName: current.targetLocationName,
            communityId: current.communityId,
            communityName: current.communityName,
            startDate: current.startDate,
            endDate: current.endDate,
            goalParticipants: current.goalParticipants,
            goalPrayerMinutes: current.goalPrayerMinutes,
            status: current.status,
            createdAt: current.createdAt,
            participantsCount: (current.participantsCount - 1).clamp(0, 1 << 30),
            viewerJoined: false,
            totalDurationSeconds: current.totalDurationSeconds,
            centerLat: current.centerLat,
            centerLng: current.centerLng,
          );
          _prayerChallenges = List.unmodifiable(_prayerChallenges.map((c) => c.id == v ? _prayerChallengeById[v]! : c));
        }
        notifyListeners();
        return true;
      }
      return false;
    }
    if (isOffline) return false;
    if (!_looksLikeUuid(v)) return false;
    try {
      final ok = await supabase!.rpc('leave_prayer_challenge', params: <String, Object?>{'p_challenge_id': v});
      if (ok == true) {
        await refreshPrayerChallenges(force: true, onlyActive: false);
        await refreshPrayerChallengePinsForMap(force: true);
      }
      return ok == true;
    } catch (_) {
      return false;
    }
  }

