  Future<bool> hydrateCampaignById(String campaignId) async {
    final sb = supabase;
    if (sb == null) return false;
    if (isOffline) return false;
    if (!_looksLikeUuid(campaignId)) return false;
    try {
      final row = await sb
          .from('campaigns')
          .select(
            'id,creator_id,community_id,title,description,image_url,goal_amount,raised_amount,currency,category,status,deadline,created_at,updated_at,location_id,location:locations(path,name,center_lat,center_lng)',
          )
          .eq('id', campaignId)
          .maybeSingle();
      if (row == null) return false;
      final loc = row['location'] is Map ? (row['location'] as Map).cast<String, dynamic>() : null;
      final locPath = loc?['path']?.toString();
      final locName = loc?['name']?.toString();
      final centerLat = (loc?['center_lat'] as num?)?.toDouble();
      final centerLng = (loc?['center_lng'] as num?)?.toDouble();
      if (locPath == null || locPath.isEmpty) return false;
      if (locName == null || locName.isEmpty) return false;

      final donationsCountRow = await sb
          .from('donations')
          .select('id')
          .eq('campaign_id', campaignId)
          .eq('status', 'succeeded')
          .count(CountOption.exact);
      final donationsCount = donationsCountRow.count;

      final campaign = CampaignModel(
        id: campaignId,
        creatorId: row['creator_id']?.toString() ?? '',
        title: (row['title'] as String?) ?? '',
        description: (row['description'] as String?) ?? '',
        imageUrl: _normalizeSupabaseMediaPublicUrl((row['image_url'] as String?)?.trim()),
        goalAmount: _numToDouble(row['goal_amount']),
        raisedAmount: _numToDouble(row['raised_amount']),
        currency: (row['currency'] as String?) ?? 'BRL',
        category: _parseCampaignCategory(row['category']?.toString()),
        status: _parseCampaignStatus(row['status']?.toString()),
        deadline: DateTime.tryParse(row['deadline']?.toString() ?? ''),
        createdAt: DateTime.tryParse(row['created_at']?.toString() ?? '') ?? DateTime.now(),
        updatedAt: DateTime.tryParse(row['updated_at']?.toString() ?? '') ?? DateTime.now(),
        locationId: row['location_id']?.toString() ?? '',
        locationPath: locPath,
        locationName: locName,
        communityId: row['community_id']?.toString(),
        donationsCount: donationsCount,
        centerLat: centerLat,
        centerLng: centerLng,
      );

      _campaignById[campaign.id] = campaign;
      final existing = _campaigns.indexWhere((c) => c.id == campaign.id);
      if (existing >= 0) {
        final list = _campaigns.toList(growable: true);
        list[existing] = campaign;
        _campaigns = List.unmodifiable(list);
      } else {
        _campaigns = List.unmodifiable([campaign, ..._campaigns.where((c) => c.id != campaign.id)]);
      }
      notifyListeners();
      return true;
    } catch (_) {
      return false;
    }
  }

  void _upsertCampaignLocal(CampaignModel campaign) {
    _campaignById[campaign.id] = campaign;
    final existing = _campaigns.indexWhere((c) => c.id == campaign.id);
    if (existing >= 0) {
      final list = _campaigns.toList(growable: true);
      list[existing] = campaign;
      _campaigns = List.unmodifiable(list);
    } else {
      _campaigns = List.unmodifiable([campaign, ..._campaigns.where((c) => c.id != campaign.id)]);
    }
  }

  void _applyDonationOptimistic(String campaignId, double amount) {
    final current = findCampaign(campaignId);
    if (current == null) return;
    final next = CampaignModel(
      id: current.id,
      creatorId: current.creatorId,
      title: current.title,
      description: current.description,
      imageUrl: current.imageUrl,
      goalAmount: current.goalAmount,
      raisedAmount: (current.raisedAmount + amount).clamp(0, 1e18),
      currency: current.currency,
      category: current.category,
      status: current.status,
      deadline: current.deadline,
      createdAt: current.createdAt,
      updatedAt: DateTime.now(),
      locationId: current.locationId,
      locationPath: current.locationPath,
      locationName: current.locationName,
      communityId: current.communityId,
      donationsCount: current.donationsCount + 1,
      centerLat: current.centerLat,
      centerLng: current.centerLng,
    );
    _upsertCampaignLocal(next);
  }

  Future<void> refreshUpdatesForCampaign(String campaignId, {bool force = false}) async {
    final id = campaignId.trim();
    if (id.isEmpty) return;
    if (!force && _campaignUpdatesLoadedFor.contains(id)) return;
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    if (!_looksLikeUuid(id)) return;
    try {
      final rows = await sb
          .from('campaign_updates')
          .select('id,campaign_id,author_id,content,media_url,created_at')
          .eq('campaign_id', id)
          .order('created_at');
      final rawList = (rows as List<dynamic>).cast<Map<String, dynamic>>();
      final list = <CampaignUpdateModel>[];
      for (final r in rawList) {
        final updateId = r['id']?.toString();
        final authorId = r['author_id']?.toString();
        if (updateId == null || updateId.isEmpty) continue;
        if (authorId == null || authorId.isEmpty) continue;
        list.add(
          CampaignUpdateModel(
            id: updateId,
            campaignId: id,
            authorId: authorId,
            content: (r['content'] as String?) ?? '',
            mediaUrl: _normalizeSupabaseMediaPublicUrl((r['media_url'] as String?)?.trim()),
            createdAt: DateTime.tryParse(r['created_at']?.toString() ?? '') ?? DateTime.now(),
          ),
        );
      }
      _campaignUpdatesById[id] = List.unmodifiable(list);
      _campaignUpdatesLoadedFor.add(id);
      notifyListeners();
    } catch (_) {}
  }

  Future<void> refreshCommentsForCampaign(String campaignId, {bool force = false}) async {
    final id = campaignId.trim();
    if (id.isEmpty) return;
    if (!force && _campaignCommentsLoadedFor.contains(id)) return;
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    if (!_looksLikeUuid(id)) return;
    try {
      final rows = await sb
          .from('campaign_comments')
          .select('id,campaign_id,user_id,content,created_at')
          .eq('campaign_id', id)
          .order('created_at');
      final rawList = (rows as List<dynamic>).cast<Map<String, dynamic>>();
      final userIds = rawList.map((r) => r['user_id']?.toString()).whereType<String>().where((v) => v.isNotEmpty).toSet();
      final profilesById = await _fetchProfilesByIds(userIds);
      final list = <CampaignCommentModel>[];
      for (final r in rawList) {
        final commentId = r['id']?.toString();
        final userId = r['user_id']?.toString();
        if (commentId == null || commentId.isEmpty) continue;
        if (userId == null || userId.isEmpty) continue;
        final profile = profilesById[userId];
        list.add(
          CampaignCommentModel(
            id: commentId,
            campaignId: id,
            userId: userId,
            username: profile?.username ?? userId,
            isVerified: profile?.isVerified ?? false,
            content: (r['content'] as String?) ?? '',
            createdAt: DateTime.tryParse(r['created_at']?.toString() ?? '') ?? DateTime.now(),
          ),
        );
      }
      _campaignCommentsById[id] = List.unmodifiable(list);
      _campaignCommentsLoadedFor.add(id);
      notifyListeners();
    } catch (_) {}
  }

