      unawaited(_donateToCampaignSupabase(campaignId: campaignId, amount: v, method: method));
    }
  }

  Future<void> _donateToCampaignSupabase({
    required String campaignId,
    required double amount,
    required PaymentMethod method,
  }) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null) return;
    if (!_looksLikeUuid(campaignId)) return;
    try {
      final insertStatus = method == PaymentMethod.pix ? 'pending' : 'succeeded';
      final row = await sb
          .from('donations')
          .insert(<String, Object?>{
            'campaign_id': campaignId,
            'donor_id': viewerId,
            'amount': amount,
            'currency': 'BRL',
            'payment_method': _paymentMethodToDb(method),
            'status': insertStatus,
          })
          .select('id,status')
          .single();

      final donationId = row['id']?.toString();
      if (donationId != null && donationId.isNotEmpty && insertStatus == 'pending') {
        Future<void>.delayed(const Duration(milliseconds: 1400)).then((_) async {
          if (isOffline) return;
          try {
            await sb.from('donations').update(<String, Object?>{'status': 'succeeded'}).eq('id', donationId);
          } catch (_) {}
          unawaited(hydrateCampaignById(campaignId));
        });
      } else {
        unawaited(hydrateCampaignById(campaignId));
      }
    } catch (_) {}
  }

  void createCampaign(
    AuthSession session, {
    required String title,
    required String description,
    required CampaignCategory category,
    required double goalAmount,
    required String locationPath,
    String? communityId,
    DateTime? deadline,
    String? imageUrl,
    CampaignStatus status = CampaignStatus.active,
  }) {
    final now = DateTime.now();
    final t = title.trim();
    final d = description.trim();
    if (t.isEmpty || d.isEmpty) return;
    if (!goalAmount.isFinite || goalAmount <= 0) return;

    final tempId = 'tmp:${now.microsecondsSinceEpoch}';
    final fallbackName = locationPath == 'world' ? 'Mundo' : locationPath.split('/').last.replaceAll('-', ' ');
    final local = CampaignModel(
      id: tempId,
      creatorId: session.userId,
      title: t,
      description: d,
      imageUrl: imageUrl,
      goalAmount: goalAmount,
      raisedAmount: 0,
      currency: 'BRL',
      category: category,
      status: status,
      deadline: deadline,
      createdAt: now,
      updatedAt: now,
      locationId: locationPath,
      locationPath: locationPath,
      locationName: fallbackName,
      communityId: communityId,
      donationsCount: 0,
    );
    _upsertCampaignLocal(local);
    notifyListeners();
    if (supabase != null) {
      unawaited(
        _createCampaignSupabase(
          tempId: tempId,
          title: t,
          description: d,
          category: category,
          goalAmount: goalAmount,
          locationPath: locationPath,
          communityId: communityId,
          deadline: deadline,
          imageUrl: imageUrl,
          status: status,
        ),
      );
    }
  }

  Future<void> _createCampaignSupabase({
    required String tempId,
    required String title,
    required String description,
    required CampaignCategory category,
    required double goalAmount,
    required String locationPath,
    String? communityId,
    DateTime? deadline,
    String? imageUrl,
    CampaignStatus status = CampaignStatus.active,
  }) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null) return;
    try {
      final locationId = await locationIdByPath(locationPath);
      if (locationId == null) throw StateError('Local inválido');

      final trimmed = imageUrl?.trim();
      final row = await sb
          .from('campaigns')
          .insert(<String, Object?>{
            'creator_id': viewerId,
            'location_id': locationId,
            'community_id': _looksLikeUuid(communityId) ? communityId : null,
            'title': title,
            'description': description,
            'image_url': (trimmed == null || trimmed.isEmpty) ? null : trimmed,
            'goal_amount': goalAmount,
            'currency': 'BRL',
            'category': _campaignCategoryToDb(category),
            'status': _campaignStatusToDb(status),
            'deadline': deadline?.toUtc().toIso8601String(),
          })
          .select('id')
          .single();
      final id = row['id']?.toString();
      if (id != null && id.isNotEmpty) {
        final local = findCampaign(tempId);
        if (local != null) {
          _campaignById.remove(tempId);
          _campaigns = List.unmodifiable(_campaigns.where((c) => c.id != tempId));
        }
        unawaited(hydrateCampaignById(id));
        unawaited(
          refreshCampaignsForCurrentFeed(
            locationPath: _lastFeedLocationPath,
            locationId: _lastFeedLocationId,
            communityId: _lastFeedCommunityId,
            lat: _lastFeedLat,
            lng: _lastFeedLng,
            force: true,
          ),
        );
      }
    } catch (_) {
      _campaignById.remove(tempId);
      _campaigns = List.unmodifiable(_campaigns.where((c) => c.id != tempId));
      notifyListeners();
    }
  }

  Future<Set<String>> _fetchViewerAlertIds({required String viewerId, required Set<String> alertIds}) async {
    final sb = supabase;
    if (sb == null) return const <String>{};
    if (alertIds.isEmpty) return const <String>{};
    if (!_looksLikeUuid(viewerId)) return const <String>{};
    try {
      final rows = await sb
          .from('alert_follows')
          .select('alert_id')
          .eq('user_id', viewerId)
          .inFilter('alert_id', alertIds.toList(growable: false));
      final out = <String>{};
      for (final raw in (rows as List<dynamic>)) {
        final r = raw as Map<String, dynamic>;
        final id = r['alert_id']?.toString();
        if (id == null || id.isEmpty) continue;
        out.add(id);
      }
      return out;
    } catch (_) {
      return const <String>{};
    }
  }

  void toggleFollowAlert(String alertId, {required bool isAuthenticated}) {
    if (!isAuthenticated) return;
    final index = _alerts.indexWhere((a) => a.id == alertId);
    if (index < 0) return;
    final a = _alerts[index];
    final shouldFollow = !a.viewerIsFollowing;
    final next = a.copyWith(viewerIsFollowing: shouldFollow);
    final list = _alerts.toList(growable: true);
    list[index] = next;
    _alerts = List.unmodifiable(list);
    if (shouldFollow) {
      _followedAlertIds.add(alertId);
      trackEvent('alert_follow', <String, Object?>{'alertId': alertId});
    } else {
      _followedAlertIds.remove(alertId);
      trackEvent('alert_unfollow', <String, Object?>{'alertId': alertId});
    }
    notifyListeners();
    if (supabase != null) {
      unawaited(_setAlertFollowSupabase(alertId: alertId, shouldFollow: shouldFollow));
    }
  }

  Future<void> _setAlertFollowSupabase({required String alertId, required bool shouldFollow}) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null) return;
    if (!_looksLikeUuid(alertId)) return;
    try {
      if (shouldFollow) {
        await sb.from('alert_follows').insert(<String, Object?>{'alert_id': alertId, 'user_id': viewerId});
      } else {
        await sb.from('alert_follows').delete().match(<String, Object>{'alert_id': alertId, 'user_id': viewerId});
      }
    } catch (_) {}
  }

  void voteOnAlert(String alertId, {required bool isAuthenticated, required AlertVote vote}) {
    if (!isAuthenticated) return;
    final index = _alerts.indexWhere((a) => a.id == alertId);
    if (index < 0) return;

    final a = _alerts[index];
    final next = switch (vote) {
      AlertVote.resolvido => a.copyWith(status: AlertStatus.resolved),
      AlertVote.confirmado => a.copyWith(confidenceScore: (a.confidenceScore + 0.1).clamp(0.0, 1.0)),
      AlertVote.falso => a.copyWith(confidenceScore: (a.confidenceScore - 0.1).clamp(0.0, 1.0)),
    };

    final list = _alerts.toList(growable: true);
    list[index] = next;
    _alerts = List.unmodifiable(list);
    notifyListeners();

    if (supabase != null) {
      unawaited(_voteOnAlertSupabase(alertId: alertId, vote: vote));
      unawaited(hydrateAlertById(alertId));
    }
  }

  Future<void> _voteOnAlertSupabase({required String alertId, required AlertVote vote}) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    if (!_looksLikeUuid(alertId)) return;
    try {
      await sb.rpc(
        'vote_on_alert',
        params: <String, Object?>{
          'p_alert_id': alertId,
          'p_vote': _alertVoteToDb(vote),
        },
      );
    } catch (_) {}
  }

  void createAlert(
    AuthSession session, {
    required String title,
    required String description,
    required AlertCategory category,
    required AlertUrgency urgency,
    required DateTime expiresAt,
    String? regionPath,
    String? locationName,
    String? communityId,
  }) {
    final now = DateTime.now();
    final displayUsername = _usernameForProfile(profileForUserId(session.userId), userId: session.userId);
    final tempId = 'tmpa:${now.microsecondsSinceEpoch}';
    final local = AlertModel(
      id: tempId,
      userId: session.userId,
      username: displayUsername,
      isVerified: profileForUserId(session.userId)?.isVerified ?? false,
      title: title,
      description: description,
      category: category,
      urgency: urgency,
      status: AlertStatus.active,
      expiresAt: expiresAt,
      createdAt: now,
      updatedAt: now,
      locationId: regionPath ?? 'world',
      locationPath: regionPath ?? 'world',
      locationName: locationName ?? 'Mundo',
      communityId: communityId,
      mediaType: AlertMediaType.none,
      viewerIsFollowing: false,
    );
    _alerts = List.unmodifiable([local, ..._alerts]);
    notifyListeners();

    if (supabase != null) {
      unawaited(
        _createAlertSupabase(
          tempId: tempId,
          title: title,
          description: description,
          category: category,
          urgency: urgency,
          expiresAt: expiresAt,
          regionPath: regionPath,
          communityId: communityId,
        ),
      );
    }
  }

  Future<void> _createAlertSupabase({
    required String tempId,
    required String title,
    required String description,
    required AlertCategory category,
    required AlertUrgency urgency,
    required DateTime expiresAt,
    String? regionPath,
    String? communityId,
  }) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null) return;
    try {
      final normalizedRegionPath = (regionPath == null || regionPath.trim().isEmpty) ? 'world' : regionPath.trim();
      final locationId = await locationIdByPath(normalizedRegionPath);
      final row = await sb
          .from('alerts')
          .insert(<String, Object?>{
            'user_id': viewerId,
            'location_id': _looksLikeUuid(locationId) ? locationId : null,
            'community_id': _looksLikeUuid(communityId) ? communityId : null,
            'title': title,
            'description': description,
            'category': _alertCategoryToDb(category),
            'urgency': _alertUrgencyToDb(urgency),
            'media_type': _alertMediaTypeToDb(AlertMediaType.none),
            'expires_at': expiresAt.toUtc().toIso8601String(),
          })
          .select('id')
          .maybeSingle();
      final createdId = row?['id']?.toString();
      if (createdId == null || createdId.isEmpty) return;
    } catch (_) {}

    _alerts = List.unmodifiable(_alerts.where((a) => a.id != tempId));
    _alertsLoadedKey = '';
    notifyListeners();
    unawaited(
      refreshAlertsForCurrentFeed(
        locationPath: _lastFeedLocationPath,
        locationId: _lastFeedLocationId,
        communityId: _lastFeedCommunityId,
        force: true,
      ),
    );
  }

  Future<bool> hydrateAlertById(String alertId) async {
    final sb = supabase;
    if (sb == null) return false;
    if (isOffline) return false;
    if (!_looksLikeUuid(alertId)) return false;
    try {
      final row = await sb
          .from('alerts')
          .select(
            'id,user_id,title,description,category,urgency,status,confidence_score,media_url,media_type,expires_at,created_at,updated_at,location_id,community_id,location:locations(path,name)',
          )
          .eq('id', alertId)
          .maybeSingle();
      if (row == null) return false;
      final id = row['id']?.toString();
      final userId = row['user_id']?.toString();
      if (id == null || id.isEmpty) return false;
      if (userId == null || userId.isEmpty) return false;

      final profilesById = await _fetchProfilesByIds(<String>{userId});
      final profile = profilesById[userId];
      final location = row['location'] is Map ? (row['location'] as Map).cast<String, dynamic>() : null;
      final locId = row['location_id']?.toString();
      final locPath = location?['path']?.toString();
      final locName = location?['name']?.toString();
      if (locId == null || locId.isEmpty) return false;
      if (locPath == null || locPath.isEmpty) return false;
      if (locName == null || locName.isEmpty) return false;

      final viewerId = sb.auth.currentUser?.id;
      final followed = viewerId == null ? const <String>{} : await _fetchViewerAlertIds(viewerId: viewerId, alertIds: <String>{id});
      if (followed.contains(id)) _followedAlertIds.add(id);

      final alert = AlertModel(
        id: id,
        userId: userId,
        username: profile?.username ?? userId,
        isVerified: profile?.isVerified ?? false,
        title: (row['title'] as String?) ?? '',
        description: (row['description'] as String?) ?? '',
        category: _parseAlertCategory(row['category']?.toString()),
        urgency: _parseAlertUrgency(row['urgency']?.toString()),
        status: _parseAlertStatus(row['status']?.toString()),
        confidenceScore: (row['confidence_score'] as num?)?.toDouble() ?? 0.5,
        expiresAt: DateTime.tryParse(row['expires_at']?.toString() ?? '') ?? DateTime.now().add(const Duration(hours: 6)),
        createdAt: DateTime.tryParse(row['created_at']?.toString() ?? '') ?? DateTime.now(),
        updatedAt: DateTime.tryParse(row['updated_at']?.toString() ?? '') ?? DateTime.now(),
        locationId: locId,
        locationPath: locPath,
        locationName: locName,
        communityId: row['community_id']?.toString(),
        mediaUrl: _normalizeSupabaseMediaPublicUrl((row['media_url'] as String?)?.trim()),
        mediaType: _parseAlertMediaType(row['media_type']?.toString()),
        viewerIsFollowing: followed.contains(id),
      );

      final existing = _alerts.indexWhere((a) => a.id == id);
      if (existing >= 0) {
        final list = _alerts.toList(growable: true);
        list[existing] = alert;
        _alerts = List.unmodifiable(list);
      } else {
        _alerts = List.unmodifiable([alert, ..._alerts.where((a) => a.id != id)]);
      }
      notifyListeners();
      return true;
    } catch (_) {
      return false;
    }
  }

  void toggleLike(String postId, {required bool isAuthenticated}) {
    if (!isAuthenticated) return;
    final index = _posts.indexWhere((p) => p.id == postId);
    if (index < 0) return;
    final p = _posts[index];
    final nextLiked = !p.viewerHasLiked;
    if (nextLiked) {
      trackEvent('like_add', <String, Object?>{
        'postId': p.id,
        'kind': p.kind.analyticsValue,
        'visibility': p.visibility.analyticsValue,
      });
    }
    _setPostAt(
      index,
      p.copyWith(
        viewerHasLiked: nextLiked,
        likeCount: nextLiked ? p.likeCount + 1 : (p.likeCount - 1).clamp(0, 1 << 30),
      ),
    );
    notifyListeners();
    if (supabase != null) {
      unawaited(_toggleLikeSupabase(postId: postId, shouldLike: nextLiked));
    }
  }

