  List<CommentModel> commentsForPost(String postId) {
    final list = _commentsByPost[postId] ?? const [];
    return List.unmodifiable(list);
  }

  void addCommentText(
    String postId, {
    required AuthSession session,
    required String text,
  }) {
    final body = text.trim();
    if (body.isEmpty) return;
    final index = _posts.indexWhere((p) => p.id == postId);
    if (index < 0) return;
    final p = _posts[index];
    trackEvent('comment_add', <String, Object?>{
      'postId': p.id,
      'kind': p.kind.analyticsValue,
      'visibility': p.visibility.analyticsValue,
    });

    final now = DateTime.now();
    final displayUsername = _usernameForProfile(profileForUserId(session.userId), userId: session.userId);
    final comment = CommentModel(
      id: now.microsecondsSinceEpoch.toString(),
      postId: postId,
      userId: session.userId,
      username: displayUsername,
      isVerified: supabase == null ? session.userId == _u2.userId : (profileForUserId(session.userId)?.isVerified ?? false),
      body: body,
      createdAt: now,
    );

    final list = (_commentsByPost[postId] ?? const <CommentModel>[]).toList(growable: true)
      ..add(comment)
      ..sort((a, b) => a.createdAt.compareTo(b.createdAt));
    _commentsByPost[postId] = list;

    _setPostAt(index, p.copyWith(commentCount: (p.commentCount + 1).clamp(0, 1 << 30)));
    notifyListeners();
    if (supabase != null) {
      unawaited(_addCommentSupabase(postId: postId, body: body));
    }
  }

  void deleteComment(
    String postId,
    String commentId, {
    required String viewerId,
  }) {
    final list = (_commentsByPost[postId] ?? const <CommentModel>[]).toList(growable: true);
    final idx = list.indexWhere((c) => c.id == commentId);
    if (idx < 0) return;
    if (list[idx].userId != viewerId) return;
    list.removeAt(idx);
    _commentsByPost[postId] = list;

    final postIndex = _posts.indexWhere((p) => p.id == postId);
    if (postIndex >= 0) {
      final p = _posts[postIndex];
      _setPostAt(postIndex, p.copyWith(commentCount: (p.commentCount - 1).clamp(0, 1 << 30)));
    }
    notifyListeners();
  }

  String? postIdForCommentId(String commentId) {
    for (final entry in _commentsByPost.entries) {
      for (final c in entry.value) {
        if (c.id == commentId) return entry.key;
      }
    }
    return null;
  }

  List<ReportModel> reportsForModeration() => List.unmodifiable(_reports);

  Future<void> refreshModerationReports() async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null) return;
    try {
      final rows = await sb
          .from('reports')
          .select('id,reporter_id,entity_type,entity_id,reason,description,status,created_at,reported_user_id')
          .order('created_at', ascending: false)
          .limit(200);
      final list = (rows as List<dynamic>).cast<Map<String, dynamic>>();
      final reporterIds = list.map((r) => r['reporter_id']?.toString()).whereType<String>().where((v) => v.isNotEmpty).toSet();
      final reportedIds =
          list.map((r) => r['reported_user_id']?.toString()).whereType<String>().where((v) => v.isNotEmpty).toSet();
      final profilesById = await _fetchProfilesByIds({...reporterIds, ...reportedIds});

      final next = <ReportModel>[];
      for (final r in list) {
        final id = r['id']?.toString();
        final reporterId = r['reporter_id']?.toString();
        final entityId = r['entity_id']?.toString();
        if (id == null || id.isEmpty) continue;
        if (reporterId == null || reporterId.isEmpty) continue;
        if (entityId == null || entityId.isEmpty) continue;
        final reportedUserId = r['reported_user_id']?.toString();
        next.add(
          ReportModel(
            id: id,
            reporterId: reporterId,
            reporterUsername: profilesById[reporterId]?.username,
            entityType: _parseReportEntityType(r['entity_type']?.toString()),
            entityId: entityId,
            reason: (r['reason'] as String?) ?? '',
            description: (r['description'] as String?)?.trim().isEmpty ?? true ? null : (r['description'] as String?)?.trim(),
            status: _parseReportStatus(r['status']?.toString()),
            createdAt: DateTime.tryParse(r['created_at']?.toString() ?? '')?.toLocal() ?? DateTime.now(),
            reportedUserId: reportedUserId,
            reportedUsername: reportedUserId == null ? null : profilesById[reportedUserId]?.username,
          ),
        );
      }
      _reports = List.unmodifiable(next);
      notifyListeners();
    } catch (_) {}
  }

  Future<void> submitReport({
    required String reporterId,
    required ReportEntityType entityType,
    required String entityId,
    required String reason,
    String? description,
    String? reportedUserId,
  }) async {
    final now = DateTime.now();
    final reporterProfile = profileForUserId(reporterId);
