      status: ReportStatus.open,
      createdAt: now,
      reportedUserId: reportedUserId,
      reportedUsername: reportedProfile?.username,
    );
    _reports = List.unmodifiable([local, ..._reports]);
    notifyListeners();

    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    try {
      await sb.from('reports').insert(<String, Object?>{
        'reporter_id': reporterId,
        'entity_type': _reportEntityTypeToDb(entityType),
        'entity_id': entityId,
        'reason': reason.trim(),
        'description': (description ?? '').trim().isEmpty ? null : description!.trim(),
        'reported_user_id': reportedUserId,
      });
    } catch (_) {}
  }

  Future<void> moderationSetReportStatus({
    required String reportId,
    required ReportStatus status,
    String? note,
  }) async {
    final sb = supabase;
    if (sb == null) {
      final idx = _reports.indexWhere((r) => r.id == reportId);
      if (idx < 0) return;
      final list = _reports.toList(growable: true);
      final r = list[idx];
      list[idx] = ReportModel(
        id: r.id,
        reporterId: r.reporterId,
        reporterUsername: r.reporterUsername,
        entityType: r.entityType,
        entityId: r.entityId,
        reason: r.reason,
        description: r.description,
        status: status,
        createdAt: r.createdAt,
        reportedUserId: r.reportedUserId,
        reportedUsername: r.reportedUsername,
      );
      _reports = List.unmodifiable(list);
      notifyListeners();
      return;
    }
    if (isOffline) return;
    try {
      await sb.rpc(
        'moderation_set_report_status',
        params: <String, Object?>{
          'p_report_id': reportId,
          'p_status': _reportStatusToDb(status),
          'p_note': (note ?? '').trim().isEmpty ? null : note!.trim(),
        },
      );
    } catch (_) {}
    unawaited(refreshModerationReports());
  }

