  void _removeLocalContent({required ReportEntityType entityType, required String entityId}) {
    switch (entityType) {
      case ReportEntityType.post:
        _posts = List.unmodifiable(_posts.where((p) => p.id != entityId));
        _commentsByPost.remove(entityId);
        _hiddenPostIds.remove(entityId);
        notifyListeners();
        break;
      case ReportEntityType.comment:
        for (final entry in _commentsByPost.entries) {
          final next = entry.value.where((c) => c.id != entityId).toList(growable: false);
          if (next.length != entry.value.length) {
            _commentsByPost[entry.key] = next;
          }
        }
        notifyListeners();
        break;
      case ReportEntityType.alert:
        _alerts = List.unmodifiable(_alerts.where((a) => a.id != entityId));
        _followedAlertIds.remove(entityId);
        notifyListeners();
        break;
      case ReportEntityType.story:
        _stories = List.unmodifiable(_stories.where((s) => s.id != entityId));
        notifyListeners();
        break;
      case ReportEntityType.user:
        notifyListeners();
        break;
    }
  }

