          mediaKind: mediaKind,
          mediaUrl: mediaUrl,
          regionPath: regionPath,
          communityId: communityId,
        ),
      );
      return completer.future;
    }
    final now = DateTime.now();
    final post = PostModel(
      id: now.microsecondsSinceEpoch.toString(),
      userId: session.userId,
      username: displayUsername,
      isVerified: session.userId == _u2.userId,
      kind: kind,
      postType: switch (kind) {
        PostKind.request => PostType.prayer,
        PostKind.testimony => PostType.normal,
      },
      visibility: visibility,
      body: body,
      createdAt: now,
      regionPath: regionPath ?? 'world',
      location: location,
      churchId: visibility == PostVisibility.church ? session.churchId : null,
      communityId: communityId,
      mediaKind: mediaKind,
      mediaUrl: mediaUrl,
      commentCount: 0,
      likeCount: 0,
      prayerCount: 0,
      viewerHasLiked: false,
      viewerHasPrayed: false,
      viewerHasSaved: false,
    );
    _posts = List.unmodifiable([post, ..._posts]);
    _commentsByPost[post.id] = <CommentModel>[];
    notifyListeners();
    return true;
  }

  Future<bool> updatePost(
    AuthSession session, {
    required String postId,
    required String body,
    required PostVisibility visibility,
    String? regionPath,
    String? location,
    String? mediaKind,
    String? mediaUrl,
  }) async {
    _lastPostUpdateError = null;
    final index = _posts.indexWhere((p) => p.id == postId);
    if (index < 0) {
      _lastPostUpdateError = 'Post não encontrado';
      return false;
    }
    final previous = _posts[index];
    if (previous.userId != session.userId) {
      _lastPostUpdateError = 'Você não tem permissão para editar este post.';
      return false;
    }
    final nextMediaKind = (mediaKind ?? '').trim();
    final nextMediaUrl = (mediaUrl ?? '').trim();
    final updated = previous.copyWith(
      body: body,
      visibility: visibility,
      regionPath: (regionPath == null || regionPath.trim().isEmpty) ? (previous.regionPath ?? 'world') : regionPath.trim(),
      location: location,
      churchId: visibility == PostVisibility.church ? (session.churchId ?? previous.churchId) : null,
      mediaKind: nextMediaKind.isEmpty ? null : nextMediaKind,
      mediaUrl: nextMediaUrl.isEmpty ? null : nextMediaUrl,
    );
    _setPostAt(index, updated);
    notifyListeners();

    if (supabase == null) return true;

    final ok = await _updatePostSupabase(
      postId: postId,
      body: body,
      visibility: visibility,
      churchId: visibility == PostVisibility.church ? session.churchId : null,
      regionPath: regionPath,
      mediaKind: nextMediaKind.isEmpty ? null : nextMediaKind,
      mediaUrl: nextMediaUrl.isEmpty ? null : nextMediaUrl,
    );
    if (!ok) {
      _setPostAt(index, previous);
      notifyListeners();
    }
    return ok;
  }

  void _completeCreatePost(String tempId, bool ok) {
    final completer = _pendingCreatePostResultByTempId.remove(tempId);
    if (completer != null && !completer.isCompleted) completer.complete(ok);
  }

  void _removeTempPost(String tempId) {
    _pendingTempPostIds.remove(tempId);
    _posts = _posts.where((p) => p.id != tempId).toList(growable: false);
    _commentsByPost.remove(tempId);
    _hiddenPostIds.remove(tempId);
  }

