  Future<void> _createPostSupabase({
    required String tempId,
    required String body,
    required PostKind kind,
    required PostVisibility visibility,
    required String? churchId,
    String? mediaKind,
    String? mediaUrl,
    String? regionPath,
    String? communityId,
    int attempt = 1,
  }) async {
    final sb = supabase;
    if (sb == null) {
      _lastPostCreateError = 'Supabase não inicializado';
      return;
    }
    if (isOffline) {
      _lastPostCreateError = 'Sem conexão com a internet';
      return;
    }
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null) {
      if (attempt < 3 && _pendingTempPostIds.contains(tempId)) {
        Future<void>.delayed(const Duration(seconds: 2), () {
          unawaited(
            _createPostSupabase(
              tempId: tempId,
              body: body,
              kind: kind,
              visibility: visibility,
              churchId: churchId,
              mediaKind: mediaKind,
              mediaUrl: mediaUrl,
              regionPath: regionPath,
              communityId: communityId,
              attempt: attempt + 1,
            ),
          );
        });
      } else {
        _lastPostCreateError = 'Sessão do Supabase não encontrada. Faça login novamente.';
        _removeTempPost(tempId);
        notifyListeners();
        _completeCreatePost(tempId, false);
      }
      return;
    }
    String? createdPostId;
    try {
      final normalizedRegionPath = (regionPath == null || regionPath.trim().isEmpty) ? 'world' : regionPath.trim();
      final locationId = await locationIdByPath(normalizedRegionPath);
      double? lat;
      double? lng;
      if (_looksLikeUuid(locationId)) {
        final loc = await sb
            .from('locations')
            .select('center_lat,center_lng')
            .eq('id', locationId!)
            .maybeSingle();
        lat = (loc?['center_lat'] as num?)?.toDouble();
        lng = (loc?['center_lng'] as num?)?.toDouble();
      }
      final basePayload = <String, Object?>{
        'user_id': viewerId,
        'kind': kind.analyticsValue,
        'visibility': visibility.analyticsValue,
        'body': body,
        'church_id': _looksLikeUuid(churchId) ? churchId : null,
        'community_id': _looksLikeUuid(communityId) ? communityId : null,
        'location_id': _looksLikeUuid(locationId) ? locationId : null,
        'lat': lat,
        'lng': lng,
      };
      final row = await sb.from('posts').insert(basePayload).select('id').single();
      createdPostId = row['id']?.toString();
      if (createdPostId != null && createdPostId.isNotEmpty) {
        final persisted = await sb.from('posts').select('id').eq('id', createdPostId).maybeSingle();
        if (persisted == null) createdPostId = null;
      }
    } catch (e) {
      if (e is PostgrestException) {
        final code = (e.code ?? '').toString().trim();
        final details = (e.details ?? '').toString().trim();
        final hint = (e.hint ?? '').toString().trim();
        final parts = <String>[
          e.message,
          if (code.isNotEmpty) 'code=$code',
          if (details.isNotEmpty) 'details=$details',
          if (hint.isNotEmpty) 'hint=$hint',
        ];
        _lastPostCreateError = parts.join(' • ');
      } else {
        _lastPostCreateError = e.toString();
      }
    }

    if (createdPostId != null && createdPostId.isNotEmpty && mediaUrl != null && mediaUrl.trim().isNotEmpty) {
      try {
        await sb.from('post_media').insert(<String, Object?>{
          'post_id': createdPostId,
          'kind': mediaKind == 'video' ? 'video' : 'image',
          'provider': 'external',
          'external_id': mediaUrl.trim(),
          'order_index': 0,
        });
      } catch (_) {}
    }

    if (createdPostId != null && createdPostId.isNotEmpty) {
      _lastPostCreateError = null;
      _pendingTempPostIds.remove(tempId);
      final index = _posts.indexWhere((p) => p.id == tempId);
      if (index >= 0) {
        final previous = _posts[index];
        final replaced = PostModel(
          id: createdPostId,
          userId: previous.userId,
          username: previous.username,
          isVerified: previous.isVerified,
          kind: previous.kind,
          postType: previous.postType,
          visibility: previous.visibility,
          body: previous.body,
          createdAt: previous.createdAt,
          regionPath: previous.regionPath,
          location: previous.location,
          churchId: previous.churchId,
          communityId: previous.communityId,
          mediaKind: previous.mediaKind,
          mediaUrl: previous.mediaUrl,
          commentCount: previous.commentCount,
          likeCount: previous.likeCount,
          prayerCount: previous.prayerCount,
          viewerHasLiked: previous.viewerHasLiked,
          viewerHasPrayed: previous.viewerHasPrayed,
          viewerHasSaved: previous.viewerHasSaved,
        );
        final nextPosts = _posts.toList(growable: false);
        nextPosts[index] = replaced;
        _posts = nextPosts;
      }
      if (_commentsByPost.containsKey(tempId)) {
        final comments = _commentsByPost.remove(tempId);
        if (comments != null) _commentsByPost[createdPostId] = comments;
      }
      _hiddenPostIds.remove(tempId);
      notifyListeners();
      _completeCreatePost(tempId, true);
      unawaited(refreshFeedForCurrentSession());
      return;
    }

    if (attempt < 3 && _pendingTempPostIds.contains(tempId)) {
      Future<void>.delayed(const Duration(seconds: 2), () {
        unawaited(
          _createPostSupabase(
            tempId: tempId,
            body: body,
            kind: kind,
            visibility: visibility,
            churchId: churchId,
            mediaKind: mediaKind,
            mediaUrl: mediaUrl,
            regionPath: regionPath,
            communityId: communityId,
            attempt: attempt + 1,
          ),
        );
      });
    } else {
      _lastPostCreateError ??= 'Falha ao inserir post no Supabase';
      _removeTempPost(tempId);
      notifyListeners();
      _completeCreatePost(tempId, false);
    }
  }

  Future<bool> _updatePostSupabase({
    required String postId,
    required String body,
    required PostVisibility visibility,
    required String? churchId,
    String? regionPath,
    String? mediaKind,
    String? mediaUrl,
  }) async {
    final sb = supabase;
    if (sb == null) {
      _lastPostUpdateError = 'Supabase não inicializado';
      return false;
    }
    if (isOffline) {
      _lastPostUpdateError = 'Sem conexão com a internet';
      return false;
    }
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null) {
      _lastPostUpdateError = 'Sessão do Supabase não encontrada. Faça login novamente.';
      return false;
    }
    try {
      final normalizedRegionPath = (regionPath == null || regionPath.trim().isEmpty) ? null : regionPath.trim();
      final locationId = normalizedRegionPath == null ? null : await locationIdByPath(normalizedRegionPath);
      double? lat;
      double? lng;
      if (_looksLikeUuid(locationId)) {
        final loc = await sb.from('locations').select('center_lat,center_lng').eq('id', locationId!).maybeSingle();
        lat = (loc?['center_lat'] as num?)?.toDouble();
        lng = (loc?['center_lng'] as num?)?.toDouble();
      }
      final payload = <String, Object?>{
        'body': body,
        'visibility': visibility.analyticsValue,
        'church_id': _looksLikeUuid(churchId) ? churchId : null,
        if (normalizedRegionPath != null) 'location_id': _looksLikeUuid(locationId) ? locationId : null,
        if (normalizedRegionPath != null) 'lat': lat,
        if (normalizedRegionPath != null) 'lng': lng,
      };
      await sb.from('posts').update(payload).eq('id', postId);
      final nextKind = (mediaKind ?? '').trim();
      final nextUrl = (mediaUrl ?? '').trim();
      if (nextKind.isNotEmpty && nextUrl.isNotEmpty) {
        await sb.from('post_media').delete().eq('post_id', postId);
        await sb.from('post_media').insert(<String, Object?>{
          'post_id': postId,
          'kind': nextKind == 'video' ? 'video' : 'image',
          'provider': 'external',
          'external_id': nextUrl,
          'order_index': 0,
        });
      }
      return true;
    } catch (e) {
      if (e is PostgrestException) {
        final code = (e.code ?? '').toString().trim();
        final details = (e.details ?? '').toString().trim();
        final hint = (e.hint ?? '').toString().trim();
        final parts = <String>[
          e.message,
          if (code.isNotEmpty) 'code=$code',
          if (details.isNotEmpty) 'details=$details',
          if (hint.isNotEmpty) 'hint=$hint',
        ];
        _lastPostUpdateError = parts.join(' • ');
      } else {
        _lastPostUpdateError = e.toString();
      }
      return false;
    }
  }

  Future<void> _updateProfileSupabase({
