  Future<void> retryMessage(String threadId, String messageId) async {
    final t = _threadById(threadId);
    if (supabase != null && t?.isGroup == true && t?.communityId != null) return;
    final list = (_messagesByThread[threadId] ?? []).toList();
    final i = list.indexWhere((m) => m.id == messageId);
    if (i < 0) return;
    final m = list[i];
    if (m.sendStatus != MessageSendStatus.failed) return;
    if (supabase != null && !isOffline && threadId.trim().startsWith('dm:')) {
      final sb = supabase!;
      final viewerId = sb.auth.currentUser?.id;
      if (viewerId != null && viewerId == m.senderId) {
        final isImage = m.kind == MessageKind.image;
        final body = isImage
            ? _encodeDirectImageBody(imageToken: (m.imageToken ?? '').trim(), caption: m.text)
            : (m.text ?? '').trim();
        if (body.isNotEmpty) {
          list[i] = m.copyWith(sendStatus: MessageSendStatus.sending);
          _messagesByThread[threadId] = list;
          notifyListeners();
          _schedulePersistDirect();
          try {
            _lastDirectSendError = null;
            await ensureDirectDmMembershipForThread(threadId.trim(), viewerId: viewerId);
            await sb.from('direct_messages').insert(<String, Object?>{
              'thread_id': threadId.trim(),
              'sender_id': viewerId,
              'body': body,
            });
            _lastDirectSendError = null;
            final cur2 = (_messagesByThread[threadId] ?? []).toList();
            final ii2 = cur2.indexWhere((x) => x.id == messageId);
            if (ii2 >= 0) {
              cur2[ii2] = cur2[ii2].copyWith(sendStatus: MessageSendStatus.sent);
              _messagesByThread[threadId] = cur2;
              notifyListeners();
              _schedulePersistDirect();
            }
            _directMessagesLoadedFor.remove(threadId.trim());
            await refreshDirectMessages(threadId.trim(), force: true);
            unawaited(refreshDirectForViewer(viewerId, force: true));
            return;
          } catch (e) {
            final msg = _shortSupabaseError(e).trim();
            _lastDirectSendError = msg.isEmpty ? (isImage ? 'Falha ao enviar imagem.' : 'Falha ao enviar mensagem.') : msg;
            final cur = (_messagesByThread[threadId] ?? []).toList();
            final ii = cur.indexWhere((x) => x.id == messageId);
            if (ii >= 0) {
              cur[ii] = cur[ii].copyWith(sendStatus: MessageSendStatus.failed);
              _messagesByThread[threadId] = cur;
            }
            notifyListeners();
            _schedulePersistDirect();
            return;
          }
        }
      }
    }
    list[i] = m.copyWith(sendStatus: MessageSendStatus.sending);
    _messagesByThread[threadId] = list;
    notifyListeners();
    _schedulePersistDirect();
    await _resolveSend(threadId, messageId);
  }

  void deleteMessage(String threadId, String messageId, {required String viewerId}) {
    final t = _threadById(threadId);
    if (supabase != null && t?.isGroup == true && t?.communityId != null) return;
    final list = (_messagesByThread[threadId] ?? []).toList();
    final i = list.indexWhere((m) => m.id == messageId);
    if (i < 0) return;
    final m = list[i];
    if (m.senderId != viewerId) return;
    list.removeAt(i);
    _messagesByThread[threadId] = list;
    notifyListeners();
    _schedulePersistDirect();
  }

  void _bumpThread(String threadId, {required String preview, required DateTime at}) {
    final i = _threads.indexWhere((t) => t.id == threadId);
    if (i < 0) return;
    final t = _threads[i];
    final updated = t.copyWith(lastMessage: preview, lastAt: at);
    _threads = [
      updated,
      ..._threads.where((x) => x.id != threadId),
    ];
    _schedulePersistDirect();
  }

  Future<void> _resolveSend(String threadId, String messageId) async {
    await Future<void>.delayed(const Duration(milliseconds: 550));
    final list = (_messagesByThread[threadId] ?? []).toList();
    final i = list.indexWhere((m) => m.id == messageId);
    if (i < 0) return;
    final m = list[i];
    if (m.sendStatus != MessageSendStatus.sending) return;
    list[i] = m.copyWith(sendStatus: _isOffline ? MessageSendStatus.failed : MessageSendStatus.sent);
    _messagesByThread[threadId] = list;
    notifyListeners();
    _schedulePersistDirect();
  }

  List<CommunityModel> communitiesFor(SessionState session, {String query = ''}) {
    final lower = query.trim().toLowerCase();
    final filtered = _communities.where((c) {
      if (lower.isEmpty) return true;
      return c.name.toLowerCase().contains(lower);
    });
    if (!session.isAuthenticated) return filtered.toList(growable: false);
    return filtered.toList(growable: false);
  }

  Future<void> refreshCommunitiesForViewer({bool force = false}) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;

    final viewerId = sb.auth.currentUser?.id;
    final nextKey = 'v:${viewerId ?? 'anon'}';
    if (!force && _communitiesLoadedForViewerKey == nextKey) return;
    _communitiesLoadedForViewerKey = nextKey;

    try {
      List<Map<String, dynamic>> rawList;
      try {
        final raw = await sb
            .from('communities')
            .select('id,name,type,is_closed,owner_id,description,image_url,location_id,visibility,join_mode,creator_id,created_at,rules')
            .order('created_at', ascending: false)
            .limit(200);
        rawList = (raw as List<dynamic>).cast<Map<String, dynamic>>();
      } on PostgrestException catch (e) {
        if (_postgrestMissingColumn(e, 'description') ||
            _postgrestMissingColumn(e, 'image_url') ||
            _postgrestMissingColumn(e, 'location_id') ||
            _postgrestMissingColumn(e, 'visibility') ||
            _postgrestMissingColumn(e, 'join_mode') ||
            _postgrestMissingColumn(e, 'creator_id')) {
          final raw = await sb
              .from('communities')
              .select('id,name,type,is_closed,owner_id,created_at')
              .order('created_at', ascending: false)
              .limit(200);
          rawList = (raw as List<dynamic>).cast<Map<String, dynamic>>();
        } else if (_postgrestMissingColumn(e, 'rules')) {
          final raw = await sb
              .from('communities')
              .select('id,name,type,is_closed,owner_id,description,image_url,location_id,visibility,join_mode,creator_id,created_at')
              .order('created_at', ascending: false)
              .limit(200);
          rawList = (raw as List<dynamic>).cast<Map<String, dynamic>>();
        } else {
          rethrow;
        }
      }

      final membershipByCommunityId = <String, Map<String, dynamic>>{};
      if (viewerId != null) {
        final mRaw = await sb.from('community_members').select('community_id,status,role').eq('user_id', viewerId);
        for (final r in (mRaw as List<dynamic>).cast<Map<String, dynamic>>()) {
          final cid = r['community_id']?.toString();
          if (cid == null || cid.isEmpty) continue;
          membershipByCommunityId[cid] = r;
        }
      }

      final locationIds = rawList
          .map((r) => r['location_id']?.toString())
          .whereType<String>()
          .where(_looksLikeUuid)
          .toSet();
      await _warmLocationNamesByIds(locationIds);

      final next = <CommunityModel>[];
      for (final r in rawList) {
        final id = r['id']?.toString();
        final name = (r['name'] as String?)?.trim();
        final ownerId = r['owner_id']?.toString();
        if (id == null || id.isEmpty) continue;
        if (name == null || name.isEmpty) continue;
        if (ownerId == null || ownerId.isEmpty) continue;

        final rawRules = r['rules'];
        final rules = rawRules is List
            ? rawRules.map((x) => x?.toString() ?? '').where((s) => s.trim().isNotEmpty).toList(growable: false)
            : const <String>[];

        final joinMode = (r['join_mode'] as String?)?.trim().toLowerCase();
        final isClosedRaw = r['is_closed'] == true;
        final resolvedJoinMode = (joinMode == null || joinMode.isEmpty)
            ? (isClosedRaw ? 'request' : 'public')
            : joinMode;
        final visibility = (r['visibility'] as String?)?.trim().toLowerCase() ?? 'public';
        final locationId = r['location_id']?.toString();
        final createdAt = DateTime.tryParse(r['created_at']?.toString() ?? '')?.toLocal();

        final membership = membershipByCommunityId[id];
        final memberStatus = (membership?['status'] as String?)?.trim().toLowerCase();
        final memberRole = (membership?['role'] as String?)?.trim().toLowerCase();
        final viewerStatus = viewerId == null
            ? CommunityViewerStatus.none
            : (ownerId == viewerId
                ? CommunityViewerStatus.approved
                : switch (memberStatus) {
                    'active' => CommunityViewerStatus.approved,
                    'pending' => CommunityViewerStatus.pending,
                    'invited' => CommunityViewerStatus.pending,
                    _ => CommunityViewerStatus.none,
                  });

        next.add(
          CommunityModel(
            id: id,
            name: name,
            ownerId: ownerId,
            type: (r['type'] as String?)?.trim().toLowerCase() ?? 'church',
            isClosed: resolvedJoinMode != 'public',
            description: (r['description'] as String?) ?? '',
            imageUrl: _normalizeSupabaseMediaPublicUrl((r['image_url'] as String?)?.trim()),
            locationId: _looksLikeUuid(locationId) ? locationId : null,
            locationName: _looksLikeUuid(locationId) ? _locationNameByIdCache[locationId!] : null,
            visibility: visibility,
            joinMode: resolvedJoinMode,
            creatorId: r['creator_id']?.toString(),
            createdAt: createdAt,
            rules: rules,
            viewerStatus: viewerStatus,
            viewerRole: ownerId == viewerId ? 'admin' : memberRole,
          ),
        );
      }

      _communities = next.toList(growable: false);
      notifyListeners();
    } catch (_) {}
  }

  Future<void> _warmLocationNamesByIds(Set<String> ids) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final missing = ids.where((id) => !_locationNameByIdCache.containsKey(id) && !_locationNameMisses.contains(id)).toSet();
    if (missing.isEmpty) return;
    try {
      final rows = await sb.from('locations').select('id,name').inFilter('id', missing.toList(growable: false));
      for (final r in (rows as List<dynamic>).cast<Map<String, dynamic>>()) {
        final id = r['id']?.toString();
        final name = (r['name'] as String?)?.trim();
        if (id == null || id.isEmpty) continue;
        if (name == null || name.isEmpty) continue;
        _locationNameByIdCache[id] = name;
      }
      for (final id in missing) {
        if (!_locationNameByIdCache.containsKey(id)) {
          _locationNameMisses.add(id);
        }
      }
    } catch (_) {}
  }

  Future<void> refreshCommunityMembers(String communityId, {bool force = false}) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    if (!force && _communityMembersLoadedFor.contains(communityId)) return;
    _communityMembersLoadedFor.add(communityId);
    try {
      final rows = await sb
          .from('community_members')
          .select('user_id,role,status,joined_at')
          .eq('community_id', communityId)
          .eq('status', 'active');
      final raw = (rows as List<dynamic>).cast<Map<String, dynamic>>();
      final memberIds = raw.map((r) => r['user_id']?.toString()).whereType<String>().where((v) => v.isNotEmpty).toSet();
      final moderators = <String>{};
      for (final r in raw) {
        final uid = r['user_id']?.toString();
        if (uid == null || uid.isEmpty) continue;
        final role = (r['role'] as String?)?.trim().toLowerCase();
        if (role == 'admin' || role == 'moderator' || role == 'founder') {
          moderators.add(uid);
        }
      }
      final profilesById = await _fetchProfilesByIds(memberIds);
      for (final p in profilesById.values) {
        _upsertProfile(p);
      }
      _communityMembersById[communityId] = memberIds;
      _communityModeratorsById[communityId] = moderators;
      final i = _communities.indexWhere((c) => c.id == communityId);
      if (i >= 0) {
        _communities[i] = _communities[i].copyWith(memberCount: memberIds.length);
      }
      notifyListeners();
    } catch (_) {}
  }

