            senderId: uid,
            kind: MessageKind.text,
            sentAt: DateTime.tryParse(r['created_at']?.toString() ?? '')?.toLocal() ?? DateTime.now(),
            sendStatus: MessageSendStatus.sent,
            text: (r['message'] as String?) ?? '',
          ),
        );
      }
      _communityMessagesById[communityId] = List.unmodifiable(list);
      final last = list.isEmpty ? null : list.last;
      if (last != null) {
        _bumpThread('tg_$communityId', preview: last.text ?? '', at: last.sentAt);
      }
      notifyListeners();
    } catch (_) {}
  }

  Future<void> _ensureCommunityChatSubscribed(String communityId) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    if (_communityChatChannelsById.containsKey(communityId)) return;
    final channel = sb.channel('realtime:community_messages:$communityId');
    channel.onPostgresChanges(
      event: PostgresChangeEvent.all,
      schema: 'public',
      table: 'community_messages',
      filter: PostgresChangeFilter(
        type: PostgresChangeFilterType.eq,
        column: 'community_id',
        value: communityId,
      ),
      callback: (_) {
        if (isOffline) return;
        unawaited(refreshCommunityMessages(communityId, force: true));
      },
    );
    channel.subscribe();
    _communityChatChannelsById[communityId] = channel;
  }

  Future<void> _sendCommunityTextMessage(String communityId, String senderId, String text) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null || viewerId != senderId) return;
    final now = DateTime.now();
    final tempId = 'tmp:${now.microsecondsSinceEpoch}';
    final next = MessageModel(
      id: tempId,
      threadId: 'tg_$communityId',
      senderId: senderId,
      kind: MessageKind.text,
      sentAt: now,
      sendStatus: MessageSendStatus.sending,
      text: text,
    );
    final list = (_communityMessagesById[communityId] ?? const <MessageModel>[]).toList()..add(next);
    _communityMessagesById[communityId] = List.unmodifiable(list);
    _bumpThread('tg_$communityId', preview: text, at: now);
    notifyListeners();
    try {
      await sb.from('community_messages').insert(<String, Object?>{
        'community_id': communityId,
        'user_id': senderId,
        'message': text,
      });
      _communityMessagesLoadedFor.remove(communityId);
      await refreshCommunityMessages(communityId, force: true);
    } catch (_) {
      final cur = (_communityMessagesById[communityId] ?? const <MessageModel>[]).toList();
      final i = cur.indexWhere((m) => m.id == tempId);
      if (i >= 0) {
        cur[i] = cur[i].copyWith(sendStatus: MessageSendStatus.failed);
        _communityMessagesById[communityId] = List.unmodifiable(cur);
        notifyListeners();
      }
    }
  }

  CommunityModel? findCommunity(String id) {
    for (final c in _communities) {
      if (c.id == id) return c;
    }
    return null;
  }

  bool isCommunityAdmin(String communityId, String userId) {
    final c = findCommunity(communityId);
    if (c == null) return false;
    return c.ownerId == userId;
  }

  bool isCommunityModerator(String communityId, String userId) {
    return _communityModeratorsById[communityId]?.contains(userId) ?? false;
  }

  bool canModerateCommunity(String communityId, String userId) {
    return isCommunityAdmin(communityId, userId) || isCommunityModerator(communityId, userId);
  }

