  Future<List<_UpcomingAssignedPrayerRun>> fetchUpcomingAssignedPrayerRuns({
    required String userId,
    required DateTime fromUtc,
    required DateTime toUtc,
  }) async {
    final sb = supabase;
    if (sb == null) return const [];
    if (isOffline) return const [];
    final uid = userId.trim();
    if (uid.isEmpty) return const [];
    try {
      final rows = await sb
          .from('community_prayer_schedule_runs')
          .select('id,community_id,starts_at,status,assigned_user_id,community_prayer_schedules(title)')
          .eq('assigned_user_id', uid)
          .eq('status', 'scheduled')
          .gte('starts_at', fromUtc.toIso8601String())
          .lte('starts_at', toUtc.toIso8601String())
          .order('starts_at', ascending: true)
          .limit(200);

      final out = <_UpcomingAssignedPrayerRun>[];
      for (final raw in (rows as List<dynamic>)) {
        final r = raw as Map<String, dynamic>;
        final runId = r['id']?.toString() ?? '';
        final communityId = r['community_id']?.toString() ?? '';
        if (runId.isEmpty || communityId.isEmpty) continue;
        final startsAtRaw = r['starts_at']?.toString() ?? '';
        final parsed = DateTime.tryParse(startsAtRaw);
        if (parsed == null) continue;
        final startsAtUtc = parsed.isUtc ? parsed : parsed.toUtc();
        String? title;
        final schedule = r['community_prayer_schedules'];
        if (schedule is Map<String, dynamic>) {
          title = schedule['title']?.toString();
        }
        final communityName = findCommunity(communityId)?.name;
        out.add(
          _UpcomingAssignedPrayerRun(
            runId: runId,
            startsAtUtc: startsAtUtc,
            title: title,
            communityName: communityName,
          ),
        );
      }
      return List.unmodifiable(out);
    } catch (_) {
      return const [];
    }
  }

