  void approveCommunityJoinRequest(String communityId, String userId) {
    if (supabase != null) {
      unawaited(_approveCommunityJoinRequestSupabase(communityId: communityId, userId: userId));
      return;
    }
    final i = _communities.indexWhere((c) => c.id == communityId);
    if (i < 0) return;
    final c = _communities[i];
    final requests = (_communityJoinRequestsById[communityId] ?? const <String>[]).toList();
    requests.removeWhere((x) => x == userId);
    _communityJoinRequestsById[communityId] = requests;
    final members = (_communityMembersById[communityId] ?? <String>{}).toSet();
    final added = members.add(userId);
    _communityMembersById[communityId] = members;
    _communities[i] = c.copyWith(
      viewerStatus: userId == _viewerUserId ? CommunityViewerStatus.approved : c.viewerStatus,
      memberCount: added ? c.memberCount + 1 : c.memberCount,
    );
    notifyListeners();
  }

  void refuseCommunityJoinRequest(String communityId, String userId) {
    if (supabase != null) {
      unawaited(_refuseCommunityJoinRequestSupabase(communityId: communityId, userId: userId));
      return;
    }
    final i = _communities.indexWhere((c) => c.id == communityId);
    if (i < 0) return;
    final c = _communities[i];
    final requests = (_communityJoinRequestsById[communityId] ?? const <String>[]).toList();
    requests.removeWhere((x) => x == userId);
    _communityJoinRequestsById[communityId] = requests;
    _communities[i] = c.copyWith(
      viewerStatus: userId == _viewerUserId ? CommunityViewerStatus.none : c.viewerStatus,
    );
    notifyListeners();
  }

  void requestCommunityJoin(String communityId, {required bool isAuthenticated}) {
    if (!isAuthenticated) return;
    if (supabase != null) {
      unawaited(_requestCommunityJoinSupabase(communityId: communityId));
      return;
    }
    final index = _communities.indexWhere((c) => c.id == communityId);
    if (index < 0) return;
    final c = _communities[index];
    if (!c.isClosed) {
      trackEvent('community_join', <String, Object?>{
        'communityId': communityId,
        'method': 'open',
      });
      final members = (_communityMembersById[communityId] ?? <String>{}).toSet();
      final added = members.add(_viewerUserId);
      _communityMembersById[communityId] = members;
      _communities[index] = c.copyWith(
        viewerStatus: CommunityViewerStatus.approved,
        memberCount: added ? c.memberCount + 1 : c.memberCount,
      );
    } else {
      trackEvent('community_request', <String, Object?>{
        'communityId': communityId,
        'method': 'request',
      });
      final requests = (_communityJoinRequestsById[communityId] ?? const <String>[]).toList();
      if (!requests.contains(_viewerUserId)) {
        requests.add(_viewerUserId);
        _communityJoinRequestsById[communityId] = requests;
      }
      _communities[index] = c.copyWith(viewerStatus: CommunityViewerStatus.pending);
    }
    notifyListeners();
  }

  void cancelCommunityJoinRequest(String communityId, {required bool isAuthenticated}) {
    if (!isAuthenticated) return;
    if (supabase != null) {
      unawaited(_cancelCommunityJoinRequestSupabase(communityId: communityId));
      return;
    }
    final index = _communities.indexWhere((c) => c.id == communityId);
    if (index < 0) return;
    final c = _communities[index];
    if (c.viewerStatus != CommunityViewerStatus.pending) return;
    final requests = (_communityJoinRequestsById[communityId] ?? const <String>[]).toList();
    requests.removeWhere((x) => x == _viewerUserId);
    _communityJoinRequestsById[communityId] = requests;
    _communities[index] = c.copyWith(viewerStatus: CommunityViewerStatus.none);
    notifyListeners();
  }

  void approveCommunityJoin(String communityId) {
    if (supabase != null) {
      unawaited(_acceptCommunityInviteSupabase(communityId: communityId));
      return;
    }
    final index = _communities.indexWhere((c) => c.id == communityId);
    if (index < 0) return;
    final c = _communities[index];
    if (c.viewerStatus == CommunityViewerStatus.approved) return;
    final requests = (_communityJoinRequestsById[communityId] ?? const <String>[]).toList();
    requests.removeWhere((x) => x == _viewerUserId);
    _communityJoinRequestsById[communityId] = requests;
    final members = (_communityMembersById[communityId] ?? <String>{}).toSet();
    final added = members.add(_viewerUserId);
    _communityMembersById[communityId] = members;
    _communities[index] = c.copyWith(
      viewerStatus: CommunityViewerStatus.approved,
      memberCount: added ? c.memberCount + 1 : c.memberCount,
    );
    notifyListeners();
  }

  Future<void> _requestCommunityJoinSupabase({required String communityId}) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null) return;
    final c = findCommunity(communityId);
    final joinMode = c?.joinMode ?? (c?.isClosed == true ? 'request' : 'public');
    if (joinMode == 'invite') return;
    try {
      await sb.from('community_members').insert(<String, Object?>{
        'community_id': communityId,
        'user_id': viewerId,
        'role': 'member',
        'status': joinMode == 'public' ? 'active' : 'pending',
      });
    } catch (_) {}
    unawaited(refreshCommunitiesForViewer(force: true));
    unawaited(refreshCommunityMembers(communityId, force: true));
    unawaited(refreshCommunityJoinRequests(communityId, force: true));
  }

  Future<void> _cancelCommunityJoinRequestSupabase({required String communityId}) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null) return;
    try {
      await sb.from('community_members').delete().match(<String, Object>{
        'community_id': communityId,
        'user_id': viewerId,
      });
    } catch (_) {}
    unawaited(refreshCommunitiesForViewer(force: true));
    unawaited(refreshCommunityMembers(communityId, force: true));
    unawaited(refreshCommunityJoinRequests(communityId, force: true));
  }

  Future<bool> leaveCommunity(String communityId, {required bool isAuthenticated}) async {
    if (!isAuthenticated) return false;
    final id = communityId.trim();
    if (id.isEmpty) return false;
    if (supabase != null) {
      return await _leaveCommunitySupabase(communityId: id);
    }
    final i = _communities.indexWhere((c) => c.id == id);
    if (i < 0) return false;
    final c = _communities[i];
    final members = (_communityMembersById[id] ?? const <String>{}).toSet();
    final removed = members.remove(_viewerUserId);
    _communityMembersById[id] = members;
    final requests = (_communityJoinRequestsById[id] ?? const <String>[]).toList();
    requests.removeWhere((x) => x == _viewerUserId);
    _communityJoinRequestsById[id] = requests;
    _communities[i] = c.copyWith(
      viewerStatus: CommunityViewerStatus.none,
      memberCount: removed ? (c.memberCount - 1).clamp(0, 1 << 30) : c.memberCount,
    );
    if (_activeCommunityFilterId == id) {
      setActiveCommunityFilterId(null);
    }
    notifyListeners();
    return true;
  }

  Future<bool> _leaveCommunitySupabase({required String communityId}) async {
    final sb = supabase;
    if (sb == null) return false;
    if (isOffline) return false;
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null) return false;
    try {
      await sb.from('community_members').delete().match(<String, Object>{
        'community_id': communityId,
        'user_id': viewerId,
      });
    } catch (_) {
      return false;
    }
    unawaited(refreshCommunitiesForViewer(force: true));
    unawaited(refreshCommunityMembers(communityId, force: true));
    unawaited(refreshCommunityJoinRequests(communityId, force: true));
    if (_activeCommunityFilterId == communityId) {
      setActiveCommunityFilterId(null);
    }
    return true;
  }

  Future<void> _acceptCommunityInviteSupabase({required String communityId}) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    final viewerId = sb.auth.currentUser?.id;
    if (viewerId == null) return;
    try {
      await sb
          .from('community_members')
          .update(<String, Object?>{'status': 'active'})
          .match(<String, Object>{'community_id': communityId, 'user_id': viewerId, 'status': 'invited'});
    } catch (_) {}
    unawaited(refreshCommunitiesForViewer(force: true));
    unawaited(refreshCommunityMembers(communityId, force: true));
  }

  Future<void> _approveCommunityJoinRequestSupabase({required String communityId, required String userId}) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    try {
      await sb
          .from('community_members')
          .update(<String, Object?>{'status': 'active'})
          .match(<String, Object>{'community_id': communityId, 'user_id': userId, 'status': 'pending'});
    } catch (_) {}
    unawaited(refreshCommunityJoinRequests(communityId, force: true));
    unawaited(refreshCommunityMembers(communityId, force: true));
    unawaited(refreshCommunitiesForViewer(force: true));
  }

  Future<void> _refuseCommunityJoinRequestSupabase({required String communityId, required String userId}) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    try {
      await sb.from('community_members').delete().match(<String, Object>{
        'community_id': communityId,
        'user_id': userId,
        'status': 'pending',
      });
    } catch (_) {}
    unawaited(refreshCommunityJoinRequests(communityId, force: true));
    unawaited(refreshCommunitiesForViewer(force: true));
  }

  Future<void> setCommunityMemberRole({
    required String communityId,
    required String targetUserId,
    required String role,
  }) async {
    if (supabase != null) {
      await _setCommunityMemberRoleSupabase(communityId: communityId, targetUserId: targetUserId, role: role);
      return;
    }
    final mods = (_communityModeratorsById[communityId] ?? const <String>{}).toSet();
    if (role == 'admin' || role == 'moderator' || role == 'founder') {
      mods.add(targetUserId);
    } else {
      mods.remove(targetUserId);
    }
    _communityModeratorsById[communityId] = mods;
    notifyListeners();
  }

  Future<void> transferCommunityOwnership({
    required String communityId,
    required String newOwnerId,
  }) async {
    if (supabase != null) {
      await _transferCommunityOwnershipSupabase(communityId: communityId, newOwnerId: newOwnerId);
      return;
    }
    final i = _communities.indexWhere((c) => c.id == communityId);
    if (i < 0) return;
    final c = _communities[i];
    _communities[i] = c.copyWith(ownerId: newOwnerId);
    final mods = (_communityModeratorsById[communityId] ?? const <String>{}).toSet();
    mods.add(c.ownerId);
    mods.add(newOwnerId);
    _communityModeratorsById[communityId] = mods;
    notifyListeners();
  }

  Future<void> _setCommunityMemberRoleSupabase({
    required String communityId,
    required String targetUserId,
    required String role,
  }) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    try {
      await sb.rpc('set_community_member_role', params: <String, Object?>{
        'p_community_id': communityId,
        'p_target_user_id': targetUserId,
        'p_role': role,
      });
    } catch (_) {}
    unawaited(refreshCommunityMembers(communityId, force: true));
    unawaited(refreshCommunitiesForViewer(force: true));
  }

  Future<void> _transferCommunityOwnershipSupabase({
    required String communityId,
    required String newOwnerId,
  }) async {
    final sb = supabase;
    if (sb == null) return;
    if (isOffline) return;
    try {
      await sb.rpc('transfer_community_ownership', params: <String, Object?>{
        'p_community_id': communityId,
        'p_new_owner_id': newOwnerId,
      });
    } catch (_) {}
    unawaited(refreshCommunityMembers(communityId, force: true));
    unawaited(refreshCommunitiesForViewer(force: true));
  }

  @override
  void dispose() {
    _directPersistDebounce?.cancel();
    _directPersistDebounce = null;
    _storyExpiryTimer?.cancel();
    _storyExpiryTimer = null;
    super.dispose();
  }
}

const _directMessageEnvelopePrefix = '__atalaia_msg__:';


class RepoScope extends InheritedNotifier<DemoRepository> {
  const RepoScope({required DemoRepository repo, required super.child, super.key})
      : super(notifier: repo);

  static DemoRepository of(BuildContext context) {
    final scope = context.dependOnInheritedWidgetOfExactType<RepoScope>();
    if (scope == null) throw StateError('RepoScope not found');
    return scope.notifier!;
  }
}

class LocaleOverrideScope extends InheritedNotifier<ValueNotifier<Locale?>> {
  const LocaleOverrideScope({required ValueNotifier<Locale?> notifier, required super.child, super.key})
      : super(notifier: notifier);

  static ValueNotifier<Locale?> of(BuildContext context) {
    final scope = context.dependOnInheritedWidgetOfExactType<LocaleOverrideScope>();
    if (scope == null) throw StateError('LocaleOverrideScope not found');
    return scope.notifier!;
  }
}

class AtalaiaApp extends StatefulWidget {
  const AtalaiaApp({super.key});

  @override
  State<AtalaiaApp> createState() => _AtalaiaAppState();
}

class _AtalaiaAppState extends State<AtalaiaApp> {
  late final ValueNotifier<SessionState> _session;
  late final ValueNotifier<AuthRedirectModel?> _authRedirect;
  late final ValueNotifier<Locale?> _localeOverride;
  late final ValueNotifier<UserLocalePrefs> _localePrefs;
  late final ValueNotifier<ThemeMode> _themeMode;
  late DemoRepository _repo;
  StreamSubscription<AuthState>? _authSub;
  String? _loadedLocalePrefsForUserId;
  int _authBootToken = 0;
  Timer? _authBootSyncTimer1;
  Timer? _authBootSyncTimer2;
  Timer? _reminderSyncDebounce;

  void _attachSupabaseAuthListener() {
    _authSub?.cancel();
    _authSub = null;
    final supabase = _repo.supabase;
    if (supabase == null) return;

    _authBootToken++;
    final bootToken = _authBootToken;
    _authBootSyncTimer1?.cancel();
    _authBootSyncTimer1 = null;
    _authBootSyncTimer2?.cancel();
    _authBootSyncTimer2 = null;
    unawaited(_syncSessionFromSupabase());
    _authBootSyncTimer1 = Timer(const Duration(milliseconds: 700), () {
      if (!mounted || bootToken != _authBootToken) return;
      unawaited(_syncSessionFromSupabase());
    });
    _authBootSyncTimer2 = Timer(const Duration(milliseconds: 2700), () {
      if (!mounted || bootToken != _authBootToken) return;
      unawaited(_syncSessionFromSupabase());
    });
    _authSub = supabase.auth.onAuthStateChange.listen((data) {
      unawaited(_syncSessionFromSupabase());
    });
  }

  void _handleSupabaseConfigChanged() {
    unawaited(_reloadRepoFromSupabase());
  }

  Future<void> _reloadRepoFromSupabase() async {
    final cfg = await _loadSupabaseConfig();
    if (!mounted) return;
    if (cfg == null) return;
    await _initSupabase(cfg);
    if (!mounted) return;

    final next = DemoRepository(supabase: _trySupabaseClient());
    next.setViewer(_session.value);
    final prev = _repo;
    setState(() => _repo = next);
    prev.dispose();
    _attachSupabaseAuthListener();
  }

  Future<void> _syncSessionFromSupabase() async {
    try {
      final s = await _repo.sessionFromSupabaseAuth();
      if (!mounted) return;
      _session.value = s ?? const AnonSession();
    } catch (_) {
      if (!mounted) return;
    }
  }

  @override
  void initState() {
    super.initState();
    _session = ValueNotifier<SessionState>(const AnonSession());
    _authRedirect = ValueNotifier<AuthRedirectModel?>(null);
    _localeOverride = ValueNotifier<Locale?>(null);
    _localePrefs = ValueNotifier<UserLocalePrefs>(const UserLocalePrefs(receiveGlobalContent: true));
    _themeMode = ValueNotifier<ThemeMode>(ThemeMode.light);
    _repo = DemoRepository(supabase: _trySupabaseClient());
    _supabaseConfigVersion.addListener(_handleSupabaseConfigChanged);
    _session.addListener(_handleSessionChanged);
    _localePrefs.addListener(_handleLocalePrefsChanged);
    _repo.setViewer(_session.value);
    unawaited(_loadLocaleOverrideFromPrefs());
    unawaited(_loadThemeModeFromPrefs());
    _attachSupabaseAuthListener();
  }

  Future<void> _loadThemeModeFromPrefs() async {
    try {
      final sp = await SharedPreferences.getInstance();
      final raw = (sp.getString('theme_mode') ?? '').trim().toLowerCase();
      if (!mounted) return;
      _themeMode.value = raw == 'dark' ? ThemeMode.dark : ThemeMode.light;
    } catch (_) {}
  }

  Future<void> _setThemeMode(ThemeMode mode) async {
    _themeMode.value = mode;
    try {
      final sp = await SharedPreferences.getInstance();
      await sp.setString('theme_mode', mode == ThemeMode.dark ? 'dark' : 'light');
    } catch (_) {}
  }

  Future<void> _syncPrayerRunReminders() async {
    if (!_supportsLocalNotifications()) return;
    final session = _session.value;
    if (session is! AuthSession) {
      await _cancelAllScheduledPrayerRunReminders();
      return;
    }
    if (_repo.supabase == null || _repo.isOffline) return;
    final allowed = await _LocalNotifications.instance.ensurePermission();
    if (!allowed) return;

    final tzName = _localePrefs.value.timezoneName?.trim();
    tz.Location? loc;
    if (tzName != null && tzName.isNotEmpty) {
      try {
        loc = tz.getLocation(tzName);
        tz.setLocalLocation(loc);
      } catch (_) {
        loc = null;
      }
    }
    loc ??= tz.local;

    final l10n = t(context);
    final nowUtc = DateTime.now().toUtc();
    final runs = await _repo.fetchUpcomingAssignedPrayerRuns(
      userId: session.userId,
      fromUtc: nowUtc.subtract(const Duration(minutes: 5)),
      toUtc: nowUtc.add(const Duration(days: 60)),
    );

    final details = _LocalNotifications.instance.reminderDetails(l10n);
    final nowLocal = tz.TZDateTime.now(loc);
    final nextIds = <int>{};

    for (final r in runs) {
      final runId = r.runId;
      final startsAtUtc = r.startsAtUtc;
      final startLocal = tz.TZDateTime.from(startsAtUtc, loc);
      final title = (r.title ?? '').trim().isEmpty ? l10n.prayerRunDefaultTitle : r.title!.trim();
      final communityName = r.communityName;

      final items = <({Duration before, String label})>[
        (before: const Duration(hours: 24), label: '24h'),
        (before: const Duration(hours: 1), label: '1h'),
        (before: const Duration(minutes: 5), label: '5min'),
      ];

      for (final it in items) {
        final scheduleAt = startLocal.subtract(it.before);
        if (!scheduleAt.isAfter(nowLocal.add(const Duration(seconds: 2)))) continue;
        final id = _fnv1a32('prayer_run:$runId:${it.label}');
        nextIds.add(id);
        final body = communityName == null || communityName.trim().isEmpty ? title : '$title • ${communityName.trim()}';
        await _LocalNotifications.instance.plugin.zonedSchedule(
          id,
          l10n.notificationPrayerRunReminderTitle(it.label),
          body,
          scheduleAt,
          details,
          androidScheduleMode: AndroidScheduleMode.exactAllowWhileIdle,
          payload: 'community_prayer_run:$runId',
        );
      }
    }

    final sp = await SharedPreferences.getInstance();
    final prevRaw = (sp.getString('scheduled_prayer_run_notification_ids') ?? '').trim();
    final prevIds = <int>{};
    if (prevRaw.isNotEmpty) {
      try {
        final decoded = jsonDecode(prevRaw);
        if (decoded is List) {
          for (final v in decoded) {
            final i = int.tryParse(v.toString());
            if (i != null) prevIds.add(i);
          }
        }
      } catch (_) {}
    }
    for (final id in prevIds.difference(nextIds)) {
      await _LocalNotifications.instance.plugin.cancel(id);
    }
    await sp.setString('scheduled_prayer_run_notification_ids', jsonEncode(nextIds.toList(growable: false)));
  }

  Future<void> _cancelAllScheduledPrayerRunReminders() async {
    if (!_supportsLocalNotifications()) return;
    final sp = await SharedPreferences.getInstance();
    final raw = (sp.getString('scheduled_prayer_run_notification_ids') ?? '').trim();
    if (raw.isEmpty) return;
    try {
      final decoded = jsonDecode(raw);
      if (decoded is List) {
        for (final v in decoded) {
          final id = int.tryParse(v.toString());
          if (id != null) {
            await _LocalNotifications.instance.plugin.cancel(id);
          }
        }
      }
    } catch (_) {}
    await sp.remove('scheduled_prayer_run_notification_ids');
  }

  Future<void> _loadLocaleOverrideFromPrefs() async {
    try {
      final prefs = await SharedPreferences.getInstance();
      final raw = prefs.getString('locale_override')?.trim();
      final tzName = prefs.getString('user_timezone_name')?.trim();
      final cc = prefs.getString('user_country_code')?.trim();
      final receiveGlobal = prefs.getBool('receive_global_content');
      if (!mounted) return;
      _localePrefs.value = _localePrefs.value.copyWith(
        timezoneName: tzName?.isEmpty ?? true ? null : tzName,
        countryCode: cc?.isEmpty ?? true ? null : cc,
        receiveGlobalContent: receiveGlobal ?? _localePrefs.value.receiveGlobalContent,
      );
      if (raw == null || raw.isEmpty || raw == 'device') {
        _localeOverride.value = null;
        return;
      }
      _localeOverride.value = _parseLocaleCode(raw);
    } catch (_) {}
  }

  Future<void> _syncLocalePrefsFromServer() async {
    final s = _session.value;
    if (s is! AuthSession) {
      _loadedLocalePrefsForUserId = null;
      return;
    }
    if (_loadedLocalePrefsForUserId == s.userId) return;
    _loadedLocalePrefsForUserId = s.userId;

    final prefs = await _repo.fetchUserLocalePreferences(userId: s.userId);
    if (!mounted) return;
    if (prefs == null) return;

    final rawLocale = (prefs['locale_code'] as String?)?.trim();
    if (rawLocale != null && rawLocale.isNotEmpty && rawLocale.toLowerCase() != 'device') {
      final parsed = _parseLocaleCode(rawLocale);
      _localeOverride.value = parsed;
      try {
        final sp = await SharedPreferences.getInstance();
        await sp.setString('locale_override', _localeCode(parsed));
      } catch (_) {}
    }
    try {
      final sp = await SharedPreferences.getInstance();
      final cc = (prefs['country_code'] as String?)?.trim();
      final tz = (prefs['timezone_name'] as String?)?.trim();
      final receiveGlobal = prefs['receive_global_content'] as bool?;
      if (cc != null) await sp.setString('user_country_code', cc);
      if (tz != null) await sp.setString('user_timezone_name', tz);
      if (receiveGlobal != null) await sp.setBool('receive_global_content', receiveGlobal);
      if (!mounted) return;
      _localePrefs.value = _localePrefs.value.copyWith(
        timezoneName: tz?.isEmpty ?? true ? null : tz,
        countryCode: cc?.isEmpty ?? true ? null : cc,
        receiveGlobalContent: receiveGlobal ?? _localePrefs.value.receiveGlobalContent,
      );
    } catch (_) {}
  }

  void _handleSessionChanged() {
    _repo.setViewer(_session.value);
    unawaited(_syncLocalePrefsFromServer());
    _reminderSyncDebounce?.cancel();
    _reminderSyncDebounce = Timer(const Duration(seconds: 1), () {
      unawaited(_syncPrayerRunReminders());
    });
  }

  void _handleLocalePrefsChanged() {
    unawaited(_repo.refreshGlobalExpansionConfig(countryCode: _localePrefs.value.countryCode));
  }

  ThemeData _buildAppTheme(Brightness brightness) {
    final cs = ColorScheme.fromSeed(seedColor: const Color(0xFF2E7D32), brightness: brightness);
    final base = ThemeData(colorScheme: cs, useMaterial3: true);
    final tt = base.textTheme.copyWith(
      titleLarge: (base.textTheme.titleLarge ?? const TextStyle()).copyWith(
        fontSize: 24,
        fontWeight: FontWeight.w600,
      ),
      titleMedium: (base.textTheme.titleMedium ?? const TextStyle()).copyWith(
        fontSize: 20,
        fontWeight: FontWeight.w600,
      ),
      bodyLarge: (base.textTheme.bodyLarge ?? const TextStyle()).copyWith(
        fontSize: 16,
        fontWeight: FontWeight.w400,
      ),
      bodyMedium: (base.textTheme.bodyMedium ?? const TextStyle()).copyWith(
        fontSize: 14,
        fontWeight: FontWeight.w400,
      ),
      bodySmall: (base.textTheme.bodySmall ?? const TextStyle()).copyWith(
        fontSize: 12,
        fontWeight: FontWeight.w400,
      ),
    );

    return base.copyWith(
      textTheme: tt,
      extensions: const [AtalaiaBrandColors()],
      snackBarTheme: SnackBarThemeData(
        behavior: SnackBarBehavior.floating,
        shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(AtalaiaRadius.lg)),
      ),
      floatingActionButtonTheme: const FloatingActionButtonThemeData(shape: CircleBorder()),
      inputDecorationTheme: InputDecorationTheme(
        isDense: true,
        border: OutlineInputBorder(borderRadius: BorderRadius.circular(AtalaiaRadius.md)),
      ),
    );
  }

  @override
  void dispose() {
    _supabaseConfigVersion.removeListener(_handleSupabaseConfigChanged);
    _session.removeListener(_handleSessionChanged);
    _localePrefs.removeListener(_handleLocalePrefsChanged);
    _session.dispose();
    _authRedirect.dispose();
    _localeOverride.dispose();
    _localePrefs.dispose();
    _themeMode.dispose();
    _authSub?.cancel();
    _authBootSyncTimer1?.cancel();
    _authBootSyncTimer2?.cancel();
    _reminderSyncDebounce?.cancel();
    _repo.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return SessionScope(
      notifier: _session,
      child: RepoScope(
        repo: _repo,
        child: LocaleOverrideScope(
          notifier: _localeOverride,
          child: UserLocalePrefsScope(
            notifier: _localePrefs,
            child: ThemeModeScope(
              notifier: _themeMode,
              child: AuthRedirectScope(
                notifier: _authRedirect,
                child: AnimatedBuilder(
                  animation: Listenable.merge([_localeOverride, _localePrefs, _themeMode]),
                  builder: (context, _) {
                    return MaterialApp(
                      debugShowCheckedModeBanner: false,
                      scaffoldMessengerKey: atalaiaScaffoldMessengerKey,
                      onGenerateTitle: (context) => t(context).appTitle,
                      locale: _localeOverride.value,
                      supportedLocales: AppLocalizations.supportedLocales,
                      localizationsDelegates: AppLocalizations.localizationsDelegates,
                    localeResolutionCallback: (deviceLocale, supportedLocales) {
                      final override = _localeOverride.value;
                      if (override != null) return override;
                      if (deviceLocale == null) return const Locale('pt', 'BR');
                      for (final s in supportedLocales) {
                        if (s.languageCode == deviceLocale.languageCode && s.countryCode == deviceLocale.countryCode) {
                          return s;
                        }
                      }
                      for (final s in supportedLocales) {
                        if (s.languageCode == deviceLocale.languageCode) return s;
                      }
                      return const Locale('pt', 'BR');
                    },
                    theme: _buildAppTheme(Brightness.light),
                    darkTheme: _buildAppTheme(Brightness.dark),
                    themeMode: _themeMode.value,
                    onGenerateRoute: (settings) {
              if (settings.name == null) return null;
              final name = settings.name!;
              switch (name) {
                case Routes.root:
                  return MaterialPageRoute(builder: (_) => const StartupScreen());
                case Routes.direct:
                  final args = settings.arguments as DirectInboxArgs?;
                  return MaterialPageRoute(builder: (_) => DirectInboxScreen(args: args));
                case Routes.chat:
                  final args = settings.arguments as ChatArgs;
                  return MaterialPageRoute(builder: (_) => ChatScreen(args: args));
                case Routes.newMessage:
                  return MaterialPageRoute(builder: (_) => const NewMessageScreen());
                case Routes.authGate:
                  return MaterialPageRoute(builder: (_) => const AuthGateScreen());
                case Routes.postDetail:
                  final args = settings.arguments as PostDetailArgs;
                  return MaterialPageRoute(
                    builder: (_) {
                      return _AnalyticsOnce(
                        eventName: 'post_open',
                        fieldsBuilder: (context) {
                          final repo = RepoScope.of(context);
                          final post = repo.findPost(args.postId);
                          if (post == null) return <String, Object?>{'postId': args.postId};
                          return <String, Object?>{
                            'postId': post.id,
                            'kind': post.kind.analyticsValue,
                            'visibility': post.visibility.analyticsValue,
                          };
                        },
                        child: PostDetailScreen(args: args),
                      );
                    },
                  );
                case Routes.campaignDetail:
                  final args = settings.arguments as CampaignDetailArgs;
                  return MaterialPageRoute(
                    builder: (_) {
                      return _AnalyticsOnce(
                        eventName: 'campaign_open',
                        fieldsBuilder: (_) => <String, Object?>{'campaignId': args.campaignId},
                        child: CampaignDetailScreen(args: args),
                      );
                    },
                  );
                case Routes.alertDetail:
                  final args = settings.arguments as AlertDetailArgs;
                  return MaterialPageRoute(builder: (_) => AlertDetailScreen(args: args));
                case Routes.newsEventDetail:
                  final args = settings.arguments as NewsEventDetailArgs;
                  return MaterialPageRoute(builder: (_) => NewsEventDetailScreen(args: args));
                case Routes.postComments:
                  final args = settings.arguments as CommentsArgs;
                  return MaterialPageRoute(builder: (_) => CommentsScreen(args: args));
                case Routes.userProfile:
                  final args = settings.arguments as UserProfileArgs;
                  return MaterialPageRoute(
                    builder: (_) {
                      return _AnalyticsOnce(
                        eventName: 'profile_view',
                        fieldsBuilder: (_) => <String, Object?>{'userId': args.userId},
                        child: UserProfileScreen(args: args),
                      );
                    },
                  );
                case Routes.followersFollowing:
                  final args = settings.arguments as FollowersFollowingArgs;
                  return MaterialPageRoute(builder: (_) => FollowersFollowingScreen(args: args));
                case Routes.editProfile:
                  final args = settings.arguments as EditProfileArgs;
                  return MaterialPageRoute(builder: (_) => EditProfileScreen(args: args));
                case Routes.login:
                  return MaterialPageRoute(builder: (_) => const LoginScreen());
                case Routes.signup:
                  return MaterialPageRoute(builder: (_) => const SignupScreen());
                case Routes.resetPassword:
                  return MaterialPageRoute(builder: (_) => const ResetPasswordScreen());
                case Routes.settings:
                  return MaterialPageRoute(builder: (_) => const SettingsScreen());
                case Routes.settingsAccount:
                  return MaterialPageRoute(builder: (_) => const AccountSettingsScreen());
                case Routes.settingsPrivacy:
                  return MaterialPageRoute(builder: (_) => const PrivacySettingsScreen());
                case Routes.legal:
                  final args = settings.arguments as LegalScreenArgs?;
                  return MaterialPageRoute(builder: (_) => LegalScreen(args: args));
                case Routes.settingsLocale:
                  return MaterialPageRoute(builder: (_) => const LocaleSettingsScreen());
                case Routes.settingsNotifications:
                  return MaterialPageRoute(builder: (_) => const NotificationSettingsScreen());
                case Routes.settingsTheme:
                  return MaterialPageRoute(builder: (_) => const ThemeSettingsScreen());
                case Routes.settingsHelp:
                  return MaterialPageRoute(builder: (_) => const HelpCenterScreen());
                case Routes.verificationPaywall:
                  return MaterialPageRoute(
                    builder: (_) {
                      return _AnalyticsOnce(
                        eventName: 'verify_paywall_view',
                        fieldsBuilder: (_) => const <String, Object?>{},
                        child: const VerificationPaywallScreen(),
                      );
                    },
                  );
                case Routes.verificationStatus:
                  return MaterialPageRoute(builder: (_) => const VerificationStatusScreen());
                case Routes.moderation:
                  return MaterialPageRoute(builder: (_) => const ModerationScreen());
                case Routes.adminAds:
                  return MaterialPageRoute(builder: (_) => const AdminAdsScreen());
                case Routes.search:
                  return MaterialPageRoute(builder: (_) => const SearchScreen());
                case Routes.notifications:
                  return MaterialPageRoute(builder: (_) => const NotificationsScreen(showBack: true));
                case Routes.createPost:
                  return MaterialPageRoute(builder: (_) => const CreatePostFlowScreen());
                case Routes.createCampaign:
                  return MaterialPageRoute(builder: (_) => const CreateCampaignScreen());
                case Routes.campaignList:
                  final args = settings.arguments as CampaignListArgs;
                  return MaterialPageRoute(builder: (_) => CampaignListScreen(args: args));
                case Routes.prayerChallengeList:
                  final args = (settings.arguments as PrayerChallengeListArgs?) ?? const PrayerChallengeListArgs();
                  return MaterialPageRoute(builder: (_) => PrayerChallengeListScreen(args: args));
                case Routes.prayerChallengeDetail:
                  final args = settings.arguments as PrayerChallengeDetailArgs;
                  return MaterialPageRoute(builder: (_) => PrayerChallengeDetailScreen(args: args));
                case Routes.communityDetail:
                  final args = settings.arguments as CommunityArgs;
                  return MaterialPageRoute(
                    builder: (_) {
                      return _AnalyticsOnce(
                        eventName: 'community_view',
                        fieldsBuilder: (context) {
                          final repo = RepoScope.of(context);
                          final session = SessionScope.of(context).value;
                          final community = repo.findCommunity(args.communityId);
                          final viewerId = session is AuthSession ? session.userId : null;
                          var role = 'guest';
                          if (community != null && viewerId != null) {
                            if (community.ownerId == viewerId) {
                              role = 'admin';
                            } else if (community.viewerStatus == CommunityViewerStatus.approved) {
                              role = 'member';
                            }
                          }
                          return <String, Object?>{
                            'communityId': args.communityId,
                            'role': role,
                          };
                        },
                        child: CommunityDetailScreen(args: args),
                      );
                    },
                  );
                case Routes.editCommunity:
                  final args = settings.arguments as EditCommunityArgs;
                  return MaterialPageRoute(builder: (_) => EditCommunityScreen(args: args));
                case Routes.communityMap:
                  final args = settings.arguments as CommunityArgs;
                  return MaterialPageRoute(builder: (_) => CommunityMapScreen(args: args));
                case Routes.communityFeed:
                  final args = settings.arguments as CommunityFeedArgs;
                  return MaterialPageRoute(builder: (_) => CommunityFeedScreen(args: args));
                case Routes.communityMembers:
                  final args = settings.arguments as CommunityMembersArgs;
                  return MaterialPageRoute(builder: (_) => CommunityMembersScreen(args: args));
                case Routes.communityEvents:
                  final args = settings.arguments as CommunityArgs;
                  return MaterialPageRoute(builder: (_) => CommunityEventsScreen(args: args));
                case Routes.communityPrayerScales:
                  final args = settings.arguments as CommunityArgs;
                  return MaterialPageRoute(builder: (_) => CommunityPrayerScalesScreen(args: args));
                case Routes.regionPosts:
                  final args = settings.arguments as RegionPostsArgs;
                  return MaterialPageRoute(builder: (_) => RegionPostsScreen(args: args));
                case Routes.regionAlerts:
                  final args = settings.arguments as RegionAlertsArgs;
                  return MaterialPageRoute(builder: (_) => RegionAlertsScreen(args: args));
                case Routes.regionNews:
                  final args = settings.arguments as RegionNewsArgs;
                  return MaterialPageRoute(builder: (_) => RegionNewsScreen(args: args));
                case Routes.regionDetail:
                  final args = settings.arguments as RegionDetailArgs;
                  return MaterialPageRoute(builder: (_) => RegionDetailScreen(args: args));
                case Routes.regionPrayerHistory:
                  final args = settings.arguments as RegionPrayerHistoryArgs;
                  return MaterialPageRoute(builder: (_) => RegionPrayerHistoryScreen(args: args));
                case Routes.regionPrayer:
                  final args = settings.arguments as RegionPrayerArgs;
                  return MaterialPageRoute(builder: (_) => PrayerSessionScreen(args: args));
                case Routes.playlistLibrary:
                  return MaterialPageRoute(builder: (_) => const PlaylistLibraryScreen());
              }
              return null;
                    },
                  );
                },
              ),
            ),
          ),
        ),
      ),
    ),
  );
  }
}

Locale? _parseLocaleCode(String raw) {
  final normalized = raw.replaceAll('_', '-').trim();
  if (normalized.isEmpty) return null;
  final parts = normalized.split('-').where((p) => p.trim().isNotEmpty).toList();
  if (parts.isEmpty) return null;
  if (parts.length == 1) return Locale(parts[0]);
  return Locale(parts[0], parts[1]);
}

String _localeCode(Locale? l) {
  if (l == null) return 'device';
  final cc = l.countryCode;
  if (cc == null || cc.trim().isEmpty) return l.languageCode;
  return '${l.languageCode}-$cc';
}

