Future<void> showLogoutConfirmDialog(BuildContext context) async {
  final session = SessionScope.of(context);
  if (session.value is! AuthSession) return;

  final repo = RepoScope.of(context);
  final result = await showAtalaiaConfirmDialog(
    context,
    title: t(context).logoutConfirmTitle,
    confirmLabel: t(context).settingsLogout,
    isDestructive: true,
  );

  if (result != true) return;
  await repo.signOut();
  session.value = const AnonSession();
  if (!context.mounted) return;
  Navigator.of(context).popUntil((r) => r.isFirst);
}

Future<void> showAuthGate(BuildContext context) async {
  final session = SessionScope.of(context);
  if (session.value is AuthSession) return;

  final redirect = AuthRedirectScope.of(context);
  redirect.value = AuthRedirectModel.fromContext(context);
  if (!context.mounted) return;
  Navigator.of(context).pushNamed(Routes.authGate);
}

class AuthGateScreen extends StatefulWidget {
  const AuthGateScreen({super.key});

  @override
  State<AuthGateScreen> createState() => _AuthGateScreenState();
}

class _AuthGateScreenState extends State<AuthGateScreen> {
  var _navigating = false;

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      final session = SessionScope.of(context).value;
      if (session is AuthSession) {
        Navigator.of(context).pushNamedAndRemoveUntil(Routes.root, (_) => false);
      }
    });
  }

  Future<void> _openAuthFlow(String routeName) async {
    if (_navigating) return;
    setState(() => _navigating = true);
    await Navigator.of(context).pushNamed(routeName);
    if (!mounted) return;
    setState(() => _navigating = false);
    final session = SessionScope.of(context).value;
    if (session is AuthSession) {
      Navigator.of(context).pushNamedAndRemoveUntil(Routes.root, (_) => false);
    }
  }

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final l10n = t(context);
    return Scaffold(
      body: SafeArea(
        child: Padding(
          padding: const EdgeInsets.all(16),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.stretch,
            children: [
              const Spacer(),
              Center(
                child: Container(
                  width: 72,
                  height: 72,
                  decoration: BoxDecoration(
                    color: cs.secondaryContainer,
                    borderRadius: BorderRadius.circular(22),
                  ),
                  child: Icon(Icons.volunteer_activism, color: cs.onSecondaryContainer, size: 34),
                ),
              ),
              const SizedBox(height: 14),
              Text(
                l10n.authGateTitle,
                textAlign: TextAlign.center,
                style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 20),
              ),
              const SizedBox(height: 8),
              Text(
                l10n.authGateSubtitle,
                textAlign: TextAlign.center,
                style: TextStyle(color: cs.outline),
              ),
              const SizedBox(height: 18),
              PrimaryButton(
                label: l10n.commonSignIn,
                loading: _navigating,
                onPressed: _navigating ? null : () => unawaited(_openAuthFlow(Routes.login)),
              ),
              const SizedBox(height: 10),
              SecondaryButton(
                label: l10n.authCreateAccount,
                onPressed: _navigating ? null : () => unawaited(_openAuthFlow(Routes.signup)),
              ),
              const Spacer(),
            ],
          ),
        ),
      ),
    );
  }
}

class StartupScreen extends StatefulWidget {
  const StartupScreen({super.key});

  @override
  State<StartupScreen> createState() => _StartupScreenState();
}

class _StartupScreenState extends State<StartupScreen> {
  var _seenOnboarding = false;
  var _loading = true;
  var _acceptedLegal = false;
  var _authBootWait = true;
  Timer? _authBootWaitTimer;

  @override
  void initState() {
    super.initState();
    SharedPreferences.getInstance().then((prefs) {
      if (!mounted) return;
      setState(() {
        _seenOnboarding = prefs.getBool('seen_onboarding') ?? false;
        _acceptedLegal = prefs.getBool(_legalAcceptedKeyV1) ?? false;
        _loading = false;
      });
    });
    _authBootWaitTimer?.cancel();
    _authBootWaitTimer = Timer(const Duration(milliseconds: 1400), () {
      if (!mounted) return;
      setState(() => _authBootWait = false);
    });
  }

  @override
  void dispose() {
    _authBootWaitTimer?.cancel();
    super.dispose();
  }

  Future<void> _finish() async {
    final prefs = await SharedPreferences.getInstance();
    await prefs.setBool('seen_onboarding', true);
    if (!mounted) return;
    setState(() => _seenOnboarding = true);
  }

  Future<void> _finishAndOpenAuthGate() async {
    await _finish();
    if (!mounted) return;
    Navigator.of(context).pushReplacementNamed(Routes.authGate);
  }

  @override
  Widget build(BuildContext context) {
    if (_loading) {
      return const Scaffold(
        body: Center(child: CircularProgressIndicator()),
      );
    }
    if (!_seenOnboarding) {
      return OnboardingScreen(
        onFinish: () => unawaited(_finishAndOpenAuthGate()),
      );
    }
    if (!_acceptedLegal) {
      return LegalAcceptanceScreen(
        onOpenTermsPrivacy: (tab) async {
          await Navigator.of(context).pushNamed(Routes.legal, arguments: LegalScreenArgs(initialTab: tab));
        },
        onAccept: () async {
          final sp = await SharedPreferences.getInstance();
          await sp.setBool(_legalAcceptedKeyV1, true);
          if (!mounted) return;
          setState(() => _acceptedLegal = true);
        },
      );
    }
    final session = SessionScope.of(context).value;
    if (session is! AuthSession) {
      final repo = RepoScope.of(context);
      final hasBackend = repo.supabase != null;
      if (hasBackend && _authBootWait) {
        return const Scaffold(
          body: Center(child: CircularProgressIndicator()),
        );
      }
      return const AuthGateScreen();
    }
    return const ShellScreen();
  }
}

class OnboardingScreen extends StatefulWidget {
  const OnboardingScreen({required this.onFinish, super.key});

  final VoidCallback onFinish;

  @override
  State<OnboardingScreen> createState() => _OnboardingScreenState();
}

class _OnboardingScreenState extends State<OnboardingScreen> {
  final _controller = PageController();
  var _index = 0;

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final l10n = t(context);

    return Scaffold(
      appBar: AppBar(
        actions: [
          AtalaiaTextButton(label: l10n.onboardingSkip, onPressed: widget.onFinish),
        ],
      ),
      body: SafeArea(
        child: Column(
          children: [
            Expanded(
              child: PageView(
                controller: _controller,
                onPageChanged: (i) => setState(() => _index = i),
                children: [
                  _OnboardingSlide(
                    title: l10n.onboardingPrayerRegionsTitle,
                    icon: Icons.volunteer_activism_outlined,
                  ),
                  _OnboardingSlide(
                    title: l10n.onboardingRequestOrTestifyTitle,
                    icon: Icons.forum_outlined,
                  ),
                  _OnboardingSlide(
                    title: l10n.onboardingMapWorldTitle,
                    icon: Icons.public_outlined,
                  ),
                ],
              ),
            ),
            Padding(
              padding: const EdgeInsets.fromLTRB(16, 6, 16, 16),
              child: Column(
                children: [
                  Row(
                    mainAxisAlignment: MainAxisAlignment.center,
                    children: List.generate(
                      3,
                      (i) => AnimatedContainer(
                        duration: const Duration(milliseconds: 180),
                        margin: const EdgeInsets.symmetric(horizontal: 4),
                        width: _index == i ? 20 : 8,
                        height: 8,
                        decoration: BoxDecoration(
                          color: _index == i ? cs.primary : cs.outlineVariant,
                          borderRadius: BorderRadius.circular(999),
                        ),
                      ),
                    ),
                  ),
                  const SizedBox(height: 14),
                  SizedBox(
                    width: double.infinity,
                    child: PrimaryButton(
                      label: _index < 2 ? l10n.onboardingNext : l10n.onboardingStart,
                      onPressed: () {
                        if (_index < 2) {
                          _controller.nextPage(
                            duration: const Duration(milliseconds: 220),
                            curve: Curves.easeOut,
                          );
                          return;
                        }
                        widget.onFinish();
                      },
                    ),
                  ),
                ],
              ),
            ),
          ],
        ),
      ),
    );
  }
