class LoginScreen extends StatefulWidget {
  const LoginScreen({super.key});

  @override
  State<LoginScreen> createState() => _LoginScreenState();
}

class _LoginScreenState extends State<LoginScreen> {
  final _email = TextEditingController();
  final _password = TextEditingController();

  var _loading = false;
  String? _error;

  @override
  void dispose() {
    _email.dispose();
    _password.dispose();
    super.dispose();
  }

  bool _isValid() {
    final email = _email.text.trim();
    final pass = _password.text;
    return email.contains('@') && pass.isNotEmpty;
  }

  Future<void> _submit() async {
    if (_loading) return;
    setState(() {
      _loading = true;
      _error = null;
    });

    final repo = RepoScope.of(context);
    if (repo.isOffline) {
      setState(() {
        _loading = false;
        _error = DemoRepository._authErrNoConnection;
      });
      return;
    }
    if (repo.supabase == null) {
      setState(() {
        _loading = false;
        _error = DemoRepository._authErrSupabaseNotConfigured;
      });
      showAtalaiaSnackBar(context, t(context).authSupabaseNotConfigured, kind: AtalaiaSnackKind.error);
      return;
    }

    await Future<void>.delayed(const Duration(milliseconds: 520));

    final s = await repo.signInWithEmail(
      email: _email.text.trim(),
      password: _password.text,
    );
    if (s == null) {
      setState(() {
        _loading = false;
        _error = repo.lastAuthError ?? DemoRepository._authErrInvalidCredentials;
      });
      return;
    }

    final session = SessionScope.of(context);
    session.value = s;
    if (!mounted) return;
    final redirect = AuthRedirectScope.of(context);
    final target = redirect.value;
    redirect.value = null;

    if (target?.routeName == null) {
      Navigator.of(context).maybePop();
      return;
    }

    final targetName = target!.routeName!;
    var found = false;
    Navigator.of(context).popUntil((r) {
      if (r.settings.name == targetName) {
        found = true;
        return true;
      }
      return r.isFirst;
    });
    if (!found) {
      Navigator.of(context).pushNamed(targetName, arguments: target.arguments);
    }
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final cs = Theme.of(context).colorScheme;
    final canSubmit = _isValid() && !_loading;

    return AnimatedBuilder(
      animation: repo,
      builder: (context, _) {
        return Scaffold(
          appBar: AppBar(
            leading: AtalaiaIconButton(
              icon: Icons.arrow_back,
              label: t(context).commonBack,
              onPressed: _loading ? null : () => Navigator.of(context).maybePop(),
            ),
          ),
          body: Column(
            children: [
              if (repo.isOffline)
                OfflineBanner(onRetry: () => repo.setOffline(false)),
              Expanded(
                child: ListView(
                  padding: const EdgeInsets.all(16),
                  children: [
                    const SizedBox(height: 10),
                    Center(
                      child: Column(
                        children: [
                          Container(
                            width: 72,
                            height: 72,
                            decoration: BoxDecoration(
                              color: cs.secondaryContainer,
                              borderRadius: BorderRadius.circular(22),
                            ),
                            child: Icon(Icons.volunteer_activism, color: cs.onSecondaryContainer, size: 34),
                          ),
                          const SizedBox(height: 10),
                          Text(t(context).authWelcomeTitle, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 22)),
                        ],
                      ),
                    ),
                    const SizedBox(height: 18),
                    AtalaiaTextField(
                      controller: _email,
                      keyboardType: TextInputType.emailAddress,
                      autofillHints: const [AutofillHints.email],
                      labelText: t(context).authEmailLabel,
                      onChanged: (_) => setState(() {}),
                    ),
                    const SizedBox(height: 12),
                    PasswordField(
                      controller: _password,
                      labelText: t(context).authPasswordLabel,
                      showPasswordLabel: t(context).authShowPassword,
                      hidePasswordLabel: t(context).authHidePassword,
                      onChanged: (_) => setState(() {}),
                    ),
                    if (_error != null) ...[
                      const SizedBox(height: 10),
                      Text(_authErrorText(context, _error), style: TextStyle(color: cs.error, fontWeight: FontWeight.w700)),
                    ],
                    const SizedBox(height: 16),
                    SizedBox(
                      width: double.infinity,
                      child: PrimaryButton(label: t(context).commonSignIn, loading: _loading, onPressed: canSubmit ? _submit : null),
                    ),
                    const SizedBox(height: 12),
                    Align(
                      alignment: Alignment.centerLeft,
                      child: AtalaiaTextButton(
                        label: t(context).authForgotPassword,
                        onPressed: _loading ? null : () => Navigator.of(context).pushNamed(Routes.resetPassword),
                      ),
                    ),
                    const SizedBox(height: 6),
                    SizedBox(
                      width: double.infinity,
                      child: SecondaryButton(
                        label: t(context).authCreateAccount,
                        onPressed: _loading ? null : () => Navigator.of(context).pushNamed(Routes.signup),
                      ),
                    ),
                    if (repo.supabase == null && _allowManualSupabaseSetup()) ...[
                      const SizedBox(height: 10),
                      Center(
                        child: AtalaiaTextButton(
                          label: t(context).authConfigureSupabase,
                          onPressed: _loading ? null : () => unawaited(showSupabaseSetupDialog(context)),
                        ),
                      ),
                    ],
                  ],
                ),
              ),
            ],
          ),
        );
      },
    );
  }
}

class SignupScreen extends StatefulWidget {
  const SignupScreen({super.key});

  @override
  State<SignupScreen> createState() => _SignupScreenState();
}

class _SignupScreenState extends State<SignupScreen> {
  final _name = TextEditingController();
  final _username = TextEditingController();
  final _email = TextEditingController();
  final _password = TextEditingController();

  var _accepted = false;
  var _loading = false;
  Timer? _cooldownTicker;
  DateTime? _cooldownUntil;

  String? _nameError;
  String? _usernameError;
  String? _emailError;
  String? _passwordError;

  @override
  void dispose() {
    _cooldownTicker?.cancel();
    _name.dispose();
    _username.dispose();
    _email.dispose();
    _password.dispose();
    super.dispose();
  }

  Duration? get _cooldownRemaining {
    final until = _cooldownUntil;
    if (until == null) return null;
    final now = DateTime.now();
    if (!until.isAfter(now)) return Duration.zero;
    return until.difference(now);
  }

  bool get _isInCooldown {
    final r = _cooldownRemaining;
    return r != null && r > Duration.zero;
  }

  void _startCooldown(Duration d) {
    _cooldownUntil = DateTime.now().add(d);
    _cooldownTicker?.cancel();
    _cooldownTicker = Timer.periodic(const Duration(seconds: 1), (_) {
      if (!mounted) return;
      if (!_isInCooldown) {
        _cooldownTicker?.cancel();
        _cooldownTicker = null;
        _cooldownUntil = null;
      }
      setState(() {});
    });
  }

  String? _validateUsername(DemoRepository repo, String value) {
    final l10n = t(context);
    final v = value.trim();
    if (v.length < 3) return l10n.authUsernameMin3;
    final lower = v.toLowerCase();
    final ok = RegExp(r'^[a-z0-9._]+$').hasMatch(lower);
    if (!ok) return l10n.authUsernameAllowedChars;
    if (lower.contains(' ')) return l10n.authUsernameNoSpaces;
    if (repo.isUsernameTaken(lower)) return l10n.authErrorUsernameUnavailable;
    return null;
  }

  void _revalidate() {
    final repo = RepoScope.of(context);
    final l10n = t(context);
    setState(() {
      _nameError = _name.text.trim().length < 2 ? l10n.authNameRequired : null;
      _usernameError = _validateUsername(repo, _username.text);
      _emailError = _email.text.trim().contains('@') ? null : l10n.authEmailInvalid;
      _passwordError = _password.text.length >= 8 ? null : l10n.authPasswordMin8;
    });
  }

  bool _isValid() {
    final repo = RepoScope.of(context);
    return _name.text.trim().length >= 2 &&
        _validateUsername(repo, _username.text) == null &&
        _email.text.trim().contains('@') &&
        _password.text.length >= 8 &&
        _accepted &&
        !_isInCooldown;
  }

  Future<void> _submit() async {
    if (_loading) return;
    if (_isInCooldown) return;
    _revalidate();
    if (!_isValid()) return;

    setState(() => _loading = true);
    final repo = RepoScope.of(context);
    if (repo.isOffline) {
      setState(() => _loading = false);
      return;
    }
    if (repo.supabase == null) {
      setState(() {
        _loading = false;
        _emailError = _authErrorText(context, DemoRepository._authErrSupabaseNotConfigured);
      });
      showAtalaiaSnackBar(context, t(context).authSupabaseNotConfigured, kind: AtalaiaSnackKind.error);
      return;
    }

    await Future<void>.delayed(const Duration(milliseconds: 650));
    final s = await repo.createAccount(
      name: _name.text.trim(),
      username: _username.text.trim().toLowerCase(),
      email: _email.text.trim().toLowerCase(),
      password: _password.text,
    );
    if (s == null) {
      final msg = repo.lastAuthError?.trim();
      if (msg != null && msg.isNotEmpty) {
        if (msg == DemoRepository._authErrRateLimit) {
          _startCooldown(const Duration(minutes: 2));
        }
        if (msg == DemoRepository._authErrUsernameUnavailable) {
          _usernameError = _authErrorText(context, msg);
        } else if (msg == DemoRepository._authErrEmailAlreadyRegistered) {
          _emailError = _authErrorText(context, msg);
        } else if (msg == DemoRepository._authErrNoConnection) {
          _emailError = _authErrorText(context, msg);
        } else if (msg == DemoRepository._authErrCreateAccountFailed) {
          _emailError = _authErrorText(context, msg);
        } else {
          final lower = msg.toLowerCase();
          if (lower.contains('rate limit')) {
            _startCooldown(const Duration(minutes: 2));
          }
          if (lower.contains('username')) {
            _usernameError = msg;
          } else if (lower.contains('email')) {
            _emailError = msg;
          } else {
            _emailError = msg;
          }
        }
      }
      setState(() {
        _loading = false;
        _emailError = repo.isEmailTaken(_email.text) ? _authErrorText(context, DemoRepository._authErrEmailAlreadyRegistered) : _emailError;
        _usernameError = repo.isUsernameTaken(_username.text) ? _authErrorText(context, DemoRepository._authErrUsernameUnavailable) : _usernameError;
      });
      return;
    }

    final session = SessionScope.of(context);
    session.value = s;
    if (!mounted) return;
    final redirect = AuthRedirectScope.of(context);
    final target = redirect.value;
    redirect.value = null;

    if (target?.routeName == null) {
      Navigator.of(context).pushNamedAndRemoveUntil(Routes.root, (r) => false);
      return;
    }

    final targetName = target!.routeName!;
    var found = false;
    Navigator.of(context).popUntil((r) {
      if (r.settings.name == targetName) {
        found = true;
        return true;
      }
      return r.isFirst;
    });
    if (!found) {
      Navigator.of(context).pushNamed(targetName, arguments: target.arguments);
    }
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final canSubmit = _isValid() && !_loading;
    final cooldown = _cooldownRemaining;
    final l10n = t(context);
    final submitLabel =
        (cooldown != null && cooldown > Duration.zero) ? l10n.authWaitSeconds(cooldown.inSeconds) : l10n.authCreateAccount;

    return AnimatedBuilder(
      animation: repo,
      builder: (context, _) {
        return Scaffold(
          appBar: AppBar(
            leading: AtalaiaIconButton(
              icon: Icons.arrow_back,
              label: t(context).commonBack,
              onPressed: _loading ? null : () => Navigator.of(context).maybePop(),
            ),
            title: Text(l10n.authCreateAccount, style: const TextStyle(fontWeight: FontWeight.w800)),
          ),
          body: Column(
            children: [
              if (repo.isOffline)
                OfflineBanner(onRetry: () => repo.setOffline(false)),
              Expanded(
                child: ListView(
                  padding: const EdgeInsets.all(16),
                  children: [
                    AtalaiaTextField(
                      controller: _name,
                      labelText: l10n.authNameLabel,
                      errorText: _nameError,
                      textCapitalization: TextCapitalization.words,
                      onChanged: (_) => _revalidate(),
                    ),
                    const SizedBox(height: 12),
                    AtalaiaTextField(
                      controller: _username,
                      labelText: l10n.authUsernameLabel,
                      errorText: _usernameError,
                      onChanged: (_) => _revalidate(),
                    ),
                    const SizedBox(height: 12),
                    AtalaiaTextField(
                      controller: _email,
                      keyboardType: TextInputType.emailAddress,
                      autofillHints: const [AutofillHints.email],
                      labelText: l10n.authEmailLabel,
                      errorText: _emailError,
                      onChanged: (_) => _revalidate(),
                    ),
                    const SizedBox(height: 12),
                    PasswordField(
                      controller: _password,
                      labelText: l10n.authPasswordLabel,
                      showPasswordLabel: l10n.authShowPassword,
                      hidePasswordLabel: l10n.authHidePassword,
                      errorText: _passwordError,
                      onChanged: (_) => _revalidate(),
                    ),
                    const SizedBox(height: 8),
                    CheckboxListTile(
                      contentPadding: EdgeInsets.zero,
                      value: _accepted,
                      onChanged: _loading ? null : (v) => setState(() => _accepted = v ?? false),
                      title: Text(l10n.authAcceptTerms),
                      controlAffinity: ListTileControlAffinity.leading,
                    ),
                    Align(
                      alignment: Alignment.centerLeft,
                      child: AtalaiaTextButton(
                        label: l10n.settingsTermsPrivacy,
                        onPressed: _loading
                            ? null
                            : () => unawaited(
                                  Navigator.of(context).pushNamed(Routes.legal, arguments: const LegalScreenArgs(initialTab: LegalTab.terms)),
                                ),
                      ),
                    ),
                    const SizedBox(height: 10),
                    SizedBox(
                      width: double.infinity,
                      child: PrimaryButton(
                        label: submitLabel,
                        loading: _loading,
                        onPressed: canSubmit ? _submit : null,
                      ),
                    ),
                    if (repo.supabase == null && _allowManualSupabaseSetup()) ...[
                      const SizedBox(height: 10),
                      Center(
                        child: AtalaiaTextButton(
                          label: l10n.authConfigureSupabase,
                          onPressed: _loading ? null : () => unawaited(showSupabaseSetupDialog(context)),
                        ),
                      ),
                    ],
                    const SizedBox(height: 10),
                    AtalaiaTextButton(
                      label: l10n.authHaveAccountSignIn,
                      onPressed: _loading ? null : () => Navigator.of(context).pushReplacementNamed(Routes.login),
                    ),
                  ],
                ),
              ),
            ],
          ),
        );
      },
    );
  }
}

class ResetPasswordScreen extends StatefulWidget {
  const ResetPasswordScreen({super.key});

  @override
  State<ResetPasswordScreen> createState() => _ResetPasswordScreenState();
}

class _ResetPasswordScreenState extends State<ResetPasswordScreen> {
  final _email = TextEditingController();
  var _loading = false;
  String? _error;

  @override
  void dispose() {
    _email.dispose();
    super.dispose();
  }

  bool _isValid() => _email.text.trim().contains('@');

  Future<void> _submit() async {
    if (_loading) return;
    setState(() {
      _loading = true;
      _error = null;
    });
    final repo = RepoScope.of(context);
    if (repo.isOffline) {
      setState(() {
        _loading = false;
        _error = DemoRepository._authErrNoConnection;
      });
      return;
    }

    await Future<void>.delayed(const Duration(milliseconds: 450));
    await repo.requestPasswordReset(_email.text.trim());
    if (!mounted) return;
    showAtalaiaSnackBar(context, t(context).authResetEmailSentSnack);
    setState(() => _loading = false);
    Navigator.of(context).maybePop();
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final cs = Theme.of(context).colorScheme;
    final canSubmit = _isValid() && !_loading;

    return AnimatedBuilder(
      animation: repo,
      builder: (context, _) {
        return Scaffold(
          appBar: AppBar(
            leading: AtalaiaIconButton(
              icon: Icons.arrow_back,
              label: t(context).commonBack,
              onPressed: _loading ? null : () => Navigator.of(context).maybePop(),
            ),
            title: Text(t(context).authResetPasswordTitle, style: const TextStyle(fontWeight: FontWeight.w800)),
          ),
          body: Column(
            children: [
              if (repo.isOffline)
                OfflineBanner(onRetry: () => repo.setOffline(false)),
              Expanded(
                child: ListView(
                  padding: const EdgeInsets.all(16),
                  children: [
                    AtalaiaTextField(
                      controller: _email,
                      hintText: t(context).authEmailLabel,
                      keyboardType: TextInputType.emailAddress,
                      textInputAction: TextInputAction.done,
                      errorText: _error == DemoRepository._authErrNoConnection ? _authErrorText(context, _error) : null,
                      onChanged: (_) => setState(() {}),
                      onSubmitted: (_) => canSubmit ? _submit() : null,
                    ),
                    if (_error != null && _error != DemoRepository._authErrNoConnection) ...[
                      const SizedBox(height: 10),
                      Text(_authErrorText(context, _error), style: TextStyle(color: cs.error, fontWeight: FontWeight.w700)),
                    ],
                    const SizedBox(height: 14),
                    SizedBox(
                      width: double.infinity,
                      child: PrimaryButton(
                        label: t(context).authSendLink,
                        onPressed: canSubmit ? _submit : null,
                        loading: _loading,
                      ),
                    ),
                  ],
                ),
              ),
            ],
          ),
        );
      },
    );
  }
}

class SettingsScreen extends StatefulWidget {
  const SettingsScreen({super.key});

  @override
  State<SettingsScreen> createState() => _SettingsScreenState();
}

class _SettingsScreenState extends State<SettingsScreen> {
  var _loading = true;

  @override
  void initState() {
    super.initState();
    Future<void>.delayed(const Duration(milliseconds: 240)).then((_) {
      if (!mounted) return;
      setState(() => _loading = false);
    });
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final l10n = t(context);
        final s = session.value;
        final isAuthenticated = s is AuthSession;
        final isModerator = isAuthenticated && (repo.profileForUserId(s.userId)?.isModerator ?? false);
        return Scaffold(
          appBar: AppBar(
            leading: AtalaiaIconButton(
              icon: Icons.arrow_back,
              label: l10n.commonBack,
              onPressed: () => Navigator.of(context).maybePop(),
            ),
            title: Text(l10n.settingsTitle, style: const TextStyle(fontWeight: FontWeight.w800)),
          ),
          body: Column(
            children: [
              if (repo.isOffline)
                OfflineBanner(onRetry: () => repo.setOffline(false)),
              Expanded(
                child: !isAuthenticated
                    ? Center(
                        child: PrimaryButton(label: l10n.settingsSignInToContinue, onPressed: () => showAuthGate(context)),
                      )
                    : _loading
                        ? const Center(child: CircularProgressIndicator())
                        : ListView(
                            padding: const EdgeInsets.symmetric(vertical: 8),
                            children: [
                              _SettingsSectionTitle(l10n.settingsSectionAccount),
                              ListTile(
                                leading: const Icon(Icons.person_outline),
                                title: Text(l10n.settingsAccount),
                                trailing: const Icon(Icons.chevron_right),
                                onTap: () => Navigator.of(context).pushNamed(Routes.settingsAccount),
                              ),
                              ListTile(
                                leading: const Icon(Icons.verified_outlined),
                                title: Text(l10n.settingsVerification),
                                trailing: const Icon(Icons.chevron_right),
                                onTap: () {
                                  final s = session.value;
                                  if (s is! AuthSession) {
                                    showAuthGate(context);
                                    return;
                                  }
                                  final userId = s.userId;
                                  final active = repo.hasActiveVerification(userId) ||
                                      (repo.profileForUserId(userId)?.isVerified ?? false);
                                  Navigator.of(context).pushNamed(
                                    active ? Routes.verificationStatus : Routes.verificationPaywall,
                                  );
                                },
                              ),
                              if (isModerator)
                                ListTile(
                                  leading: const Icon(Icons.gavel_outlined),
                                  title: Text(l10n.settingsModeration),
                                  trailing: const Icon(Icons.chevron_right),
                                  onTap: () => Navigator.of(context).pushNamed(Routes.moderation),
                                ),
                              if (isModerator)
                                ListTile(
                                  leading: const Icon(Icons.campaign_outlined),
                                  title: Text(l10n.settingsAds),
                                  trailing: const Icon(Icons.chevron_right),
                                  onTap: () => Navigator.of(context).pushNamed(Routes.adminAds),
                                ),
                              const Divider(height: 26),
                              _SettingsSectionTitle(l10n.settingsSectionPreferences),
                              ListTile(
                                leading: const Icon(Icons.language_outlined),
                                title: Text(l10n.settingsLanguageRegion),
                                trailing: const Icon(Icons.chevron_right),
                                onTap: () => Navigator.of(context).pushNamed(Routes.settingsLocale),
                              ),
                              ListTile(
                                leading: const Icon(Icons.volunteer_activism_outlined),
                                title: Text(l10n.settingsNotifications),
                                trailing: const Icon(Icons.chevron_right),
                                onTap: () => Navigator.of(context).pushNamed(Routes.settingsNotifications),
                              ),
                              ListTile(
                                leading: const Icon(Icons.dark_mode_outlined),
                                title: Text(l10n.settingsTheme),
                                trailing: const Icon(Icons.chevron_right),
                                onTap: () => Navigator.of(context).pushNamed(Routes.settingsTheme),
                              ),
                              ListTile(
                                leading: const Icon(Icons.library_music_outlined),
                                title: Text(l10n.playlistLibraryTitle),
                                trailing: const Icon(Icons.chevron_right),
                                onTap: () => Navigator.of(context).pushNamed(Routes.playlistLibrary),
                              ),
                              const Divider(height: 26),
                              _SettingsSectionTitle(l10n.settingsSectionSupport),
                              ListTile(
                                leading: const Icon(Icons.help_outline),
                                title: Text(l10n.settingsHelp),
                                trailing: const Icon(Icons.chevron_right),
                                onTap: () => Navigator.of(context).pushNamed(Routes.settingsHelp),
                              ),
                              ListTile(
                                leading: const Icon(Icons.policy_outlined),
                                title: Text(l10n.settingsTermsPrivacy),
                                trailing: const Icon(Icons.chevron_right),
                                onTap: () => Navigator.of(context).pushNamed(Routes.legal),
                              ),
                              const Divider(height: 26),
                              _SettingsSectionTitle(l10n.settingsSectionActions),
                              ListTile(
                                leading: const Icon(Icons.logout),
                                title: Text(
                                  l10n.settingsLogout,
                                  style: TextStyle(color: Theme.of(context).colorScheme.error),
                                ),
                                onTap: () => showLogoutConfirmDialog(context),
                              ),
                            ],
                          ),
              ),
            ],
          ),
        );
      },
    );
  }
}

class NotificationSettingsScreen extends StatefulWidget {
  const NotificationSettingsScreen({super.key});

  @override
  State<NotificationSettingsScreen> createState() => _NotificationSettingsScreenState();
}

class _NotificationSettingsScreenState extends State<NotificationSettingsScreen> {
  bool _loading = true;
  String? _error;
  Map<String, bool> _prefs = <String, bool>{};

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_load());
    });
  }

  Future<void> _load() async {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context).value;
    final sb = repo.supabase;
    if (sb == null || repo.isOffline || session is! AuthSession) {
      if (!mounted) return;
      setState(() {
        _loading = false;
        _error = 'Conecte sua conta para gerenciar notificações.';
      });
      return;
    }

    try {
      final uid = session.userId;
      final row = await sb
          .from('notification_preferences')
          .select('world_enabled,country_enabled,state_enabled,city_enabled,community_enabled,alerts_enabled,prayers_enabled,stories_enabled,posts_enabled,push_enabled')
          .eq('user_id', uid)
          .maybeSingle();
      if (row == null) {
        await sb.from('notification_preferences').upsert(<String, Object?>{'user_id': uid}, onConflict: 'user_id');
      }
      final row2 = await sb
          .from('notification_preferences')
          .select('world_enabled,country_enabled,state_enabled,city_enabled,community_enabled,alerts_enabled,prayers_enabled,stories_enabled,posts_enabled,push_enabled')
          .eq('user_id', uid)
          .maybeSingle();
      final map = <String, bool>{};
      if (row2 is Map<String, dynamic>) {
        for (final key in [
          'push_enabled',
          'posts_enabled',
          'stories_enabled',
          'prayers_enabled',
          'alerts_enabled',
          'community_enabled',
          'world_enabled',
          'country_enabled',
          'state_enabled',
          'city_enabled',
        ]) {
          map[key] = row2[key] == true;
        }
      }
      if (!mounted) return;
      setState(() {
        _prefs = map;
        _loading = false;
        _error = null;
      });
    } catch (e) {
      if (!mounted) return;
      setState(() {
        _loading = false;
        _error = 'Falha ao carregar preferências.';
      });
    }
  }

  Future<void> _setPref(String key, bool value) async {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context).value;
    final sb = repo.supabase;
    if (sb == null || repo.isOffline || session is! AuthSession) return;
    setState(() {
      _prefs = {..._prefs, key: value};
    });
    try {
      await sb.from('notification_preferences').update(<String, Object?>{key: value}).eq('user_id', session.userId);
    } catch (_) {
      if (!mounted) return;
      setState(() {
        _prefs = {..._prefs, key: !value};
      });
      showErrorSnackBar(
        context,
        message: 'Não foi possível salvar. Tente novamente.',
        onRetry: () => unawaited(_setPref(key, value)),
      );
    }
  }

  Widget _tile({
    required IconData icon,
    required String title,
    String? subtitle,
    required bool enabled,
    required bool value,
    required ValueChanged<bool>? onChanged,
  }) {
    return SwitchListTile(
      secondary: Icon(icon),
      title: Text(title),
      subtitle: subtitle == null ? null : Text(subtitle),
      value: value,
      onChanged: enabled ? onChanged : null,
    );
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    return Scaffold(
      appBar: AppBar(title: Text(t(context).settingsNotifications)),
      body: Column(
        children: [
          if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
          Expanded(
            child: _loading
                ? const Center(child: CircularProgressIndicator())
                : (_error != null)
                    ? Center(child: Padding(padding: const EdgeInsets.all(16), child: Text(_error!)))
                    : ListView(
                        children: [
                          const SizedBox(height: 8),
                          _SettingsSectionTitle('Gerais'),
                          _tile(
                            icon: Icons.notifications_active_outlined,
                            title: 'Notificações push',
                            subtitle: 'Ativa/desativa push (quando disponível).',
                            enabled: true,
                            value: _prefs['push_enabled'] ?? true,
                            onChanged: (v) => unawaited(_setPref('push_enabled', v)),
                          ),
                          const Divider(height: 26),
                          _SettingsSectionTitle('Posts, stories e comentários'),
                          _tile(
