class _ReportProblemScreen extends StatefulWidget {
  const _ReportProblemScreen();

  @override
  State<_ReportProblemScreen> createState() => _ReportProblemScreenState();
}

class _ReportProblemScreenState extends State<_ReportProblemScreen> {
  static const _supportEmail = 'suporte@atalaia.social';

  final _subject = TextEditingController(text: 'Relatar um problema no Atalaia');
  final _details = TextEditingController();

  @override
  void dispose() {
    _subject.dispose();
    _details.dispose();
    super.dispose();
  }

  Future<void> _copyEmail() async {
    await Clipboard.setData(const ClipboardData(text: _supportEmail));
    if (!mounted) return;
    showInfoSnackBar(context, 'E-mail copiado.');
  }

  Future<void> _sendEmail() async {
    final repo = RepoScope.of(context);
    final uid = repo.supabase?.auth.currentUser?.id;
    final now = DateTime.now();
    final subject = _subject.text.trim().isEmpty ? 'Relatar um problema no Atalaia' : _subject.text.trim();
    final bodyLines = <String>[
      _details.text.trim().isEmpty ? 'Descreva o que aconteceu aqui…' : _details.text.trim(),
      '',
      '---',
      'Data: ${now.toIso8601String()}',
      if (uid != null && uid.trim().isNotEmpty) 'Usuário: $uid',
      if (kIsWeb) 'Plataforma: web' else 'Plataforma: ${defaultTargetPlatform.name}',
    ];
    final uri = Uri(
      scheme: 'mailto',
      path: _supportEmail,
      queryParameters: <String, String>{
        'subject': subject,
        'body': bodyLines.join('\n'),
      },
    );
    final ok = await launchUrl(uri, mode: LaunchMode.externalApplication);
    if (!mounted) return;
    if (!ok) {
      showErrorSnackBar(
        context,
        message: 'Não foi possível abrir o app de e-mail.',
        onRetry: () => unawaited(_sendEmail()),
      );
    }
  }

  @override
  Widget build(BuildContext context) {
    return Scaffold(
      appBar: AppBar(title: const Text('Relatar um problema')),
      body: ListView(
        padding: const EdgeInsets.all(16),
        children: [
          const Text(
            'Envie o máximo de detalhes possível para a equipe de Ajuda.',
            style: TextStyle(fontWeight: FontWeight.w700),
          ),
          const SizedBox(height: 12),
          AtalaiaTextField(
            controller: _subject,
            hintText: 'Assunto',
            maxLength: 80,
          ),
          const SizedBox(height: 12),
          AtalaiaTextField(
            controller: _details,
            hintText: 'O que aconteceu? Como reproduzir? (pode colar links e horários)',
            minLines: 5,
            maxLines: 10,
            maxLength: 1200,
          ),
          const SizedBox(height: 12),
          Card(
            child: Padding(
              padding: const EdgeInsets.all(12),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  const Text('Contato', style: TextStyle(fontWeight: FontWeight.w900)),
                  const SizedBox(height: 8),
                  Text(_supportEmail),
                  const SizedBox(height: 10),
                  Wrap(
                    spacing: 8,
                    runSpacing: 8,
                    children: [
                      OutlinedButton.icon(
                        onPressed: () => unawaited(_copyEmail()),
                        icon: const Icon(Icons.copy_rounded),
                        label: const Text('Copiar e-mail'),
                      ),
                      FilledButton.icon(
                        onPressed: () => unawaited(_sendEmail()),
                        icon: const Icon(Icons.send_rounded),
                        label: const Text('Enviar e-mail'),
                      ),
                    ],
                  ),
                ],
              ),
            ),
          ),
          const SizedBox(height: 12),
          const Text(
            'Dica: anexe prints e informe o horário aproximado do erro.',
            style: TextStyle(fontWeight: FontWeight.w600),
          ),
        ],
      ),
    );
  }
}

class ModerationScreen extends StatefulWidget {
  const ModerationScreen({super.key});

  @override
  State<ModerationScreen> createState() => _ModerationScreenState();
}

class _ModerationScreenState extends State<ModerationScreen> {
  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      final repo = RepoScope.of(context);
      unawaited(repo.refreshModerationReports());
    });
  }

  Future<void> _openActions(
    BuildContext context, {
    required ReportModel report,
    required DemoRepository repo,
  }) async {
    final l10n = t(context);
    String labelFor(ReportStatus s) {
      return switch (s) {
        ReportStatus.open => l10n.reportsStatusOpen,
        ReportStatus.reviewing => l10n.reportsStatusReviewing,
        ReportStatus.resolved => l10n.reportsStatusResolved,
        ReportStatus.dismissed => l10n.reportsStatusDismissed,
      };
    }

    final canRemoveContent = report.entityType != ReportEntityType.user;
    final canActOnUser = report.reportedUserId != null && report.reportedUserId!.isNotEmpty;

    final choice = await showAtalaiaBottomSheet<String>(
      context,
      builder: (ctx) {
        return SafeArea(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              ListTile(
                leading: const Icon(Icons.search_outlined),
                title: Text(l10n.moderationMarkAs(labelFor(ReportStatus.reviewing))),
                onTap: () => Navigator.pop(ctx, 'reviewing'),
              ),
              ListTile(
                leading: const Icon(Icons.check_circle_outline),
                title: Text(l10n.moderationMarkAs(labelFor(ReportStatus.resolved))),
                onTap: () => Navigator.pop(ctx, 'resolved'),
              ),
              ListTile(
                leading: const Icon(Icons.block_outlined),
                title: Text(l10n.moderationMarkAs(labelFor(ReportStatus.dismissed))),
                onTap: () => Navigator.pop(ctx, 'dismissed'),
              ),
              if (canRemoveContent) ...[
                const Divider(height: 18),
                ListTile(
                  leading: Icon(Icons.delete_outline, color: Theme.of(ctx).colorScheme.error),
                  title: Text(l10n.moderationRemoveContent, style: TextStyle(color: Theme.of(ctx).colorScheme.error)),
                  onTap: () => Navigator.pop(ctx, 'remove'),
                ),
              ],
              if (canActOnUser) ...[
                const Divider(height: 18),
                ListTile(
                  leading: const Icon(Icons.warning_amber_outlined),
                  title: Text(l10n.moderationWarnUser),
                  onTap: () => Navigator.pop(ctx, 'warn'),
                ),
                ListTile(
                  leading: const Icon(Icons.timer_off_outlined),
                  title: Text(l10n.moderationSuspendDays(1)),
                  onTap: () => Navigator.pop(ctx, 'suspend_1d'),
                ),
                ListTile(
                  leading: const Icon(Icons.timer_off_outlined),
                  title: Text(l10n.moderationSuspendDays(7)),
                  onTap: () => Navigator.pop(ctx, 'suspend_7d'),
                ),
                ListTile(
                  leading: const Icon(Icons.timer_off_outlined),
                  title: Text(l10n.moderationSuspendDays(30)),
                  onTap: () => Navigator.pop(ctx, 'suspend_30d'),
                ),
              ],
              const Divider(height: 18),
              ListTile(
                leading: const Icon(Icons.copy_all_outlined),
                title: Text(l10n.moderationCopyReportId),
                onTap: () => Navigator.pop(ctx, 'copy'),
              ),
              const SizedBox(height: 8),
            ],
          ),
        );
      },
    );

    if (!context.mounted) return;

    switch (choice) {
      case 'reviewing':
        await repo.moderationSetReportStatus(reportId: report.id, status: ReportStatus.reviewing);
        if (!context.mounted) return;
        showAtalaiaSnackBar(context, l10n.moderationReportMarkedReviewing, kind: AtalaiaSnackKind.success);
      case 'resolved':
        await repo.moderationSetReportStatus(reportId: report.id, status: ReportStatus.resolved);
        if (!context.mounted) return;
        showAtalaiaSnackBar(context, l10n.moderationReportResolved, kind: AtalaiaSnackKind.success);
      case 'dismissed':
        await repo.moderationSetReportStatus(reportId: report.id, status: ReportStatus.dismissed);
        if (!context.mounted) return;
        showAtalaiaSnackBar(context, l10n.moderationReportDismissed, kind: AtalaiaSnackKind.success);
      case 'remove':
        if (!canRemoveContent) return;
        final ok = await showAtalaiaConfirmDialog(
          context,
          title: l10n.moderationRemoveContentConfirmTitle,
          confirmLabel: l10n.moderationRemoveContent,
          isDestructive: true,
        );
        if (!context.mounted) return;
        if (ok == true) {
          await repo.moderationRemoveContent(entityType: report.entityType, entityId: report.entityId);
          await repo.moderationSetReportStatus(reportId: report.id, status: ReportStatus.resolved);
          if (!context.mounted) return;
          showAtalaiaSnackBar(context, l10n.moderationContentRemoved, kind: AtalaiaSnackKind.success);
        }
      case 'warn':
        final userId = report.reportedUserId;
        if (userId == null || userId.isEmpty) return;
        await repo.moderationWarnUser(userId: userId);
        if (!context.mounted) return;
        showAtalaiaSnackBar(context, l10n.moderationWarningRegistered, kind: AtalaiaSnackKind.success);
      case 'suspend_1d':
      case 'suspend_7d':
      case 'suspend_30d':
        final userId = report.reportedUserId;
        if (userId == null || userId.isEmpty) return;
        final duration = switch (choice) {
          'suspend_1d' => const Duration(days: 1),
          'suspend_7d' => const Duration(days: 7),
          _ => const Duration(days: 30),
        };
        final ok = await showAtalaiaConfirmDialog(
          context,
          title: l10n.moderationSuspendUserConfirmTitle,
          confirmLabel: l10n.moderationSuspendConfirmLabel,
          isDestructive: true,
        );
        if (!context.mounted) return;
        if (ok == true) {
          await repo.moderationSuspendUser(userId: userId, duration: duration);
          if (!context.mounted) return;
          showAtalaiaSnackBar(context, l10n.moderationSuspensionRegistered, kind: AtalaiaSnackKind.success);
        }
      case 'copy':
        await Clipboard.setData(ClipboardData(text: report.id));
        if (!context.mounted) return;
        showAtalaiaSnackBar(context, t(context).commonIdCopied, kind: AtalaiaSnackKind.success);
      default:
        return;
    }
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final s = session.value;
        if (s is! AuthSession) {
          return Scaffold(
            appBar: AppBar(title: Text(t(context).settingsModeration, style: const TextStyle(fontWeight: FontWeight.w800))),
            body: Center(
              child: PrimaryButton(label: t(context).settingsSignInToContinue, onPressed: () => showAuthGate(context)),
            ),
          );
        }

        final me = repo.profileForUserId(s.userId);
        if (me == null || !me.isModerator) {
          return Scaffold(
            appBar: AppBar(
              leading: AtalaiaIconButton(
                icon: Icons.arrow_back,
                label: t(context).commonBack,
                onPressed: () => Navigator.of(context).maybePop(),
              ),
              title: Text(t(context).settingsModeration, style: const TextStyle(fontWeight: FontWeight.w800)),
            ),
            body: Center(child: Text(t(context).commonRestrictedAccess)),
          );
        }

        final reports = repo.reportsForModeration();
        return Scaffold(
          appBar: AppBar(
            leading: AtalaiaIconButton(
              icon: Icons.arrow_back,
              label: t(context).commonBack,
              onPressed: () => Navigator.of(context).maybePop(),
            ),
            title: Text(t(context).settingsModeration, style: const TextStyle(fontWeight: FontWeight.w800)),
            actions: [
              AtalaiaIconButton(
                icon: Icons.refresh,
                label: t(context).commonRefresh,
                onPressed: () => unawaited(repo.refreshModerationReports()),
              ),
            ],
          ),
          body: Column(
            children: [
              if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
              Expanded(
                child: RefreshIndicator(
                  onRefresh: repo.refreshModerationReports,
                  child: reports.isEmpty
                      ? ListView(
                          children: [
                            SizedBox(height: 120),
                            Center(child: Text(t(context).reportsEmpty)),
                          ],
                        )
                      : ListView.separated(
                          padding: const EdgeInsets.all(12),
                          itemCount: reports.length,
                          separatorBuilder: (_, __) => const SizedBox(height: 10),
                          itemBuilder: (context, index) {
                            final r = reports[index];
                            final l10n = t(context);
                            final who = r.reportedUsername ?? r.reportedUserId ?? r.entityId;
                            final reporter = r.reporterUsername ?? r.reporterId;
                            final statusLabel = switch (r.status) {
                              ReportStatus.open => l10n.reportsStatusOpen,
                              ReportStatus.reviewing => l10n.reportsStatusReviewing,
                              ReportStatus.resolved => l10n.reportsStatusResolved,
                              ReportStatus.dismissed => l10n.reportsStatusDismissed,
                            };
                            final desc = (r.description ?? '').trim();
                            return Card(
                              child: ListTile(
                                title: Text(r.reason, maxLines: 2, overflow: TextOverflow.ellipsis),
                                subtitle: Text(
                                  '${_reportEntityTypeLabel(context, r.entityType)} • ${l10n.reportsStatus(statusLabel)}\n'
                                  '${l10n.moderationTarget(who)} • ${l10n.moderationReporter(reporter)}${desc.isEmpty ? '' : '\n$desc'}',
                                  maxLines: 4,
                                  overflow: TextOverflow.ellipsis,
                                ),
                                onTap: () {
                                  switch (r.entityType) {
                                    case ReportEntityType.post:
                                      Navigator.of(context).pushNamed(
                                        Routes.postDetail,
                                        arguments: PostDetailArgs(postId: r.entityId),
                                      );
                                    case ReportEntityType.alert:
                                      Navigator.of(context).pushNamed(
                                        Routes.alertDetail,
                                        arguments: AlertDetailArgs(alertId: r.entityId),
                                      );
                                    case ReportEntityType.user:
                                      Navigator.of(context).pushNamed(
                                        Routes.userProfile,
                                        arguments: UserProfileArgs(userId: r.entityId),
                                      );
                                    case ReportEntityType.comment:
                                      final postId = repo.postIdForCommentId(r.entityId);
                                      if (postId == null) {
                                        showAtalaiaSnackBar(context, l10n.moderationCommentNotFoundLocally);
                                        return;
                                      }
                                      Navigator.of(context).pushNamed(
                                        Routes.postComments,
                                        arguments: CommentsArgs(postId: postId),
                                      );
                                    case ReportEntityType.story:
                                      showAtalaiaSnackBar(context, l10n.moderationStoryUiPlaceholder);
                                  }
                                },
                                trailing: IconButton(
                                  icon: const Icon(Icons.more_horiz),
                                  onPressed: () => unawaited(_openActions(context, report: r, repo: repo)),
                                ),
                              ),
                            );
                          },
                        ),
                ),
              ),
            ],
          ),
        );
      },
    );
  }
}

class AdminAdsScreen extends StatefulWidget {
  const AdminAdsScreen({super.key});

  @override
  State<AdminAdsScreen> createState() => _AdminAdsScreenState();
}

class _AdminAdsScreenState extends State<AdminAdsScreen> {
  var _loadingAdvertisers = true;
  var _loadingCampaigns = false;
  var _loadingCreatives = false;
  var _loadingTargets = false;
  var _loadingPins = false;
  var _loadingMetrics = false;

  var _advertisers = const <Map<String, dynamic>>[];
  var _campaigns = const <Map<String, dynamic>>[];
  var _creatives = const <Map<String, dynamic>>[];
  var _targets = const <Map<String, dynamic>>[];
  var _pins = const <Map<String, dynamic>>[];
  var _metrics = const <Map<String, dynamic>>[];

  String? _selectedAdvertiserId;
  String? _selectedCampaignId;

  String _adsObjectiveLabel(BuildContext context, String raw) {
    final l10n = t(context);
    return switch (raw) {
      'traffic' => l10n.adsObjectiveTraffic,
      'awareness' => l10n.adsObjectiveAwareness,
      'promotion' => l10n.adsObjectivePromotion,
      'community' => l10n.adsObjectiveCommunity,
      'event' => l10n.adsObjectiveEvent,
      _ => raw,
    };
  }

  String _adsScopeLabel(BuildContext context, String raw) {
    final l10n = t(context);
    return switch (raw) {
      'world' => l10n.adsScopeWorld,
      'country' => l10n.adsScopeCountry,
      'state' => l10n.adsScopeState,
      'city' => l10n.adsScopeCity,
      'community' => l10n.adsScopeCommunity,
      _ => raw,
    };
  }

  String _adsPlacementLabel(BuildContext context, String raw) {
    final l10n = t(context);
    return switch (raw) {
      'feed' => l10n.adsPlacementFeed,
      'map_pin' => l10n.adsPlacementMapPin,
      'story_slot' => l10n.adsPlacementStorySlot,
      'community_feed' => l10n.adsPlacementCommunityFeed,
      _ => raw,
    };
  }

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) => unawaited(_refreshAdvertisers()));
  }

  Future<void> _refreshAdvertisers() async {
    if (!mounted) return;
    final repo = RepoScope.of(context);
    final sb = repo.supabase;
    if (sb == null || repo.isOffline) {
      setState(() {
        _advertisers = const <Map<String, dynamic>>[];
        _loadingAdvertisers = false;
      });
      return;
    }
    setState(() => _loadingAdvertisers = true);
    try {
      final rows = await sb.from('advertisers').select('id,name,is_active,created_at').order('created_at', ascending: false);
      if (!mounted) return;
      final list = (rows as List<dynamic>).cast<Map<String, dynamic>>();
      final selectedStillExists = _selectedAdvertiserId != null && list.any((r) => r['id']?.toString() == _selectedAdvertiserId);
      setState(() {
        _advertisers = List.unmodifiable(list);
        _loadingAdvertisers = false;
        if (!selectedStillExists) {
          _selectedAdvertiserId = list.isEmpty ? null : list.first['id']?.toString();
          _selectedCampaignId = null;
          _campaigns = const <Map<String, dynamic>>[];
          _creatives = const <Map<String, dynamic>>[];
          _targets = const <Map<String, dynamic>>[];
          _pins = const <Map<String, dynamic>>[];
          _metrics = const <Map<String, dynamic>>[];
        }
      });
      if (_selectedAdvertiserId != null) {
        await _refreshCampaigns();
      }
    } catch (_) {
      if (!mounted) return;
      setState(() => _loadingAdvertisers = false);
    }
  }

  Future<void> _refreshCampaigns() async {
    if (!mounted) return;
    final repo = RepoScope.of(context);
    final sb = repo.supabase;
    final advertiserId = _selectedAdvertiserId;
    if (sb == null || repo.isOffline || advertiserId == null) return;
    setState(() => _loadingCampaigns = true);
    try {
      final rows = await sb
          .from('ad_campaigns')
          .select('id,advertiser_id,title,objective,status,start_date,end_date,updated_at,created_at')
          .eq('advertiser_id', advertiserId)
          .order('created_at', ascending: false);
      if (!mounted) return;
      final list = (rows as List<dynamic>).cast<Map<String, dynamic>>();
      final selectedStillExists = _selectedCampaignId != null && list.any((r) => r['id']?.toString() == _selectedCampaignId);
      setState(() {
        _campaigns = List.unmodifiable(list);
        _loadingCampaigns = false;
        if (!selectedStillExists) {
          _selectedCampaignId = list.isEmpty ? null : list.first['id']?.toString();
          _creatives = const <Map<String, dynamic>>[];
          _targets = const <Map<String, dynamic>>[];
          _pins = const <Map<String, dynamic>>[];
          _metrics = const <Map<String, dynamic>>[];
        }
      });
      await _refreshCampaignDetails();
    } catch (_) {
      if (!mounted) return;
      setState(() => _loadingCampaigns = false);
    }
  }

  Future<void> _refreshCampaignDetails() async {
    final id = _selectedCampaignId;
    if (id == null) return;
    await Future.wait([
      _refreshCreatives(),
      _refreshTargets(),
      _refreshPins(),
      _refreshMetrics(),
    ]);
  }

  Future<void> _refreshCreatives() async {
    if (!mounted) return;
    final repo = RepoScope.of(context);
    final sb = repo.supabase;
    final campaignId = _selectedCampaignId;
    if (sb == null || repo.isOffline || campaignId == null) return;
    setState(() => _loadingCreatives = true);
    try {
      final rows = await sb
          .from('ad_creatives')
          .select('id,campaign_id,creative_type,headline,body,cta_label,target_url,is_active,created_at')
          .eq('campaign_id', campaignId)
          .order('created_at', ascending: false);
      if (!mounted) return;
      setState(() {
        _creatives = List.unmodifiable((rows as List<dynamic>).cast<Map<String, dynamic>>());
        _loadingCreatives = false;
      });
    } catch (_) {
      if (!mounted) return;
      setState(() => _loadingCreatives = false);
    }
  }

  Future<void> _refreshTargets() async {
    if (!mounted) return;
    final repo = RepoScope.of(context);
    final sb = repo.supabase;
    final campaignId = _selectedCampaignId;
    if (sb == null || repo.isOffline || campaignId == null) return;
    setState(() => _loadingTargets = true);
    try {
      final rows = await sb
          .from('ad_targets')
          .select('id,campaign_id,scope,location_id,community_id,placement,priority,is_active,created_at')
          .eq('campaign_id', campaignId)
          .order('priority', ascending: false)
          .order('created_at', ascending: false);
      if (!mounted) return;
      setState(() {
        _targets = List.unmodifiable((rows as List<dynamic>).cast<Map<String, dynamic>>());
        _loadingTargets = false;
      });
    } catch (_) {
      if (!mounted) return;
      setState(() => _loadingTargets = false);
    }
  }

  Future<void> _refreshPins() async {
    if (!mounted) return;
    final repo = RepoScope.of(context);
    final sb = repo.supabase;
    final campaignId = _selectedCampaignId;
    if (sb == null || repo.isOffline || campaignId == null) return;
    setState(() => _loadingPins = true);
    try {
      final rows = await sb
          .from('sponsored_map_pins')
          .select('id,campaign_id,creative_id,location_id,pin_label,is_active,created_at')
          .eq('campaign_id', campaignId)
          .order('created_at', ascending: false);
      if (!mounted) return;
      setState(() {
        _pins = List.unmodifiable((rows as List<dynamic>).cast<Map<String, dynamic>>());
        _loadingPins = false;
      });
    } catch (_) {
      if (!mounted) return;
      setState(() => _loadingPins = false);
    }
  }

  Future<void> _refreshMetrics() async {
    if (!mounted) return;
    final repo = RepoScope.of(context);
    final sb = repo.supabase;
    final campaignId = _selectedCampaignId;
    if (sb == null || repo.isOffline || campaignId == null) return;
    setState(() => _loadingMetrics = true);
    try {
      final rows = await sb.rpc('get_ad_campaign_metrics', params: <String, Object?>{'p_campaign_id': campaignId});
      if (!mounted) return;
      setState(() {
        _metrics = List.unmodifiable((rows as List<dynamic>).cast<Map<String, dynamic>>());
        _loadingMetrics = false;
      });
    } catch (_) {
