class LocaleSettingsScreen extends StatefulWidget {
  const LocaleSettingsScreen({super.key});

  @override
  State<LocaleSettingsScreen> createState() => _LocaleSettingsScreenState();
}

class _LocaleSettingsScreenState extends State<LocaleSettingsScreen> {
  Locale? _selectedLocale;
  late final TextEditingController _countryController;
  late final TextEditingController _timezoneController;
  var _receiveGlobalContent = true;
  var _saving = false;

  @override
  void initState() {
    super.initState();
    _countryController = TextEditingController();
    _timezoneController = TextEditingController();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      final localeOverride = LocaleOverrideScope.of(context).value;
      final prefs = UserLocalePrefsScope.of(context).value;
      setState(() {
        _selectedLocale = localeOverride;
        _receiveGlobalContent = prefs.receiveGlobalContent;
      });
      _countryController.text = (prefs.countryCode ?? '').trim();
      _timezoneController.text = (prefs.timezoneName ?? '').trim();
    });
  }

  @override
  void dispose() {
    _countryController.dispose();
    _timezoneController.dispose();
    super.dispose();
  }

  Future<void> _save() async {
    if (_saving) return;
    setState(() => _saving = true);

    final repo = RepoScope.of(context);
    final session = SessionScope.of(context).value;
    final localeNotifier = LocaleOverrideScope.of(context);
    final prefsNotifier = UserLocalePrefsScope.of(context);
    final l10n = t(context);

    final localeCode = _localeCode(_selectedLocale);
    final rawCountry = _countryController.text.trim().toUpperCase();
    final rawTimezone = _timezoneController.text.trim();
    final countryCode = rawCountry.isEmpty ? null : rawCountry;
    final timezoneName = rawTimezone.isEmpty ? null : rawTimezone;

    localeNotifier.value = _selectedLocale;
    prefsNotifier.value = prefsNotifier.value.copyWith(
      countryCode: countryCode,
      timezoneName: timezoneName,
      receiveGlobalContent: _receiveGlobalContent,
    );

    try {
      final sp = await SharedPreferences.getInstance();
      await sp.setString('locale_override', localeCode);
      if (countryCode == null) {
        await sp.remove('user_country_code');
      } else {
        await sp.setString('user_country_code', countryCode);
      }
      if (timezoneName == null) {
        await sp.remove('user_timezone_name');
      } else {
        await sp.setString('user_timezone_name', timezoneName);
      }
      await sp.setBool('receive_global_content', _receiveGlobalContent);
    } catch (_) {}

    if (session is AuthSession) {
      await repo.upsertUserLocalePreferences(
        userId: session.userId,
        localeCode: localeCode,
        timezoneName: timezoneName,
        countryCode: countryCode,
        receiveGlobalContent: _receiveGlobalContent,
      );
    }

    if (!mounted) return;
    setState(() => _saving = false);
    showAtalaiaSnackBar(context, l10n.commonSaved, kind: AtalaiaSnackKind.success);
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final l10n = t(context);
    final cs = Theme.of(context).colorScheme;

    return AnimatedBuilder(
      animation: repo,
      builder: (context, _) {
        return Scaffold(
          appBar: AppBar(
            leading: AtalaiaIconButton(
              icon: Icons.arrow_back,
              label: l10n.commonBack,
              onPressed: () => Navigator.of(context).maybePop(),
            ),
            title: Text(l10n.localeScreenTitle, style: const TextStyle(fontWeight: FontWeight.w800)),
          ),
          body: Column(
            children: [
              if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
              Expanded(
                child: ListView(
                  padding: const EdgeInsets.fromLTRB(16, 14, 16, 16),
                  children: [
                    Text(l10n.localeLanguageLabel, style: TextStyle(color: cs.outline, fontWeight: FontWeight.w800)),
                    const SizedBox(height: 8),
                    DropdownButtonFormField<Locale?>(
                      initialValue: _selectedLocale,
                      items: [
                        DropdownMenuItem<Locale?>(
                          value: null,
                          child: Text(l10n.localeLanguageDevice),
                        ),
                        DropdownMenuItem<Locale?>(
                          value: const Locale('pt', 'BR'),
                          child: Text(l10n.localeLanguagePortuguese),
                        ),
                        DropdownMenuItem<Locale?>(
                          value: const Locale('en'),
                          child: Text(l10n.localeLanguageEnglish),
                        ),
                        DropdownMenuItem<Locale?>(
                          value: const Locale('es'),
                          child: Text(l10n.localeLanguageSpanish),
                        ),
                      ],
                      onChanged: (v) => setState(() => _selectedLocale = v),
                      decoration: const InputDecoration(),
                    ),
                    const SizedBox(height: 14),
                    Text(l10n.localeCountryLabel, style: TextStyle(color: cs.outline, fontWeight: FontWeight.w800)),
                    const SizedBox(height: 8),
                    TextField(
                      controller: _countryController,
                      textCapitalization: TextCapitalization.characters,
                      maxLength: 2,
                      inputFormatters: [
                        FilteringTextInputFormatter.allow(RegExp(r'[a-zA-Z]')),
                        LengthLimitingTextInputFormatter(2),
                      ],
                      decoration: InputDecoration(
                        counterText: '',
                        hintText: l10n.localeHintCountry,
                        suffixIcon: IconButton(
                          tooltip: l10n.localeLanguageDevice,
                          onPressed: () => _countryController.clear(),
                          icon: const Icon(Icons.close),
                        ),
                      ),
                    ),
                    const SizedBox(height: 14),
                    Text(l10n.localeTimezoneLabel, style: TextStyle(color: cs.outline, fontWeight: FontWeight.w800)),
                    const SizedBox(height: 8),
                    TextField(
                      controller: _timezoneController,
                      decoration: InputDecoration(
                        hintText: l10n.localeHintTimezone,
                        suffixIcon: IconButton(
                          tooltip: l10n.localeTimezoneDevice,
                          onPressed: () => _timezoneController.clear(),
                          icon: const Icon(Icons.close),
                        ),
                      ),
                    ),
                    const SizedBox(height: 10),
                    SwitchListTile(
                      contentPadding: EdgeInsets.zero,
                      title: Text(l10n.localeReceiveGlobalContent, style: const TextStyle(fontWeight: FontWeight.w800)),
                      value: _receiveGlobalContent,
                      onChanged: (v) => setState(() => _receiveGlobalContent = v),
                    ),
                    const SizedBox(height: 16),
                    PrimaryButton(
                      label: l10n.commonSave,
                      loading: _saving,
                      onPressed: _save,
                    ),
                  ],
                ),
              ),
            ],
          ),
        );
      },
    );
  }
}

enum _VerificationSubject { person, church }

enum _VerificationBilling { monthly, yearly }

class VerificationPaywallScreen extends StatefulWidget {
  const VerificationPaywallScreen({super.key});

  @override
  State<VerificationPaywallScreen> createState() => _VerificationPaywallScreenState();
}

class _VerificationPaywallScreenState extends State<VerificationPaywallScreen> {
  var _subject = _VerificationSubject.person;
  var _billing = _VerificationBilling.monthly;
  var _loading = false;
  String? _error;

  String _planLabel() {
    final subjectLabel = _subject == _VerificationSubject.person ? 'Pessoa' : 'Igreja';
    final billingLabel = _billing == _VerificationBilling.monthly ? 'Mensal' : 'Anual';
    return '$subjectLabel • $billingLabel';
  }

  Future<void> _startCheckout() async {
    if (_loading) return;
    setState(() {
      _loading = true;
      _error = null;
    });

    final repo = RepoScope.of(context);
    final plan = _planLabel();
    final l10n = t(context);
    repo.trackEvent('verify_subscribe_tap', <String, Object?>{'plan': plan});
    if (repo.isOffline) {
      repo.trackEvent('verify_purchase_fail', <String, Object?>{'reason': 'offline', 'plan': plan});
      setState(() {
        _loading = false;
        _error = l10n.paymentStartFailed;
      });
      showInfoSnackBar(context, l10n.paymentStartFailed);
      return;
    }

    await Future<void>.delayed(const Duration(milliseconds: 900));
    if (!mounted) return;

    final ok = DateTime.now().millisecondsSinceEpoch % 7 != 0;
    if (!ok) {
      repo.trackEvent('verify_purchase_fail', <String, Object?>{'reason': 'provider', 'plan': plan});
      setState(() {
        _loading = false;
        _error = l10n.paymentStartFailed;
      });
      showInfoSnackBar(context, l10n.paymentStartFailed);
      return;
    }

    repo.activateVerificationForViewer(planLabel: plan);
    setState(() => _loading = false);
    if (!mounted) return;
    showInfoSnackBar(context, l10n.verificationSubscriptionActive);
    Navigator.of(context).pushReplacementNamed(Routes.verificationStatus);
  }

  @override
  Widget build(BuildContext context) {
    final session = SessionScope.of(context).value;
    final cs = Theme.of(context).colorScheme;
    final l10n = t(context);

    if (session is! AuthSession) {
      return Scaffold(
        appBar: AppBar(
          leading: AtalaiaIconButton(
            icon: Icons.arrow_back,
            label: t(context).commonBack,
            onPressed: () => Navigator.of(context).maybePop(),
          ),
          title: Text(l10n.verificationBadgeTitle, style: const TextStyle(fontWeight: FontWeight.w800)),
        ),
        body: Center(
          child: PrimaryButton(label: t(context).settingsSignInToContinue, onPressed: () => showAuthGate(context)),
        ),
      );
    }

    return Scaffold(
      appBar: AppBar(
        leading: AtalaiaIconButton(
          icon: Icons.arrow_back,
          label: t(context).commonBack,
          onPressed: _loading ? null : () => Navigator.of(context).maybePop(),
        ),
        title: Text(l10n.verificationBadgeTitle, style: const TextStyle(fontWeight: FontWeight.w800)),
      ),
      body: ListView(
        padding: const EdgeInsets.all(16),
        children: [
          Row(
            children: [
              Container(
                width: 44,
                height: 44,
                decoration: BoxDecoration(
                  color: cs.primaryContainer,
                  borderRadius: BorderRadius.circular(14),
                ),
                child: Icon(Icons.verified, color: cs.primary),
              ),
              const SizedBox(width: 12),
              Expanded(
                child: Text(
                  l10n.verificationBadgeTitle,
                  style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 18),
                ),
              ),
            ],
          ),
          const SizedBox(height: 14),
          Text(
            l10n.verificationBadgeDescription,
            style: TextStyle(color: cs.outline, fontWeight: FontWeight.w600),
          ),
          const SizedBox(height: 14),
          _BenefitRow(text: l10n.verificationBenefitCredibility),
          _BenefitRow(text: l10n.verificationBenefitHighlight),
          _BenefitRow(text: l10n.verificationBenefitProtection),
          const SizedBox(height: 18),
          Text(l10n.verificationPlansTitle, style: const TextStyle(fontWeight: FontWeight.w900)),
          const SizedBox(height: 10),
          _TwoChoiceRow(
            leftLabel: l10n.verificationSubjectPerson,
            rightLabel: l10n.verificationSubjectChurch,
            leftSelected: _subject == _VerificationSubject.person,
            onLeft: _loading ? null : () => setState(() => _subject = _VerificationSubject.person),
            onRight: _loading ? null : () => setState(() => _subject = _VerificationSubject.church),
          ),
          const SizedBox(height: 12),
          _TwoChoiceRow(
            leftLabel: l10n.verificationBillingMonthly,
            rightLabel: l10n.verificationBillingYearly,
            leftSelected: _billing == _VerificationBilling.monthly,
            onLeft: _loading ? null : () => setState(() => _billing = _VerificationBilling.monthly),
            onRight: _loading ? null : () => setState(() => _billing = _VerificationBilling.yearly),
          ),
          const SizedBox(height: 14),
          Card(
            elevation: 0,
            color: cs.surfaceContainerHighest,
            child: Padding(
              padding: const EdgeInsets.all(12),
              child: Row(
                children: [
                  Expanded(
                    child: Text(
                      _planLabel(),
                      style: const TextStyle(fontWeight: FontWeight.w900),
                    ),
                  ),
                  Text(
                    _billing == _VerificationBilling.monthly ? l10n.verificationPriceMonthly : l10n.verificationPriceYearly,
                    style: TextStyle(color: cs.onSurface, fontWeight: FontWeight.w900),
                  ),
                ],
              ),
            ),
          ),
          if (_error != null) ...[
            const SizedBox(height: 10),
            Text(_error!, style: TextStyle(color: cs.error, fontWeight: FontWeight.w800)),
          ],
          const SizedBox(height: 14),
          SizedBox(
            width: double.infinity,
            child: PrimaryButton(
              label: l10n.verificationSubscribe,
              loading: _loading,
              onPressed: _loading ? null : _startCheckout,
            ),
          ),
          const SizedBox(height: 10),
          AtalaiaTextButton(
            label: l10n.verificationRestorePurchase,
            onPressed: _loading ? null : () => showInfoSnackBar(context, l10n.verificationRestorePhase2),
          ),
          const SizedBox(height: 6),
          AtalaiaTextButton(
            label: l10n.verificationTerms,
            onPressed: _loading
                ? null
                : () => Navigator.of(context).pushNamed(Routes.legal, arguments: const LegalScreenArgs(initialTab: LegalTab.terms)),
          ),
        ],
      ),
    );
  }
}

