      showInfoSnackBar(context, l10n.commonLinkCopied);
    case 'external':
      showInfoSnackBar(context, l10n.commonComingSoon);
    case 'direct':
      Navigator.of(context).pushNamed(
        Routes.direct,
        arguments: DirectInboxArgs(selectForSharedText: playlistText),
      );
    default:
