enum _ReportReason { spam, inappropriate, harassment, misleading, other }

final class _ReportPayload {
  const _ReportPayload({
    required this.reason,
    required this.otherText,
  });

  final _ReportReason reason;
  final String otherText;
}

String _reportReasonLabel(AppLocalizations l10n, _ReportReason r) {
  return switch (r) {
    _ReportReason.spam => l10n.postReportReasonSpam,
    _ReportReason.inappropriate => l10n.postReportReasonInappropriate,
    _ReportReason.harassment => l10n.postReportReasonHarassment,
    _ReportReason.misleading => l10n.postReportReasonMisleading,
    _ReportReason.other => l10n.postReportReasonOther,
  };
}

Future<_ReportPayload?> showReportReasonSheet(BuildContext context) async {
  return showAtalaiaBottomSheet<_ReportPayload>(
    context,
    builder: (context) {
      final l10n = t(context);
      var reason = _ReportReason.spam;
      final other = TextEditingController();
      return StatefulBuilder(
        builder: (context, setState) {
          final bottomInset = MediaQuery.viewInsetsOf(context).bottom;
          final canSubmit = reason != _ReportReason.other || other.text.trim().isNotEmpty;

          return SafeArea(
            child: Padding(
              padding: EdgeInsets.only(bottom: bottomInset),
              child: Column(
                mainAxisSize: MainAxisSize.min,
                children: [
                  const SizedBox(height: 8),
                  Padding(
                    padding: EdgeInsets.symmetric(horizontal: 16),
                    child: Align(
                      alignment: Alignment.centerLeft,
                      child: Text(l10n.postActionReport, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 18)),
                    ),
                  ),
                  const SizedBox(height: 8),
                  RadioGroup<_ReportReason>(
                    groupValue: reason,
                    onChanged: (v) => setState(() => reason = v ?? reason),
                    child: Column(
                      mainAxisSize: MainAxisSize.min,
                      children: _ReportReason.values
                          .map(
                            (r) => RadioListTile<_ReportReason>(
                              value: r,
                              title: Text(_reportReasonLabel(l10n, r)),
                            ),
                          )
                          .toList(growable: false),
                    ),
                  ),
                  if (reason == _ReportReason.other) ...[
                    Padding(
                      padding: const EdgeInsets.fromLTRB(16, 0, 16, 12),
                      child: AtalaiaTextField(
                        controller: other,
                        onChanged: (_) => setState(() {}),
                        maxLines: 3,
                        minLines: 2,
                        hintText: l10n.postReportExplainHint,
                      ),
                    ),
                  ],
                  Padding(
                    padding: const EdgeInsets.fromLTRB(16, 0, 16, 16),
                    child: SizedBox(
                      width: double.infinity,
                      child: PrimaryButton(
                        onPressed: canSubmit
                            ? () {
                                Navigator.of(context).pop(
                                  _ReportPayload(reason: reason, otherText: other.text.trim()),
                                );
                              }
                            : null,
                        label: l10n.postReportSubmit,
                      ),
                    ),
                  ),
                ],
              ),
            ),
          );
        },
      );
    },
  );
}

Future<void> showPostActionsSheet(
  BuildContext context, {
  required PostModel post,
}) async {
  final l10n = t(context);
  final session = SessionScope.of(context).value;
  final repo = RepoScope.of(context);
  final isAuthor = session is AuthSession && session.userId == post.userId;

  final choice = await showAtalaiaBottomSheet<String>(
    context,
    builder: (context) {
      return SafeArea(
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            if (!isAuthor) ...[
              ListTile(
                leading: const Icon(Icons.flag_outlined),
                title: Text(l10n.postActionReport),
                onTap: () => Navigator.pop(context, 'report'),
              ),
              ListTile(
                leading: const Icon(Icons.link),
                title: Text(l10n.postActionCopyLink),
                onTap: () => Navigator.pop(context, 'copy'),
              ),
              ListTile(
                leading: const Icon(Icons.visibility_off_outlined),
                title: Text(l10n.postActionHidePost),
                onTap: () => Navigator.pop(context, 'hide'),
              ),
              ListTile(
                leading: const Icon(Icons.person_remove_outlined),
                title: Text(l10n.postActionUnfollow),
                onTap: () => Navigator.pop(context, 'unfollow'),
              ),
            ] else ...[
              ListTile(
                leading: const Icon(Icons.visibility_off_outlined),
                title: Text(l10n.postActionHidePost),
                onTap: () => Navigator.pop(context, 'hide'),
              ),
              ListTile(
                leading: const Icon(Icons.edit_outlined),
                title: Text(l10n.postActionEdit),
                onTap: () => Navigator.pop(context, 'edit'),
              ),
              ListTile(
                leading: const Icon(Icons.delete_outline),
                title: Text(l10n.postActionDelete),
                onTap: () => Navigator.pop(context, 'delete'),
              ),
            ],
            const SizedBox(height: 8),
          ],
        ),
      );
    },
  );

  if (!context.mounted) return;

  switch (choice) {
    case 'report':
      if (!session.isAuthenticated) {
        showCtaSnackBar(context);
        return;
      }
      final selected = await showReportReasonSheet(context);
      if (!context.mounted) return;
      if (selected != null) {
        final s = session;
        if (s is! AuthSession) return;
        await repo.submitReport(
          reporterId: s.userId,
          entityType: ReportEntityType.post,
          entityId: post.id,
          reason: selected.reason.name,
          description: selected.otherText,
          reportedUserId: post.userId,
        );
        if (!context.mounted) return;
        showInfoSnackBar(context, l10n.postSnackReportSent);
      }
    case 'copy':
      showInfoSnackBar(context, l10n.commonLinkCopied);
    case 'hide':
      repo.hidePost(post.id);
      showAtalaiaSnackBar(
        context,
        l10n.postSnackPostHidden,
        actionLabel: l10n.postSnackUndo,
        onAction: () => repo.unhidePost(post.id),
      );
    case 'unfollow':
      if (!session.isAuthenticated) {
        showCtaSnackBar(context);
        return;
      }
      showInfoSnackBar(context, l10n.commonComingSoon);
    case 'edit':
      if (!session.isAuthenticated) {
        showCtaSnackBar(context);
        return;
      }
      final s = session;
      if (s is! AuthSession) return;
      Navigator.of(context).push(
        MaterialPageRoute<void>(
          builder: (_) => PostComposerScreen(
            draft: ComposerDraft(
              initialText: post.body,
              initialKind: post.kind,
              initialVisibility: post.visibility,
              initialLocation: post.location,
              initialRegionPath: post.regionPath,
              existingMediaKind: post.mediaKind,
              existingMediaUrl: post.mediaUrl,
            ),
            editingPostId: post.id,
          ),
        ),
      );
    case 'delete':
      final ok = await showAtalaiaConfirmDialog(
        context,
        title: l10n.postDeleteConfirmTitle,
        message: l10n.postDeleteConfirmMessage,
        confirmLabel: l10n.postDeleteConfirmLabel,
        isDestructive: true,
      );
      if (!context.mounted) return;
      if (ok == true) {
        repo.deletePost(post.id, viewerIsAuthor: isAuthor);
        showInfoSnackBar(context, l10n.postSnackPostDeleted);
      }
    default:
      return;
  }
}

class ShellScreen extends StatefulWidget {
  const ShellScreen({super.key});

  @override
  State<ShellScreen> createState() => _ShellScreenState();
}

class _ShellScreenState extends State<ShellScreen> {
  int _index = 0;
  final GlobalKey<_MapScreenState> _mapKey = GlobalKey<_MapScreenState>();

  void _onMapContextChanged() {
    if (!mounted) return;
    setState(() {});
  }

  @override
  void dispose() {
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final l10n = t(context);
        final value = session.value;
        final cs = Theme.of(context).colorScheme;
        final viewerId = value is AuthSession ? value.userId : null;
        final viewerProfile = viewerId == null ? null : repo.profileForUserId(viewerId);
        final viewerUsername = value is AuthSession ? _usernameForProfile(viewerProfile, userId: value.userId) : null;
        final viewerName = viewerProfile == null ? '' : _displayNameForProfile(viewerProfile).trim();
        final viewerAvatarUrl = viewerProfile?.avatarUrl;
        final mapState = _index == 1 ? _mapKey.currentState : null;
        final activeMapCommunityId = _index == 1 ? mapState?.activeCommunityId : null;
        final activeMapCommunity = activeMapCommunityId == null ? null : repo.findCommunity(activeMapCommunityId);
        final title = (_index == 1 && activeMapCommunityId != null)
            ? (activeMapCommunity?.name ?? l10n.mainTitleCommunity)
            : switch (_index) {
          0 => l10n.appTitle,
          1 => l10n.mainTitleMap,
          2 => l10n.mainTitleMessages,
          3 => viewerName.isNotEmpty ? viewerName : l10n.mainTitleProfile,
          _ => l10n.appTitle,
        };
        final String? leadingLabel = (_index == 1 && activeMapCommunityId == null)
            ? null
            : (_index == 1 && activeMapCommunityId != null)
                ? l10n.mainLeadingFeed
                : switch (_index) {
                    2 => l10n.mainLeadingNewMessage,
                    _ => l10n.mainLeadingCreate,
                  };
        final IconData? leadingIcon = (_index == 1 && activeMapCommunityId == null)
            ? null
            : (_index == 1 && activeMapCommunityId != null)
                ? Icons.rss_feed_outlined
                : switch (_index) {
                    2 => Icons.edit_outlined,
                    _ => Icons.add_box_outlined,
                  };
        final VoidCallback? leadingAction = (_index == 1 && activeMapCommunityId == null)
            ? null
            : () {
                if (_index == 1) {
                  final future = _mapKey.currentState?.openActiveCommunityFeedFromAppBar();
                  if (future == null) return;
                  unawaited(future);
                  return;
                }
                if (!value.isAuthenticated) {
                  showCtaSnackBar(context);
                  return;
                }
                if (_index == 2) {
                  Navigator.of(context).pushNamed(Routes.newMessage);
                  return;
                }
                Navigator.of(context).pushNamed(Routes.createPost);
              };

        final actionLabel = (_index == 1 && activeMapCommunityId != null)
            ? l10n.mainActionChat
            : switch (_index) {
          0 => l10n.mainActionNotifications,
          1 => l10n.mainActionCommunities,
          2 => l10n.mainActionRequests,
          3 => l10n.mainActionMenu,
          _ => l10n.mainActionNotifications,
        };
        final actionIcon = (_index == 1 && activeMapCommunityId != null)
            ? Icons.chat_bubble_outline
            : switch (_index) {
          0 => null,
          1 => Icons.groups_outlined,
          2 => Icons.inbox_outlined,
          3 => Icons.menu_rounded,
          _ => null,
        };

        final VoidCallback action = switch (_index) {
          0 => () => Navigator.of(context).pushNamed(Routes.notifications),
          1 => () {
              final future = activeMapCommunityId != null
                  ? _mapKey.currentState?.openActiveCommunityChatFromAppBar()
                  : _mapKey.currentState?.openCommunitiesSheetFromAppBar();
              if (future == null) return;
              unawaited(future);
            },
          2 => () => showInfoSnackBar(context, l10n.commonComingSoon),
          3 => () => Navigator.of(context).pushNamed(Routes.settings),
          _ => () => Navigator.of(context).pushNamed(Routes.notifications),
        };

        final secondaryActionLabel = null;
        final secondaryActionIcon = null;
        final VoidCallback? onSecondaryAction = null;

        return Scaffold(
          appBar: _AtalaiaMainAppBar(
            title: title,
            leadingIcon: leadingIcon,
            leadingLabel: leadingLabel,
            onLeading: leadingAction,
            actionIcon: actionIcon,
            actionLabel: actionLabel,
            onAction: action,
            secondaryActionIcon: secondaryActionIcon,
            secondaryActionLabel: secondaryActionLabel,
            onSecondaryAction: onSecondaryAction,
            unreadCount: (_index == 0 && viewerId != null) ? repo.unreadNotificationCount(viewerId) : 0,
          ),
          body: IndexedStack(
            index: _index,
            children: [
              HomeFeedScreen(),
              _MapTab(mapKey: _mapKey, onCommunityContextChanged: _onMapContextChanged),
              const DirectInboxScreen(args: null, embedded: true),
              const ProfileScreen(embedded: true),
            ],
          ),
          bottomNavigationBar: NavigationBarTheme(
            data: NavigationBarThemeData(
              height: 72,
              indicatorColor: cs.primary.withValues(alpha: 0.14),
              labelTextStyle: WidgetStateProperty.resolveWith((states) {
                final selected = states.contains(WidgetState.selected);
                return TextStyle(
                  fontSize: 12,
                  fontWeight: selected ? FontWeight.w800 : FontWeight.w600,
                  color: selected ? cs.onSurface : cs.onSurfaceVariant,
                );
              }),
              iconTheme: WidgetStateProperty.resolveWith((states) {
                final selected = states.contains(WidgetState.selected);
                return IconThemeData(
                  size: 28,
                  color: selected ? cs.onSurface : cs.onSurfaceVariant,
                );
              }),
            ),
            child: NavigationBar(
              selectedIndex: _index,
              labelBehavior: NavigationDestinationLabelBehavior.alwaysShow,
              onDestinationSelected: (i) => setState(() => _index = i),
              destinations: [
                NavigationDestination(
                  icon: Icon(Icons.home_outlined),
                  selectedIcon: Icon(Icons.home),
                  label: l10n.navHome,
                ),
                NavigationDestination(
                  icon: Icon(Icons.map_outlined),
                  selectedIcon: Icon(Icons.map),
                  label: l10n.navMap,
                ),
                NavigationDestination(
                  icon: Icon(Icons.send_outlined),
                  selectedIcon: Icon(Icons.send_rounded),
                  label: l10n.navDirect,
                ),
                NavigationDestination(
                  icon: _BottomNavAvatar(
                    isAuthenticated: value is AuthSession,
                    username: viewerUsername,
                    avatarUrl: viewerAvatarUrl,
                    selected: false,
                  ),
                  selectedIcon: _BottomNavAvatar(
                    isAuthenticated: value is AuthSession,
                    username: viewerUsername,
                    avatarUrl: viewerAvatarUrl,
                    selected: true,
                  ),
                  label: l10n.navProfile,
                ),
              ],
            ),
          ),
        );
      },
    );
  }
}

class _MapTab extends StatelessWidget {
