class _AtalaiaMainAppBar extends StatelessWidget implements PreferredSizeWidget {
  const _AtalaiaMainAppBar({
    required this.title,
    this.leadingIcon,
    this.leadingLabel,
    this.onLeading,
    required this.actionLabel,
    required this.onAction,
    required this.unreadCount,
    this.actionIcon,
    this.secondaryActionIcon,
    this.secondaryActionLabel,
    this.onSecondaryAction,
  });

  final String title;
  final IconData? leadingIcon;
  final String? leadingLabel;
  final VoidCallback? onLeading;
  final String actionLabel;
  final VoidCallback onAction;
  final int unreadCount;
  final IconData? actionIcon;
  final IconData? secondaryActionIcon;
  final String? secondaryActionLabel;
  final VoidCallback? onSecondaryAction;

  @override
  Size get preferredSize => const Size.fromHeight(kToolbarHeight);

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    return AppBar(
      elevation: 0,
      scrolledUnderElevation: 0,
      titleSpacing: 0,
      centerTitle: true,
      leading: (leadingIcon != null && leadingLabel != null && onLeading != null)
          ? AtalaiaIconButton(
              icon: leadingIcon!,
              label: leadingLabel!,
              onPressed: onLeading!,
            )
          : null,
      title: SizedBox(
        width: double.infinity,
        child: Center(
          child: Text(
            title,
            style: const TextStyle(fontWeight: FontWeight.w800, letterSpacing: 0.2),
          ),
        ),
      ),
      actions: [
        if (secondaryActionIcon != null && secondaryActionLabel != null && onSecondaryAction != null)
          AtalaiaIconButton(
            icon: secondaryActionIcon!,
            label: secondaryActionLabel!,
            onPressed: onSecondaryAction,
          ),
        actionIcon == null
            ? Semantics(
                button: true,
                label: actionLabel,
                child: Tooltip(
                  message: actionLabel,
                  child: IconButton(
                    onPressed: onAction,
                    constraints: const BoxConstraints(
                      minWidth: AtalaiaTapTarget.min,
                      minHeight: AtalaiaTapTarget.min,
                    ),
                    padding: const EdgeInsets.all(10),
                    icon: Stack(
                      clipBehavior: Clip.none,
                      children: [
                        ShofarIcon(color: cs.onSurface, size: 28),
                        if (unreadCount > 0)
                          Positioned(
                            right: -2,
                            top: -2,
                            child: Container(
                              padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
                              decoration: BoxDecoration(
                                color: cs.error,
                                borderRadius: BorderRadius.circular(999),
                                border: Border.all(color: cs.surface, width: 2),
                              ),
                              constraints: const BoxConstraints(minWidth: 18),
                              child: Text(
                                unreadCount > 99 ? '99+' : '$unreadCount',
                                textAlign: TextAlign.center,
                                style: TextStyle(
                                  color: cs.onError,
                                  fontSize: 11,
                                  fontWeight: FontWeight.w900,
                                  height: 1.1,
                                ),
                              ),
                            ),
                          ),
                      ],
                    ),
                  ),
                ),
              )
            : AtalaiaIconButton(
                icon: actionIcon!,
                label: actionLabel,
                onPressed: onAction,
              ),
        const SizedBox(width: 10),
      ],
    );
  }
}

class _BottomNavAvatar extends StatelessWidget {
  const _BottomNavAvatar({
    required this.isAuthenticated,
    required this.username,
    required this.avatarUrl,
    required this.selected,
  });

  final bool isAuthenticated;
  final String? username;
  final String? avatarUrl;
  final bool selected;

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final borderColor = selected ? cs.onSurface : cs.onSurfaceVariant.withValues(alpha: 0.8);
    final child = isAuthenticated && (username ?? '').trim().isNotEmpty
        ? Avatar(
            name: username!.trim(),
            imageUrl: avatarUrl,
            size: AvatarSize.s32,
          )
        : Icon(Icons.person_outline, color: cs.onSurfaceVariant);

    return Container(
      width: 34,
      height: 34,
      decoration: BoxDecoration(
        shape: BoxShape.circle,
        border: Border.all(color: borderColor, width: selected ? 1.6 : 1.1),
      ),
      alignment: Alignment.center,
      child: child,
    );
  }
}

class AtalaiaPrayingHandsIcon extends StatelessWidget {
  const AtalaiaPrayingHandsIcon({required this.color, this.size = 22, super.key});

  final Color color;
  final double size;

  @override
  Widget build(BuildContext context) {
    return SizedBox(
      width: size,
      height: size,
      child: CustomPaint(painter: _PrayingHandsPainter(color)),
    );
  }
}

class _PrayingHandsPainter extends CustomPainter {
  const _PrayingHandsPainter(this.color);

  final Color color;

  @override
  void paint(Canvas canvas, Size size) {
    final stroke = Paint()
      ..color = color
      ..style = PaintingStyle.stroke
      ..strokeWidth = (size.shortestSide * 0.09).clamp(1.6, 2.2)
      ..strokeCap = StrokeCap.round
      ..strokeJoin = StrokeJoin.round;

    final w = size.width;
    final h = size.height;

    final left = ui.Path()
      ..moveTo(w * 0.14, h * 0.70)
      ..cubicTo(w * 0.10, h * 0.62, w * 0.11, h * 0.50, w * 0.18, h * 0.42)
      ..cubicTo(w * 0.28, h * 0.32, w * 0.40, h * 0.34, w * 0.46, h * 0.41)
      ..cubicTo(w * 0.50, h * 0.46, w * 0.50, h * 0.54, w * 0.47, h * 0.58)
      ..cubicTo(w * 0.44, h * 0.63, w * 0.38, h * 0.67, w * 0.30, h * 0.70)
      ..cubicTo(w * 0.22, h * 0.73, w * 0.16, h * 0.73, w * 0.14, h * 0.70)
      ..close();

    final right = ui.Path()
      ..moveTo(w * 0.78, h * 0.90)
      ..cubicTo(w * 0.90, h * 0.80, w * 0.94, h * 0.62, w * 0.88, h * 0.44)
      ..cubicTo(w * 0.82, h * 0.26, w * 0.72, h * 0.12, w * 0.62, h * 0.10)
      ..cubicTo(w * 0.56, h * 0.10, w * 0.54, h * 0.15, w * 0.54, h * 0.22)
      ..lineTo(w * 0.54, h * 0.52)
      ..cubicTo(w * 0.54, h * 0.60, w * 0.56, h * 0.66, w * 0.60, h * 0.70)
      ..cubicTo(w * 0.66, h * 0.76, w * 0.72, h * 0.82, w * 0.74, h * 0.90)
      ..close();

    canvas.drawPath(left, stroke);
    canvas.drawPath(right, stroke);

    final detail = Paint()
      ..color = color
      ..style = PaintingStyle.stroke
      ..strokeWidth = (stroke.strokeWidth * 0.70).clamp(1.1, 1.7)
      ..strokeCap = StrokeCap.round
      ..strokeJoin = StrokeJoin.round;

    final leftFingers1 = ui.Path()
      ..moveTo(w * 0.26, h * 0.45)
      ..quadraticBezierTo(w * 0.32, h * 0.41, w * 0.38, h * 0.44);
    final leftFingers2 = ui.Path()
      ..moveTo(w * 0.28, h * 0.52)
      ..quadraticBezierTo(w * 0.34, h * 0.48, w * 0.40, h * 0.51);
    final leftThumb = ui.Path()
      ..moveTo(w * 0.41, h * 0.60)
      ..quadraticBezierTo(w * 0.45, h * 0.62, w * 0.46, h * 0.66);

    final rightFingers1 = ui.Path()
      ..moveTo(w * 0.64, h * 0.20)
      ..quadraticBezierTo(w * 0.68, h * 0.26, w * 0.70, h * 0.34);
    final rightFingers2 = ui.Path()
      ..moveTo(w * 0.60, h * 0.22)
      ..quadraticBezierTo(w * 0.62, h * 0.30, w * 0.64, h * 0.38);
    final rightThumb = ui.Path()
      ..moveTo(w * 0.60, h * 0.58)
      ..quadraticBezierTo(w * 0.56, h * 0.60, w * 0.54, h * 0.64);

    canvas.drawPath(leftFingers1, detail);
    canvas.drawPath(leftFingers2, detail);
    canvas.drawPath(leftThumb, detail);
    canvas.drawPath(rightFingers1, detail);
    canvas.drawPath(rightFingers2, detail);
    canvas.drawPath(rightThumb, detail);
  }

  @override
  bool shouldRepaint(covariant _PrayingHandsPainter oldDelegate) => oldDelegate.color != color;
}

class AdCard extends StatefulWidget {
  const AdCard({
    required this.slotId,
    required this.placement,
    this.margin,
    super.key,
  });

  final String slotId;
  final String placement;
  final EdgeInsetsGeometry? margin;

  @override
  State<AdCard> createState() => _AdCardState();
}

class _AdCardState extends State<AdCard> {
  ScrollPosition? _position;
  Timer? _impressionTimer;
  var _impressionFired = false;

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();
    _attachScrollable();
    WidgetsBinding.instance.addPostFrameCallback((_) => _checkVisibility());
  }

  void _attachScrollable() {
    final next = Scrollable.maybeOf(context)?.position;
    if (identical(next, _position)) return;
    _position?.removeListener(_checkVisibility);
    _position = next;
    _position?.addListener(_checkVisibility);
  }

  bool _isAtLeastHalfVisible() {
    final position = _position;
    if (position == null) return false;
    final renderObject = context.findRenderObject();
    if (renderObject is! RenderBox) return false;
    final viewport = RenderAbstractViewport.of(renderObject);

    final reveal = viewport.getOffsetToReveal(renderObject, 0);
    final top = reveal.offset - position.pixels;
    final height = renderObject.size.height;
    if (height <= 0) return false;
    final bottom = top + height;
    final viewportDim = position.viewportDimension;

    final visibleHeight = math.max(0.0, math.min(bottom, viewportDim) - math.max(top, 0.0));
    return (visibleHeight / height) >= 0.5;
  }

  void _checkVisibility() {
    if (!mounted) return;
    if (_impressionFired) return;

    final repo = RepoScope.of(context);
    if (repo.isAdSlotHidden(widget.slotId)) return;
    final slot = repo.adSlotFor(slotId: widget.slotId, placement: widget.placement);
    if (slot.status == _AdSlotStatus.loading) {
      _impressionTimer?.cancel();
      _impressionTimer = null;
      return;
    }

    final halfVisible = _isAtLeastHalfVisible();
    if (!halfVisible) {
      _impressionTimer?.cancel();
      _impressionTimer = null;
      return;
    }

    _impressionTimer ??= Timer(const Duration(seconds: 1), () {
      if (!mounted) return;
      final repo = RepoScope.of(context);
      if (repo.isAdSlotHidden(widget.slotId)) return;
      final slot = repo.adSlotFor(slotId: widget.slotId, placement: widget.placement);
      if (slot.status == _AdSlotStatus.loading) return;
      if (!_isAtLeastHalfVisible()) return;
      repo.markAdImpression(
        slotId: widget.slotId,
        placement: widget.placement,
        provider: slot.creative.provider,
        campaignId: slot.creative.campaignId,
        creativeId: slot.creative.id,
      );
      if (!mounted) return;
      setState(() => _impressionFired = true);
    });
  }

  Future<void> _openDestination(AdCreative creative) async {
    final repo = RepoScope.of(context);
    repo.trackAdClick(
      slotId: widget.slotId,
      placement: widget.placement,
      provider: creative.provider,
      campaignId: creative.campaignId,
      creativeId: creative.id,
    );

    final uri = Uri.tryParse(creative.destinationUrl);
    if (uri == null) {
      showInfoSnackBar(context, t(context).commonInvalidLink);
      return;
    }
    final ok = await launchUrl(uri, mode: LaunchMode.inAppBrowserView);
    if (!context.mounted) return;
    if (!ok) {
      await Clipboard.setData(ClipboardData(text: uri.toString()));
      if (!context.mounted) return;
      showInfoSnackBar(context, t(context).commonLinkCopied);
    }
  }

  @override
  void dispose() {
    _position?.removeListener(_checkVisibility);
    _impressionTimer?.cancel();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    if (repo.isAdSlotHidden(widget.slotId)) return const SizedBox.shrink();

    final slot = repo.adSlotFor(slotId: widget.slotId, placement: widget.placement);
    return switch (slot.status) {
      _AdSlotStatus.loading => _AdSkeleton(margin: widget.margin),
      _AdSlotStatus.ready || _AdSlotStatus.fallback => _AdReadyCard(
        margin: widget.margin,
        creative: slot.creative,
        onOpen: () => _openDestination(slot.creative),
        onHide: () {
          repo.trackEvent('ad_dismiss', <String, Object?>{
            'placement': widget.placement,
            'slotId': widget.slotId,
            'provider': slot.creative.provider,
            'creativeId': slot.creative.id,
          });
          repo.hideAdSlot(widget.slotId);
          showInfoSnackBar(context, t(context).adsHiddenSnack);
        },
      ),
    };
  }
}

