class PostCard extends StatelessWidget {
  const PostCard({
    required this.post,
    required this.isAuthenticated,
    required this.onOpenPost,
    required this.onLike,
    required this.onPray,
    required this.onComment,
    required this.onShare,
    required this.onSave,
    this.margin = const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
    this.compact = false,
    super.key,
  });

  final PostModel post;
  final bool isAuthenticated;
  final VoidCallback onOpenPost;
  final VoidCallback onLike;
  final VoidCallback onPray;
  final VoidCallback onComment;
  final VoidCallback onShare;
  final VoidCallback onSave;
  final EdgeInsets margin;
  final bool compact;

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final l10n = t(context);
    final cs = Theme.of(context).colorScheme;
    final identity = _identityForUserId(repo, post.userId, legacyVerified: post.isVerified, userFallback: l10n.commonUserFallback);
    final session = SessionScope.of(context).value;
    final viewerProfile = session is AuthSession ? repo.profileForUserId(session.userId) : null;
    final viewerName = viewerProfile == null ? null : _displayNameForProfile(viewerProfile, userFallback: l10n.commonUserFallback).trim();
    void safePray() {
      if (!isAuthenticated) {
        showCtaSnackBar(context);
        return;
      }
      onPray();
    }

    Widget actionWithCount({
      required IconData icon,
      required String label,
      required VoidCallback onTap,
      required int count,
      Color? color,
    }) {
      final showCount = count > 0;
      final fg = color ?? cs.onSurfaceVariant;
      return Semantics(
        button: true,
        label: showCount ? '$label ($count)' : label,
        child: Tooltip(
          message: label,
          child: Material(
            color: Colors.transparent,
            child: InkWell(
              borderRadius: BorderRadius.circular(14),
              onTap: onTap,
              child: ConstrainedBox(
                constraints: const BoxConstraints(minWidth: AtalaiaTapTarget.min, minHeight: AtalaiaTapTarget.min),
                child: Padding(
                  padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 10),
                  child: Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Icon(icon, size: 22, color: fg),
                      if (showCount) ...[
                        const SizedBox(width: 6),
                        Text(
                          '$count',
                          style: TextStyle(color: fg, fontWeight: FontWeight.w800, fontSize: 12, height: 1.0),
                        ),
                      ],
                    ],
                  ),
                ),
              ),
            ),
          ),
        ),
      );
    }

    Widget prayAction() {
      final l10n = t(context);
      final count = post.prayerCount;
      final showCount = count > 0;
      if (post.viewerHasPrayed) {
        return actionWithCount(
          icon: Icons.volunteer_activism,
          label: l10n.postPrayAction,
          onTap: safePray,
          count: count,
          color: const Color(0xFF2E7D32),
        );
      }

      final fg = cs.onSurfaceVariant;
      return Semantics(
        button: true,
        label: showCount ? '${l10n.postPrayAction} ($count)' : l10n.postPrayAction,
        child: Tooltip(
          message: l10n.postPrayAction,
          child: Material(
            color: Colors.transparent,
            child: InkWell(
              borderRadius: BorderRadius.circular(14),
              onTap: safePray,
              child: ConstrainedBox(
                constraints: const BoxConstraints(minWidth: AtalaiaTapTarget.min, minHeight: AtalaiaTapTarget.min),
                child: Padding(
                  padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 10),
                  child: Row(
                    mainAxisSize: MainAxisSize.min,
                    children: [
                      Icon(Icons.volunteer_activism_outlined, size: 22, color: fg),
                      if (showCount) ...[
                        const SizedBox(width: 6),
                        Text(
                          '$count',
                          style: TextStyle(color: fg, fontWeight: FontWeight.w800, fontSize: 12, height: 1.0),
                        ),
                      ],
                      const SizedBox(width: 8),
                      Text(
                        l10n.postPrayAction,
                        style: TextStyle(color: fg, fontWeight: FontWeight.w900, fontSize: 12, height: 1.0),
                      ),
                    ],
                  ),
                ),
              ),
            ),
          ),
        ),
      );
    }

    String? prayerByline() {
      final l10n = t(context);
      final total = post.prayerCount;
      if (total <= 0) return null;
      final cached = repo.prayerUsernamesForPost(post.id);
      if (cached.isEmpty) {
        unawaited(repo.prefetchPrayerUsernamesForPost(post.id));
      }
      final first = cached.isNotEmpty ? cached.first : (post.viewerHasPrayed ? viewerName : null);
      if (total == 1) {
        return first == null ? l10n.postPrayedByOnePerson : l10n.postPrayedByName(first);
      }
      if (total == 2) {
        if (first != null) return l10n.postPrayedByNameAndOneOther(first);
        return l10n.postPrayedByTwoPeople;
      }
      if (first != null) return l10n.postPrayedByNameAndOthers(first);
      return l10n.postPrayedByManyPeople(total);
    }

    return Card(
      elevation: 0,
      surfaceTintColor: Colors.transparent,
      clipBehavior: Clip.antiAlias,
      shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(18)),
      margin: margin,
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Padding(
            padding: EdgeInsets.fromLTRB(12, compact ? 10 : 12, 12, 0),
            child: Row(
              children: [
                InkWell(
                  onTap: () {
                    Navigator.of(context).pushNamed(
                      Routes.userProfile,
                      arguments: UserProfileArgs(userId: post.userId),
                    );
                  },
                  customBorder: const CircleBorder(),
                  child: Avatar(name: identity.avatarName, imageUrl: identity.avatarUrl, size: AvatarSize.s44),
                ),
                const SizedBox(width: 10),
                Expanded(
                  child: InkWell(
                    onTap: () {
                      Navigator.of(context).pushNamed(
                        Routes.userProfile,
                        arguments: UserProfileArgs(userId: post.userId),
                      );
                    },
                    child: Column(
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Row(
                          children: [
                            Expanded(
                              child: Text(
                                identity.displayName,
                                maxLines: 1,
                                overflow: TextOverflow.ellipsis,
                                style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 15, letterSpacing: 0.1),
                              ),
                            ),
                            if (identity.isVerified) ...[
                              const SizedBox(width: 6),
                              Icon(Icons.verified, size: 16, color: context.brand.verifiedBlue),
                            ],
                            const SizedBox(width: 10),
                            Text(
                              _relativeTime(context, post.createdAt),
                              style: AtalaiaText.meta(context).copyWith(fontSize: 11),
                            ),
                          ],
                        ),
                      ],
                    ),
                  ),
                ),
                AtalaiaIconButton(
                  icon: Icons.more_horiz_rounded,
                  label: t(context).postMore,
                  color: cs.onSurfaceVariant,
                  onPressed: () => showPostActionsSheet(context, post: post),
                ),
              ],
            ),
          ),
          if (post.mediaKind != null) ...[
            SizedBox(height: compact ? 10 : 12),
            PostMedia(
              kind: post.mediaKind!,
              mediaUrl: post.mediaUrl,
              onTap: () => unawaited(
                _openPostMediaViewer(
                  context,
                  kind: post.mediaKind!,
                  mediaUrl: post.mediaUrl,
                ),
              ),
              onDoubleTap: () {
                if (!post.viewerHasLiked) onLike();
              },
            ),
          ],
          SizedBox(height: compact ? 8 : 10),
          Padding(
            padding: const EdgeInsets.symmetric(horizontal: 12),
            child: Row(
              children: [
                prayAction(),
                actionWithCount(
                  icon: post.viewerHasLiked ? Icons.favorite : Icons.favorite_border,
                  label: t(context).postLike,
                  onTap: onLike,
                  count: post.likeCount,
                  color: post.viewerHasLiked ? cs.error : null,
                ),
                actionWithCount(
                  icon: Icons.chat_bubble_outline,
                  label: t(context).postComment,
                  onTap: onComment,
                  count: post.commentCount,
                ),
                actionWithCount(
                  icon: Icons.send_rounded,
                  label: t(context).postShare,
                  onTap: onShare,
                  count: 0,
                ),
              ],
            ),
          ),
          Builder(
            builder: (context) {
              final byline = prayerByline();
              if (byline == null) return SizedBox(height: compact ? 10 : 12);
              return Padding(
                padding: const EdgeInsets.fromLTRB(12, 6, 12, 0),
                child: Text(
                  byline,
                  maxLines: 1,
                  overflow: TextOverflow.ellipsis,
                  style: AtalaiaText.meta(context).copyWith(
                    fontSize: 12,
                    fontWeight: FontWeight.w800,
                    color: cs.onSurfaceVariant,
                  ),
                ),
              );
            },
          ),
          Padding(
            padding: EdgeInsets.fromLTRB(12, 6, 12, compact ? 10 : 12),
            child: ExpandablePostText(
              text: post.body,
              maxLines: compact ? 2 : 3,
              onTap: onOpenPost,
            ),
          ),
        ],
      ),
    );
  }
}

