String _formatVideoDuration(Duration d) {
  final totalSeconds = d.inSeconds;
  if (totalSeconds <= 0) return '';
  final minutes = totalSeconds ~/ 60;
  final seconds = totalSeconds % 60;
  if (minutes >= 60) {
    final hours = minutes ~/ 60;
    final remMin = minutes % 60;
    return '${hours}:${remMin.toString().padLeft(2, '0')}:${seconds.toString().padLeft(2, '0')}';
  }
  return '${minutes}:${seconds.toString().padLeft(2, '0')}';
}

class PostMedia extends StatefulWidget {
  const PostMedia({
    required this.kind,
    required this.mediaUrl,
    required this.onTap,
    required this.onDoubleTap,
    super.key,
  });

  final String kind;
  final String? mediaUrl;
  final VoidCallback onTap;
  final VoidCallback onDoubleTap;

  @override
  State<PostMedia> createState() => _PostMediaState();
}

class _PostMediaState extends State<PostMedia> {
  VideoPlayerController? _vc;
  bool _muted = true;

  bool get _isVideo => widget.kind == 'video';
  String? get _resolvedUrl => _normalizeSupabaseMediaPublicUrl(widget.mediaUrl);

  @override
  void initState() {
    super.initState();
    if (_isVideo) {
      unawaited(_initVideoCover());
    }
  }

  @override
  void didUpdateWidget(covariant PostMedia oldWidget) {
    super.didUpdateWidget(oldWidget);
    final oldUrl = _normalizeSupabaseMediaPublicUrl(oldWidget.mediaUrl);
    final nextUrl = _resolvedUrl;
    final changed = oldWidget.kind != widget.kind || oldUrl != nextUrl;
    if (changed) {
      unawaited(_resetVideo());
    }
  }

  Future<void> _resetVideo() async {
    final old = _vc;
    _vc = null;
    old?.dispose();
    if (mounted) setState(() {});
    if (_isVideo) {
      await _initVideoCover();
    }
  }

  Future<void> _initVideoCover() async {
    final url = _resolvedUrl;
    if (!_isVideo || url == null || url.isEmpty) return;
    if (_vc != null) return;
    final vc = VideoPlayerController.networkUrl(Uri.parse(url));
    _vc = vc;
    try {
      await vc.initialize();
      if (!mounted) return;
      await vc.setLooping(true);
      await vc.setVolume(0);
      await vc.pause();
    } catch (_) {}
    if (mounted) setState(() {});
  }

  void _toggleInlinePlayPause() {
    if (!_isVideo) return;
    final vc = _vc;
    if (vc == null || !vc.value.isInitialized) {
      unawaited(_initVideoCover().then((_) {
        final next = _vc;
        if (!mounted || next == null || !next.value.isInitialized) return;
        unawaited(next.play());
        setState(() {});
      }));
      return;
    }
    if (vc.value.isPlaying) {
      unawaited(vc.pause());
      setState(() {});
      return;
    }
    unawaited(vc.play());
    setState(() {});
  }

  void _toggleMute() {
    final vc = _vc;
    if (!_isVideo || vc == null || !vc.value.isInitialized) return;
    final next = !_muted;
    setState(() => _muted = next);
    unawaited(vc.setVolume(next ? 0 : 1));
  }

  @override
  void dispose() {
    _vc?.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final isVideo = _isVideo;
    final url = _resolvedUrl;
    final hasMedia = url != null && url.isNotEmpty;
    final vc = _vc;
    final ready = isVideo && vc != null && vc.value.isInitialized;
    final playing = ready && vc.value.isPlaying;
    final durationLabel = ready ? _formatVideoDuration(vc.value.duration) : '';

    return GestureDetector(
      onTap: isVideo ? _toggleInlinePlayPause : widget.onTap,
      onLongPress: isVideo ? widget.onTap : null,
      onDoubleTap: widget.onDoubleTap,
      child: ClipRRect(
        borderRadius: BorderRadius.circular(12),
        child: AspectRatio(
          aspectRatio: 4 / 5,
          child: Stack(
            children: [
              Positioned.fill(
                child: !isVideo
                    ? (hasMedia
                        ? Image.network(
                            url,
                            fit: BoxFit.cover,
                            errorBuilder: (_, __, ___) => Container(
                              color: cs.surfaceContainerHighest,
                              child: Center(
                                child: Icon(
                                  Icons.broken_image_outlined,
                                  size: 48,
                                  color: cs.outline,
                                ),
                              ),
                            ),
                          )
                        : Container(
                            color: cs.surfaceContainerHighest,
                            child: Center(
                              child: Icon(Icons.image_outlined, size: 48, color: cs.outline),
                            ),
                          ))
                    : (!ready
                        ? Container(
                            color: cs.surfaceContainerHighest,
                            child: Center(
                              child: Icon(Icons.play_circle_outline, size: 48, color: cs.outline),
                            ),
                          )
                        : FittedBox(
                            fit: BoxFit.cover,
                            child: SizedBox(
                              width: vc.value.size.width,
                              height: vc.value.size.height,
                              child: VideoPlayer(vc),
                            ),
                          )),
              ),
              if (isVideo)
                Positioned.fill(
                  child: IgnorePointer(
                    child: DecoratedBox(
                      decoration: BoxDecoration(
                        gradient: LinearGradient(
                          begin: Alignment.topCenter,
                          end: Alignment.bottomCenter,
                          colors: [
                            Colors.black.withValues(alpha: 0.15),
                            Colors.transparent,
                            Colors.black.withValues(alpha: 0.35),
                          ],
                        ),
                      ),
                    ),
                  ),
                ),
              if (isVideo && (!playing))
                const Center(
                  child: Icon(Icons.play_circle_outline, color: Colors.white70, size: 88),
                ),
              if (isVideo)
                Positioned(
                  right: 10,
                  top: 10,
                  child: InkWell(
                    onTap: widget.onTap,
                    borderRadius: BorderRadius.circular(999),
                    child: Container(
                      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
                      decoration: BoxDecoration(
                        color: Colors.black.withValues(alpha: 0.55),
                        borderRadius: BorderRadius.circular(999),
                      ),
                      child: const Icon(Icons.fullscreen, color: Colors.white, size: 18),
                    ),
                  ),
                ),
              if (isVideo && ready)
                Positioned(
                  left: 10,
                  bottom: 10,
                  child: InkWell(
                    onTap: _toggleMute,
                    borderRadius: BorderRadius.circular(999),
                    child: Container(
                      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
                      decoration: BoxDecoration(
                        color: Colors.black.withValues(alpha: 0.55),
                        borderRadius: BorderRadius.circular(999),
                      ),
                      child: Icon(_muted ? Icons.volume_off : Icons.volume_up, color: Colors.white, size: 18),
                    ),
                  ),
                ),
              if (isVideo && durationLabel.isNotEmpty)
                Positioned(
                  right: 10,
                  bottom: 10,
                  child: Container(
                    padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                    decoration: BoxDecoration(
                      color: Colors.black.withValues(alpha: 0.6),
                      borderRadius: BorderRadius.circular(999),
                    ),
                    child: Text(
                      durationLabel,
                      style: const TextStyle(color: Colors.white, fontWeight: FontWeight.w600),
                    ),
                  ),
                ),
            ],
          ),
        ),
      ),
    );
  }
}

Future<void> _openPostMediaViewer(
  BuildContext context, {
  required String kind,
  required String? mediaUrl,
}) async {
  final url = _normalizeSupabaseMediaPublicUrl(mediaUrl);
  if (url == null || url.isEmpty) return;
  await Navigator.of(context).push(
    MaterialPageRoute<void>(
      builder: (_) => _PostMediaViewerScreen(kind: kind, url: url),
      fullscreenDialog: true,
    ),
  );
}

class _PostMediaViewerScreen extends StatefulWidget {
  const _PostMediaViewerScreen({required this.kind, required this.url});

  final String kind;
  final String url;

  @override
  State<_PostMediaViewerScreen> createState() => _PostMediaViewerScreenState();
}

class _PostMediaViewerScreenState extends State<_PostMediaViewerScreen> {
  VideoPlayerController? _videoController;
  bool _muted = true;
  bool _showChrome = true;

  @override
  void initState() {
    super.initState();
    if (widget.kind == 'video') {
      unawaited(_initVideo());
    }
  }

  Future<void> _initVideo() async {
    final vc = VideoPlayerController.networkUrl(Uri.parse(widget.url));
    _videoController = vc;
    try {
      await vc.initialize();
      if (!mounted) return;
      vc.addListener(_handleVideoTick);
      await vc.setLooping(true);
      await vc.setVolume(0);
      await vc.play();
    } catch (_) {}
    if (mounted) setState(() {});
  }

  void _handleVideoTick() {
    if (!mounted) return;
    setState(() {});
  }

  @override
  void dispose() {
    _videoController?.removeListener(_handleVideoTick);
    _videoController?.dispose();
    super.dispose();
  }

  void _togglePlayPause() {
    final vc = _videoController;
    if (widget.kind != 'video' || vc == null || !vc.value.isInitialized) return;
    if (vc.value.isPlaying) {
      vc.pause();
      setState(() => _showChrome = true);
      return;
    }
    vc.play();
    setState(() => _showChrome = false);
  }

  void _toggleMute() {
    final vc = _videoController;
    if (widget.kind != 'video' || vc == null) return;
    final next = !_muted;
    setState(() => _muted = next);
    unawaited(vc.setVolume(next ? 0 : 1));
  }

  double _progress() {
    final vc = _videoController;
    if (vc == null || !vc.value.isInitialized) return 0;
    final d = vc.value.duration.inMilliseconds;
    if (d <= 0) return 0;
    return (vc.value.position.inMilliseconds / d).clamp(0.0, 1.0);
  }

  Widget _buildBody() {
    if (widget.kind != 'video') {
      return Center(
        child: InteractiveViewer(
          minScale: 1,
          maxScale: 4,
          child: Image.network(
            widget.url,
            fit: BoxFit.contain,
            errorBuilder: (_, __, ___) => const Center(
              child: Icon(Icons.broken_image_outlined, color: Colors.white70, size: 72),
            ),
          ),
        ),
      );
    }

    final vc = _videoController;
    if (vc == null || !vc.value.isInitialized) {
      return const Center(child: CircularProgressIndicator());
    }

    return GestureDetector(
      behavior: HitTestBehavior.opaque,
      onTap: _togglePlayPause,
      onLongPressStart: (_) => unawaited(vc.pause()),
      onLongPressEnd: (_) => unawaited(vc.play()),
      child: FittedBox(
        fit: BoxFit.cover,
        child: SizedBox(
          width: vc.value.size.width,
          height: vc.value.size.height,
          child: VideoPlayer(vc),
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final isVideo = widget.kind == 'video';
    final vc = _videoController;

    return Scaffold(
      backgroundColor: Colors.black,
      body: SafeArea(
        child: Stack(
          children: [
            Positioned.fill(child: _buildBody()),
            if (isVideo)
              Positioned.fill(
                child: IgnorePointer(
                  child: DecoratedBox(
                    decoration: BoxDecoration(
                      gradient: LinearGradient(
                        begin: Alignment.topCenter,
                        end: Alignment.bottomCenter,
                        colors: [
                          Colors.black.withValues(alpha: 0.35),
                          Colors.transparent,
                          Colors.black.withValues(alpha: 0.55),
                        ],
                      ),
                    ),
                  ),
                ),
              ),
            Positioned(
              left: 8,
              top: 8,
              child: IconButton(
                onPressed: () => Navigator.of(context).maybePop(),
                icon: const Icon(Icons.close, color: Colors.white),
              ),
            ),
            if (isVideo)
              Positioned(
                right: 8,
                top: 8,
                child: IconButton(
                  onPressed: _toggleMute,
                  icon: Icon(_muted ? Icons.volume_off : Icons.volume_up, color: Colors.white),
                ),
              ),
            if (isVideo)
              Positioned(
                left: 0,
                right: 0,
                bottom: 0,
                child: AnimatedOpacity(
                  duration: const Duration(milliseconds: 120),
                  opacity: (_showChrome || (vc?.value.isPlaying ?? false) == false) ? 1 : 0.35,
                  child: Padding(
                    padding: const EdgeInsets.fromLTRB(14, 0, 14, 12),
                    child: ClipRRect(
                      borderRadius: BorderRadius.circular(999),
                      child: LinearProgressIndicator(
                        value: _progress(),
                        minHeight: 4,
                        backgroundColor: Colors.white24,
                        valueColor: AlwaysStoppedAnimation<Color>(cs.primary),
                      ),
                    ),
                  ),
                ),
              ),
            if (isVideo && (vc == null || !vc.value.isPlaying))
              const Center(
                child: Icon(Icons.play_circle_outline, color: Colors.white70, size: 88),
              ),
          ],
        ),
      ),
    );
  }
}

class HomeFeedScreen extends StatefulWidget {
  const HomeFeedScreen({super.key});

  @override
  State<HomeFeedScreen> createState() => _HomeFeedScreenState();
}

class _HomeFeedScreenState extends State<HomeFeedScreen> {
  final ScrollController _scrollController = ScrollController();
  var _refreshing = false;
  var _feedViewTracked = false;
  var _maxScrollDepthTracked = 0;
  var _campaignSort = _CampaignSort.nearby;
  var _locationLabel = 'Mundo';
  var _locationPath = 'world';

  String _scopeForPath(String path) {
    final parts = path.split('/').where((p) => p.trim().isNotEmpty).length;
    return switch (parts) {
      <= 1 => 'world',
      3 => 'country',
      4 => 'state',
      >= 5 => 'city',
      _ => 'world',
    };
  }

  LatLng _centerForFeedPath(String path) {
    return switch (path) {
      'world' => const LatLng(0, 0),
      'world/sa' => const LatLng(-15.6, -57.8),
      'world/sa/br' => const LatLng(-14.2, -51.9),
      'world/sa/br/go' => const LatLng(-15.9, -49.9),
      'world/sa/br/go/goiania' => const LatLng(-16.6869, -49.2648),
      'world/sa/br/sp/sao-paulo' => const LatLng(-23.5505, -46.6333),
      _ => const LatLng(0, 0),
    };
  }

  LocationRef _locationRefForFeed() {
    return LocationRef(
      id: _locationPath,
      name: _locationLabel,
      level: _scopeForPath(_locationPath),
      path: _locationPath,
      center: _centerForFeedPath(_locationPath),
      postsCount: 0,
      prayersCount: 0,
    );
  }

  Future<void> _onRefresh() async {
    setState(() => _refreshing = true);
    final repo = RepoScope.of(context);
    if (repo.supabase != null && !repo.isOffline) {
      final center = _centerForFeedPath(_locationPath);
      await repo.refreshFeedForCurrentSession(
        scope: _scopeForPath(_locationPath),
        locationPath: _locationPath,
        sort: 'recent',
        lat: center.latitude,
        lng: center.longitude,
      );
      await repo.fetchStoriesForHomeSocial();
    } else {
      await Future<void>.delayed(const Duration(milliseconds: 450));
    }
    if (!mounted) return;
    setState(() => _refreshing = false);
  }

  @override
  void initState() {
    super.initState();
    _scrollController.addListener(_onScroll);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      if (_feedViewTracked) return;
      _feedViewTracked = true;
      final repo = RepoScope.of(context);
      repo.trackEvent('feed_view', const <String, Object?>{});
      unawaited(repo.fetchStoriesForHomeSocial());
    });
  }

  void _onScroll() {
    if (!_scrollController.hasClients) return;
    final max = _scrollController.position.maxScrollExtent;
    if (max <= 0) return;
    final p = (_scrollController.position.pixels / max).clamp(0.0, 1.0);
    final nextDepth = switch (p) {
      >= 0.999 => 100,
      >= 0.75 => 75,
      >= 0.50 => 50,
      >= 0.25 => 25,
      _ => 0,
    };
    if (nextDepth <= _maxScrollDepthTracked) return;
    _maxScrollDepthTracked = nextDepth;
    RepoScope.of(context).trackEvent('feed_scroll_depth', <String, Object?>{'depth': nextDepth});
  }

  @override
  void dispose() {
    _scrollController.removeListener(_onScroll);
    _scrollController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final visibleBase = repo.visiblePostsFor(session.value);
        final visible = visibleBase.where((p) => p.communityId == null).toList(growable: false);
        final now = DateTime.now();
        final campaignsAll = repo
            .campaignsForRegion(session.value, _locationPath, communityId: null)
            .where((c) => c.status == CampaignStatus.active)
            .toList(growable: false);
        final center = _centerForFeedPath(_locationPath);
        int byUrgency(CampaignModel a, CampaignModel b) {
          final au = a.isUrgent ? 1 : 0;
          final bu = b.isUrgent ? 1 : 0;
          if (au != bu) return bu.compareTo(au);
          final ad = a.deadline;
          final bd = b.deadline;
          if (ad != null && bd != null) return ad.compareTo(bd);
          if (ad != null) return -1;
          if (bd != null) return 1;
          return b.createdAt.compareTo(a.createdAt);
        }

        int byPopular(CampaignModel a, CampaignModel b) {
          final dc = b.donationsCount.compareTo(a.donationsCount);
          if (dc != 0) return dc;
          final rc = b.raisedAmount.compareTo(a.raisedAmount);
          if (rc != 0) return rc;
          return b.createdAt.compareTo(a.createdAt);
        }

        int byNearby(CampaignModel a, CampaignModel b) {
          final ap = _campaignCenter(a);
          final bp = _campaignCenter(b);
          final ad = ap == null ? 1e18 : _distanceKm(center, ap);
          final bd = bp == null ? 1e18 : _distanceKm(center, bp);
          final d = ad.compareTo(bd);
          if (d != 0) return d;
          return byUrgency(a, b);
        }

        campaignsAll.sort(
          switch (_campaignSort) {
            _CampaignSort.nearby => byNearby,
            _CampaignSort.urgent => byUrgency,
            _CampaignSort.popular => byPopular,
          },
        );
        final campaignsPreview = campaignsAll.length <= 3 ? campaignsAll : campaignsAll.take(3).toList(growable: false);
        final alertsAll = (_locationPath == 'world' ? repo.visibleAlertsFor(session.value) : repo.alertsForRegion(session.value, _locationPath))
            .where((a) => a.communityId == null)
            .where((a) => a.status == AlertStatus.active)
            .where((a) => a.expiresAt.isAfter(now))
            .toList(growable: false)
          ..sort((a, b) => b.createdAt.compareTo(a.createdAt));
        final alertsPreview = alertsAll.length <= 3 ? alertsAll : alertsAll.take(3).toList(growable: false);
        final hasHighlights = campaignsPreview.isNotEmpty || alertsPreview.isNotEmpty;
        final isAuthenticated = session.value.isAuthenticated;
        final itemCount = visible.length + (visible.length ~/ 15);

        return Column(
          children: [
            if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
            Expanded(
              child: RefreshIndicator(
                onRefresh: _onRefresh,
                child: _refreshing
                    ? ListView.builder(
                        controller: _scrollController,
                        physics: const AlwaysScrollableScrollPhysics(),
                        itemCount: 6,
                        itemBuilder: (context, index) {
                          return PostCardSkeleton(
                            hasMedia: index.isEven,
                            margin: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
                          );
                        },
                      )
                    : (visible.isEmpty && !hasHighlights)
                        ? ListView(
                            controller: _scrollController,
                            physics: const AlwaysScrollableScrollPhysics(),
                            children: [
                              _HomeStoriesStrip(repo: repo, session: session.value),
                              SizedBox(height: MediaQuery.sizeOf(context).height * 0.14),
                              EmptyState(
                                icon: Icons.inbox_outlined,
                                title: t(context).feedEmptyPosts,
                                ctaLabel: t(context).feedCreatePost,
                                onCta: () {
                                  if (!isAuthenticated) return showCtaSnackBar(context);
                                  Navigator.of(context).pushNamed(Routes.createPost);
                                },
                              ),
                            ],
                          )
                        : ListView.builder(
                            controller: _scrollController,
                            physics: const AlwaysScrollableScrollPhysics(),
                            itemCount: 1 + (hasHighlights ? 1 : 0) + (visible.isEmpty ? 1 : itemCount),
                            itemBuilder: (context, index) {
                              if (index == 0) {
                                return _HomeStoriesStrip(repo: repo, session: session.value);
                              }

                              final hasHighlightsHere = hasHighlights;
                              if (hasHighlightsHere && index == 1) {
                                return _HomeHighlightsRow(
                                  campaigns: campaignsPreview,
                                  campaignsCount: campaignsAll.length,
                                  alerts: alertsPreview,
                                  alertsCount: alertsAll.length,
                                  locationLabel: _locationLabel,
                                  onOpenCampaigns: () {
                                    Navigator.of(context).pushNamed(
                                      Routes.campaignList,
                                      arguments: CampaignListArgs(
                                        locationPath: _locationPath,
                                        locationLabel: _locationLabel,
                                        communityId: null,
                                      ),
                                    );
                                  },
                                  onOpenAlerts: () {
                                    Navigator.of(context).pushNamed(
                                      Routes.regionAlerts,
                                      arguments: RegionAlertsArgs(
                                        location: _locationRefForFeed(),
                                        contextBreadcrumb: 'Feed • $_locationLabel',
                                        communityId: null,
                                      ),
                                    );
                                  },
                                );
                              }

                              final contentIndex = index - 1 - (hasHighlightsHere ? 1 : 0);

                              if (visible.isEmpty) {
                                return Padding(
                                  padding: const EdgeInsets.only(top: 10),
                                  child: EmptyState(
                                    icon: Icons.inbox_outlined,
                                    title: t(context).feedEmptyPosts,
                                    ctaLabel: t(context).feedCreatePost,
                                    onCta: () {
                                      if (!isAuthenticated) return showCtaSnackBar(context);
                                      Navigator.of(context).pushNamed(Routes.createPost);
                                    },
                                  ),
                                );
                              }

                              final i = contentIndex;
                              final isAdSlot = i != 0 && i % 16 == 15;
                              if (isAdSlot) {
                                final slot = (i + 1) ~/ 16;
                                final slotId = 'feed_slot_$slot';
                                return AdCard(
                                  key: ValueKey(slotId),
                                  slotId: slotId,
                                  placement: 'feed',
                                );
                              }

                              final realIndex = i - (i ~/ 16);
                              if (realIndex < 0 || realIndex >= visible.length) {
                                return const SizedBox.shrink();
                              }
                              final post = visible[realIndex];

                              return PostCard(
                                post: post,
                                isAuthenticated: isAuthenticated,
                                onOpenPost: () {
                                  Navigator.of(context).pushNamed(
                                    Routes.postDetail,
                                    arguments: PostDetailArgs(postId: post.id),
                                  );
                                },
                                onLike: () {
                                  if (!isAuthenticated) return showCtaSnackBar(context);
                                  repo.toggleLike(post.id, isAuthenticated: true);
                                },
                                onPray: () {
                                  if (!isAuthenticated) return showCtaSnackBar(context);
                                  repo.togglePrayer(post.id, isAuthenticated: true);
                                  showInfoSnackBar(context, t(context).prayerRegisteredSnack);
                                },
                                onComment: () {
                                  if (!isAuthenticated) return showCtaSnackBar(context);
                                  Navigator.of(context).pushNamed(
                                    Routes.postComments,
                                    arguments: CommentsArgs(postId: post.id),
                                  );
                                },
                                onShare: () async {
                                  await showShareSheet(
                                    context,
                                    post: post,
                                    isAuthenticated: isAuthenticated,
                                  );
                                },
                                onSave: () {
                                  if (!isAuthenticated) return showCtaSnackBar(context);
                                  final willSave = !post.viewerHasSaved;
                                  repo.toggleSave(post.id, isAuthenticated: true);
                                  if (willSave) showInfoSnackBar(context, t(context).commonSaved);
                                },
                              );
                            },
                          ),
              ),
            ),
          ],
        );
      },
    );
  }
}

enum _CampaignSort { nearby, urgent, popular }

LatLng? _campaignCenter(CampaignModel c) {
  final lat = c.centerLat;
  final lng = c.centerLng;
  if (lat == null || lng == null) return null;
  if (!lat.isFinite || !lng.isFinite) return null;
  return LatLng(lat, lng);
}

class CampaignCard extends StatelessWidget {
  const CampaignCard({
    required this.campaign,
    required this.onOpen,
    super.key,
  });

  final CampaignModel campaign;
  final VoidCallback onOpen;

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final progress = campaign.progress;
    final isUrgent = campaign.isUrgent;

    return Card(
      margin: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
      child: InkWell(
        borderRadius: BorderRadius.circular(16),
        onTap: onOpen,
        child: Padding(
          padding: const EdgeInsets.all(12),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Row(
                children: [
                  Expanded(
                    child: Text(
                      campaign.title,
                      maxLines: 2,
                      overflow: TextOverflow.ellipsis,
                      style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 16),
                    ),
                  ),
                  const SizedBox(width: 10),
                  Chip(
                    visualDensity: VisualDensity.compact,
                    avatar: Icon(isUrgent ? Icons.local_fire_department_outlined : Icons.volunteer_activism_outlined, size: 18),
                    label: Text(isUrgent ? t(context).campaignUrgent : _campaignStatusLabel(context, campaign.status)),
                  ),
                ],
              ),
              const SizedBox(height: 8),
              Wrap(
                spacing: 8,
                runSpacing: 8,
                children: [
                  Chip(
                    visualDensity: VisualDensity.compact,
                    avatar: const Icon(Icons.category_outlined, size: 18),
                    label: Text(_campaignCategoryLabel(context, campaign.category)),
                  ),
                  Chip(
