      ),
    );
  }
}

class CampaignListScreen extends StatefulWidget {
  const CampaignListScreen({required this.args, super.key});

  final CampaignListArgs args;

  @override
  State<CampaignListScreen> createState() => _CampaignListScreenState();
}

class _CampaignListScreenState extends State<CampaignListScreen> {
  var _sort = _CampaignSort.nearby;
  var _loading = true;

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) => unawaited(_load()));
  }

  LatLng _centerForPath(String path) {
    return switch (path) {
      'world' => const LatLng(0, 0),
      'world/sa' => const LatLng(-15.6, -57.8),
      'world/sa/br' => const LatLng(-14.2, -51.9),
      'world/sa/br/go' => const LatLng(-15.9, -49.9),
      'world/sa/br/go/goiania' => const LatLng(-16.6869, -49.2648),
      'world/sa/br/sp/sao-paulo' => const LatLng(-23.5505, -46.6333),
      _ => const LatLng(0, 0),
    };
  }

  Future<void> _load() async {
    if (!mounted) return;
    setState(() => _loading = true);
    final repo = RepoScope.of(context);
    if (repo.supabase != null && !repo.isOffline) {
      final center = _centerForPath(widget.args.locationPath);
      await repo.refreshCampaignsForCurrentFeed(
        locationPath: widget.args.locationPath,
        communityId: widget.args.communityId,
        lat: center.latitude,
        lng: center.longitude,
        force: true,
      );
    } else {
      await Future<void>.delayed(const Duration(milliseconds: 260));
    }
    if (!mounted) return;
    setState(() => _loading = false);
  }

  List<CampaignModel> _sorted(List<CampaignModel> input, LatLng center) {
    final list = input.toList(growable: false);
    int byUrgency(CampaignModel a, CampaignModel b) {
      final au = a.isUrgent ? 1 : 0;
      final bu = b.isUrgent ? 1 : 0;
      if (au != bu) return bu.compareTo(au);
      final ad = a.deadline;
      final bd = b.deadline;
      if (ad != null && bd != null) return ad.compareTo(bd);
      if (ad != null) return -1;
      if (bd != null) return 1;
      return b.createdAt.compareTo(a.createdAt);
    }

    int byPopular(CampaignModel a, CampaignModel b) {
      final dc = b.donationsCount.compareTo(a.donationsCount);
      if (dc != 0) return dc;
      final rc = b.raisedAmount.compareTo(a.raisedAmount);
      if (rc != 0) return rc;
      return b.createdAt.compareTo(a.createdAt);
    }

    int byNearby(CampaignModel a, CampaignModel b) {
      final ap = _campaignCenter(a);
      final bp = _campaignCenter(b);
      final ad = ap == null ? 1e18 : _distanceKm(center, ap);
      final bd = bp == null ? 1e18 : _distanceKm(center, bp);
      final d = ad.compareTo(bd);
      if (d != 0) return d;
      return byUrgency(a, b);
    }

    list.sort(
      switch (_sort) {
        _CampaignSort.nearby => byNearby,
        _CampaignSort.urgent => byUrgency,
        _CampaignSort.popular => byPopular,
      },
    );
    return list;
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    final l10n = t(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final s = session.value;
        final center = _centerForPath(widget.args.locationPath);
        final base = repo.campaignsForRegion(s, widget.args.locationPath, communityId: widget.args.communityId);
        final campaigns = _sorted(base, center);

        return Scaffold(
          appBar: AppBar(
            title: Text(l10n.campaignsTitle(widget.args.locationLabel)),
            actions: [
              IconButton(
                onPressed: () {
                  if (s is! AuthSession) return showCtaSnackBar(context);
                  Navigator.of(context).push(
                    MaterialPageRoute<void>(
                      builder: (_) => CreateCampaignScreen(
                        initialLocationPath: widget.args.locationPath,
                        initialLocationLabel: widget.args.locationLabel,
                        initialCommunityId: widget.args.communityId,
                      ),
                    ),
                  );
                },
                icon: const Icon(Icons.add),
                tooltip: l10n.commonCreate,
              ),
            ],
          ),
          body: RefreshIndicator(
            onRefresh: _load,
            child: ListView(
              physics: const AlwaysScrollableScrollPhysics(),
              children: [
                Padding(
                  padding: const EdgeInsets.fromLTRB(12, 10, 12, 6),
                  child: Wrap(
                    spacing: 8,
                    runSpacing: 8,
                    children: [
                      ChoiceChip(
                        label: Text(l10n.campaignSortNearby),
                        selected: _sort == _CampaignSort.nearby,
                        onSelected: (_) => setState(() => _sort = _CampaignSort.nearby),
                      ),
                      ChoiceChip(
                        label: Text(l10n.campaignUrgent),
                        selected: _sort == _CampaignSort.urgent,
                        onSelected: (_) => setState(() => _sort = _CampaignSort.urgent),
                      ),
                      ChoiceChip(
                        label: Text(l10n.campaignSortPopular),
                        selected: _sort == _CampaignSort.popular,
                        onSelected: (_) => setState(() => _sort = _CampaignSort.popular),
                      ),
                    ],
                  ),
                ),
                if (repo.isOffline)
                  Padding(
                    padding: const EdgeInsets.fromLTRB(12, 0, 12, 8),
                    child: Text(l10n.commonNoConnection, style: TextStyle(color: Theme.of(context).colorScheme.outline)),
                  ),
                if (_loading && campaigns.isEmpty)
                  ...List.generate(
                    3,
                    (i) => const PostCardSkeleton(hasMedia: false, margin: EdgeInsets.symmetric(horizontal: 12, vertical: 8)),
                  )
                else if (campaigns.isEmpty)
                  Padding(
                    padding: const EdgeInsets.only(top: 40),
                    child: EmptyState(
                      icon: Icons.volunteer_activism_outlined,
                      title: l10n.campaignEmptyHere,
                      ctaLabel: l10n.campaignCreateTitle,
                      onCta: () {
                        if (s is! AuthSession) return showCtaSnackBar(context);
                        Navigator.of(context).push(
                          MaterialPageRoute<void>(
                            builder: (_) => CreateCampaignScreen(
                              initialLocationPath: widget.args.locationPath,
                              initialLocationLabel: widget.args.locationLabel,
                              initialCommunityId: widget.args.communityId,
                            ),
                          ),
                        );
                      },
                    ),
                  )
                else
                  ...campaigns.map((c) {
                    return CampaignCard(
                      campaign: c,
                      onOpen: () {
                        Navigator.of(context).pushNamed(
                          Routes.campaignDetail,
                          arguments: CampaignDetailArgs(campaignId: c.id),
                        );
                      },
                    );
                  }),
                const SizedBox(height: 12),
              ],
            ),
          ),
        );
      },
    );
  }
}

class CampaignDetailScreen extends StatefulWidget {
  const CampaignDetailScreen({required this.args, super.key});

  final CampaignDetailArgs args;

  @override
  State<CampaignDetailScreen> createState() => _CampaignDetailScreenState();
}

class _CampaignDetailScreenState extends State<CampaignDetailScreen> {
  Future<bool>? _hydrateFuture;
  String? _extrasLoadedFor;
  final _comment = TextEditingController();
  final _update = TextEditingController();
  final _amount = TextEditingController(text: '20');
  var _method = PaymentMethod.pix;

  @override
  void dispose() {
    _comment.dispose();
    _update.dispose();
    _amount.dispose();
    super.dispose();
  }

  void _ensureExtrasLoaded(DemoRepository repo, CampaignModel c) {
    if (_extrasLoadedFor == c.id) return;
    _extrasLoadedFor = c.id;
    if (repo.supabase != null && !repo.isOffline) {
      unawaited(repo.refreshUpdatesForCampaign(c.id, force: true));
      unawaited(repo.refreshCommentsForCampaign(c.id, force: true));
    }
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    final s = session.value;
    final l10n = t(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final campaign = repo.findCampaign(widget.args.campaignId);
        final canHydrate = repo.supabase != null && !repo.isOffline && _looksLikeUuid(widget.args.campaignId);
        if (campaign == null && canHydrate && _hydrateFuture == null) {
          _hydrateFuture = repo.hydrateCampaignById(widget.args.campaignId);
        }
        if (campaign != null) _ensureExtrasLoaded(repo, campaign);

        final body = campaign == null
            ? FutureBuilder<bool>(
                future: _hydrateFuture,
                builder: (context, snapshot) {
                  final hydrated = repo.findCampaign(widget.args.campaignId);
                  if (hydrated != null) return const SizedBox.shrink();
                  if (snapshot.connectionState != ConnectionState.done) {
                    return ListView(
                      padding: const EdgeInsets.fromLTRB(12, 12, 12, 16),
                      children: const [
                        RowSkeleton(primaryWidth: 220, secondaryWidth: 160),
                        SizedBox(height: 12),
                        RowSkeleton(primaryWidth: 260, secondaryWidth: 180),
                        RowSkeleton(primaryWidth: 240, secondaryWidth: 220),
                      ],
                    );
                  }
                  return Center(
                    child: Padding(
                      padding: const EdgeInsets.all(20),
                      child: Column(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Text(l10n.campaignUnavailable),
                          const SizedBox(height: 12),
                          PrimaryButton(label: t(context).commonBack, onPressed: () => Navigator.of(context).maybePop()),
                        ],
                      ),
                    ),
                  );
                },
              )
            : _CampaignDetailBody(
                campaign: campaign,
                session: s,
                repo: repo,
                commentController: _comment,
                updateController: _update,
                amountController: _amount,
                method: _method,
                onMethodChanged: (m) => setState(() => _method = m),
              );

        return Scaffold(
          appBar: AppBar(title: Text(l10n.campaignTitle)),
          body: body,
        );
      },
    );
  }
}

class _CampaignDetailBody extends StatelessWidget {
  const _CampaignDetailBody({
    required this.campaign,
    required this.session,
    required this.repo,
    required this.commentController,
    required this.updateController,
    required this.amountController,
    required this.method,
    required this.onMethodChanged,
  });

  final CampaignModel campaign;
  final SessionState session;
  final DemoRepository repo;
  final TextEditingController commentController;
  final TextEditingController updateController;
  final TextEditingController amountController;
  final PaymentMethod method;
  final ValueChanged<PaymentMethod> onMethodChanged;

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final isAuth = session is AuthSession;
    final viewerId = isAuth ? (session as AuthSession).userId : null;
    final canPostUpdate = viewerId != null && viewerId == campaign.creatorId;
    final updates = repo.updatesForCampaign(campaign.id);
    final comments = repo.commentsForCampaign(campaign.id);
    final l10n = t(context);

    void donate() {
      if (session is! AuthSession) return showCtaSnackBar(context);
      final auth = session as AuthSession;
      final raw = amountController.text.trim().replaceAll('.', '').replaceAll(',', '.');
      final amount = double.tryParse(raw) ?? 0;
      if (amount <= 0) return showAtalaiaSnackBar(context, l10n.campaignInvalidAmount, kind: AtalaiaSnackKind.error);
      repo.donateToCampaign(
        campaign.id,
        session: auth,
        amount: amount,
        method: method,
      );
      final label = method == PaymentMethod.pix ? l10n.campaignPixGeneratedDemo : l10n.campaignDonationRecorded;
      showAtalaiaSnackBar(context, label, kind: AtalaiaSnackKind.success);
    }

    void publishUpdate() {
      if (session is! AuthSession) return showCtaSnackBar(context);
      final auth = session as AuthSession;
      final text = updateController.text.trim();
      if (text.isEmpty) return;
      updateController.clear();
      repo.addCampaignUpdateText(campaign.id, session: auth, content: text);
      showAtalaiaSnackBar(context, l10n.campaignUpdatePublished, kind: AtalaiaSnackKind.success);
    }

    void publishComment() {
      if (session is! AuthSession) return showCtaSnackBar(context);
      final auth = session as AuthSession;
      final text = commentController.text.trim();
      if (text.isEmpty) return;
      commentController.clear();
      repo.addCampaignCommentText(campaign.id, session: auth, text: text);
    }

    return ListView(
      padding: const EdgeInsets.fromLTRB(12, 12, 12, 16),
      children: [
        if (campaign.imageUrl != null && campaign.imageUrl!.isNotEmpty)
          ClipRRect(
            borderRadius: BorderRadius.circular(16),
            child: AspectRatio(
              aspectRatio: 16 / 9,
              child: Image.network(
                campaign.imageUrl!,
                fit: BoxFit.cover,
                errorBuilder: (_, __, ___) => Container(color: cs.surfaceContainerHighest),
              ),
            ),
          ),
        const SizedBox(height: 12),
        Text(campaign.title, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 20)),
        const SizedBox(height: 8),
        Wrap(
          spacing: 8,
          runSpacing: 8,
          children: [
            Chip(
              visualDensity: VisualDensity.compact,
              avatar: const Icon(Icons.category_outlined, size: 18),
              label: Text(_campaignCategoryLabel(context, campaign.category)),
            ),
            Chip(
              visualDensity: VisualDensity.compact,
              avatar: const Icon(Icons.place_outlined, size: 18),
              label: Text(campaign.locationName),
            ),
            Chip(
              visualDensity: VisualDensity.compact,
              avatar: Icon(campaign.isUrgent ? Icons.local_fire_department_outlined : Icons.flag_outlined, size: 18),
              label: Text(campaign.isUrgent ? t(context).campaignUrgent : _campaignStatusLabel(context, campaign.status)),
            ),
          ],
        ),
        const SizedBox(height: 12),
        ClipRRect(
          borderRadius: BorderRadius.circular(999),
          child: LinearProgressIndicator(
            value: campaign.progress,
            minHeight: 12,
            backgroundColor: cs.surfaceContainerHighest,
          ),
        ),
        const SizedBox(height: 10),
        Row(
          children: [
            Expanded(
              child: Text(
                _formatBrl(campaign.raisedAmount),
                style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 18),
              ),
            ),
            Text(
              l10n.campaignGoalAmount(_formatBrl(campaign.goalAmount)),
              style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700),
            ),
          ],
        ),
        const SizedBox(height: 6),
        Text(
          l10n.campaignDonationsCount(campaign.donationsCount),
          style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700),
        ),
        const SizedBox(height: 12),
        Card(
          child: Padding(
            padding: const EdgeInsets.all(12),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                Text(l10n.campaignDonateTitle, style: const TextStyle(fontWeight: FontWeight.w900)),
                const SizedBox(height: 10),
                Wrap(
                  spacing: 8,
                  runSpacing: 8,
                  children: [
                    ChoiceChip(
                      label: Row(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Icon(_paymentMethodIcon(PaymentMethod.pix), size: 18),
                          const SizedBox(width: 6),
                          Text(l10n.paymentMethodPix),
                        ],
                      ),
                      selected: method == PaymentMethod.pix,
                      onSelected: (_) => onMethodChanged(PaymentMethod.pix),
                    ),
                    ChoiceChip(
                      label: Row(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Icon(_paymentMethodIcon(PaymentMethod.card), size: 18),
                          const SizedBox(width: 6),
                          Text(l10n.paymentMethodCard),
                        ],
                      ),
                      selected: method == PaymentMethod.card,
                      onSelected: (_) => onMethodChanged(PaymentMethod.card),
                    ),
                  ],
                ),
                const SizedBox(height: 10),
                AtalaiaTextField(
                  controller: amountController,
                  labelText: l10n.campaignAmountLabel,
                  prefixText: 'R\$ ',
                  keyboardType: const TextInputType.numberWithOptions(decimal: true),
                ),
                const SizedBox(height: 10),
                PrimaryButton(
                  label: isAuth ? l10n.campaignConfirmDonation : l10n.campaignSignInToDonate,
                  onPressed: isAuth ? donate : () => showCtaSnackBar(context),
                ),
                if (method == PaymentMethod.pix) ...[
                  const SizedBox(height: 10),
                  Text(
                    l10n.campaignPixPendingInfo,
                    style: TextStyle(color: cs.outline),
                  ),
                ],
              ],
            ),
          ),
        ),
        const SizedBox(height: 12),
        Text(l10n.commonDescription, style: const TextStyle(fontWeight: FontWeight.w900)),
        const SizedBox(height: 6),
        Text(campaign.description, style: TextStyle(color: cs.onSurfaceVariant, height: 1.35)),
        const SizedBox(height: 18),
        Row(
          children: [
            Text(l10n.campaignUpdatesTitle, style: const TextStyle(fontWeight: FontWeight.w900)),
            const Spacer(),
            if (canPostUpdate)
              Text(
                l10n.campaignOnlyCreatorPublishes,
                style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700),
              ),
          ],
        ),
        const SizedBox(height: 8),
        if (canPostUpdate)
          Card(
            child: Padding(
              padding: const EdgeInsets.all(12),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  AtalaiaTextField(
                    controller: updateController,
                    labelText: l10n.campaignWriteUpdate,
                    maxLines: 4,
                    minLines: 2,
                    textCapitalization: TextCapitalization.sentences,
                  ),
                  const SizedBox(height: 10),
                  PrimaryButton(label: l10n.commonPublish, onPressed: publishUpdate),
                ],
              ),
            ),
          ),
        if (updates.isEmpty)
          Padding(
            padding: const EdgeInsets.symmetric(vertical: 10),
            child: Text(l10n.campaignNoUpdatesYet, style: TextStyle(color: cs.outline)),
          )
        else
          ...updates.map(
            (u) => Card(
              child: Padding(
                padding: const EdgeInsets.all(12),
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(_formatTimestamp(u.createdAt.toLocal()), style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700)),
                    const SizedBox(height: 8),
                    Text(u.content, style: TextStyle(color: cs.onSurfaceVariant, height: 1.35)),
                    if (u.mediaUrl != null && u.mediaUrl!.isNotEmpty) ...[
                      const SizedBox(height: 10),
                      ClipRRect(
                        borderRadius: BorderRadius.circular(12),
                        child: AspectRatio(
                          aspectRatio: 16 / 9,
                          child: Image.network(
                            u.mediaUrl!,
                            fit: BoxFit.cover,
                            errorBuilder: (_, __, ___) => Container(color: cs.surfaceContainerHighest),
                          ),
                        ),
                      ),
                    ],
                  ],
                ),
              ),
            ),
          ),
        const SizedBox(height: 18),
        Text(l10n.campaignCommentsTitle(comments.length), style: const TextStyle(fontWeight: FontWeight.w900)),
        const SizedBox(height: 10),
        if (!isAuth)
          Card(
            child: Padding(
              padding: const EdgeInsets.all(12),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  Text(t(context).postSignInToComment, style: TextStyle(color: cs.outline)),
                  const SizedBox(height: 10),
                  PrimaryButton(label: t(context).commonSignIn, onPressed: () => showCtaSnackBar(context)),
                ],
              ),
            ),
          )
        else
          Card(
            child: Padding(
              padding: const EdgeInsets.all(12),
              child: Column(
                crossAxisAlignment: CrossAxisAlignment.stretch,
                children: [
                  AtalaiaTextField(
                    controller: commentController,
                    labelText: t(context).commentAddLabel,
                    maxLines: 4,
                    minLines: 1,
                    textCapitalization: TextCapitalization.sentences,
                  ),
                  const SizedBox(height: 10),
                  PrimaryButton(label: t(context).commonPublish, onPressed: publishComment),
                ],
              ),
            ),
          ),
        if (comments.isEmpty)
          Padding(
            padding: const EdgeInsets.symmetric(vertical: 10),
            child: Text(t(context).commentNoCommentsYet, style: TextStyle(color: cs.outline)),
          )
        else
          ...comments.map((c) {
            final identity = _identityForUserId(repo, c.userId, legacyVerified: c.isVerified, userFallback: t(context).commonUserFallback);
            return Card(
              child: ListTile(
                leading: Avatar(name: identity.avatarName, imageUrl: identity.avatarUrl, size: AvatarSize.s44),
                title: Row(
                  children: [
                    Expanded(
                      child: Text(
                        identity.displayName,
                        maxLines: 1,
                        overflow: TextOverflow.ellipsis,
                        style: const TextStyle(fontWeight: FontWeight.w900),
                      ),
                    ),
                    if (identity.isVerified) ...[
                      const SizedBox(width: 6),
                      Icon(Icons.verified, size: 18, color: context.brand.verifiedBlue),
                      const SizedBox(width: 6),
                    ],
                    Text(_relativeTime(context, c.createdAt), style: TextStyle(color: cs.outline, fontWeight: FontWeight.w600)),
                  ],
                ),
                subtitle: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text('@${identity.username}', style: TextStyle(color: cs.outline)),
                    const SizedBox(height: 4),
                    Text(c.content),
                  ],
                ),
              ),
            );
          }),
      ],
    );
  }
}

class CreateCampaignScreen extends StatefulWidget {
  const CreateCampaignScreen({
    this.initialLocationPath,
    this.initialLocationLabel,
    this.initialCommunityId,
    super.key,
  });

  final String? initialLocationPath;
  final String? initialLocationLabel;
  final String? initialCommunityId;

  @override
  State<CreateCampaignScreen> createState() => _CreateCampaignScreenState();
}

class _CreateCampaignScreenState extends State<CreateCampaignScreen> {
  final _title = TextEditingController();
  final _description = TextEditingController();
  final _goal = TextEditingController();
  final _imageUrl = TextEditingController();
  CampaignCategory _category = CampaignCategory.communityProject;
  DateTime? _deadline;
  late String _locationPath;
  late String _locationLabel;

  String _locationLabelFor(BuildContext context, String path) {
    final l10n = t(context);
    return switch (path) {
      'world' => l10n.campaignLocationWorld,
      'world/sa/br' => l10n.campaignLocationBrazil,
      'world/sa/br/go/goiania' => l10n.campaignLocationGoiania,
      'world/sa/br/sp/sao-paulo' => l10n.campaignLocationSaoPaulo,
      _ => _locationLabel.isNotEmpty ? _locationLabel : l10n.campaignLocationWorld,
    };
  }

  @override
  void initState() {
    super.initState();
    _locationPath = widget.initialLocationPath ?? 'world';
    _locationLabel = widget.initialLocationLabel ?? '';
  }

  @override
  void dispose() {
    _title.dispose();
    _description.dispose();
    _goal.dispose();
    _imageUrl.dispose();
    super.dispose();
  }

  Future<void> _pickLocation() async {
    final picked = await showAtalaiaBottomSheet<String>(
      context,
      isScrollControlled: false,
      builder: (ctx) {
        return SafeArea(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              ListTile(title: Text(t(context).campaignChooseLocation, style: const TextStyle(fontWeight: FontWeight.w900))),
              ListTile(
                leading: const Icon(Icons.public),
                title: Text(t(context).campaignLocationWorld),
                onTap: () => Navigator.of(ctx).pop('world'),
              ),
              ListTile(
                leading: const Icon(Icons.flag_outlined),
                title: Text(t(context).campaignLocationBrazil),
                onTap: () => Navigator.of(ctx).pop('world/sa/br'),
              ),
              ListTile(
                leading: const Icon(Icons.place_outlined),
                title: Text(t(context).campaignLocationGoiania),
                onTap: () => Navigator.of(ctx).pop('world/sa/br/go/goiania'),
              ),
              ListTile(
                leading: const Icon(Icons.place_outlined),
                title: Text(t(context).campaignLocationSaoPaulo),
                onTap: () => Navigator.of(ctx).pop('world/sa/br/sp/sao-paulo'),
              ),
              const SizedBox(height: 8),
            ],
          ),
        );
      },
    );
    if (!mounted) return;
    if (picked == null) return;
    final nextPath = picked;
    setState(() {
      _locationPath = nextPath;
      _locationLabel = _locationLabelFor(context, nextPath);
    });
  }

  Future<void> _pickDeadline() async {
    final now = DateTime.now();
    final picked = await showDatePicker(
      context: context,
      firstDate: now,
      lastDate: DateTime(now.year + 2),
      initialDate: _deadline ?? now.add(const Duration(days: 7)),
    );
    if (!mounted) return;
    if (picked == null) return;
    setState(() => _deadline = picked);
  }

  void _submit(AuthSession session, DemoRepository repo) {
    final l10n = t(context);
    final titleText = _title.text.trim();
    final descriptionText = _description.text.trim();
    final gRaw = _goal.text.trim().replaceAll('.', '').replaceAll(',', '.');
    final g = double.tryParse(gRaw) ?? 0;
    if (titleText.isEmpty) return showAtalaiaSnackBar(context, l10n.campaignEnterTitle, kind: AtalaiaSnackKind.error);
    if (descriptionText.isEmpty) return showAtalaiaSnackBar(context, l10n.campaignEnterDescription, kind: AtalaiaSnackKind.error);
    if (g <= 0) return showAtalaiaSnackBar(context, l10n.campaignEnterValidGoal, kind: AtalaiaSnackKind.error);

    final imgUrl = _imageUrl.text.trim();
    repo.createCampaign(
      session,
      title: titleText,
      description: descriptionText,
      category: _category,
      goalAmount: g,
      locationPath: _locationPath,
      communityId: widget.initialCommunityId,
      deadline: _deadline,
      imageUrl: imgUrl.isEmpty ? null : imgUrl,
      status: CampaignStatus.active,
    );
    showAtalaiaSnackBar(context, l10n.campaignCreated, kind: AtalaiaSnackKind.success);
    Future<void>.delayed(const Duration(milliseconds: 220)).then((_) {
      if (!context.mounted) return;
      Navigator.of(context).maybePop();
    });
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    final l10n = t(context);

    return ValueListenableBuilder(
      valueListenable: session,
      builder: (context, s, _) {
        final cs = Theme.of(context).colorScheme;
        if (s is! AuthSession) {
          return Scaffold(
            appBar: AppBar(title: Text(l10n.campaignCreateTitle)),
            body: Center(
              child: PrimaryButton(
                label: t(context).ctaSignInToCreate,
                onPressed: () => showLoginSnackBar(context, message: t(context).ctaSignInToCreate),
              ),
            ),
          );
        }

        return Scaffold(
          appBar: AppBar(title: Text(l10n.campaignCreateTitle)),
          body: ListView(
            padding: const EdgeInsets.all(12),
            children: [
              AtalaiaTextField(
                controller: _title,
                labelText: l10n.campaignFieldTitle,
                textCapitalization: TextCapitalization.sentences,
              ),
              const SizedBox(height: 10),
              AtalaiaTextField(
                controller: _description,
                labelText: l10n.commonDescription,
                maxLines: 6,
                minLines: 3,
                textCapitalization: TextCapitalization.sentences,
              ),
              const SizedBox(height: 10),
              AtalaiaTextField(
                controller: _goal,
                labelText: l10n.campaignGoalLabel,
                keyboardType: const TextInputType.numberWithOptions(decimal: true),
              ),
              const SizedBox(height: 10),
              DropdownButtonFormField<CampaignCategory>(
                initialValue: _category,
                decoration: InputDecoration(isDense: true, labelText: l10n.campaignCategoryFieldLabel, border: const OutlineInputBorder()),
                items: CampaignCategory.values
                    .map((c) => DropdownMenuItem(value: c, child: Text(_campaignCategoryLabel(context, c))))
                    .toList(growable: false),
                onChanged: (v) => setState(() => _category = v ?? CampaignCategory.communityProject),
              ),
              const SizedBox(height: 10),
              Card(
                child: ListTile(
                  leading: const Icon(Icons.place_outlined),
                  title: Text(_locationLabelFor(context, _locationPath), style: const TextStyle(fontWeight: FontWeight.w800)),
                  subtitle: Text(_locationPath),
                  trailing: const Icon(Icons.chevron_right),
                  onTap: _pickLocation,
                ),
              ),
              const SizedBox(height: 10),
              Card(
                child: ListTile(
                  leading: const Icon(Icons.schedule),
                  title: Text(_deadline == null ? l10n.campaignSetDeadlineOptional : _formatTimestamp(_deadline!.toLocal())),
                  trailing: const Icon(Icons.chevron_right),
                  onTap: _pickDeadline,
                ),
              ),
              const SizedBox(height: 10),
              AtalaiaTextField(
                controller: _imageUrl,
                labelText: l10n.campaignImageUrlLabel,
                keyboardType: TextInputType.url,
              ),
              const SizedBox(height: 14),
              Text(
                l10n.campaignDonationsStoredInfo,
                style: TextStyle(color: cs.outline),
              ),
              const SizedBox(height: 12),
              PrimaryButton(label: l10n.campaignPublishCta, onPressed: () => _submit(s, repo)),
              const SizedBox(height: 12),
            ],
          ),
        );
      },
    );
  }
}

class PrayerChallengeListScreen extends StatefulWidget {
  const PrayerChallengeListScreen({required this.args, super.key});

  final PrayerChallengeListArgs args;

  @override
  State<PrayerChallengeListScreen> createState() => _PrayerChallengeListScreenState();
}

class _PrayerChallengeListScreenState extends State<PrayerChallengeListScreen> {
  var _onlyActive = true;
  var _loading = true;

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) => unawaited(_load(force: true)));
  }

  Future<void> _load({bool force = false}) async {
    if (!mounted) return;
    setState(() => _loading = true);
    final repo = RepoScope.of(context);
    if (repo.supabase != null && !repo.isOffline) {
      await repo.refreshPrayerChallenges(onlyActive: _onlyActive, force: force);
    } else {
      await Future<void>.delayed(const Duration(milliseconds: 220));
    }
    if (!mounted) return;
    setState(() => _loading = false);
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final s = session.value;
        final challenges = repo.visiblePrayerChallengesFor(
          s,
          onlyActive: _onlyActive,
          communityId: widget.args.communityId,
        );

        return Scaffold(
          appBar: AppBar(
            title: Text(t(context).prayerChallengesTitle),
            actions: [
              IconButton(
                onPressed: () => unawaited(_load(force: true)),
                icon: const Icon(Icons.refresh),
                tooltip: t(context).commonRefresh,
              ),
            ],
          ),
          body: RefreshIndicator(
            onRefresh: () => _load(force: true),
            child: ListView(
              physics: const AlwaysScrollableScrollPhysics(),
              children: [
                Padding(
                  padding: const EdgeInsets.fromLTRB(12, 10, 12, 6),
                  child: Wrap(
                    spacing: 8,
                    runSpacing: 8,
                    children: [
                      ChoiceChip(
                        label: Text(t(context).prayerChallengesFilterActive),
                        selected: _onlyActive,
                        onSelected: (_) => setState(() {
                          _onlyActive = true;
                          unawaited(_load(force: true));
                        }),
                      ),
                      ChoiceChip(
                        label: Text(t(context).prayerChallengesFilterAll),
                        selected: !_onlyActive,
                        onSelected: (_) => setState(() {
                          _onlyActive = false;
                          unawaited(_load(force: true));
                        }),
                      ),
                    ],
                  ),
                ),
                if (_loading)
                  const Padding(
                    padding: EdgeInsets.symmetric(vertical: 14),
                    child: Center(child: CircularProgressIndicator()),
                  )
                else if (challenges.isEmpty)
                  Padding(
                    padding: const EdgeInsets.all(12),
                    child: Text(
                      _onlyActive ? t(context).prayerChallengesEmptyActive : t(context).prayerChallengesEmptyAll,
                      style: TextStyle(color: Theme.of(context).colorScheme.outline),
                    ),
                  )
                else
                  ...challenges.map(
                    (c) => _PrayerChallengeListTile(
                      challenge: c,
                      onOpen: () {
                        Navigator.of(context).pushNamed(
                          Routes.prayerChallengeDetail,
                          arguments: PrayerChallengeDetailArgs(challengeId: c.id),
                        );
                      },
                    ),
                  ),
                const SizedBox(height: 18),
              ],
            ),
          ),
        );
      },
    );
  }
}

class _PrayerChallengeListTile extends StatelessWidget {
  const _PrayerChallengeListTile({
    required this.challenge,
    required this.onOpen,
  });

  final PrayerChallengeModel challenge;
  final VoidCallback onOpen;

  String _windowLabel(BuildContext context, DateTime nowUtc) {
    final now = nowUtc;
    final start = challenge.startDate.toUtc();
    final end = challenge.endDate.toUtc();
    if (now.isBefore(start)) {
      final d = start.difference(now);
      final duration = d.inDays >= 1 ? '${d.inDays} d' : '${d.inHours} h';
      return t(context).prayerChallengeStartsIn(duration);
    }
    if (now.isAfter(end)) return t(context).prayerChallengeEnded;
    final d = end.difference(now);
    final duration = d.inDays >= 1 ? '${d.inDays} d' : '${d.inHours} h';
    return t(context).prayerChallengeEndsIn(duration);
  }

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final now = DateTime.now().toUtc();
    final subtitle = challenge.description.trim().isEmpty ? t(context).prayerChallengeNoDescription : challenge.description.trim();
    final participants = _formatCompactInt(challenge.participantsCount);
    final window = _windowLabel(context, now);

    return Card(
      margin: const EdgeInsets.fromLTRB(12, 6, 12, 6),
      child: InkWell(
        onTap: onOpen,
        borderRadius: BorderRadius.circular(12),
        child: Padding(
          padding: const EdgeInsets.all(12),
          child: Column(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Row(
                children: [
                  const Icon(Icons.local_fire_department_outlined, color: Color(0xFFEF6C00)),
                  const SizedBox(width: 8),
                  Expanded(
                    child: Text(
                      challenge.title,
                      maxLines: 1,
                      overflow: TextOverflow.ellipsis,
                      style: const TextStyle(fontWeight: FontWeight.w900),
                    ),
                  ),
                  if (challenge.viewerJoined)
                    DecoratedBox(
                      decoration: BoxDecoration(
                        color: cs.primaryContainer,
                        borderRadius: BorderRadius.circular(999),
                      ),
                      child: Padding(
                        padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 4),
                        child: Text(
                          t(context).prayerChallengeParticipating,
                          style: TextStyle(color: cs.onPrimaryContainer, fontWeight: FontWeight.w900, fontSize: 12),
                        ),
                      ),
                    ),
                ],
              ),
              const SizedBox(height: 8),
              Text(
                subtitle,
                maxLines: 2,
                overflow: TextOverflow.ellipsis,
                style: TextStyle(color: cs.onSurfaceVariant, height: 1.3),
              ),
              const SizedBox(height: 10),
              Row(
                children: [
                  Icon(Icons.groups_2_outlined, size: 16, color: cs.outline),
                  const SizedBox(width: 6),
                  Text(t(context).prayerChallengeParticipantsCount(participants), style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700)),
                  const SizedBox(width: 12),
                  Icon(Icons.schedule, size: 16, color: cs.outline),
                  const SizedBox(width: 6),
                  Expanded(child: Text(window, style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700))),
                ],
              ),
            ],
          ),
        ),
      ),
    );
  }
}

class PrayerChallengeDetailScreen extends StatefulWidget {
  const PrayerChallengeDetailScreen({required this.args, super.key});

  final PrayerChallengeDetailArgs args;

  @override
  State<PrayerChallengeDetailScreen> createState() => _PrayerChallengeDetailScreenState();
}

class _PrayerChallengeDetailScreenState extends State<PrayerChallengeDetailScreen> {
  var _loading = true;
  PrayerChallengeProgress? _progress;
  var _rankUsers = const <PrayerChallengeRankUserRow>[];
  var _rankCommunities = const <PrayerChallengeRankCommunityRow>[];
  var _rankCountries = const <PrayerChallengeRankCountryRow>[];

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) => unawaited(_load(force: true)));
  }

  Future<void> _load({bool force = false}) async {
    if (!mounted) return;
    setState(() => _loading = true);
    final repo = RepoScope.of(context);
    if (repo.supabase != null && !repo.isOffline) {
      await repo.refreshPrayerChallenges(onlyActive: false, force: force);
      final p = await repo.fetchPrayerChallengeProgress(widget.args.challengeId);
      final users = await repo.fetchPrayerChallengeRankUsers(widget.args.challengeId);
      final comms = await repo.fetchPrayerChallengeRankCommunities(widget.args.challengeId);
      final countries = await repo.fetchPrayerChallengeRankCountries(widget.args.challengeId);
      if (!mounted) return;
      setState(() {
        _progress = p;
        _rankUsers = users;
        _rankCommunities = comms;
        _rankCountries = countries;
      });
    } else {
      await Future<void>.delayed(const Duration(milliseconds: 180));
    }
    if (!mounted) return;
    setState(() => _loading = false);
  }

  String _levelFromRegionPath(String path) {
    final p = path.trim();
    if (p.isEmpty) return 'world';
    final parts = p.split('/').where((s) => s.trim().isNotEmpty).toList(growable: false);
    if (parts.isEmpty) return 'world';
    if (parts.length <= 1) return 'world';
    if (parts.length == 2) return 'continent';
    if (parts.length == 3) return 'country';
    if (parts.length == 4) return 'state';
    return 'city';
  }

  Future<void> _startPrayer(PrayerChallengeModel challenge) async {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context).value;
    if (session is! AuthSession) return showAuthGate(context);

    final locationId = challenge.targetLocationId;
    final regionPath = challenge.targetRegion.trim().isEmpty ? 'world' : challenge.targetRegion.trim();
    final resolvedLocationId = _looksLikeUuid(locationId) ? locationId : await repo.locationIdByPath(regionPath);
    if (!mounted) return;
    if (resolvedLocationId == null || resolvedLocationId.isEmpty) {
      return showAtalaiaSnackBar(context, t(context).prayerChallengeRegionUnavailable, kind: AtalaiaSnackKind.error);
    }
    final locationName = challenge.targetLocationName?.trim().isNotEmpty ?? false ? challenge.targetLocationName!.trim() : t(context).prayerChallengeRegionFallback;
    final level = _levelFromRegionPath(regionPath);
    Navigator.of(context).pushNamed(
      Routes.regionPrayer,
      arguments: RegionPrayerArgs(
        locationId: resolvedLocationId,
        locationName: locationName,
        locationLevel: level,
        locationPath: regionPath,
        challengeId: challenge.id,
      ),
    );
  }

  Future<void> _toggleJoin(PrayerChallengeModel challenge) async {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context).value;
    if (session is! AuthSession) return showAuthGate(context);
    final ok = challenge.viewerJoined ? await repo.leavePrayerChallenge(challenge.id) : await repo.joinPrayerChallenge(challenge.id);
    if (!mounted) return;
    if (!ok) {
      showAtalaiaSnackBar(context, t(context).participationUpdateFailed, kind: AtalaiaSnackKind.error);
    } else {
      unawaited(_load(force: true));
    }
  }

  Future<void> _share(PrayerChallengeModel challenge) async {
    final text = t(context).prayerChallengeShareText(challenge.title);
    await Clipboard.setData(ClipboardData(text: text));
    if (!mounted) return;
    showAtalaiaSnackBar(context, t(context).prayerChallengeShareCopied, kind: AtalaiaSnackKind.success);
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final cs = Theme.of(context).colorScheme;
        final challenge = repo.findPrayerChallenge(widget.args.challengeId);

        if (challenge == null && !_loading) {
          return Scaffold(
            appBar: AppBar(title: Text(t(context).prayerChallengeTitle)),
            body: Center(
              child: Padding(
                padding: const EdgeInsets.all(16),
                child: Text(t(context).prayerChallengeNotFound, style: TextStyle(color: cs.outline)),
              ),
            ),
          );
        }

        final c = challenge;
        final progress = _progress;
        final participantsCount = progress?.participantsCount ?? c?.participantsCount ?? 0;
        final goalParticipants = (progress?.goalParticipants ?? c?.goalParticipants ?? 0).clamp(0, 1 << 30);
        final totalSeconds = progress?.totalDurationSeconds ?? c?.totalDurationSeconds ?? 0;
        final goalPrayerMinutes = progress?.goalPrayerMinutes ?? c?.goalPrayerMinutes ?? 0;
        final goalPrayerSeconds = (goalPrayerMinutes * 60).clamp(0, 1 << 30);
        final participantsPct = goalParticipants <= 0 ? 0.0 : (participantsCount / goalParticipants).clamp(0.0, 1.0);
        final prayerPct = goalPrayerSeconds <= 0 ? 0.0 : (totalSeconds / goalPrayerSeconds).clamp(0.0, 1.0);

        return Scaffold(
          appBar: AppBar(
            title: Text(c?.title ?? t(context).prayerChallengeTitle),
            actions: [
              IconButton(
                onPressed: c == null ? null : () => unawaited(_share(c)),
                icon: const Icon(Icons.share_outlined),
                tooltip: t(context).prayerChallengeShare,
              ),
              IconButton(
                onPressed: () => unawaited(_load(force: true)),
                icon: const Icon(Icons.refresh),
                tooltip: t(context).commonRefresh,
              ),
            ],
          ),
          body: _loading && c == null
              ? const Center(child: CircularProgressIndicator())
              : RefreshIndicator(
                  onRefresh: () => _load(force: true),
                  child: ListView(
                    physics: const AlwaysScrollableScrollPhysics(),
                    padding: const EdgeInsets.all(12),
                    children: [
                      if (c != null)
                        Card(
                          child: Padding(
                            padding: const EdgeInsets.all(12),
                            child: Column(
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                                Text(c.title, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 18)),
                                const SizedBox(height: 8),
                                if (c.description.trim().isNotEmpty)
                                  Text(c.description.trim(), style: TextStyle(color: cs.onSurfaceVariant, height: 1.35)),
                                const SizedBox(height: 12),
                                Row(
                                  children: [
                                    Icon(Icons.public, size: 16, color: cs.outline),
                                    const SizedBox(width: 6),
                                    Expanded(
                                      child: Text(
                                        c.targetLocationName?.trim().isNotEmpty ?? false ? c.targetLocationName!.trim() : c.targetRegion,
                                        style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700),
                                      ),
                                    ),
                                  ],
                                ),
                                if (c.communityName?.trim().isNotEmpty ?? false) ...[
                                  const SizedBox(height: 8),
                                  Row(
                                    children: [
                                      Icon(Icons.groups_2_outlined, size: 16, color: cs.outline),
                                      const SizedBox(width: 6),
                                      Expanded(
                                        child: Text(
                                          c.communityName!.trim(),
                                          style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700),
                                        ),
                                      ),
                                    ],
                                  ),
                                ],
                                const SizedBox(height: 10),
                                Row(
                                  children: [
                                    Expanded(
                                      child: PrimaryButton(
                                        label: c.viewerJoined ? t(context).prayerChallengeLeaveAction : t(context).prayerChallengeJoinAction,
                                        onPressed: () => unawaited(_toggleJoin(c)),
                                      ),
                                    ),
                                    const SizedBox(width: 10),
                                    Expanded(
                                      child: PrimaryButton(
                                        label: t(context).prayerStart,
                                        onPressed: () => unawaited(_startPrayer(c)),
                                      ),
                                    ),
                                  ],
                                ),
                              ],
                            ),
                          ),
                        ),
                      const SizedBox(height: 12),
                      Card(
                        child: Padding(
                          padding: const EdgeInsets.all(12),
                          child: Column(
                            crossAxisAlignment: CrossAxisAlignment.start,
                            children: [
                              Text(t(context).prayerChallengeProgressTitle, style: const TextStyle(fontWeight: FontWeight.w900)),
                              const SizedBox(height: 10),
                              Row(
                                children: [
                                  Expanded(
                                    child: Text(
                                      t(context).prayerChallengeParticipantsProgress(
                                        _formatCompactInt(participantsCount),
                                        goalParticipants > 0 ? ' / ${_formatCompactInt(goalParticipants)}' : '',
                                      ),
                                      style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700),
                                    ),
                                  ),
                                  Text('${(participantsPct * 100).round()}%', style: const TextStyle(fontWeight: FontWeight.w900)),
                                ],
                              ),
                              const SizedBox(height: 8),
                              LinearProgressIndicator(value: goalParticipants > 0 ? participantsPct : null, minHeight: 8),
                              const SizedBox(height: 14),
                              Row(
                                children: [
                                  Expanded(
                                    child: Text(
                                      t(context).prayerChallengeTimeProgress(
                                        _formatHoursFromSeconds(totalSeconds),
                                        goalPrayerSeconds > 0 ? ' / ${_formatHoursFromSeconds(goalPrayerSeconds)}' : '',
                                      ),
                                      style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700),
                                    ),
                                  ),
                                  Text('${(prayerPct * 100).round()}%', style: const TextStyle(fontWeight: FontWeight.w900)),
                                ],
                              ),
                              const SizedBox(height: 8),
                              LinearProgressIndicator(value: goalPrayerSeconds > 0 ? prayerPct : null, minHeight: 8),
                            ],
                          ),
                        ),
                      ),
                      const SizedBox(height: 12),
                      if (_rankUsers.isNotEmpty) ...[
                        Text(t(context).prayerChallengeTopIntercessors, style: const TextStyle(fontWeight: FontWeight.w900)),
                        const SizedBox(height: 8),
                        ..._rankUsers.take(10).toList(growable: false).asMap().entries.map(
                              (e) => _RankRow(
                                rank: e.key + 1,
                                title: e.value.displayName.trim().isNotEmpty ? e.value.displayName.trim() : (e.value.username.trim().isNotEmpty ? e.value.username.trim() : e.value.userId),
                                subtitle: t(context).prayerChallengeRankSessions(
                                  _formatHoursFromSeconds(e.value.totalDurationSeconds),
                                  _formatCompactInt(e.value.sessionsCount),
                                ),
                                leadingUrl: e.value.avatarUrl,
                              ),
                            ),
                        const SizedBox(height: 12),
                      ],
                      if (_rankCommunities.isNotEmpty) ...[
                        Text(t(context).prayerChallengeTopCommunities, style: const TextStyle(fontWeight: FontWeight.w900)),
                        const SizedBox(height: 8),
                        ..._rankCommunities.take(10).toList(growable: false).asMap().entries.map(
                              (e) => _RankRow(
                                rank: e.key + 1,
                                title: e.value.name.trim().isEmpty ? e.value.communityId : e.value.name.trim(),
                                subtitle: t(context).prayerChallengeParticipantsCount(_formatCompactInt(e.value.participantsCount)),
                                leadingUrl: null,
                              ),
                            ),
                        const SizedBox(height: 12),
                      ],
                      if (_rankCountries.isNotEmpty) ...[
                        Text(t(context).prayerChallengeTopCountries, style: const TextStyle(fontWeight: FontWeight.w900)),
                        const SizedBox(height: 8),
                        ..._rankCountries.take(10).toList(growable: false).asMap().entries.map(
                              (e) => _RankRow(
                                rank: e.key + 1,
                                title: e.value.countryName,
                                subtitle: t(context).prayerChallengeRankSessions(
                                  _formatHoursFromSeconds(e.value.totalDurationSeconds),
                                  _formatCompactInt(e.value.participantsCount),
                                ),
                                leadingUrl: null,
                              ),
                            ),
                      ],
                      const SizedBox(height: 18),
                    ],
                  ),
                ),
        );
      },
    );
  }
}

