Future<void> _showConversationSearchSheet(
  BuildContext context, {
  required DemoRepository repo,
  required AuthSession session,
  required String threadId,
}) async {
  final search = TextEditingController();
  await showAtalaiaBottomSheet<void>(
    context,
    builder: (context) {
      return StatefulBuilder(
        builder: (context, setState) {
          final query = search.text.trim().toLowerCase();
          final results = repo
              .messagesFor(threadId, session)
              .where((m) => (m.text ?? '').trim().isNotEmpty)
              .where((m) => query.isEmpty ? false : (m.text ?? '').toLowerCase().contains(query))
              .toList(growable: false)
            ..sort((a, b) => b.sentAt.compareTo(a.sentAt));
          final cs = Theme.of(context).colorScheme;
          return SafeArea(
            child: Padding(
              padding: EdgeInsets.only(bottom: MediaQuery.viewInsetsOf(context).bottom),
              child: ConstrainedBox(
                constraints: const BoxConstraints(maxHeight: 540),
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    const SizedBox(height: 10),
                    Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 16),
                      child: SearchField(
                        controller: search,
                        hintText: 'Pesquisar palavra',
                        onChanged: (_) => setState(() {}),
                      ),
                    ),
                    const SizedBox(height: 10),
                    if (query.isEmpty)
                      Padding(
                        padding: const EdgeInsets.fromLTRB(16, 6, 16, 16),
                        child: Text(
                          'Digite uma palavra para buscar nesta conversa.',
                          style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700),
                        ),
                      )
                    else if (results.isEmpty)
                      Padding(
                        padding: const EdgeInsets.fromLTRB(16, 6, 16, 16),
                        child: Text(
                          t(context).directEmptyPeopleSearch,
                          style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700),
                        ),
                      )
                    else
                      Flexible(
                        child: ListView.separated(
                          shrinkWrap: true,
                          itemCount: results.length,
                          separatorBuilder: (_, __) => const Divider(height: 1),
                          itemBuilder: (_, index) {
                            final m = results[index];
                            return ListTile(
                              title: Text(
                                m.text ?? '',
                                maxLines: 2,
                                overflow: TextOverflow.ellipsis,
                                style: const TextStyle(fontWeight: FontWeight.w700),
                              ),
                              subtitle: Text(_relativeTime(context, m.sentAt)),
                            );
                          },
                        ),
                      ),
                    const SizedBox(height: 8),
                  ],
                ),
              ),
            ),
          );
        },
      );
    },
  );
  search.dispose();
}

class TextMessageBubble extends StatelessWidget {
  const TextMessageBubble({required this.text, required this.color, super.key});

  final String text;
  final Color color;

  @override
  Widget build(BuildContext context) {
    final match = RegExp(r'https?://\S+').firstMatch(text);
    final style = TextStyle(
      color: color,
      fontSize: 15,
      height: 1.35,
    );
    if (match == null) return Text(text, style: style);

    return InkWell(
      onTap: () {
        showAtalaiaSnackBar(context, t(context).chatOpenLinkUi(match.group(0) ?? ''));
      },
      child: Text(
        text,
        style: style.copyWith(decoration: TextDecoration.underline),
      ),
    );
  }
}

class ImageMessageBubble extends StatelessWidget {
  const ImageMessageBubble({
    required this.token,
    required this.caption,
    required this.color,
    required this.status,
    required this.onRetry,
    required this.onTapImage,
    super.key,
  });

  final String token;
  final String? caption;
  final Color color;
  final MessageSendStatus status;
  final VoidCallback onRetry;
  final VoidCallback onTapImage;

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final maxHeight = MediaQuery.sizeOf(context).height >= 760 ? 360.0 : 320.0;
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        GestureDetector(
          onTap: onTapImage,
          child: ClipRRect(
            borderRadius: BorderRadius.circular(18),
            child: ConstrainedBox(
              constraints: BoxConstraints(maxHeight: maxHeight),
              child: AspectRatio(
                aspectRatio: 4 / 5,
                child: Stack(
                  children: [
                    Positioned.fill(
                      child: token.trim().isEmpty
                          ? Container(
                              color: cs.surfaceContainerHighest,
                              child: const Center(child: Icon(Icons.image_outlined, size: 42)),
                            )
                          : Image.network(
                              token.trim(),
                              fit: BoxFit.cover,
                              errorBuilder: (_, __, ___) => Container(
                                color: cs.surfaceContainerHighest,
                                child: const Center(child: Icon(Icons.broken_image_outlined, size: 42)),
                              ),
                              loadingBuilder: (context, child, progress) {
                                if (progress == null) return child;
                                return Container(
                                  color: cs.surfaceContainerHighest,
                                  child: const Center(child: SizedBox(width: 18, height: 18, child: CircularProgressIndicator(strokeWidth: 2))),
                                );
                              },
                            ),
                    ),
                    if (status == MessageSendStatus.sending)
                      Positioned.fill(
                        child: Container(
                          color: Colors.black.withValues(alpha: 0.15),
                          child: const Center(child: SizedBox(width: 22, height: 22, child: CircularProgressIndicator(strokeWidth: 2))),
                        ),
                      ),
                    if (status == MessageSendStatus.failed)
                      Positioned.fill(
                        child: Container(
                          color: Colors.black.withValues(alpha: 0.18),
                          child: Center(
                            child: SecondaryButton(label: t(context).commonTryAgain, onPressed: onRetry),
                          ),
                        ),
                      ),
                  ],
                ),
              ),
            ),
          ),
        ),
        if (caption != null && caption!.trim().isNotEmpty) ...[
          const SizedBox(height: 8),
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
            decoration: BoxDecoration(
              color: cs.surfaceContainerHighest,
              borderRadius: BorderRadius.circular(18),
            ),
            child: Text(
              caption!,
              style: TextStyle(color: color, fontSize: 15, height: 1.35),
            ),
          ),
        ],
      ],
    );
  }
}


