extension on _ChatScreenState {
  MessageModel? _lastFailedMine(List<MessageModel> messages, String viewerId) {
    for (var i = messages.length - 1; i >= 0; i--) {
      final m = messages[i];
      if (m.senderId == viewerId && m.sendStatus == MessageSendStatus.failed) return m;
    }
    return null;
  }

  void _maybeNotifySendFailure(
    BuildContext context, {
    required List<MessageModel> messages,
    required String viewerId,
    required VoidCallback onRetry,
  }) {
    final lastFailed = _lastFailedMine(messages, viewerId);
    if (lastFailed == null) return;
    if (_notifiedFailedId == lastFailed.id) return;
    _notifiedFailedId = lastFailed.id;

    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      final repo = RepoScope.of(context);
      final raw = repo.lastDirectSendError;
      final msg = raw == null || raw.trim().isEmpty ? 'Falha ao enviar mensagem.' : raw.trim();
      showErrorSnackBar(context, message: msg, onRetry: onRetry);
    });
  }
}

enum _RegionPostsFilter { all, requests, testimonies }

class RegionPostsScreen extends StatefulWidget {
  const RegionPostsScreen({required this.args, super.key});

  final RegionPostsArgs args;

  @override
  State<RegionPostsScreen> createState() => _RegionPostsScreenState();
}

class _RegionPostsScreenState extends State<RegionPostsScreen> {
  final _scrollController = ScrollController();
  var _filter = _RegionPostsFilter.requests;
  var _loading = true;
  var _loadingMore = false;
  var _hasMore = true;
  String? _error;
  String? _resolvedLocationId;
  DateTime? _cursorCreatedAt;
  List<PostModel> _posts = const [];

  @override
  void initState() {
    super.initState();
    _scrollController.addListener(_maybeLoadMore);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_loadInitial());
    });
  }

  @override
  void dispose() {
    _scrollController.dispose();
    super.dispose();
  }

  void _maybeLoadMore() {
    if (!_hasMore || _loading || _loadingMore) return;
    final pos = _scrollController.position;
    if (pos.maxScrollExtent <= 0) return;
    if (pos.pixels < pos.maxScrollExtent - 320) return;
    unawaited(_loadMore());
  }

  PostKind? get _kindFilter {
    return switch (_filter) {
      _RegionPostsFilter.all => null,
      _RegionPostsFilter.requests => PostKind.request,
      _RegionPostsFilter.testimonies => PostKind.testimony,
    };
  }

  String _emptyTitle() {
    return switch (_filter) {
      _RegionPostsFilter.testimonies => t(context).regionPostsEmptyTestimonies,
      _ => t(context).regionPostsEmptyRequests,
    };
  }

  String _ctaLabel() {
    return switch (_filter) {
      _RegionPostsFilter.testimonies => t(context).regionPostsCreateTestimony,
      _ => t(context).regionPostsCreateRequest,
    };
  }

  Future<String?> _ensureLocationId(DemoRepository repo) async {
    final id = widget.args.location.id;
    if (_looksLikeUuid(id)) return id;
    return repo.locationIdByPath(widget.args.location.path);
  }

  Future<void> _loadInitial() async {
    if (!mounted) return;
    setState(() {
      _loading = true;
      _loadingMore = false;
      _hasMore = true;
      _error = null;
      _cursorCreatedAt = null;
      _posts = const [];
    });

    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    final useRemote = repo.supabase != null && !repo.isOffline;

    final s = session.value;
    if (!useRemote) {
      final all = widget.args.communityId == null
          ? repo.postsForRegion(s, widget.args.location.path)
          : repo.postsForRegionInCommunity(s, widget.args.location.path, widget.args.communityId!);
      final kind = _kindFilter;
      final filtered = kind == null ? all : all.where((p) => p.kind == kind).toList(growable: false);
      if (!mounted) return;
      setState(() {
        _loading = false;
        _hasMore = false;
        _posts = filtered;
      });
      return;
    }

    final locationId = await _ensureLocationId(repo);
    if (!mounted) return;
    if (locationId == null) {
      setState(() {
        _loading = false;
        _error = t(context).regionIdentifyFailed;
      });
      return;
    }
    _resolvedLocationId = locationId;
    final items = await repo.fetchRegionPostsByLocationId(
      locationId,
      communityId: widget.args.communityId,
      limit: 20,
      kind: _kindFilter,
    );
    if (!mounted) return;
    setState(() {
      _loading = false;
      _posts = items;
      _cursorCreatedAt = items.isEmpty ? null : items.last.createdAt;
      _hasMore = items.length >= 20;
    });
  }

  Future<void> _loadMore() async {
    final repo = RepoScope.of(context);
    if (repo.supabase == null || repo.isOffline) return;
    final locationId = _resolvedLocationId;
    final cursor = _cursorCreatedAt;
    if (locationId == null || cursor == null) {
      setState(() => _hasMore = false);
      return;
    }
    setState(() => _loadingMore = true);
    final items = await repo.fetchRegionPostsByLocationId(
      locationId,
      communityId: widget.args.communityId,
      cursorCreatedAt: cursor,
      limit: 20,
      kind: _kindFilter,
    );
    if (!mounted) return;
    final existingIds = _posts.map((p) => p.id).toSet();
    final next = [..._posts, ...items.where((p) => !existingIds.contains(p.id))];
    setState(() {
      _loadingMore = false;
      _posts = next;
      _cursorCreatedAt = items.isEmpty ? _cursorCreatedAt : items.last.createdAt;
      _hasMore = items.length >= 20;
    });
  }

  void _setFilter(_RegionPostsFilter value) {
    if (_filter == value) return;
    setState(() => _filter = value);
    unawaited(_loadInitial());
  }

  void _replacePostAt(int index, PostModel next) {
    final list = _posts.toList(growable: true);
    list[index] = next;
    setState(() => _posts = List.unmodifiable(list));
  }

  Future<void> _handleLike(DemoRepository repo, PostModel post) async {
    final idx = _posts.indexWhere((p) => p.id == post.id);
    if (idx < 0) return;
    final p = _posts[idx];
    final nextLiked = !p.viewerHasLiked;
    if (nextLiked) {
      repo.trackEvent('like_add', <String, Object?>{
        'postId': p.id,
        'kind': p.kind.analyticsValue,
        'visibility': p.visibility.analyticsValue,
      });
    }
    final updated = p.copyWith(
      viewerHasLiked: nextLiked,
      likeCount: nextLiked ? p.likeCount + 1 : (p.likeCount - 1).clamp(0, 1 << 30),
    );
    _replacePostAt(idx, updated);

    final useRemote = repo.supabase != null && !repo.isOffline;
    if (!useRemote) return;
    final ok = await repo.setLikeOnPostSupabase(postId: p.id, shouldLike: nextLiked);
    if (!mounted) return;
    if (!ok) {
      _replacePostAt(idx, p);
      showAtalaiaSnackBar(context, t(context).likeRegisterFailed, kind: AtalaiaSnackKind.error);
    }
  }

  Future<void> _handlePray(DemoRepository repo, PostModel post) async {
    final idx = _posts.indexWhere((p) => p.id == post.id);
    if (idx < 0) return;
    final p = _posts[idx];
    if (p.viewerHasPrayed) return;
    repo.trackEvent('prayer_add', <String, Object?>{
      'postId': p.id,
      'kind': p.kind.analyticsValue,
      'visibility': p.visibility.analyticsValue,
    });
    final updated = p.copyWith(viewerHasPrayed: true, prayerCount: p.prayerCount + 1);
    _replacePostAt(idx, updated);
    showInfoSnackBar(context, t(context).prayerRegisteredSnack);

    final useRemote = repo.supabase != null && !repo.isOffline;
    if (!useRemote) return;
    final ok = await repo.addPrayerOnPostSupabase(postId: p.id);
    if (!mounted) return;
    if (!ok) {
      _replacePostAt(idx, p);
      showAtalaiaSnackBar(context, t(context).prayerRegisterFailed, kind: AtalaiaSnackKind.error);
    }
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    final s = session.value;
    final isAuthenticated = s.isAuthenticated;
    final communityName = widget.args.communityId == null ? null : repo.findCommunity(widget.args.communityId!)?.name;

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final titleBase = communityName == null
            ? t(context).regionPostsTitle(widget.args.location.name)
            : t(context).regionPostsTitleWithCommunity(widget.args.location.name, communityName);
        final breadcrumb = widget.args.contextBreadcrumb;
        return Scaffold(
          appBar: AppBar(
            title: Text(titleBase),
            bottom: breadcrumb == null || breadcrumb.trim().isEmpty
                ? null
                : PreferredSize(
                    preferredSize: const Size.fromHeight(22),
                    child: Padding(
                      padding: const EdgeInsets.fromLTRB(16, 0, 16, 10),
                      child: Align(
                        alignment: Alignment.centerLeft,
                        child: Text(
                          breadcrumb,
                          style: TextStyle(color: Theme.of(context).colorScheme.outline, fontWeight: FontWeight.w700),
                          overflow: TextOverflow.ellipsis,
                        ),
                      ),
                    ),
                  ),
          ),
          body: Column(
            children: [
              Padding(
                padding: const EdgeInsets.fromLTRB(12, 10, 12, 6),
                child: Wrap(
                  spacing: 8,
                  children: [
                    ChoiceChip(
                      label: Text(t(context).regionPostsFilterAll),
                      selected: _filter == _RegionPostsFilter.all,
                      onSelected: (_) => _setFilter(_RegionPostsFilter.all),
                    ),
                    ChoiceChip(
                      label: Text(t(context).regionPostsFilterRequests),
                      selected: _filter == _RegionPostsFilter.requests,
                      onSelected: (_) => _setFilter(_RegionPostsFilter.requests),
                    ),
                    ChoiceChip(
                      label: Text(t(context).regionPostsFilterTestimonies),
                      selected: _filter == _RegionPostsFilter.testimonies,
                      onSelected: (_) => _setFilter(_RegionPostsFilter.testimonies),
                    ),
                  ],
                ),
              ),
              Expanded(
                child: _loading && _posts.isEmpty
                    ? const Center(child: CircularProgressIndicator())
                    : _error != null
                        ? ListView(
                            physics: const AlwaysScrollableScrollPhysics(),
                            children: [
                              SizedBox(height: MediaQuery.sizeOf(context).height * 0.16),
                              EmptyState(icon: Icons.error_outline, title: _error!),
                              const SizedBox(height: 14),
                              Padding(
                                padding: const EdgeInsets.symmetric(horizontal: 16),
                                child: PrimaryButton(label: t(context).commonTryAgain, onPressed: () => unawaited(_loadInitial())),
                              ),
                            ],
                          )
                        : _posts.isEmpty
                            ? ListView(
                                physics: const AlwaysScrollableScrollPhysics(),
                                children: [
                                  SizedBox(height: MediaQuery.sizeOf(context).height * 0.14),
                                  EmptyState(
                                    icon: Icons.map_outlined,
                                    title: _emptyTitle(),
                                  ),
                                  const SizedBox(height: 14),
                                  Padding(
                                    padding: const EdgeInsets.symmetric(horizontal: 16),
                                    child: PrimaryButton(
                                      label: isAuthenticated ? _ctaLabel() : t(context).ctaSignInToCreate,
                                      onPressed: () {
                                        if (!isAuthenticated) return showCtaSnackBar(context);
                                        final kind = _kindFilter ?? PostKind.request;
                                        Navigator.of(context).push(
                                          MaterialPageRoute<void>(
                                            builder: (_) => PostComposerScreen(
                                              draft: ComposerDraft(
                                                initialKind: kind,
                                                initialRegionPath: widget.args.location.path,
                                                initialCommunityId: widget.args.communityId,
                                              ),
                                            ),
                                          ),
                                        );
                                      },
                                    ),
                                  ),
                                ],
                              )
                            : ListView.builder(
                                controller: _scrollController,
                                padding: const EdgeInsets.only(top: 6, bottom: 10),
                                itemCount: _posts.length + (_loadingMore ? 1 : 0),
                                itemBuilder: (context, index) {
                                  if (index >= _posts.length) {
                                    return const Padding(
                                      padding: EdgeInsets.all(16),
                                      child: Center(child: SizedBox(width: 24, height: 24, child: CircularProgressIndicator(strokeWidth: 2))),
                                    );
                                  }
                                  final post = _posts[index];
                                  return PostCard(
                                    post: post,
                                    isAuthenticated: isAuthenticated,
                                    onOpenPost: () {
                                      Navigator.of(context).pushNamed(
                                        Routes.postDetail,
                                        arguments: PostDetailArgs(postId: post.id),
                                      );
                                    },
                                    onLike: () {
                                      if (!isAuthenticated) return showCtaSnackBar(context);
                                      unawaited(_handleLike(repo, post));
                                    },
                                    onPray: () {
                                      if (!isAuthenticated) return showCtaSnackBar(context);
                                      unawaited(_handlePray(repo, post));
                                    },
                                    onComment: () {
                                      if (!isAuthenticated) return showCtaSnackBar(context);
                                      Navigator.of(context).pushNamed(
                                        Routes.postComments,
                                        arguments: CommentsArgs(postId: post.id),
                                      );
                                    },
                                    onShare: () async {
                                      await showShareSheet(context, post: post, isAuthenticated: isAuthenticated);
                                    },
                                    onSave: () {
                                      if (!isAuthenticated) return showCtaSnackBar(context);
                                      final willSave = !post.viewerHasSaved;
                                      repo.toggleSave(post.id, isAuthenticated: true);
                                      if (willSave) showInfoSnackBar(context, t(context).commonSaved);
                                    },
                                  );
                                },
                              ),
              ),
            ],
          ),
        );
      },
    );
  }
}

class RegionAlertsScreen extends StatefulWidget {
  const RegionAlertsScreen({required this.args, super.key});

  final RegionAlertsArgs args;

