                            const SizedBox(width: 6),
                            Icon(Icons.verified, size: 18, color: context.brand.verifiedBlue),
                          ],
                        ],
                      ),
                      Text('@$displayUsername • $when', style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700)),
