class NewsEventDetailScreen extends StatefulWidget {
  const NewsEventDetailScreen({required this.args, super.key});

  final NewsEventDetailArgs args;

  @override
  State<NewsEventDetailScreen> createState() => _NewsEventDetailScreenState();
}

class _NewsEventDetailScreenState extends State<NewsEventDetailScreen> {
  Future<({NewsEventModel? event, List<NewsItemModel> items})>? _future;

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      _reload();
    });
  }

  Future<({NewsEventModel? event, List<NewsItemModel> items})> _fetchWithTranslations() async {
    final repo = RepoScope.of(context);
    final data = await repo.fetchNewsEventDetail(widget.args.eventId);
    final event = data.event;
    if (event == null) return data;

    final localeCode = _localeCode(Localizations.localeOf(context));
    final translatedTitleFuture = repo.fetchContentTranslation(
      entityType: 'news_event',
      entityId: event.id,
      fieldName: 'title',
      localeCode: localeCode,
    );
    final translatedSummaryFuture = repo.fetchContentTranslation(
      entityType: 'news_event',
      entityId: event.id,
      fieldName: 'summary',
      localeCode: localeCode,
    );

    final translatedTitle = await translatedTitleFuture;
    final translatedSummary = await translatedSummaryFuture;

    final merged = NewsEventModel(
      id: event.id,
      title: translatedTitle ?? event.title,
      summary: translatedSummary ?? event.summary,
      category: event.category,
      urgencyLevel: event.urgencyLevel,
      occurredAt: event.occurredAt,
      lastSeenAt: event.lastSeenAt,
      locationId: event.locationId,
      locationPath: event.locationPath,
      locationName: event.locationName,
      prayerPostId: event.prayerPostId,
      itemsCount: event.itemsCount,
    );

    return (event: merged, items: data.items);
  }

  void _reload() {
    setState(() {
      _future = _fetchWithTranslations();
    });
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final f = _future;
    return Scaffold(
      appBar: AppBar(
        title: const Text('Detalhe', style: TextStyle(fontWeight: FontWeight.w800)),
        actions: [
          IconButton(
            onPressed: repo.supabase == null || repo.isOffline ? null : _reload,
            icon: const Icon(Icons.refresh),
            tooltip: t(context).commonRefresh,
          ),
        ],
      ),
      body: f == null
          ? const Center(child: CircularProgressIndicator())
          : FutureBuilder<({NewsEventModel? event, List<NewsItemModel> items})>(
              future: f,
              builder: (context, snapshot) {
                if (snapshot.connectionState == ConnectionState.waiting) {
                  return const Center(child: CircularProgressIndicator());
                }
                final data = snapshot.data;
                final event = data?.event;
                final items = data?.items ?? const <NewsItemModel>[];
                if (event == null) {
                  return ListView(
                    children: [
                      SizedBox(height: MediaQuery.sizeOf(context).height * 0.16),
                      EmptyState(icon: Icons.public, title: t(context).eventLoadFailed),
                      const SizedBox(height: 14),
                      Padding(
                        padding: const EdgeInsets.symmetric(horizontal: 16),
                        child: PrimaryButton(label: t(context).commonTryAgain, onPressed: _reload),
                      ),
                    ],
                  );
                }

                final urgency = _parseAlertUrgency(event.urgencyLevel);
                final cs = Theme.of(context).colorScheme;
                final loc = (event.locationName ?? '').trim();
                final summary = (event.summary ?? '').trim();

                return ListView(
                  padding: const EdgeInsets.fromLTRB(16, 14, 16, 16),
                  children: [
                    Text(event.title, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 18)),
                    const SizedBox(height: 10),
                    Wrap(
                      spacing: 8,
                      runSpacing: 8,
                      children: [
                        _UrgencyPill(label: _alertUrgencyLabel(context, urgency), color: _alertUrgencyColor(urgency)),
                        if (loc.isNotEmpty) _Pill(label: loc, background: cs.surfaceContainerHighest, foreground: cs.onSurface),
                        _Pill(
                          label: _formatRelativeTimeForUser(context, event.lastSeenAt),
                          background: cs.surfaceContainerHighest,
                          foreground: cs.onSurface,
                        ),
                      ],
                    ),
                    if (summary.isNotEmpty) ...[
                      const SizedBox(height: 12),
                      Text(summary, style: TextStyle(color: cs.onSurface.withValues(alpha: 0.88))),
                    ],
                    if (event.prayerPostId != null && _looksLikeUuid(event.prayerPostId!)) ...[
                      const SizedBox(height: 14),
                      PrimaryButton(
                        label: 'Abrir pedido de oração',
                        onPressed: () {
                          Navigator.of(context).pushNamed(
                            Routes.postDetail,
                            arguments: PostDetailArgs(postId: event.prayerPostId!),
                          );
                        },
                      ),
                    ],
                    const SizedBox(height: 14),
                    const Text('Fontes', style: TextStyle(fontWeight: FontWeight.w900)),
                    const SizedBox(height: 6),
                    if (items.isEmpty)
                      Text('Sem links disponíveis.', style: TextStyle(color: cs.outline, fontWeight: FontWeight.w600))
                    else
                      for (final it in items)
                        ListTile(
                          contentPadding: EdgeInsets.zero,
                          leading: const Icon(Icons.link),
                          title: Text(it.title, maxLines: 2, overflow: TextOverflow.ellipsis),
                          subtitle: it.publishedAt == null
                              ? null
                              : Text(
                                  _formatRelativeTimeForUser(context, it.publishedAt!),
                                  style: TextStyle(color: cs.outline, fontWeight: FontWeight.w600),
                                ),
                          trailing: const Icon(Icons.open_in_new),
                          onTap: it.url == null
                              ? null
                              : () async {
                                  final uri = Uri.tryParse(it.url!);
                                  if (uri == null) return;
                                  await launchUrl(uri, mode: LaunchMode.externalApplication);
                                },
                        ),
                  ],
                );
              },
            ),
    );
  }
}

class _RegionAlertsScreenState extends State<RegionAlertsScreen> {
  final _scrollController = ScrollController();
  var _loading = true;
  var _loadingMore = false;
  var _hasMore = true;
  String? _error;
  String? _resolvedLocationId;
  DateTime? _cursorCreatedAt;
  List<AlertModel> _alerts = const [];

  @override
  void initState() {
    super.initState();
    _scrollController.addListener(_maybeLoadMore);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_loadInitial());
    });
  }

  @override
  void dispose() {
    _scrollController.dispose();
    super.dispose();
  }

  void _maybeLoadMore() {
    if (!_hasMore || _loading || _loadingMore) return;
    final pos = _scrollController.position;
    if (pos.maxScrollExtent <= 0) return;
    if (pos.pixels < pos.maxScrollExtent - 320) return;
    unawaited(_loadMore());
  }

  Future<String?> _ensureLocationId(DemoRepository repo) async {
    final id = widget.args.location.id;
    if (_looksLikeUuid(id)) return id;
    return repo.locationIdByPath(widget.args.location.path);
  }

  Future<void> _loadInitial() async {
    if (!mounted) return;
    setState(() {
      _loading = true;
      _loadingMore = false;
      _hasMore = true;
      _error = null;
      _cursorCreatedAt = null;
      _alerts = const [];
    });

    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    final useRemote = repo.supabase != null && !repo.isOffline;
    final s = session.value;

    if (!useRemote) {
      final all = widget.args.communityId == null
          ? repo.alertsForRegion(s, widget.args.location.path)
          : repo.alertsForRegionInCommunity(s, widget.args.location.path, widget.args.communityId!);
      final sorted = all.toList(growable: false)..sort((a, b) => b.createdAt.compareTo(a.createdAt));
      if (!mounted) return;
      setState(() {
        _loading = false;
        _hasMore = false;
        _alerts = sorted;
      });
      return;
    }

    final locationId = await _ensureLocationId(repo);
    if (!mounted) return;
    if (locationId == null) {
      setState(() {
        _loading = false;
        _error = t(context).regionIdentifyFailed;
      });
      return;
    }
    _resolvedLocationId = locationId;
    final items = await repo.fetchRegionAlertsByLocationId(
      locationId,
      communityId: widget.args.communityId,
      limit: 20,
    );
    if (!mounted) return;
    setState(() {
      _loading = false;
      _alerts = items;
      _cursorCreatedAt = items.isEmpty ? null : items.last.createdAt;
      _hasMore = items.length >= 20;
    });
  }

  Future<void> _loadMore() async {
    final repo = RepoScope.of(context);
    if (repo.supabase == null || repo.isOffline) return;
    final locationId = _resolvedLocationId;
    final cursor = _cursorCreatedAt;
    if (locationId == null || cursor == null) {
      setState(() => _hasMore = false);
      return;
    }
    setState(() => _loadingMore = true);
    final items = await repo.fetchRegionAlertsByLocationId(
      locationId,
      communityId: widget.args.communityId,
      cursorCreatedAt: cursor,
      limit: 20,
    );
    if (!mounted) return;
    final existingIds = _alerts.map((a) => a.id).toSet();
    final next = [..._alerts, ...items.where((a) => !existingIds.contains(a.id))];
    setState(() {
      _loadingMore = false;
      _alerts = next;
      _cursorCreatedAt = items.isEmpty ? _cursorCreatedAt : items.last.createdAt;
      _hasMore = items.length >= 20;
    });
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    final s = session.value;
    final isAuthenticated = s.isAuthenticated;
    final communityName = widget.args.communityId == null ? null : repo.findCommunity(widget.args.communityId!)?.name;
    final titleBase = widget.args.location.name;
    final title = communityName == null
        ? t(context).alertsTitleWithLocation(titleBase)
        : t(context).alertsTitleWithLocationAndCommunity(titleBase, communityName);
    final subtitle = widget.args.contextBreadcrumb ?? widget.args.location.path;

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        return Scaffold(
          appBar: AppBar(
            title: Text(t(context).alertsTitle, style: const TextStyle(fontWeight: FontWeight.w800)),
          ),
          body: Column(
            children: [
              if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
              Padding(
                padding: const EdgeInsets.fromLTRB(12, 10, 12, 4),
                child: Row(
                  children: [
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          Text(title, style: const TextStyle(fontWeight: FontWeight.w900)),
                          const SizedBox(height: 2),
                          Text(subtitle, style: TextStyle(color: Theme.of(context).colorScheme.outline, fontWeight: FontWeight.w600)),
                        ],
                      ),
                    ),
                    AtalaiaIconButton(
                      icon: Icons.refresh,
                      label: t(context).commonRefresh,
                      onPressed: () {
                        if (repo.supabase == null || repo.isOffline) return;
                        unawaited(_loadInitial());
                      },
                    ),
                  ],
                ),
              ),
              Expanded(
                child: _loading && _alerts.isEmpty
                    ? const Center(child: CircularProgressIndicator())
                    : _error != null
                        ? ListView(
                            physics: const AlwaysScrollableScrollPhysics(),
                            children: [
                              SizedBox(height: MediaQuery.sizeOf(context).height * 0.16),
                              EmptyState(icon: Icons.error_outline, title: _error!),
                              const SizedBox(height: 14),
                              Padding(
                                padding: const EdgeInsets.symmetric(horizontal: 16),
                                child: PrimaryButton(label: t(context).commonTryAgain, onPressed: () => unawaited(_loadInitial())),
                              ),
                            ],
                          )
                        : _alerts.isEmpty
                            ? ListView(
                                physics: const AlwaysScrollableScrollPhysics(),
                                children: [
                                  SizedBox(height: MediaQuery.sizeOf(context).height * 0.14),
                                  EmptyState(
                                    icon: Icons.notification_important_outlined,
                                    title: t(context).alertsNoAlertsInRegion,
                                  ),
                                  const SizedBox(height: 14),
                                  Padding(
                                    padding: const EdgeInsets.symmetric(horizontal: 16),
                                    child: PrimaryButton(
                                      label: isAuthenticated ? t(context).alertsCreateAlert : t(context).ctaSignInToCreate,
                                      onPressed: () {
                                        if (!isAuthenticated) return showCtaSnackBar(context);
                                        Navigator.of(context).pushNamed(Routes.createPost);
                                      },
                                    ),
                                  ),
                                ],
                              )
                            : ListView.builder(
                                controller: _scrollController,
                                padding: const EdgeInsets.only(top: 6, bottom: 10),
                                itemCount: _alerts.length + (_loadingMore ? 1 : 0),
                                itemBuilder: (context, index) {
                                  if (index >= _alerts.length) {
                                    return const Padding(
                                      padding: EdgeInsets.all(16),
                                      child: Center(child: SizedBox(width: 24, height: 24, child: CircularProgressIndicator(strokeWidth: 2))),
                                    );
                                  }
                                  final alert = _alerts[index];
                                  return AlertCard(
                                    alert: alert,
                                    isAuthenticated: isAuthenticated,
                                    onOpen: () {
                                      Navigator.of(context).pushNamed(
                                        Routes.alertDetail,
                                        arguments: AlertDetailArgs(alertId: alert.id),
                                      );
                                    },
                                    onFollow: () {
                                      if (!isAuthenticated) return showCtaSnackBar(context);
                                      final willFollow = !alert.viewerIsFollowing;
                                      repo.toggleFollowAlert(alert.id, isAuthenticated: true);
                                      showInfoSnackBar(
                                        context,
                                        willFollow ? t(context).alertFollowingStartedSnack : t(context).alertFollowingStoppedSnack,
                                      );
                                    },
                                  );
                                },
                              ),
              ),
            ],
          ),
        );
      },
    );
  }
}

enum _PrayerExitChoice { finish, cancel, keepPraying }

final class _PrayerFinishRecord {
  const _PrayerFinishRecord({
    required this.type,
    required this.text,
  });

  final String type;
  final String text;
}

final class _PrayerLibrarySelection {
  const _PrayerLibrarySelection({this.playlistId, this.mediaItemId});

