}

class PrayerSessionScreen extends StatefulWidget {
  const PrayerSessionScreen({required this.args, super.key});

  final RegionPrayerArgs args;

  @override
  State<PrayerSessionScreen> createState() => _PrayerSessionScreenState();
}

class _PrayerSessionScreenState extends State<PrayerSessionScreen> {
  Timer? _ticker;
  DateTime? _startedAt;
  DateTime? _pausedAt;
  var _pausedTotal = Duration.zero;

  var _starting = false;
  var _creating = true;
  var _finishing = false;
  var _loadedLastLibrarySelection = false;
  String? _selectedPlaylistId;
  String? _selectedMediaItemId;
  String? _sessionId;
  String? _error;
  VideoPlayerController? _inlinePlayerController;
  ypf.YoutubePlayerController? _inlineYoutubeMobileController;
  String? _inlineYoutubeVideoId;
  bool _inlineYoutubePlaying = false;
  bool _inlinePlayerLoading = false;
  String? _inlinePlayerError;
  String? _inlinePlayerErrorDetails;

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_start());
    });
  }

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();
    if (_loadedLastLibrarySelection) return;
    _loadedLastLibrarySelection = true;
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_loadLastPrayerLibrarySelection());
    });
  }

  @override
  void dispose() {
    _ticker?.cancel();
    _inlinePlayerController?.dispose();
    _inlineYoutubeMobileController?.dispose();
    super.dispose();
  }

  bool get _isPaused => _pausedAt != null;

  Duration _elapsed(DateTime now) {
    final startedAt = _startedAt;
    if (startedAt == null) return Duration.zero;
    final pausedAt = _pausedAt;
    final base = pausedAt == null ? now.difference(startedAt) : pausedAt.difference(startedAt);
    final d = base - _pausedTotal;
    if (d.isNegative) return Duration.zero;
    return d;
  }

  String _formatDuration(Duration d) {
    final total = d.inSeconds;
    final h = total ~/ 3600;
    final m = (total % 3600) ~/ 60;
    final s = total % 60;
    String two(int v) => v.toString().padLeft(2, '0');
    return h > 0 ? '${two(h)}:${two(m)}:${two(s)}' : '${two(m)}:${two(s)}';
  }

  String _shortSupabaseError(Object e) {
    if (e is PostgrestException) {
      final parts = <String>[
        e.message,
        if ((e.code ?? '').toString().trim().isNotEmpty) 'code=${e.code}',
        if ((e.details ?? '').toString().trim().isNotEmpty) 'details=${e.details}',
        if ((e.hint ?? '').toString().trim().isNotEmpty) 'hint=${e.hint}',
      ];
      return parts.where((p) => p.trim().isNotEmpty).join(' • ');
    }
    if (e is AuthException) return e.message;
    return e.toString();
  }

  void _startTicker() {
    _ticker?.cancel();
    _ticker = Timer.periodic(const Duration(seconds: 1), (_) {
      if (!mounted) return;
      setState(() {});
    });
  }

  Future<void> _start() async {
    if (_starting || _finishing) return;
    _starting = true;
    setState(() {
      _creating = true;
      _finishing = false;
      _error = null;
      _sessionId = null;
      _startedAt = null;
      _pausedAt = null;
      _pausedTotal = Duration.zero;
    });

    try {
      final repo = RepoScope.of(context);
      final sb = repo.supabase;
      final session = SessionScope.of(context).value;

      if (session is! AuthSession || sb?.auth.currentUser == null) {
        await showAuthGate(context);
        if (!mounted) return;
        Navigator.of(context).pop();
        return;
      }

      final startedAt = DateTime.now();
      final id = await repo.createPrayerSession(
        locationId: widget.args.locationId,
        locationLevel: widget.args.locationLevel,
        challengeId: widget.args.challengeId,
        communityId: widget.args.communityId,
        scheduleRunId: widget.args.scheduleRunId,
        startedAt: startedAt,
      );
      if (!mounted) return;
      setState(() {
        _creating = false;
        _sessionId = id;
        _startedAt = startedAt;
      });
      _startTicker();
    } catch (e, st) {
      assert(() {
        final repo = RepoScope.of(context);
        final uid = repo.supabase?.auth.currentUser?.id;
        debugPrint(
          '[prayer] createPrayerSession failed uid=${uid ?? ''} locationId=${widget.args.locationId} level=${widget.args.locationLevel}',
        );
        if (e is PostgrestException) {
          debugPrint('[prayer] postgrest message=${e.message} code=${e.code} details=${e.details} hint=${e.hint}');
        } else {
          debugPrint('[prayer] error=$e');
        }
        debugPrintStack(stackTrace: st);
        return true;
      }());
      if (!mounted) return;
      var errorText = t(context).prayerSessionStartFailed;
      assert(() {
        final short = _shortSupabaseError(e).trim();
        if (short.isNotEmpty) errorText = 'Algo deu errado: $short';
        return true;
      }());
      setState(() {
        _creating = false;
        _error = errorText;
      });
      assert(() {
        final short = _shortSupabaseError(e).trim();
        if (short.isEmpty) return true;
        WidgetsBinding.instance.addPostFrameCallback((_) {
          if (!mounted) return;
          showAtalaiaSnackBar(context, '${t(context).commonSomethingWentWrong}: $short', kind: AtalaiaSnackKind.error);
        });
        return true;
      }());
    } finally {
      _starting = false;
    }
  }

  String _prayerLibrarySelectionKey(String userId) => 'prayer_library_selection_v1:$userId';

  Future<void> _loadLastPrayerLibrarySelection() async {
    final session = SessionScope.of(context).value;
    if (session is! AuthSession) return;
    try {
      final sp = await SharedPreferences.getInstance();
      final raw = sp.getString(_prayerLibrarySelectionKey(session.userId));
      if (raw == null || raw.trim().isEmpty) return;
      final decoded = jsonDecode(raw);
      if (decoded is! Map) return;
      final playlistId = decoded['playlistId']?.toString().trim();
      final mediaItemId = decoded['mediaItemId']?.toString().trim();
      final resolvedPlaylistId = (playlistId == null || playlistId.isEmpty) ? null : playlistId;
      final resolvedMediaItemId = (mediaItemId == null || mediaItemId.isEmpty) ? null : mediaItemId;
      if (!mounted) return;
      if (resolvedPlaylistId == null && resolvedMediaItemId == null) return;
      setState(() {
        _selectedPlaylistId = resolvedPlaylistId;
        _selectedMediaItemId = resolvedMediaItemId;
      });

      // Prepare a ready-to-play preview without autoplay.
      final repo = RepoScope.of(context);
      final playbackItem = _selectedPlaybackItem(repo);
      if (playbackItem == null) return;
      if (playbackItem.type == PlaylistItemType.youtube) {
        final videoId = _extractYoutubeVideoId(playbackItem.mediaUrl);
        if (!mounted) return;
        setState(() {
          _inlineYoutubeVideoId = videoId;
          _inlineYoutubePlaying = false;
          _inlinePlayerLoading = false;
          _inlinePlayerError = null;
          _inlinePlayerErrorDetails = null;
        });
      }
    } catch (_) {}
  }

  Future<void> _saveLastPrayerLibrarySelection({required AuthSession session}) async {
    try {
      final sp = await SharedPreferences.getInstance();
      final data = <String, Object?>{
        'playlistId': _selectedPlaylistId,
        'mediaItemId': _selectedMediaItemId,
      };
      await sp.setString(_prayerLibrarySelectionKey(session.userId), jsonEncode(data));
    } catch (_) {}
  }

