                                                          ),
                                                        ),
                                              if (_inlinePlayerError != null) ...[
                                                const SizedBox(height: 8),
                                                Text(
                                                  _inlinePlayerError!,
                                                  style: TextStyle(color: cs.error, fontWeight: FontWeight.w700),
                                                ),
                                                if (_inlinePlayerErrorDetails != null && _inlinePlayerErrorDetails!.trim().isNotEmpty)
