                                  if (_isPaused) {
                                    _resume();
                                  } else {
                                    _pause();
                                  }
                                },
                        ),
                      ),
                      const SizedBox(width: 12),
                      Expanded(
                        child: PrimaryButton(
                          label: t(context).prayerSessionFinishAction,
                          loading: _finishing,
                          onPressed: _finishing ? null : () => unawaited(_finish(status: 'finished', outcome: PrayerSessionOutcome.finished)),
                        ),
                      ),
                    ],
                  ),
                ],
              ],
            ),
          ),
        ),
      ),
