class CommentsScreen extends StatefulWidget {
  const CommentsScreen({required this.args, super.key});

  final CommentsArgs args;

  @override
  State<CommentsScreen> createState() => _CommentsScreenState();
}

class _CommentsScreenState extends State<CommentsScreen> {
  final _text = TextEditingController();
  final _scrollController = ScrollController();

  var _initialLoading = true;
  var _loadingMore = false;
  var _loadedCount = 0;

  static const _pageSize = 24;

  @override
  void initState() {
    super.initState();
    _scrollController.addListener(_onScroll);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_loadInitial());
    });
  }

  Future<void> _loadInitial() async {
    final repo = RepoScope.of(context);
    if (repo.supabase != null && !repo.isOffline) {
      await repo.refreshCommentsForPost(widget.args.postId);
    }
    await Future<void>.delayed(const Duration(milliseconds: 350));
    if (!mounted) return;
    setState(() => _initialLoading = false);
    _ensureMinLoaded();
  }

  void _ensureMinLoaded() {
    final repo = RepoScope.of(context);
    final total = repo.commentsForPost(widget.args.postId).length;
    if (_loadedCount == 0 && total > 0) {
      setState(() => _loadedCount = total.clamp(0, _pageSize));
    }
  }

  void _onScroll() {
    if (_initialLoading || _loadingMore) return;
    if (!_scrollController.hasClients) return;

    final pos = _scrollController.position;
    if (pos.maxScrollExtent <= 0) return;
    final remaining = pos.maxScrollExtent - pos.pixels;
    if (remaining > 240) return;

    final repo = RepoScope.of(context);
    final total = repo.commentsForPost(widget.args.postId).length;
    if (_loadedCount >= total) return;

    setState(() => _loadingMore = true);
    Future<void>.delayed(const Duration(milliseconds: 320)).then((_) {
      if (!mounted) return;
      final repo = RepoScope.of(context);
      final total = repo.commentsForPost(widget.args.postId).length;
      setState(() {
        _loadedCount = (_loadedCount + _pageSize).clamp(0, total);
        _loadingMore = false;
      });
    });
  }

  @override
  void dispose() {
    _scrollController.dispose();
    _text.dispose();
    super.dispose();
  }

  Future<void> _openCommentMenu(
    BuildContext context, {
    required CommentModel comment,
    required bool isAuthenticated,
    required String? viewerId,
  }) async {
    final canDelete = isAuthenticated && viewerId != null && comment.userId == viewerId;
    final choice = await showAtalaiaBottomSheet<String>(
      context,
      builder: (context) {
        final l10n = t(context);
        return SafeArea(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              ListTile(
                leading: const Icon(Icons.flag_outlined),
                title: Text(l10n.postActionReport),
                onTap: () => Navigator.pop(context, 'report'),
              ),
              if (canDelete)
                ListTile(
                  leading: const Icon(Icons.delete_outline),
                  title: Text(l10n.postActionDelete),
                  onTap: () => Navigator.pop(context, 'delete'),
                ),
              const SizedBox(height: 8),
            ],
          ),
        );
      },
    );

    if (!context.mounted) return;

    switch (choice) {
      case 'report':
        if (!isAuthenticated) return showCtaSnackBar(context);
        final selected = await showReportReasonSheet(context);
        if (!context.mounted) return;
        if (selected != null) {
          if (viewerId == null) return;
          final repo = RepoScope.of(context);
          await repo.submitReport(
            reporterId: viewerId,
            entityType: ReportEntityType.comment,
            entityId: comment.id,
            reason: selected.reason.name,
            description: selected.otherText,
            reportedUserId: comment.userId,
          );
          if (!context.mounted) return;
          showInfoSnackBar(context, t(context).postSnackReportSent);
        }
      case 'delete':
        if (!canDelete) return;
        final ok = await showAtalaiaConfirmDialog(
          context,
          title: t(context).commentDeleteConfirmTitle,
          confirmLabel: t(context).postActionDelete,
          isDestructive: true,
        );
        if (!context.mounted) return;
        if (ok == true) {
          final repo = RepoScope.of(context);
          repo.deleteComment(
            comment.postId,
            comment.id,
            viewerId: viewerId,
          );
          showInfoSnackBar(context, t(context).commentDeletedSnack);
        }
      default:
        return;
    }
  }

  void _send() {
    final session = SessionScope.of(context).value;
    if (session is! AuthSession) return showCtaSnackBar(context);
    final repo = RepoScope.of(context);
    repo.addCommentText(widget.args.postId, session: session, text: _text.text);
    _text.clear();
    final total = repo.commentsForPost(widget.args.postId).length;
    setState(() {
      _loadedCount = total.clamp(0, _loadedCount + 1);
    });
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final isAuthenticated = session.value.isAuthenticated;
        final viewerId = session.value is AuthSession ? (session.value as AuthSession).userId : null;
        final all = repo.commentsForPost(widget.args.postId);
        final total = all.length;
        final shown = _initialLoading ? const <CommentModel>[] : all.take(_loadedCount).toList();

        return Scaffold(
          appBar: AppBar(
            title: Text(total == 0 ? t(context).commentsTitle : t(context).campaignCommentsTitle(total)),
          ),
          body: Column(
            children: [
              if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
              Expanded(
                child: _initialLoading
                    ? ListView.builder(
                        padding: const EdgeInsets.all(12),
                        itemCount: 6,
                        itemBuilder: (context, index) {
                          final cs = Theme.of(context).colorScheme;
                          return Padding(
                            padding: const EdgeInsets.symmetric(vertical: 10),
                            child: Row(
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                                Container(
                                  width: 28,
                                  height: 28,
                                  decoration: BoxDecoration(
                                    color: cs.surfaceContainerHighest,
                                    shape: BoxShape.circle,
                                  ),
                                ),
                                const SizedBox(width: 10),
                                Expanded(
                                  child: Column(
                                    crossAxisAlignment: CrossAxisAlignment.start,
                                    children: [
                                      Container(
                                        height: 12,
                                        width: 140,
                                        decoration: BoxDecoration(
                                          color: cs.surfaceContainerHighest,
                                          borderRadius: BorderRadius.circular(6),
                                        ),
                                      ),
                                      const SizedBox(height: 8),
                                      Container(
                                        height: 12,
                                        decoration: BoxDecoration(
                                          color: cs.surfaceContainerHighest,
                                          borderRadius: BorderRadius.circular(6),
                                        ),
                                      ),
                                      const SizedBox(height: 6),
                                      Container(
                                        height: 12,
                                        width: 220,
                                        decoration: BoxDecoration(
                                          color: cs.surfaceContainerHighest,
                                          borderRadius: BorderRadius.circular(6),
                                        ),
                                      ),
                                    ],
                                  ),
                                ),
                              ],
                            ),
                          );
                        },
                      )
                    : (total == 0
                        ? ListView(
                            physics: const AlwaysScrollableScrollPhysics(),
                            children: [
                              SizedBox(height: MediaQuery.sizeOf(context).height * 0.18),
                              EmptyState(icon: Icons.chat_bubble_outline, title: t(context).commentBeFirst),
                            ],
                          )
                        : ListView.builder(
                            controller: _scrollController,
                            padding: const EdgeInsets.fromLTRB(12, 12, 12, 12),
                            itemCount: shown.length + (_loadingMore ? 1 : 0),
                            itemBuilder: (context, index) {
                              if (_loadingMore && index == shown.length) {
                                return const Padding(
                                  padding: EdgeInsets.symmetric(vertical: 16),
                                  child: Center(child: CircularProgressIndicator()),
                                );
                              }

                              final c = shown[index];
                              final cs = Theme.of(context).colorScheme;
                              final identity = _identityForUserId(
                                repo,
                                c.userId,
                                legacyVerified: c.isVerified,
                                userFallback: t(context).commonUserFallback,
                              );
                              return Padding(
                                padding: const EdgeInsets.symmetric(vertical: 10),
                                child: Row(
                                  crossAxisAlignment: CrossAxisAlignment.start,
                                  children: [
                                    Avatar(name: identity.avatarName, imageUrl: identity.avatarUrl, size: AvatarSize.s32),
                                    const SizedBox(width: 10),
                                    Expanded(
                                      child: Column(
                                        crossAxisAlignment: CrossAxisAlignment.start,
                                        children: [
                                          Row(
                                            children: [
                                              Flexible(
                                                child: Text(
                                                  identity.displayName,
                                                  maxLines: 1,
                                                  overflow: TextOverflow.ellipsis,
                                                  style: const TextStyle(fontWeight: FontWeight.w800),
                                                ),
                                              ),
                                              if (identity.isVerified) ...[
                                                const SizedBox(width: 6),
                                                Icon(Icons.verified, size: 16, color: context.brand.verifiedBlue),
                                              ],
                                              const SizedBox(width: 8),
                                              Text(
                                                _relativeTime(context, c.createdAt),
                                                style: TextStyle(color: cs.outline),
                                              ),
                                              const Spacer(),
                                              AtalaiaIconButton(
                                                icon: Icons.more_horiz,
                                                label: t(context).postMore,
                                                onPressed: () => _openCommentMenu(
                                                  context,
                                                  comment: c,
                                                  isAuthenticated: isAuthenticated,
                                                  viewerId: viewerId,
                                                ),
                                              ),
                                            ],
                                          ),
                                          const SizedBox(height: 2),
                                          Text(
                                            '@${identity.username}',
                                            style: TextStyle(color: cs.outline, fontWeight: FontWeight.w600),
                                            maxLines: 1,
                                            overflow: TextOverflow.ellipsis,
                                          ),
                                          const SizedBox(height: 4),
                                          Text(c.body),
                                        ],
                                      ),
                                    ),
                                  ],
                                ),
                              );
                            },
                          )),
              ),
              SafeArea(
                top: false,
                child: Padding(
                  padding: const EdgeInsets.fromLTRB(12, 8, 12, 12),
                  child: Row(
                    children: [
                      Expanded(
                        child: AtalaiaTextField(
                          controller: _text,
                          enabled: isAuthenticated,
                          hintText: isAuthenticated ? t(context).commentAddLabel : t(context).postSignInToComment,
                          minLines: 1,
                          maxLines: 3,
                          keyboardType: TextInputType.multiline,
                          textInputAction: TextInputAction.send,
                          onSubmitted: (_) => _send(),
                        ),
                      ),
                      const SizedBox(width: 8),
                      AtalaiaFilledIconButton(
                        icon: Icons.send_rounded,
                        label: t(context).postComment,
                        onPressed: _send,
                      ),
                    ],
                  ),
                ),
              ),
            ],
          ),
        );
      },
    );
  }
}

class PostDetailScreen extends StatefulWidget {
  const PostDetailScreen({required this.args, super.key});

  final PostDetailArgs args;

  @override
  State<PostDetailScreen> createState() => _PostDetailScreenState();
}

class _PostDetailScreenState extends State<PostDetailScreen> {
  var _scheduledMissingPop = false;
  var _showLikePulse = false;
  var _loading = true;
  Future<bool>? _hydrateFuture;

  @override
  void initState() {
    super.initState();
    Future<void>.delayed(const Duration(milliseconds: 260)).then((_) {
      if (!mounted) return;
      setState(() => _loading = false);
    });
  }

  @override
  void dispose() {
    super.dispose();
  }

  void _pulseLike() {
    if (_showLikePulse) return;
    setState(() => _showLikePulse = true);
    Future<void>.delayed(const Duration(milliseconds: 360)).then((_) {
      if (!mounted) return;
      setState(() => _showLikePulse = false);
    });
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final post = repo.findPost(widget.args.postId);
        if (post == null) {
          final canHydrate = repo.supabase != null && !repo.isOffline;
          if (canHydrate && _hydrateFuture == null) {
            _hydrateFuture = repo.hydratePostById(widget.args.postId);
            unawaited(
              _hydrateFuture!.then((ok) {
                if (!ok) return;
                unawaited(repo.refreshCommentsForPost(widget.args.postId));
              }),
            );
          }

          if (_hydrateFuture != null) {
            final l10n = t(context);
            return Scaffold(
              appBar: AppBar(title: Text(l10n.postTitle)),
              body: FutureBuilder<bool>(
                future: _hydrateFuture,
                builder: (context, snapshot) {
                  final hydrated = repo.findPost(widget.args.postId);
                  if (hydrated != null || snapshot.connectionState != ConnectionState.done) {
                    return ListView(
                      physics: const AlwaysScrollableScrollPhysics(),
                      padding: const EdgeInsets.fromLTRB(12, 12, 12, 16),
                      children: const [
                        PostCardSkeleton(hasMedia: true, margin: EdgeInsets.zero),
                        SizedBox(height: 14),
                        RowSkeleton(primaryWidth: 160, secondaryWidth: 220),
                        RowSkeleton(primaryWidth: 180, secondaryWidth: 260),
                      ],
                    );
                  }
                  return Center(
                    child: Padding(
                      padding: const EdgeInsets.all(20),
                      child: Column(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Text(l10n.postUnavailable),
                          const SizedBox(height: 12),
                          PrimaryButton(label: l10n.commonBack, onPressed: () => Navigator.of(context).maybePop()),
                        ],
                      ),
                    ),
                  );
                },
              ),
            );
          }

          if (!_scheduledMissingPop) {
            _scheduledMissingPop = true;
            Future<void>.delayed(const Duration(milliseconds: 1200)).then((_) {
              if (!mounted) return;
              Navigator.of(context).maybePop();
            });
          }
          final l10n = t(context);
          return Scaffold(
            appBar: AppBar(title: Text(l10n.postTitle)),
            body: Center(
              child: Padding(
                padding: const EdgeInsets.all(20),
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    Text(l10n.postUnavailable),
                    const SizedBox(height: 12),
                    PrimaryButton(label: l10n.commonBack, onPressed: () => Navigator.of(context).maybePop()),
                  ],
                ),
              ),
            ),
          );
        }

        if (_loading) {
          final l10n = t(context);
          return Scaffold(
            appBar: AppBar(title: Text(l10n.postTitle)),
            body: ListView(
              physics: const AlwaysScrollableScrollPhysics(),
              padding: const EdgeInsets.fromLTRB(12, 12, 12, 16),
              children: const [
                PostCardSkeleton(hasMedia: true, margin: EdgeInsets.zero),
                SizedBox(height: 14),
                RowSkeleton(primaryWidth: 160, secondaryWidth: 220),
                RowSkeleton(primaryWidth: 180, secondaryWidth: 260),
              ],
            ),
          );
        }

        final l10n = t(context);
        final cs = Theme.of(context).colorScheme;
        final isAuthenticated = session.value.isAuthenticated;
        final identity = _identityForUserId(repo, post.userId, legacyVerified: post.isVerified, userFallback: l10n.commonUserFallback);
        final viewer = session.value;
        final viewerProfile = viewer is AuthSession ? repo.profileForUserId(viewer.userId) : null;
        final viewerName = viewerProfile == null ? null : _displayNameForProfile(viewerProfile, userFallback: l10n.commonUserFallback).trim();

        Widget actionWithCount({
          required IconData icon,
          required String label,
          required VoidCallback onTap,
          required int count,
          Color? color,
        }) {
          final showCount = count > 0;
          final fg = color ?? cs.onSurfaceVariant;
          return Semantics(
            button: true,
            label: showCount ? '$label ($count)' : label,
            child: Tooltip(
              message: label,
              child: Material(
                color: Colors.transparent,
                child: InkWell(
                  borderRadius: BorderRadius.circular(14),
                  onTap: onTap,
                  child: ConstrainedBox(
                    constraints: const BoxConstraints(minWidth: AtalaiaTapTarget.min, minHeight: AtalaiaTapTarget.min),
                    child: Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 10),
                      child: Row(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Icon(icon, size: 22, color: fg),
                          if (showCount) ...[
                            const SizedBox(width: 6),
                            Text(
                              '$count',
                              style: TextStyle(color: fg, fontWeight: FontWeight.w800, fontSize: 12, height: 1.0),
                            ),
                          ],
                        ],
                      ),
                    ),
                  ),
                ),
              ),
            ),
          );
        }

        Widget prayAction() {
          final count = post.prayerCount;
          final showCount = count > 0;
          if (post.viewerHasPrayed) {
            return actionWithCount(
              icon: Icons.volunteer_activism,
              label: l10n.postPrayAction,
              onTap: () {
                if (!isAuthenticated) return showCtaSnackBar(context);
                repo.togglePrayer(post.id, isAuthenticated: true);
              },
              count: count,
              color: const Color(0xFF2E7D32),
            );
          }

          final fg = cs.onSurfaceVariant;
          return Semantics(
            button: true,
            label: showCount ? '${l10n.postPrayAction} ($count)' : l10n.postPrayAction,
            child: Tooltip(
              message: l10n.postPrayAction,
              child: Material(
                color: Colors.transparent,
                child: InkWell(
                  borderRadius: BorderRadius.circular(14),
                  onTap: () {
                    if (!isAuthenticated) return showCtaSnackBar(context);
                    repo.togglePrayer(post.id, isAuthenticated: true);
                  },
                  child: ConstrainedBox(
                    constraints: const BoxConstraints(minWidth: AtalaiaTapTarget.min, minHeight: AtalaiaTapTarget.min),
                    child: Padding(
                      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 10),
                      child: Row(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Icon(Icons.volunteer_activism_outlined, size: 22, color: fg),
                          if (showCount) ...[
                            const SizedBox(width: 6),
                            Text(
                              '$count',
                              style: TextStyle(color: fg, fontWeight: FontWeight.w800, fontSize: 12, height: 1.0),
                            ),
                          ],
                          const SizedBox(width: 8),
                          Text(
                            l10n.postPrayAction,
                            style: TextStyle(color: fg, fontWeight: FontWeight.w900, fontSize: 12, height: 1.0),
                          ),
                        ],
                      ),
                    ),
                  ),
                ),
              ),
            ),
          );
        }

        String? prayerByline() {
          final total = post.prayerCount;
          if (total <= 0) return null;
          final cached = repo.prayerUsernamesForPost(post.id);
          if (cached.isEmpty) {
            unawaited(repo.prefetchPrayerUsernamesForPost(post.id));
          }
          final first = cached.isNotEmpty ? cached.first : (post.viewerHasPrayed ? viewerName : null);
          if (total == 1) {
            return first == null ? l10n.postPrayedByOnePerson : l10n.postPrayedByName(first);
          }
          if (total == 2) {
            if (first != null) return l10n.postPrayedByNameAndOneOther(first);
            return l10n.postPrayedByTwoPeople;
          }
          if (first != null) return l10n.postPrayedByNameAndOthers(first);
