        );
      },
    );
  }
}

enum _CreateMode { post, story, video }

class CreatePostFlowScreen extends StatefulWidget {
  const CreatePostFlowScreen({
    super.key,
    this.initialMode = _CreateMode.post,
  });

  final _CreateMode initialMode;

  @override
  State<CreatePostFlowScreen> createState() => _CreatePostFlowScreenState();
}

class _CreatePostFlowScreenState extends State<CreatePostFlowScreen> {
  final ImagePicker _imagePicker = ImagePicker();
  late _CreateMode _mode;
  var _didAutoOpenStoryGallery = false;

  @override
  void initState() {
    super.initState();
    _mode = widget.initialMode;
  }

  String get _title {
    return switch (_mode) {
      _CreateMode.post => t(context).createFlowTitleNewPost,
      _CreateMode.story => t(context).createFlowTitleNewStory,
      _CreateMode.video => t(context).createFlowTitleNewVideo,
    };
  }

  String? _extensionFromPath(String path, {required bool isVideo}) {
    final i = path.lastIndexOf('.');
    if (i < 0 || i == path.length - 1) return isVideo ? 'mp4' : 'jpg';
    final ext = path.substring(i + 1).toLowerCase().trim();
    return ext.isEmpty ? (isVideo ? 'mp4' : 'jpg') : ext;
  }

  String? _inferContentType(String ext, {required bool isVideo}) {
    final e = ext.toLowerCase();
    if (!isVideo) {
      if (e == 'jpg' || e == 'jpeg') return 'image/jpeg';
      if (e == 'png') return 'image/png';
      if (e == 'webp') return 'image/webp';
      return 'image/jpeg';
    }
    if (e == 'mp4') return 'video/mp4';
    if (e == 'mov') return 'video/quicktime';
    if (e == 'm4v') return 'video/x-m4v';
    if (e == 'webm') return 'video/webm';
    return 'video/mp4';
  }

  Future<XFile?> _pickStoryMediaFromGallery() async {
    if (kIsWeb) return null;
    try {
      return await _imagePicker.pickImage(source: ImageSource.gallery);
    } catch (_) {
      return null;
    }
  }

  Future<PlatformFile?> _pickStoryMediaFromFilePicker() async {
    final picked = await FilePicker.platform.pickFiles(
      type: FileType.custom,
      allowMultiple: false,
      withData: true,
      allowedExtensions: const ['jpg', 'jpeg', 'png', 'webp'],
    );
    if (!context.mounted) return null;
    final file = (picked == null || picked.files.isEmpty) ? null : picked.files.first;
    if (file == null) return null;
    if (file.bytes == null || file.bytes!.isEmpty) return null;
    return file;
  }

  Future<void> _openPostText() async {
    final repo = RepoScope.of(context);
    Navigator.of(context).push(
      MaterialPageRoute<void>(
        builder: (_) => PostComposerScreen(draft: _draftForQuickPost(repo)),
      ),
    );
  }

  ComposerDraft _draftForQuickPost(DemoRepository repo) {
    return ComposerDraft(
      initialRegionPath: repo.lastFeedLocationPath,
      initialCommunityId: repo.activeCommunityFilterId,
      initialKind: PostKind.testimony,
    );
  }

  bool _isVideoExt(String ext) {
    final e = ext.toLowerCase().trim();
    return e == 'mp4' || e == 'mov' || e == 'webm' || e == 'm4v';
  }

  Future<ComposerMediaDraft?> _pickComposerMediaDraftAny(BuildContext context) async {
    final isMobile = !kIsWeb && (defaultTargetPlatform == TargetPlatform.android || defaultTargetPlatform == TargetPlatform.iOS);
    if (isMobile) {
      XFile? x;
      try {
        x = await _imagePicker.pickMedia();
      } catch (_) {
        x = null;
      }
      if (!context.mounted || x == null) return null;
      final bytes = await x.readAsBytes();
      if (!context.mounted) return null;
      if (bytes.isEmpty) return null;
      final ext = _extensionFromPath(x.path, isVideo: false) ?? '';
      final e = ext.trim().isEmpty ? '' : ext.trim().toLowerCase();
      final isVideo = _isVideoExt(e) || (x.mimeType ?? '').toLowerCase().startsWith('video');
      final inferredExt = e.isEmpty ? (isVideo ? 'mp4' : 'jpg') : e;
      final contentType = _inferContentType(inferredExt, isVideo: isVideo);
      if (contentType == null) return null;
      final fileName = x.name;
      final pf = PlatformFile(
        name: fileName,
        size: bytes.length,
        bytes: bytes,
      );
      return isVideo
          ? ComposerMediaDraft.video(fileName: fileName, file: pf, contentType: contentType, fileExtension: inferredExt)
          : ComposerMediaDraft.photo(fileName: fileName, file: pf, contentType: contentType, fileExtension: inferredExt);
    }

    final picked = await FilePicker.platform.pickFiles(
      type: FileType.custom,
      allowMultiple: false,
      withData: true,
      allowedExtensions: const ['jpg', 'jpeg', 'png', 'webp', 'mp4', 'mov', 'm4v', 'webm'],
    );
    if (!context.mounted) return null;
    final file = (picked == null || picked.files.isEmpty) ? null : picked.files.first;
    if (file == null || file.bytes == null || file.bytes!.isEmpty) return null;
    final ext = (file.extension ?? '').trim().toLowerCase();
    final isVideo = _isVideoExt(ext);
    final inferredExt = ext.isEmpty ? (isVideo ? 'mp4' : 'jpg') : ext;
    final contentType = _inferContentType(inferredExt, isVideo: isVideo);
    if (contentType == null) return null;
    final fileName = file.name;
    return isVideo
        ? ComposerMediaDraft.video(fileName: fileName, file: file, contentType: contentType, fileExtension: inferredExt)
        : ComposerMediaDraft.photo(fileName: fileName, file: file, contentType: contentType, fileExtension: inferredExt);
  }

  Future<void> _openPostMediaAny() async {
    final media = await _pickComposerMediaDraftAny(context);
    if (!context.mounted || media == null) return;
    Navigator.of(context).push(
      MaterialPageRoute<void>(
        builder: (_) => MediaEditScreen(draft: media, baseDraft: _draftForQuickPost(RepoScope.of(context))),
      ),
    );
  }

  Future<void> _openPostVideoAny() async {
    final media = await _pickComposerMediaDraftAny(context);
    if (!context.mounted || media == null) return;
    if (media.kind != ComposerMediaKind.video) {
      showInfoSnackBar(context, t(context).createFlowSelectVideoSnack);
      return;
    }
    Navigator.of(context).push(
      MaterialPageRoute<void>(
        builder: (_) => MediaEditScreen(draft: media, baseDraft: _draftForQuickPost(RepoScope.of(context))),
      ),
    );
  }

  Future<void> _createMediaStory({required DemoRepository repo, required AuthSession session}) async {
    if (repo.isOffline) {
      showErrorSnackBar(context, message: t(context).commonNoConnection, onRetry: () {});
      return;
    }
    final isMobile = !kIsWeb && (defaultTargetPlatform == TargetPlatform.android || defaultTargetPlatform == TargetPlatform.iOS);
    Uint8List? bytes;
    String? ext;
    if (isMobile) {
      final x = await _pickStoryMediaFromGallery();
      if (!context.mounted || x == null) return;
      bytes = await x.readAsBytes();
      if (!context.mounted) return;
      ext = _extensionFromPath(x.path, isVideo: false);
    } else {
      final file = await _pickStoryMediaFromFilePicker();
      if (!context.mounted || file == null) return;
      bytes = file.bytes;
      ext = file.extension;
    }
    final mediaBytes = bytes;
    if (mediaBytes == null || mediaBytes.isEmpty) {
      showInfoSnackBar(context, t(context).createFlowEmptyFileSnack);
      return;
    }

    final e = (ext ?? '').trim().toLowerCase();
    final isImage = e == 'jpg' || e == 'jpeg' || e == 'png' || e == 'webp';
    if (!isImage && e.isNotEmpty) {
      showInfoSnackBar(context, t(context).createFlowStoryMustBePhotoSnack);
      return;
    }
    final normalizedExt = e.isEmpty ? 'jpg' : e;

    final confirm = await showAtalaiaBottomSheet<bool>(
      context,
      isScrollControlled: true,
      builder: (ctx) {
        final l10n = t(ctx);
        return SafeArea(
          child: Padding(
            padding: const EdgeInsets.only(left: 16, right: 16, top: 12, bottom: 16),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                Text(l10n.storiesShareSheetTitle, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 16)),
                const SizedBox(height: 10),
                ClipRRect(
                  borderRadius: BorderRadius.circular(16),
                  child: Image.memory(
                    mediaBytes,
                    fit: BoxFit.cover,
                    height: 220,
                  ),
                ),
                const SizedBox(height: 10),
                FilledButton(
                  onPressed: () => Navigator.of(ctx).pop(true),
                  child: Text(l10n.storiesPublish),
                ),
              ],
            ),
          ),
        );
      },
    );
    if (!context.mounted) {
      return;
    }
    if (confirm != true) {
      return;
    }
    await WidgetsBinding.instance.endOfFrame;
    await Future<void>.delayed(const Duration(milliseconds: 220));
    if (!context.mounted) return;
    final story = await repo.createStory(
      session: session,
      cityId: null,
      mediaType: 'image',
      communityId: null,
      mediaBytes: mediaBytes,
      contentType: _inferContentType(normalizedExt, isVideo: false),
      fileExtension: normalizedExt,
      text: null,
    );
    if (!context.mounted) return;
    if (story == null) {
      showErrorSnackBar(
        context,
        message: repo.lastStoryCreateError ?? t(context).commonSomethingWentWrong,
        onRetry: () {},
      );
      return;
    }
    showInfoSnackBar(context, t(context).storiesPublished);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      Navigator.of(context).pop();
    });
  }

  Widget _buildModeSelector(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    Widget item(_CreateMode mode) {
      final selected = _mode == mode;
      return InkWell(
        onTap: () => setState(() {
          _mode = mode;
          if (mode != _CreateMode.story) _didAutoOpenStoryGallery = false;
        }),
        borderRadius: BorderRadius.circular(999),
        child: Padding(
          padding: const EdgeInsets.symmetric(horizontal: 14, vertical: 10),
          child: Text(
            switch (mode) {
              _CreateMode.post => t(context).createFlowModePost,
              _CreateMode.story => t(context).createFlowModeStory,
              _CreateMode.video => t(context).createFlowModeVideo,
            },
            style: TextStyle(
              fontWeight: selected ? FontWeight.w900 : FontWeight.w700,
              letterSpacing: 0.8,
              color: selected ? cs.onSurface : cs.onSurfaceVariant,
              fontSize: 12,
            ),
          ),
        ),
      );
    }

    return Material(
      color: cs.surfaceContainerHighest,
      borderRadius: BorderRadius.circular(999),
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 6),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          children: [
            item(_CreateMode.post),
            item(_CreateMode.story),
            item(_CreateMode.video),
          ],
        ),
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final session = SessionScope.of(context);
    final repo = RepoScope.of(context);

    return ValueListenableBuilder(
      valueListenable: session,
      builder: (context, value, _) {
        if (!value.isAuthenticated) {
          return Scaffold(
            appBar: AppBar(title: Text(t(context).mainLeadingCreate)),
            body: Center(
              child: PrimaryButton(
                label: t(context).createFlowSignInToPost,
                onPressed: () => showLoginSnackBar(context, message: t(context).createFlowSignInToPost),
              ),
            ),
          );
        }

        final auth = value is AuthSession ? value : null;
        if (auth == null) {
          return Scaffold(
            appBar: AppBar(title: Text(t(context).mainLeadingCreate)),
            body: const SizedBox.shrink(),
          );
        }

        final cs = Theme.of(context).colorScheme;
        return Scaffold(
          appBar: AppBar(
            title: Text(_title),
            leading: AtalaiaIconButton(
              icon: Icons.close,
              label: t(context).commonClose,
              onPressed: () => Navigator.of(context).pop(),
            ),
          ),
          body: Padding(
            padding: const EdgeInsets.all(12),
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                Expanded(
                  child: switch (_mode) {
                    _CreateMode.post => Column(
                        crossAxisAlignment: CrossAxisAlignment.stretch,
                        children: [
                          Text(
                            t(context).createFlowSectionPost,
                            style: TextStyle(color: cs.onSurface, fontWeight: FontWeight.w900, fontSize: 16),
                          ),
                          const SizedBox(height: 10),
                          PrimaryButton(
                            label: t(context).createFlowWriteNow,
                            onPressed: _openPostText,
                          ),
                          const SizedBox(height: 10),
                          SecondaryButton(
                            label: t(context).createFlowAddMedia,
                            onPressed: () => unawaited(_openPostMediaAny()),
                          ),
                          const SizedBox(height: 14),
                          Text(
                            t(context).createFlowPostHelp,
                            style: TextStyle(color: cs.outline),
                          ),
                        ],
                      ),
                    _CreateMode.story => Builder(
                        builder: (context) {
                          if (!_didAutoOpenStoryGallery) {
                            WidgetsBinding.instance.addPostFrameCallback((_) {
                              if (!mounted) return;
                              setState(() => _didAutoOpenStoryGallery = true);
                              unawaited(_createMediaStory(repo: repo, session: auth));
                            });
                          }
                          return Column(
                            crossAxisAlignment: CrossAxisAlignment.stretch,
                            children: [
                              Text(
                                t(context).createFlowSectionStory24h,
                                style: TextStyle(color: cs.onSurface, fontWeight: FontWeight.w900, fontSize: 16),
                              ),
                              const SizedBox(height: 10),
                              PrimaryButton(
                                label: t(context).createFlowOpenGallery,
                                onPressed: () => unawaited(_createMediaStory(repo: repo, session: auth)),
                              ),
                              const SizedBox(height: 14),
                              Text(
                                t(context).createFlowStoryHelp,
                                style: TextStyle(color: cs.outline),
                              ),
                            ],
                          );
                        },
                      ),
                    _CreateMode.video => Column(
                        crossAxisAlignment: CrossAxisAlignment.stretch,
                        children: [
                          Text(
                            t(context).createFlowSectionVideo,
                            style: TextStyle(color: cs.onSurface, fontWeight: FontWeight.w900, fontSize: 16),
                          ),
                          const SizedBox(height: 10),
                          PrimaryButton(
                            label: t(context).createFlowSelectVideo,
                            onPressed: () => unawaited(_openPostVideoAny()),
                          ),
                          const SizedBox(height: 14),
                          Text(
                            t(context).createFlowVideoHelp,
                            style: TextStyle(color: cs.outline),
                          ),
                        ],
                      ),
                  },
                ),
                const SizedBox(height: 10),
                Align(
                  alignment: Alignment.center,
                  child: _buildModeSelector(context),
                ),
              ],
            ),
          ),
        );
      },
    );
  }
}

