enum ComposerMediaKind { photo, video }

enum PhotoCropPreset { ratio4x5, ratio1x1 }

final class ComposerMediaDraft {
  const ComposerMediaDraft._({
    required this.kind,
    required this.fileName,
    required this.file,
    required this.contentType,
    required this.fileExtension,
    required this.photoCrop,
    required this.photoQuarterTurns,
    required this.videoCover,
    required this.videoTrim,
  });

  ComposerMediaDraft.photo({
    required String fileName,
    required PlatformFile file,
    required String contentType,
    required String fileExtension,
  })
      : this._(
          kind: ComposerMediaKind.photo,
          fileName: fileName,
          file: file,
          contentType: contentType,
          fileExtension: fileExtension,
          photoCrop: PhotoCropPreset.ratio4x5,
          photoQuarterTurns: 0,
          videoCover: 0.35,
          videoTrim: const RangeValues(0.0, 1.0),
        );

  ComposerMediaDraft.video({
    required String fileName,
    required PlatformFile file,
    required String contentType,
    required String fileExtension,
  })
      : this._(
          kind: ComposerMediaKind.video,
          fileName: fileName,
          file: file,
          contentType: contentType,
          fileExtension: fileExtension,
          photoCrop: PhotoCropPreset.ratio4x5,
          photoQuarterTurns: 0,
          videoCover: 0.35,
          videoTrim: const RangeValues(0.15, 0.9),
        );

  final ComposerMediaKind kind;
  final String fileName;
  final PlatformFile file;
  final String contentType;
  final String fileExtension;
  final PhotoCropPreset photoCrop;
  final int photoQuarterTurns;
  final double videoCover;
  final RangeValues videoTrim;

  ComposerMediaDraft copyWith({
    PhotoCropPreset? photoCrop,
    int? photoQuarterTurns,
    double? videoCover,
    RangeValues? videoTrim,
  }) {
    return ComposerMediaDraft._(
      kind: kind,
      fileName: fileName,
      file: file,
      contentType: contentType,
      fileExtension: fileExtension,
      photoCrop: photoCrop ?? this.photoCrop,
      photoQuarterTurns: photoQuarterTurns ?? this.photoQuarterTurns,
      videoCover: videoCover ?? this.videoCover,
      videoTrim: videoTrim ?? this.videoTrim,
    );
  }
}

final class ComposerDraft {
  const ComposerDraft({
    this.media,
    this.initialText = '',
    this.initialKind = PostKind.request,
    this.initialVisibility = PostVisibility.public,
    this.initialLocation,
    this.initialRegionPath,
    this.initialCommunityId,
    this.existingMediaKind,
    this.existingMediaUrl,
  });

  final ComposerMediaDraft? media;
  final String initialText;
  final PostKind initialKind;
  final PostVisibility initialVisibility;
  final String? initialLocation;
  final String? initialRegionPath;
  final String? initialCommunityId;
  final String? existingMediaKind;
  final String? existingMediaUrl;
}

Future<ComposerMediaDraft?> _pickComposerMediaDraft(BuildContext context, {required ComposerMediaKind kind}) async {
  final l10n = t(context);
  final picked = await FilePicker.platform.pickFiles(
    type: kind == ComposerMediaKind.photo ? FileType.image : FileType.video,
    allowMultiple: false,
    withData: true,
    withReadStream: kind == ComposerMediaKind.video,
  );
  if (!context.mounted) return null;
  final file = (picked == null || picked.files.isEmpty) ? null : picked.files.first;
  if (file == null) return null;
  final byteLength = file.size;
  if (byteLength <= 0) return null;
  final maxSize = kind == ComposerMediaKind.photo ? 5 * 1024 * 1024 : 30 * 1024 * 1024;
  if (byteLength > maxSize) {
    showInfoSnackBar(
      context,
      kind == ComposerMediaKind.photo ? l10n.composerImageTooLargeMax5mb : l10n.composerVideoTooLargeMax30mb,
    );
    return null;
  }
  final ext = (file.extension ?? '').trim().toLowerCase();
  if (ext.isEmpty) {
    showInfoSnackBar(context, l10n.composerFileExtensionUnsupported);
    return null;
  }
  final contentType = switch (kind) {
    ComposerMediaKind.photo => switch (ext) {
      'jpg' || 'jpeg' => 'image/jpeg',
      'png' => 'image/png',
      'webp' => 'image/webp',
      _ => '',
    },
    ComposerMediaKind.video => switch (ext) {
      'mp4' => 'video/mp4',
      'mov' => 'video/quicktime',
      'webm' => 'video/webm',
      'm4v' => 'video/x-m4v',
      _ => '',
    },
  };
  if (contentType.isEmpty) {
    showInfoSnackBar(
      context,
      kind == ComposerMediaKind.photo
          ? l10n.composerUnsupportedImageFormat
          : l10n.composerUnsupportedVideoFormat,
    );
    return null;
  }
  final name = (file.name).trim().isEmpty ? 'upload.$ext' : file.name.trim();
  return kind == ComposerMediaKind.photo
      ? ComposerMediaDraft.photo(
          fileName: name,
          file: file,
          contentType: contentType,
          fileExtension: ext,
        )
      : ComposerMediaDraft.video(
          fileName: name,
          file: file,
          contentType: contentType,
          fileExtension: ext,
        );
}

Future<Uint8List?> _readComposerFileBytes(PlatformFile file) async {
  final inMemory = file.bytes;
  if (inMemory != null && inMemory.isNotEmpty) return inMemory;
  final stream = file.readStream;
  if (stream == null) return null;
  final out = <int>[];
  await for (final chunk in stream) {
    out.addAll(chunk);
  }
  return out.isEmpty ? null : Uint8List.fromList(out);
}

class _ComposerVideoCoverPreview extends StatefulWidget {
  const _ComposerVideoCoverPreview({
    required this.file,
    required this.contentType,
    required this.coverFraction,
  });

  final PlatformFile file;
  final String contentType;
  final double coverFraction;

  @override
  State<_ComposerVideoCoverPreview> createState() => _ComposerVideoCoverPreviewState();
}

class _ComposerVideoCoverPreviewState extends State<_ComposerVideoCoverPreview> {
  VideoPlayerController? _vc;
  bool _muted = true;

  @override
  void initState() {
    super.initState();
    unawaited(_init());
  }

  @override
  void didUpdateWidget(covariant _ComposerVideoCoverPreview oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (oldWidget.file.path != widget.file.path || oldWidget.file.size != widget.file.size) {
      unawaited(_reset());
      return;
    }
    if (oldWidget.coverFraction != widget.coverFraction) {
      unawaited(_seekToCover(pauseFirst: true));
    }
  }

  String? _sourceUrl() {
    final p = (widget.file.path ?? '').trim();
    if (p.isNotEmpty && (p.startsWith('http://') || p.startsWith('https://') || p.startsWith('blob:') || p.startsWith('data:'))) {
      return p;
    }
    final b = widget.file.bytes;
    if (b == null || b.isEmpty) return null;
    return Uri.dataFromBytes(b, mimeType: widget.contentType).toString();
  }

  Future<void> _reset() async {
    final old = _vc;
    _vc = null;
    old?.dispose();
    if (mounted) setState(() {});
    await _init();
  }

  Future<void> _init() async {
    final src = _sourceUrl();
    if (src == null || src.isEmpty) return;
    final vc = VideoPlayerController.networkUrl(Uri.parse(src));
    _vc = vc;
    try {
      await vc.initialize();
      if (!mounted) return;
      await vc.setLooping(true);
      await vc.setVolume(0);
      await _seekToCover(pauseFirst: true);
    } catch (_) {}
    if (mounted) setState(() {});
  }

  Future<void> _seekToCover({required bool pauseFirst}) async {
    final vc = _vc;
    if (vc == null) return;
    if (!vc.value.isInitialized) return;
    if (pauseFirst && vc.value.isPlaying) {
      await vc.pause();
    }
    final d = vc.value.duration;
    if (d.inMilliseconds <= 0) return;
    final frac = widget.coverFraction.clamp(0.0, 1.0);
    final targetMs = (d.inMilliseconds * frac).round();
    await vc.seekTo(Duration(milliseconds: targetMs));
  }

  void _togglePlay() {
    final vc = _vc;
    if (vc == null || !vc.value.isInitialized) return;
    if (vc.value.isPlaying) {
      unawaited(vc.pause());
      setState(() {});
      return;
    }
    unawaited(vc.play());
    setState(() {});
  }

  void _toggleMute() {
    final vc = _vc;
    if (vc == null || !vc.value.isInitialized) return;
    final next = !_muted;
    setState(() => _muted = next);
    unawaited(vc.setVolume(next ? 0 : 1));
  }

  @override
  void dispose() {
    _vc?.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final vc = _vc;
    final isReady = vc != null && vc.value.isInitialized;
    final isPlaying = vc?.value.isPlaying ?? false;
    final showPlay = !isReady || !isPlaying;

    return GestureDetector(
      behavior: HitTestBehavior.opaque,
      onTap: _togglePlay,
      child: Stack(
        children: [
          Positioned.fill(
            child: !isReady
                ? Container(
                    color: cs.surfaceContainerHighest,
                    child: Center(child: Icon(Icons.play_circle_outline, size: 52, color: cs.outline)),
                  )
                : FittedBox(
                    fit: BoxFit.cover,
                    child: SizedBox(
                      width: vc.value.size.width,
                      height: vc.value.size.height,
                      child: VideoPlayer(vc),
                    ),
                  ),
          ),
          Positioned.fill(
            child: IgnorePointer(
              child: DecoratedBox(
                decoration: BoxDecoration(
                  gradient: LinearGradient(
                    begin: Alignment.topCenter,
                    end: Alignment.bottomCenter,
                    colors: [
                      Colors.black.withValues(alpha: 0.25),
                      Colors.transparent,
                      Colors.black.withValues(alpha: 0.35),
                    ],
                  ),
                ),
              ),
            ),
          ),
          if (showPlay)
            const Center(
              child: Icon(Icons.play_circle_outline, color: Colors.white70, size: 88),
            ),
          if (isReady)
            Positioned(
              right: 10,
              bottom: 10,
              child: InkWell(
                onTap: _toggleMute,
                borderRadius: BorderRadius.circular(999),
                child: Container(
                  padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
                  decoration: BoxDecoration(
                    color: Colors.black.withValues(alpha: 0.55),
                    borderRadius: BorderRadius.circular(999),
                  ),
                  child: Icon(_muted ? Icons.volume_off : Icons.volume_up, color: Colors.white, size: 18),
                ),
              ),
            ),
        ],
      ),
    );
  }
}

class MediaEditScreen extends StatefulWidget {
  const MediaEditScreen({
    required this.draft,
    this.baseDraft,
    this.editingPostId,
    this.replaceOnContinue = false,
    super.key,
  });

  final ComposerMediaDraft draft;
  final ComposerDraft? baseDraft;
  final String? editingPostId;
  final bool replaceOnContinue;

  @override
  State<MediaEditScreen> createState() => _MediaEditScreenState();
}

class _MediaEditScreenState extends State<MediaEditScreen> {
  late ComposerMediaDraft _draft = widget.draft;

  @override
  Widget build(BuildContext context) {
    final isPhoto = _draft.kind == ComposerMediaKind.photo;
    final cs = Theme.of(context).colorScheme;
    final cropRatio = switch (_draft.photoCrop) {
      PhotoCropPreset.ratio4x5 => 4 / 5,
      PhotoCropPreset.ratio1x1 => 1.0,
    };

    return Scaffold(
      appBar: AppBar(
        title: Text(t(context).mediaEditTitle),
        actions: [
          AtalaiaTextButton(
            label: t(context).mediaEditNext,
            onPressed: () {
              final base = widget.baseDraft ?? const ComposerDraft();
              final route = MaterialPageRoute<void>(
                builder: (_) => PostComposerScreen(
                  draft: ComposerDraft(
                    media: _draft,
                    initialText: base.initialText,
                    initialKind: base.initialKind,
                    initialVisibility: base.initialVisibility,
                    initialLocation: base.initialLocation,
                    initialRegionPath: base.initialRegionPath,
                    initialCommunityId: base.initialCommunityId,
                    existingMediaKind: base.existingMediaKind,
                    existingMediaUrl: base.existingMediaUrl,
                  ),
                  editingPostId: widget.editingPostId,
                ),
              );
              if (widget.replaceOnContinue) {
                Navigator.of(context).pushReplacement(route);
              } else {
                Navigator.of(context).push(route);
              }
            },
          ),
        ],
      ),
      body: ListView(
        padding: const EdgeInsets.all(12),
        children: [
          if (isPhoto)
            AspectRatio(
              aspectRatio: cropRatio,
              child: Container(
                decoration: BoxDecoration(
                  borderRadius: BorderRadius.circular(16),
                  color: cs.surfaceContainerHighest,
                ),
                clipBehavior: Clip.antiAlias,
                child: _draft.file.bytes == null
                    ? Center(
                        child: RotatedBox(
                          quarterTurns: _draft.photoQuarterTurns,
                          child: const Icon(Icons.image_outlined, size: 44),
                        ),
                      )
                    : RotatedBox(
                        quarterTurns: _draft.photoQuarterTurns,
                        child: Image.memory(
                          _draft.file.bytes!,
                          fit: BoxFit.cover,
                          width: double.infinity,
                          height: double.infinity,
                          errorBuilder: (_, __, ___) => const Center(
                            child: Icon(Icons.broken_image_outlined, size: 44),
                          ),
                        ),
                      ),
              ),
            )
          else
            AspectRatio(
              aspectRatio: 16 / 9,
              child: Container(
                decoration: BoxDecoration(
                  borderRadius: BorderRadius.circular(16),
                  color: cs.surfaceContainerHighest,
                ),
                clipBehavior: Clip.antiAlias,
                child: _ComposerVideoCoverPreview(
                  file: _draft.file,
                  contentType: _draft.contentType,
                  coverFraction: _draft.videoCover,
                ),
              ),
            ),
          const SizedBox(height: 14),
          if (isPhoto) ...[
            Text(t(context).mediaEditCropSection, style: const TextStyle(fontWeight: FontWeight.w900)),
            const SizedBox(height: 8),
            Wrap(
              spacing: 8,
              runSpacing: 8,
              children: [
                ChoiceChip(
                  label: const Text('4:5'),
                  selected: _draft.photoCrop == PhotoCropPreset.ratio4x5,
                  onSelected: (_) => setState(() {
                    _draft = _draft.copyWith(photoCrop: PhotoCropPreset.ratio4x5);
                  }),
                ),
                ChoiceChip(
                  label: const Text('1:1'),
                  selected: _draft.photoCrop == PhotoCropPreset.ratio1x1,
                  onSelected: (_) => setState(() {
                    _draft = _draft.copyWith(photoCrop: PhotoCropPreset.ratio1x1);
                  }),
                ),
                ActionChip(
                  label: Text(t(context).mediaEditRotateAction),
                  avatar: const Icon(Icons.rotate_right, size: 18),
                  onPressed: () => setState(() {
                    _draft = _draft.copyWith(photoQuarterTurns: (_draft.photoQuarterTurns + 1) % 4);
                  }),
                ),
              ],
            ),
          ] else ...[
            Text(t(context).mediaEditCoverSection, style: const TextStyle(fontWeight: FontWeight.w900)),
            const SizedBox(height: 8),
            Slider(
              value: _draft.videoCover,
              min: 0,
              max: 1,
              onChanged: (v) => setState(() => _draft = _draft.copyWith(videoCover: v)),
            ),
            const SizedBox(height: 10),
            Text(t(context).mediaEditCropSection, style: const TextStyle(fontWeight: FontWeight.w900)),
            const SizedBox(height: 8),
            RangeSlider(
              values: _draft.videoTrim,
              min: 0,
              max: 1,
              onChanged: (v) => setState(() => _draft = _draft.copyWith(videoTrim: v)),
            ),
          ],
        ],
      ),
    );
  }
}

class PostComposerScreen extends StatefulWidget {
  const PostComposerScreen({required this.draft, this.editingPostId, super.key});

  final ComposerDraft draft;
  final String? editingPostId;

  @override
  State<PostComposerScreen> createState() => _PostComposerScreenState();
}

class _PostComposerScreenState extends State<PostComposerScreen> {
  late final TextEditingController _text = TextEditingController(text: widget.draft.initialText);
  final TextEditingController _tagInput = TextEditingController();
  final List<String> _tags = <String>[];
  PostVisibility _visibility = PostVisibility.public;
  PostKind _kind = PostKind.testimony;
  String? _location;

  bool _uploading = false;
  double _progress = 0;

  @override
  void initState() {
    super.initState();
    _visibility = widget.draft.initialVisibility;
    if (_visibility == PostVisibility.church) {
      _visibility = PostVisibility.followers;
    }
    _kind = PostKind.testimony;
    _location = widget.draft.initialLocation;
  }

  @override
  void dispose() {
    _text.dispose();
    _tagInput.dispose();
    super.dispose();
  }

  bool get _hasMedia {
    if (widget.draft.media != null) return true;
    final kind = widget.draft.existingMediaKind;
    final url = widget.draft.existingMediaUrl;
    return kind != null && kind.isNotEmpty && url != null && url.isNotEmpty;
  }

  bool get _isValid {
    if (_hasMedia) return true;
    return _text.text.trim().isNotEmpty;
  }

  void _addTag(String raw) {
    final cleaned = raw.trim().replaceAll('#', '');
    if (cleaned.isEmpty) return;
    if (_tags.contains(cleaned)) return;
    setState(() => _tags.add(cleaned));
  }

  Future<void> _pickLocation() async {
    final picked = await showAtalaiaBottomSheet<String>(
      context,
      isScrollControlled: false,
      builder: (ctx) {
        return SafeArea(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              ListTile(
                title: Text(t(context).composerAddLocation, style: const TextStyle(fontWeight: FontWeight.w900)),
              ),
              ListTile(
                leading: const Icon(Icons.place_outlined),
                title: Text(t(context).composerLocationGoiania),
                onTap: () => Navigator.of(ctx).pop(t(context).composerLocationGoiania),
              ),
              ListTile(
                leading: const Icon(Icons.place_outlined),
                title: Text(t(context).composerLocationSaoPaulo),
                onTap: () => Navigator.of(ctx).pop(t(context).composerLocationSaoPaulo),
              ),
              ListTile(
                leading: const Icon(Icons.place_outlined),
                title: Text(t(context).composerLocationBrazil),
                onTap: () => Navigator.of(ctx).pop(t(context).composerLocationBrazil),
              ),
              ListTile(
                leading: const Icon(Icons.clear),
                title: Text(t(context).composerRemoveLocation),
                onTap: () => Navigator.of(ctx).pop(''),
              ),
              const SizedBox(height: 8),
            ],
          ),
        );
      },
    );

    if (!mounted) return;
    if (picked == null) return;
    setState(() => _location = picked.isEmpty ? null : picked);
  }

  Future<void> _changeMedia() async {
    if (_uploading) return;
    final kind = await showAtalaiaBottomSheet<ComposerMediaKind>(
      context,
      isScrollControlled: false,
      builder: (ctx) {
        return SafeArea(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              ListTile(
                title: Text(t(context).composerMediaSheetTitle, style: const TextStyle(fontWeight: FontWeight.w900)),
              ),
              ListTile(
                leading: const Icon(Icons.photo_outlined),
                title: Text(t(context).composerPhoto),
                onTap: () => Navigator.of(ctx).pop(ComposerMediaKind.photo),
              ),
              ListTile(
                leading: const Icon(Icons.videocam_outlined),
                title: Text(t(context).composerVideo),
                onTap: () => Navigator.of(ctx).pop(ComposerMediaKind.video),
              ),
              const SizedBox(height: 8),
            ],
          ),
        );
      },
    );
    if (!mounted || kind == null) return;
    final media = await _pickComposerMediaDraft(context, kind: kind);
    if (!mounted || media == null) return;

    Navigator.of(context).pushReplacement(
      MaterialPageRoute<void>(
        builder: (_) => MediaEditScreen(
          draft: media,
          baseDraft: ComposerDraft(
            initialText: _text.text,
            initialKind: _kind,
            initialVisibility: _visibility,
            initialLocation: _location,
            initialRegionPath: widget.draft.initialRegionPath,
            initialCommunityId: widget.draft.initialCommunityId,
            existingMediaKind: widget.draft.existingMediaKind,
            existingMediaUrl: widget.draft.existingMediaUrl,
          ),
          editingPostId: widget.editingPostId,
          replaceOnContinue: true,
        ),
      ),
    );
  }

  String? _regionFromLocation(String? location) {
    final l10n = t(context);
    return switch (location) {
      null => null,
      _ when location == l10n.composerLocationBrazil => 'world/sa/br',
      _ when location == l10n.composerLocationGoiania => 'world/sa/br/go/goiania',
      _ when location == l10n.composerLocationSaoPaulo => 'world/sa/br/sp/sao-paulo',
      _ => 'world',
    };
  }

  Future<void> _publish({required bool isAuthenticated}) async {
    if (!isAuthenticated) {
      showCtaSnackBar(context);
      return;
    }
    if (!_isValid) return;
    if (_uploading) return;

    final repo = RepoScope.of(context);
    final session = SessionScope.of(context).value;
    if (session is! AuthSession) {
      showCtaSnackBar(context);
      return;
    }

    final editingPostId = widget.editingPostId;
    if (editingPostId != null && editingPostId.isNotEmpty) {
      String? uploadedMediaUrl;
      String? uploadedMediaKind;
      final media = widget.draft.media;
      if (media != null) {
        final mediaBytes = await _readComposerFileBytes(media.file);
        if (!mounted) return;
        if (mediaBytes == null || mediaBytes.isEmpty) {
          showInfoSnackBar(context, t(context).mediaSelectedReadFailed);
          return;
        }
        setState(() {
          _uploading = true;
          _progress = 0.2;
        });
        try {
          uploadedMediaKind = media.kind == ComposerMediaKind.photo ? 'image' : 'video';
          uploadedMediaUrl = await repo.uploadPostMedia(
            userId: session.userId,
            mediaKind: uploadedMediaKind,
            bytes: mediaBytes,
            contentType: media.contentType,
            fileExtension: media.fileExtension,
          );
        } on StorageException catch (e) {
          if (!mounted) return;
          setState(() {
            _uploading = false;
            _progress = 0;
          });
          final code = e.statusCode == null ? '' : ' (${e.statusCode})';
          showAtalaiaSnackBar(context, t(context).uploadFailedWithCode(code, e.message), kind: AtalaiaSnackKind.error);
          return;
        } catch (_) {
          if (!mounted) return;
          setState(() {
            _uploading = false;
            _progress = 0;
          });
          showErrorSnackBar(context, onRetry: () => _publish(isAuthenticated: true));
          return;
        }
        if (!mounted) return;
        if (uploadedMediaUrl == null || uploadedMediaUrl.trim().isEmpty) {
          setState(() {
            _uploading = false;
            _progress = 0;
          });
          showInfoSnackBar(context, t(context).mediaSendFailed);
          return;
        }
        setState(() => _progress = 1);
      } else {
        setState(() {
          _uploading = true;
          _progress = 0.2;
        });
      }
      final regionPath = _regionFromLocation(_location) ?? widget.draft.initialRegionPath ?? 'world';
      final ok = await repo.updatePost(
        session,
        postId: editingPostId,
        body: _text.text.trim(),
        visibility: _visibility,
        regionPath: regionPath,
        location: _location,
        mediaKind: uploadedMediaKind,
        mediaUrl: uploadedMediaUrl,
      );
      if (!mounted) return;
      setState(() {
        _uploading = false;
        _progress = 0;
      });
      if (!ok) {
        final msg = (repo.lastPostUpdateError ?? '').trim();
        showAtalaiaSnackBar(
          context,
          msg.isEmpty ? t(context).postSaveFailedCheckSupabase : t(context).postSaveFailedWithMessage(msg),
          kind: AtalaiaSnackKind.error,
        );
        return;
      }
      showAtalaiaSnackBar(context, t(context).commonSaved, kind: AtalaiaSnackKind.success);
      Navigator.of(context).maybePop();
      return;
    }

    String? uploadedMediaUrl;
    final media = widget.draft.media;
    if (media != null) {
      final mediaBytes = await _readComposerFileBytes(media.file);
      if (!mounted) return;
      if (mediaBytes == null || mediaBytes.isEmpty) {
        showInfoSnackBar(context, t(context).mediaSelectedReadFailed);
        return;
      }
      setState(() {
        _uploading = true;
        _progress = 0.2;
      });
      try {
        uploadedMediaUrl = await repo.uploadPostMedia(
          userId: session.userId,
          mediaKind: media.kind == ComposerMediaKind.photo ? 'image' : 'video',
          bytes: mediaBytes,
          contentType: media.contentType,
          fileExtension: media.fileExtension,
        );
      } on StorageException catch (e) {
        if (!mounted) return;
        setState(() {
          _uploading = false;
          _progress = 0;
        });
        final code = e.statusCode == null ? '' : ' (${e.statusCode})';
        showAtalaiaSnackBar(context, t(context).uploadFailedWithCode(code, e.message), kind: AtalaiaSnackKind.error);
        return;
      } catch (_) {
        if (!mounted) return;
        setState(() {
          _uploading = false;
          _progress = 0;
        });
        showErrorSnackBar(context, onRetry: () => _publish(isAuthenticated: true));
        return;
      }
      if (!mounted) return;
      if (uploadedMediaUrl == null || uploadedMediaUrl.trim().isEmpty) {
        setState(() {
          _uploading = false;
          _progress = 0;
        });
        showInfoSnackBar(context, t(context).mediaSendFailed);
        return;
      }
      setState(() => _progress = 1);
    }

    final text = _text.text.trim();
    final tagsText = _tags.isEmpty ? '' : _tags.map((t) => '#$t').join(' ');
    final body = [
      if (text.isNotEmpty) text,
      if (tagsText.isNotEmpty) tagsText,
    ].join('\n');

    final created = await repo.createPost(
      session,
      body: body,
      kind: _kind,
      visibility: _visibility,
      mediaKind: media == null ? null : (media.kind == ComposerMediaKind.photo ? 'image' : 'video'),
      mediaUrl: uploadedMediaUrl,
      regionPath: _regionFromLocation(_location) ?? widget.draft.initialRegionPath ?? 'world',
      location: _location,
      communityId: widget.draft.initialCommunityId,
    );

    if (!mounted) return;
    setState(() {
      _uploading = false;
      _progress = 0;
    });
    if (!created) {
      final msg = (repo.lastPostCreateError ?? '').trim();
      showAtalaiaSnackBar(
        context,
        msg.isEmpty ? t(context).postPublishFailedCheckSupabase : t(context).postPublishFailedWithMessage(msg),
        kind: AtalaiaSnackKind.error,
      );
      return;
    }
    showAtalaiaSnackBar(context, t(context).commonPublished, kind: AtalaiaSnackKind.success);
    Navigator.of(context).popUntil((r) => r.isFirst);
  }

  @override
  Widget build(BuildContext context) {
    final session = SessionScope.of(context);
    final cs = Theme.of(context).colorScheme;
    final media = widget.draft.media;
    final existingMediaKind = widget.draft.existingMediaKind;
    final existingMediaUrl = widget.draft.existingMediaUrl;

    final Widget? mediaPreview;
    if (media != null) {
      mediaPreview = media.kind == ComposerMediaKind.photo
          ? AspectRatio(
              aspectRatio: switch (media.photoCrop) {
                PhotoCropPreset.ratio4x5 => 4 / 5,
                PhotoCropPreset.ratio1x1 => 1,
              },
              child: Container(
                decoration: BoxDecoration(
                  borderRadius: BorderRadius.circular(16),
                  color: cs.surfaceContainerHighest,
                ),
                clipBehavior: Clip.antiAlias,
                child: media.file.bytes == null
                    ? Center(
                        child: RotatedBox(
                          quarterTurns: media.photoQuarterTurns,
                          child: const Icon(Icons.image_outlined, size: 44),
                        ),
                      )
                    : RotatedBox(
                        quarterTurns: media.photoQuarterTurns,
                        child: Image.memory(
                          media.file.bytes!,
                          fit: BoxFit.cover,
                          width: double.infinity,
                          height: double.infinity,
                          errorBuilder: (_, __, ___) => const Center(
                            child: Icon(Icons.broken_image_outlined, size: 44),
                          ),
                        ),
                      ),
              ),
            )
          : AspectRatio(
              aspectRatio: 16 / 9,
              child: Container(
                decoration: BoxDecoration(
                  borderRadius: BorderRadius.circular(16),
                  color: cs.surfaceContainerHighest,
                ),
                clipBehavior: Clip.antiAlias,
                child: _ComposerVideoCoverPreview(
                  file: media.file,
                  contentType: media.contentType,
                  coverFraction: media.videoCover,
                ),
              ),
            );
    } else if (existingMediaKind != null &&
        existingMediaKind.isNotEmpty &&
        existingMediaUrl != null &&
        existingMediaUrl.isNotEmpty) {
      mediaPreview = ClipRRect(
        borderRadius: BorderRadius.circular(16),
        child: PostMedia(
          kind: existingMediaKind,
          mediaUrl: existingMediaUrl,
          onTap: () {},
          onDoubleTap: () {},
        ),
      );
    } else {
      mediaPreview = null;
    }

    return ValueListenableBuilder(
      valueListenable: session,
      builder: (context, s, _) {
        final isEditing = widget.editingPostId != null && widget.editingPostId!.isNotEmpty;
        return Scaffold(
          appBar: AppBar(
            title: Text(
              isEditing
                  ? t(context).composerEditPostTitle
                  : t(context).createFlowTitleNewPost,
            ),
            actions: [
              AtalaiaIconButton(
                icon: Icons.photo_library_outlined,
                label: t(context).composerMediaAction,
                onPressed: _uploading ? null : _changeMedia,
              ),
              AtalaiaTextButton(
                label: isEditing ? t(context).commonSave : t(context).commonPublish,
                onPressed: _isValid && !_uploading ? () => _publish(isAuthenticated: s.isAuthenticated) : null,
              ),
            ],
          ),
          body: ListView(
            padding: const EdgeInsets.all(12),
            children: [
              if (_uploading) ...[
                LinearProgressIndicator(value: _progress),
                const SizedBox(height: 12),
              ],
              if (mediaPreview != null) ...[
                mediaPreview,
                const SizedBox(height: 12),
              ],
              AtalaiaTextField(
                controller: _text,
                minLines: 4,
                maxLines: 10,
                keyboardType: TextInputType.multiline,
                textInputAction: TextInputAction.newline,
                onChanged: (_) => setState(() {}),
                hintText: t(context).prayerSessionRecordHint,
              ),
              const SizedBox(height: 12),
              AtalaiaTextField(
                controller: _tagInput,
                hintText: t(context).composerAddTagHint,
                prefixText: '#',
                textInputAction: TextInputAction.done,
                onSubmitted: (v) {
                  _addTag(v);
                  _tagInput.clear();
                },
              ),
              if (_tags.isNotEmpty) ...[
                const SizedBox(height: 10),
                Wrap(
                  spacing: 8,
                  runSpacing: 8,
                  children: _tags
                      .map(
                        (t) => InputChip(
                          label: Text('#$t'),
                          onDeleted: () => setState(() => _tags.remove(t)),
                        ),
                      )
                      .toList(growable: false),
                ),
              ],
              const SizedBox(height: 12),
              DropdownButtonFormField<PostVisibility>(
                initialValue: _visibility,
                decoration: InputDecoration(
                  labelText: t(context).composerVisibilityField,
                  border: const OutlineInputBorder(),
                ),
                items: [
                  DropdownMenuItem(value: PostVisibility.public, child: Text(t(context).composerVisibilityPublic)),
                  DropdownMenuItem(value: PostVisibility.followers, child: Text(t(context).composerVisibilityFollowers)),
                ],
                onChanged: (v) => setState(() => _visibility = v ?? _visibility),
              ),
              const SizedBox(height: 12),
              ListTile(
                contentPadding: EdgeInsets.zero,
                leading: const Icon(Icons.place_outlined),
                title: Text(_location == null ? t(context).composerAddLocation : _location!),
                trailing: const Icon(Icons.chevron_right),
                onTap: _pickLocation,
              ),
            ],
          ),
        );
      },
    );
  }
}

class AlertCard extends StatelessWidget {
