class AlertDetailScreen extends StatefulWidget {
  const AlertDetailScreen({required this.args, super.key});

  final AlertDetailArgs args;

  @override
  State<AlertDetailScreen> createState() => _AlertDetailScreenState();
}

class _AlertDetailScreenState extends State<AlertDetailScreen> {
  var _loading = true;
  Future<bool>? _hydrateFuture;
  var _scheduledMissingPop = false;
  AlertVote? _myVote;

  @override
  void initState() {
    super.initState();
    Future<void>.delayed(const Duration(milliseconds: 260)).then((_) {
      if (!mounted) return;
      setState(() => _loading = false);
    });
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final alert = repo.findAlert(widget.args.alertId);
        final canHydrate = repo.supabase != null && !repo.isOffline;

        if (alert == null) {
          if (canHydrate && _hydrateFuture == null) {
            _hydrateFuture = repo.hydrateAlertById(widget.args.alertId);
          }

          if (_hydrateFuture != null) {
            return Scaffold(
              appBar: AppBar(title: Text(t(context).alertDetailTitle)),
              body: FutureBuilder<bool>(
                future: _hydrateFuture,
                builder: (context, snapshot) {
                  final hydrated = repo.findAlert(widget.args.alertId);
                  if (hydrated != null || snapshot.connectionState != ConnectionState.done) {
                    return ListView(
                      physics: const AlwaysScrollableScrollPhysics(),
                      padding: const EdgeInsets.fromLTRB(12, 12, 12, 16),
                      children: const [
                        RowSkeleton(primaryWidth: 180, secondaryWidth: 120),
                        SizedBox(height: 12),
                        RowSkeleton(primaryWidth: 260, secondaryWidth: 220),
                        RowSkeleton(primaryWidth: 240, secondaryWidth: 180),
                        SizedBox(height: 12),
                        RowSkeleton(primaryWidth: 220, secondaryWidth: 160),
                      ],
                    );
                  }
                  return Center(
                    child: Padding(
                      padding: const EdgeInsets.all(20),
                      child: Column(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          Text(t(context).alertNotAvailable),
                          const SizedBox(height: 12),
                          PrimaryButton(label: t(context).commonBack, onPressed: () => Navigator.of(context).maybePop()),
                        ],
                      ),
                    ),
                  );
                },
              ),
            );
          }

          if (!_scheduledMissingPop) {
            _scheduledMissingPop = true;
            Future<void>.delayed(const Duration(milliseconds: 1200)).then((_) {
              if (!mounted) return;
              Navigator.of(context).maybePop();
            });
          }

          return Scaffold(
            appBar: AppBar(title: Text(t(context).alertDetailTitle)),
            body: Center(
              child: Padding(
                padding: const EdgeInsets.all(20),
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    Text(t(context).alertNotAvailable),
                    const SizedBox(height: 12),
                    PrimaryButton(label: t(context).commonBack, onPressed: () => Navigator.of(context).maybePop()),
                  ],
                ),
              ),
            ),
          );
        }

        if (_loading) {
          return Scaffold(
            appBar: AppBar(title: Text(t(context).alertDetailTitle)),
            body: ListView(
              physics: const AlwaysScrollableScrollPhysics(),
              padding: const EdgeInsets.fromLTRB(12, 12, 12, 16),
              children: const [
                RowSkeleton(primaryWidth: 180, secondaryWidth: 120),
                SizedBox(height: 12),
                RowSkeleton(primaryWidth: 260, secondaryWidth: 220),
                RowSkeleton(primaryWidth: 240, secondaryWidth: 180),
                SizedBox(height: 12),
                RowSkeleton(primaryWidth: 220, secondaryWidth: 160),
              ],
            ),
          );
        }

        final cs = Theme.of(context).colorScheme;
        final isAuthenticated = session.value.isAuthenticated;
        final urgencyColor = _alertUrgencyColor(alert.urgency);
        final l10n = t(context);
        final identity = _identityForUserId(repo, alert.userId, legacyVerified: alert.isVerified, userFallback: l10n.commonUserFallback);

        Future<void> openAlertMenu() async {
          final choice = await showAtalaiaBottomSheet<String>(
            context,
            builder: (ctx) {
              return SafeArea(
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    ListTile(
                      leading: const Icon(Icons.flag_outlined),
                      title: Text(l10n.postActionReport),
                      onTap: () => Navigator.pop(ctx, 'report'),
                    ),
                    ListTile(
                      leading: const Icon(Icons.link),
                      title: Text(l10n.postActionCopyLink),
                      onTap: () => Navigator.pop(ctx, 'copy'),
                    ),
                    const SizedBox(height: 8),
                  ],
                ),
              );
            },
          );

          if (!context.mounted) return;

          switch (choice) {
            case 'report':
              if (!isAuthenticated) return showCtaSnackBar(context);
              final selected = await showReportReasonSheet(context);
              if (!context.mounted) return;
              if (selected != null) {
                final s = session.value;
                if (s is! AuthSession) return;
                await repo.submitReport(
                  reporterId: s.userId,
                  entityType: ReportEntityType.alert,
                  entityId: alert.id,
                  reason: selected.reason.name,
                  description: selected.otherText,
                  reportedUserId: alert.userId,
                );
                if (!context.mounted) return;
                showInfoSnackBar(context, l10n.postSnackReportSent);
              }
            case 'copy':
              showInfoSnackBar(context, l10n.commonLinkCopied);
            default:
              return;
          }
        }

        return Scaffold(
          appBar: AppBar(
            title: Text(t(context).alertDetailTitle),
            actions: [
              AtalaiaIconButton(
                icon: alert.viewerIsFollowing ? Icons.volunteer_activism : Icons.volunteer_activism_outlined,
                label: alert.viewerIsFollowing ? t(context).alertFollowing : t(context).alertFollow,
                onPressed: () {
                  if (!isAuthenticated) return showCtaSnackBar(context);
                  final willFollow = !alert.viewerIsFollowing;
                  repo.toggleFollowAlert(alert.id, isAuthenticated: true);
                  showInfoSnackBar(
                    context,
                    willFollow ? t(context).alertFollowingStartedSnack : t(context).alertFollowingStoppedSnack,
                  );
                },
              ),
              AtalaiaIconButton(
                icon: Icons.more_horiz,
                label: t(context).postMore,
                onPressed: () => unawaited(openAlertMenu()),
              ),
            ],
          ),
          body: Column(
            children: [
              if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
              Expanded(
                child: ListView(
                  padding: const EdgeInsets.fromLTRB(12, 12, 12, 16),
                  children: [
                    Card(
                      child: Padding(
                        padding: const EdgeInsets.all(12),
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Row(
                              children: [
                                InkWell(
                                  onTap: () {
                                    Navigator.of(context).pushNamed(
                                      Routes.userProfile,
                                      arguments: UserProfileArgs(userId: alert.userId),
                                    );
                                  },
                                  customBorder: const CircleBorder(),
                                  child: Avatar(name: identity.avatarName, imageUrl: identity.avatarUrl, size: AvatarSize.s44),
                                ),
                                const SizedBox(width: 10),
                                Expanded(
                                  child: Column(
                                    crossAxisAlignment: CrossAxisAlignment.start,
                                    children: [
                                      Row(
                                        children: [
                                          Flexible(
                                            child: Text(
                                              identity.displayName,
                                              style: const TextStyle(fontWeight: FontWeight.w900),
                                              maxLines: 1,
                                              overflow: TextOverflow.ellipsis,
                                            ),
                                          ),
                                          if (identity.isVerified) ...[
                                            const SizedBox(width: 6),
                                            Icon(Icons.verified, size: 18, color: context.brand.verifiedBlue),
                                          ],
                                          const Spacer(),
                                          Text(
                                            _relativeTime(context, alert.createdAt),
                                            style: TextStyle(color: cs.outline, fontWeight: FontWeight.w600),
                                          ),
                                        ],
                                      ),
                                      const SizedBox(height: 2),
                                      Text(
                                        '@${identity.username}',
                                        style: AtalaiaText.meta(context).copyWith(fontWeight: FontWeight.w700),
                                        maxLines: 1,
                                        overflow: TextOverflow.ellipsis,
                                      ),
                                    ],
                                  ),
                                ),
                              ],
                            ),
                            const SizedBox(height: 10),
                            Wrap(
                              spacing: 8,
                              runSpacing: 8,
                              children: [
                                Chip(
                                  avatar: Icon(Icons.warning_amber_rounded, size: 18, color: urgencyColor),
                                  label: Text(t(context).alertUrgency(_alertUrgencyLabel(context, alert.urgency))),
                                  visualDensity: VisualDensity.compact,
                                ),
                                Chip(
                                  avatar: const Icon(Icons.category_outlined, size: 18),
                                  label: Text(_alertCategoryLabel(context, alert.category)),
                                  visualDensity: VisualDensity.compact,
                                ),
                                Chip(
                                  avatar: const Icon(Icons.how_to_vote_outlined, size: 18),
                                  label: Text(t(context).alertConfidenceLabel(alert.confidenceScore.toInt().toString())),
                                  visualDensity: VisualDensity.compact,
                                ),
                              ],
                            ),
                            const SizedBox(height: 12),
                            Card(
                              elevation: 0,
                              child: Padding(
                                padding: const EdgeInsets.all(12),
                                child: Column(
                                  crossAxisAlignment: CrossAxisAlignment.start,
                                  children: [
                                    Text(t(context).alertCommunityVoteTitle, style: const TextStyle(fontWeight: FontWeight.w900)),
                                    const SizedBox(height: 8),
                                    Wrap(
                                      spacing: 8,
                                      runSpacing: 8,
                                      children: [
                                        ChoiceChip(
                                          label: Text(t(context).alertVoteConfirmed),
                                          selected: _myVote == AlertVote.confirmado,
                                          onSelected: (_) {
                                            if (!isAuthenticated) return showCtaSnackBar(context);
                                            setState(() => _myVote = AlertVote.confirmado);
                                            repo.voteOnAlert(
                                              alert.id,
                                              isAuthenticated: true,
                                              vote: AlertVote.confirmado,
                                            );
                                            showAtalaiaSnackBar(
                                              context,
                                              t(context).alertVoteRegisteredSnack,
                                              kind: AtalaiaSnackKind.success,
                                            );
                                          },
                                        ),
                                        ChoiceChip(
                                          label: Text(t(context).alertVoteFalse),
                                          selected: _myVote == AlertVote.falso,
                                          onSelected: (_) {
                                            if (!isAuthenticated) return showCtaSnackBar(context);
                                            setState(() => _myVote = AlertVote.falso);
                                            repo.voteOnAlert(
                                              alert.id,
                                              isAuthenticated: true,
                                              vote: AlertVote.falso,
                                            );
                                            showAtalaiaSnackBar(
                                              context,
                                              t(context).alertVoteRegisteredSnack,
                                              kind: AtalaiaSnackKind.success,
                                            );
                                          },
                                        ),
                                        ChoiceChip(
                                          label: Text(t(context).alertVoteResolved),
                                          selected: _myVote == AlertVote.resolvido,
                                          onSelected: (_) {
                                            if (!isAuthenticated) return showCtaSnackBar(context);
                                            setState(() => _myVote = AlertVote.resolvido);
                                            repo.voteOnAlert(
                                              alert.id,
                                              isAuthenticated: true,
                                              vote: AlertVote.resolvido,
                                            );
                                            showAtalaiaSnackBar(
                                              context,
                                              t(context).alertVoteRegisteredSnack,
                                              kind: AtalaiaSnackKind.success,
                                            );
                                          },
                                        ),
                                      ],
                                    ),
                                    const SizedBox(height: 6),
                                    Text(
                                      t(context).alertConfidenceHelp,
                                      style: TextStyle(color: cs.outline),
                                    ),
                                  ],
                                ),
                              ),
                            ),
                            const SizedBox(height: 10),
                            Text(alert.title, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 18)),
                            const SizedBox(height: 8),
                            Text(alert.description, style: TextStyle(color: cs.onSurfaceVariant, height: 1.35)),
                            const SizedBox(height: 12),
                            Row(
                              children: [
                                Icon(Icons.place_outlined, size: 18, color: cs.outline),
                                const SizedBox(width: 8),
                                Expanded(
                                  child: Text(
                                    alert.locationName,
                                    style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700),
                                  ),
                                ),
                              ],
                            ),
                            const SizedBox(height: 8),
                            Row(
                              children: [
                                Icon(Icons.schedule, size: 18, color: cs.outline),
                                const SizedBox(width: 8),
                                Expanded(
                                  child: Text(
                                    t(context).alertExpiresAt(_formatTimestamp(alert.expiresAt.toLocal())),
                                    style: TextStyle(color: cs.outline, fontWeight: FontWeight.w700),
                                  ),
                                ),
                              ],
                            ),
                          ],
                        ),
                      ),
                    ),
                    const SizedBox(height: 12),
                    PrimaryButton(
                      label: isAuthenticated
                          ? (alert.viewerIsFollowing ? t(context).alertFollowing : t(context).alertFollowAction)
                          : t(context).alertSignInToFollow,
                      onPressed: () {
                        if (!isAuthenticated) return showCtaSnackBar(context);
                        final willFollow = !alert.viewerIsFollowing;
                        repo.toggleFollowAlert(alert.id, isAuthenticated: true);
                        showInfoSnackBar(
                          context,
                          willFollow ? t(context).alertFollowingStartedSnack : t(context).alertFollowingStoppedSnack,
                        );
                      },
                    ),
                  ],
                ),
              ),
            ],
          ),
        );
      },
    );
  }
}

final class RegionRef {
  const RegionRef({
    required this.path,
    required this.name,
    required this.center,
    required this.targetZoom,
  });

  final String path;
  final String name;
  final LatLng center;
  final double targetZoom;
}

final class LocationRef {
  const LocationRef({
    required this.id,
    required this.name,
    required this.level,
    required this.path,
    required this.center,
    required this.postsCount,
    required this.prayersCount,
  });

  final String id;
  final String name;
  final String level;
  final String path;
  final LatLng center;
  final int postsCount;
  final int prayersCount;

  static LocationRef fromAgg(_MapLocationAgg agg) {
    return LocationRef(
      id: agg.locationId,
      name: agg.name,
      level: agg.level,
      path: agg.locationPath,
      center: agg.center,
      postsCount: agg.postsCount,
      prayersCount: agg.prayersCount,
    );
  }

  static LocationRef fromRegion(RegionRef region, {required String level}) {
    return LocationRef(
      id: region.path,
      name: region.name,
      level: level,
      path: region.path,
      center: region.center,
      postsCount: 0,
      prayersCount: 0,
    );
  }

  static LocationRef world({required String id}) {
    return LocationRef(
      id: id,
      name: 'Mundo',
      level: 'world',
      path: 'world',
      center: const LatLng(0, 0),
      postsCount: 0,
      prayersCount: 0,
    );
  }
}

