class _HomeStoriesStrip extends StatelessWidget {
  const _HomeStoriesStrip({
    required this.repo,
    required this.session,
  });

  final DemoRepository repo;
  final SessionState session;

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final viewerId = session is AuthSession ? (session as AuthSession).userId : null;

    final all = repo.storiesForHomeSocial();
    final byUser = <String, List<StoryModel>>{};
    for (final s in all) {
      (byUser[s.userId] ??= <StoryModel>[]).add(s);
    }
    for (final e in byUser.entries) {
      e.value.sort((a, b) => a.createdAt.compareTo(b.createdAt));
    }
    final orderedUserIds = byUser.keys.toList(growable: false)
      ..sort((a, b) => (byUser[b]?.last.createdAt ?? DateTime(1970)).compareTo(byUser[a]?.last.createdAt ?? DateTime(1970)));

    final myStories = viewerId == null ? null : byUser[viewerId];
    final hasMyStories = (myStories ?? const <StoryModel>[]).isNotEmpty;
    final others = orderedUserIds.where((id) => id != viewerId).take(24).toList(growable: false);

    Widget tile({
      required String label,
      required VoidCallback onTap,
      VoidCallback? onLongPress,
      String? avatarUrl,
      bool isAdd = false,
      Color? borderColor,
      double? labelFontSize,
      FontWeight? labelWeight,
      bool showUnreadDot = false,
    }) {
      final imageProvider = (avatarUrl != null && avatarUrl.trim().isNotEmpty) ? NetworkImage(avatarUrl.trim()) : null;
      return InkWell(
        onTap: onTap,
        onLongPress: onLongPress,
        borderRadius: BorderRadius.circular(18),
        child: SizedBox(
          width: 104,
          child: Column(
            mainAxisSize: MainAxisSize.min,
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Stack(
                children: [
                  Container(
                    decoration: BoxDecoration(
                      borderRadius: BorderRadius.circular(18),
                      border: Border.all(color: borderColor ?? cs.outlineVariant, width: (borderColor == null) ? 1 : 2),
                      boxShadow: [
                        BoxShadow(
                          color: cs.shadow.withValues(alpha: 0.08),
                          blurRadius: 14,
                          offset: const Offset(0, 8),
                        ),
                      ],
                    ),
                    child: ClipRRect(
                      borderRadius: BorderRadius.circular(16),
                      child: Container(
                          height: 104,
                        decoration: BoxDecoration(
                          color: cs.surfaceContainerHighest,
                          image: imageProvider == null
                              ? null
                              : DecorationImage(
                                  image: imageProvider,
                                  fit: BoxFit.cover,
                                ),
                        ),
                        alignment: Alignment.center,
                        child: imageProvider == null ? Icon(isAdd ? Icons.add : Icons.person, color: cs.onSurfaceVariant) : null,
                      ),
                    ),
                  ),
                  if (showUnreadDot)
                    Positioned(
                      left: 10,
                      top: 10,
                      child: Container(
                        width: 10,
                        height: 10,
                        decoration: BoxDecoration(
                          color: cs.primary,
                          shape: BoxShape.circle,
                          border: Border.all(color: cs.surface, width: 2),
                        ),
                      ),
                    ),
                  if (isAdd)
                    Positioned(
                      right: 8,
                      bottom: 8,
                      child: Container(
                        decoration: BoxDecoration(
                          color: cs.primary,
                          shape: BoxShape.circle,
                          border: Border.all(color: cs.surface, width: 2),
                        ),
                        padding: const EdgeInsets.all(2),
                        child: Icon(Icons.add, size: 14, color: cs.onPrimary),
                      ),
                    ),
                ],
              ),
              const SizedBox(height: 8),
              Center(
                child: Text(
                  label,
                  maxLines: 1,
                  overflow: TextOverflow.ellipsis,
                  style: TextStyle(
                    color: cs.onSurfaceVariant,
                    fontSize: labelFontSize ?? 12,
                    fontWeight: labelWeight ?? FontWeight.w700,
                    height: 1.1,
                  ),
                ),
              ),
            ],
          ),
        ),
      );
    }

    return Container(
      color: Theme.of(context).scaffoldBackgroundColor,
      padding: const EdgeInsets.fromLTRB(12, 10, 12, 8),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            children: [
              Text(t(context).storiesTitleMoments, style: const TextStyle(fontWeight: FontWeight.w900)),
              const Spacer(),
              if (!session.isAuthenticated)
                AtalaiaTextButton(
                  label: t(context).commonSignIn,
                  onPressed: () => Navigator.of(context).pushNamed(Routes.login),
                ),
            ],
          ),
          const SizedBox(height: 10),
          SizedBox(
            height: 142,
            child: ListView(
              scrollDirection: Axis.horizontal,
              children: [
                tile(
                  label: t(context).storiesYourStory,
                  isAdd: true,
                  avatarUrl: viewerId == null ? null : repo.profileForUserId(viewerId)?.avatarUrl,
                  borderColor: hasMyStories ? cs.primary : cs.outlineVariant,
                  labelFontSize: 11,
                  labelWeight: FontWeight.w600,
                  onTap: () {
                    if (!session.isAuthenticated) return showCtaSnackBar(context);
                    if (hasMyStories) {
                      Navigator.of(context).push(
                        MaterialPageRoute(
                          builder: (_) => _StoryViewerScreen(
                            cityName: t(context).storiesTitleMoments,
                            stories: myStories!,
                          ),
                        ),
                      );
                      return;
                    }
                    Navigator.of(context).push(MaterialPageRoute(builder: (_) => const CreatePostFlowScreen(initialMode: _CreateMode.story)));
                  },
                  onLongPress: () {
                    if (!session.isAuthenticated) return;
                    Navigator.of(context).push(MaterialPageRoute(builder: (_) => const CreatePostFlowScreen(initialMode: _CreateMode.story)));
                  },
                ),
                const SizedBox(width: 10),
                for (final userId in others) ...[
                  tile(
                    label: () {
                      final p = repo.profileForUserId(userId);
                      if (p == null) return t(context).storiesUserFallback;
                      return _displayNameForProfile(p, userFallback: t(context).storiesUserFallback);
                    }(),
                    avatarUrl: repo.profileForUserId(userId)?.avatarUrl,
                    borderColor: cs.primary,
                    showUnreadDot: true,
                    onTap: () {
                      final ordered = others;
                      final nextStories = <StoryModel>[];
                      for (final id in ordered) {
                        final list = byUser[id];
                        if (list != null && list.isNotEmpty) nextStories.addAll(list);
                      }
                      if (nextStories.isEmpty) return;
                      Navigator.of(context).push(
                        MaterialPageRoute(
                          builder: (_) => _StoryViewerScreen(
                            cityName: t(context).storiesTitleMoments,
                            stories: nextStories,
                            orderedUserIds: ordered,
                            initialUserId: userId,
                          ),
                        ),
                      );
                    },
                  ),
                  const SizedBox(width: 10),
                ],
                if (others.isEmpty && !hasMyStories)
                  Padding(
                    padding: const EdgeInsets.only(left: 6, top: 20),
                    child: Text(t(context).storiesNoStoriesYet, style: TextStyle(color: cs.outline)),
                  ),
              ],
            ),
          ),
        ],
      ),
    );
  }
}

class _HomeHighlightsRow extends StatelessWidget {
  const _HomeHighlightsRow({
    required this.campaigns,
    required this.campaignsCount,
    required this.alerts,
    required this.alertsCount,
    required this.locationLabel,
    required this.onOpenCampaigns,
    required this.onOpenAlerts,
  });

  final List<CampaignModel> campaigns;
  final int campaignsCount;
  final List<AlertModel> alerts;
  final int alertsCount;
  final String locationLabel;
  final VoidCallback onOpenCampaigns;
  final VoidCallback onOpenAlerts;

  @override
  Widget build(BuildContext context) {
    if (campaigns.isEmpty && alerts.isEmpty) return const SizedBox.shrink();
    final cs = Theme.of(context).colorScheme;

    Widget card({
      required IconData icon,
      required String title,
      required String subtitle,
      required String? preview,
      required VoidCallback onTap,
      Color? accent,
    }) {
      final a = accent ?? cs.primary;
      return SizedBox(
        width: 280,
        child: Card(
          margin: EdgeInsets.zero,
          child: InkWell(
            borderRadius: BorderRadius.circular(16),
            onTap: onTap,
            child: Padding(
              padding: const EdgeInsets.all(12),
              child: Row(
                children: [
                  Container(
                    width: 40,
                    height: 40,
                    decoration: BoxDecoration(
                      color: a.withValues(alpha: 0.14),
                      borderRadius: BorderRadius.circular(12),
                    ),
                    alignment: Alignment.center,
                    child: Icon(icon, color: a),
                  ),
                  const SizedBox(width: 12),
                  Expanded(
                    child: Column(
                      mainAxisSize: MainAxisSize.min,
                      crossAxisAlignment: CrossAxisAlignment.start,
                      children: [
                        Text(title, style: const TextStyle(fontWeight: FontWeight.w900)),
                        const SizedBox(height: 2),
                        Text(subtitle, style: TextStyle(color: cs.outline, fontWeight: FontWeight.w600)),
                        if ((preview ?? '').trim().isNotEmpty) ...[
                          const SizedBox(height: 6),
                          Text(
                            preview!,
                            maxLines: 1,
                            overflow: TextOverflow.ellipsis,
                            style: TextStyle(color: cs.onSurface, fontWeight: FontWeight.w700),
                          ),
                        ],
                      ],
                    ),
                  ),
                  Icon(Icons.chevron_right, color: cs.outline),
                ],
              ),
            ),
          ),
        ),
      );
    }

    AlertUrgency? maxUrgency() {
      if (alerts.isEmpty) return null;
      var u = alerts.first.urgency;
      for (final a in alerts.skip(1)) {
        if (a.urgency.index > u.index) u = a.urgency;
      }
      return u;
    }

    final urgency = maxUrgency();
    final alertAccent = urgency == null ? cs.primary : _alertUrgencyColor(urgency);
    final alertSubtitle = urgency == null
        ? '${t(context).mapAlertsActiveCount(alertsCount.toString())} • $locationLabel'
        : '${_alertUrgencyLabel(context, urgency)} • ${t(context).mapAlertsActiveCount(alertsCount.toString())}';

    final items = <Widget>[];
    if (campaigns.isNotEmpty) {
      items.add(
        card(
          icon: Icons.volunteer_activism_outlined,
          title: t(context).mapCampaignsTitle,
          subtitle: '${t(context).mapCampaignsActiveCount(campaignsCount.toString())} • $locationLabel',
          preview: campaigns.first.title,
          onTap: onOpenCampaigns,
        ),
      );
    }
    if (alerts.isNotEmpty) {
      if (items.isNotEmpty) items.add(const SizedBox(width: 10));
      items.add(
        card(
          icon: Icons.warning_amber_outlined,
          title: t(context).mapAlertsTitle,
          subtitle: alertSubtitle,
          preview: alerts.first.title,
          accent: alertAccent,
          onTap: onOpenAlerts,
        ),
      );
    }

    return Container(
      color: Theme.of(context).scaffoldBackgroundColor,
      padding: const EdgeInsets.fromLTRB(12, 0, 12, 8),
      child: SizedBox(
        height: 92,
        child: ListView(
          scrollDirection: Axis.horizontal,
          children: items,
        ),
      ),
    );
  }
}

class MapScreen extends StatefulWidget {
  const MapScreen({super.key, this.initialCommunityId, this.onCommunityContextChanged});

  final String? initialCommunityId;
  final VoidCallback? onCommunityContextChanged;

  @override
  State<MapScreen> createState() => _MapScreenState();
}

class _MapScreenState extends State<MapScreen> {
  final MapController _mapController = MapController();
  final ImagePicker _imagePicker = ImagePicker();
  final TextEditingController _communitySearch = TextEditingController();
  double _mapZoom = 2.3;
  LocationRef? _contextLocation;
  LocationRef? _selectedLocation;
  String? _activeCommunityId;
  var _showPrayerHeatmap = false;
  var _mapOpenTracked = false;
  int? _lastTrackedZoomBucket;
  String? _aggKey;
  Future<List<_MapLocationAgg>>? _aggFuture;
  String? _shapesKey;
  Future<List<_MapLocationShape>>? _shapesFuture;
  List<_MapLocationAgg> _lastAggItems = const <_MapLocationAgg>[];
  String _currentLevel = 'continent';
  String? _currentParentId;
  final Map<String, String> _lastValidParentIdByLevel = <String, String>{};
  final Map<String, String> _locationNameById = <String, String>{};
  String? _lastLoggedAggKey;
  var _isRegionSheetOpen = false;
  Timer? _moveEndDebounce;

  String? get activeCommunityId => _activeCommunityId;

  Future<void> openCommunitiesSheetFromAppBar() async {
    if (!mounted) return;
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context).value;
    await _openCommunitiesSheet(context, repo: repo, session: session);
  }

  void clearCommunityFilterFromAppBar() {
    final repo = RepoScope.of(context);
    repo.trackEvent('map_community_filter_clear', const <String, Object?>{});
    _setCommunityFilter(null);
  }

  Future<void> createMomentFromAppBar() async {
    if (!mounted) return;
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context).value;
    await _handleCreateStory(context, repo: repo, session: session);
  }

  Future<void> openActiveCommunityFeedFromAppBar() async {
    if (!mounted) return;
    var communityId = _activeCommunityId;
    while (mounted && communityId != null) {
      final result = await Navigator.of(context).pushNamed(
        Routes.communityDetail,
        arguments: CommunityArgs(communityId: communityId),
      );
      if (!mounted) return;
      if (result == true) {
        clearCommunityFilterFromAppBar();
        return;
      }
      if (result is String && _looksLikeUuid(result)) {
        RepoScope.of(context).trackEvent('map_community_filter_set', <String, Object?>{'communityId': result});
        _setCommunityFilter(result);
        communityId = result;
        continue;
      }
      return;
    }
  }

  Future<void> openActiveCommunityChatFromAppBar() async {
    if (!mounted) return;
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context).value;
    final l10n = t(context);
    final communityId = _activeCommunityId;
    if (communityId == null) return;
    final c = repo.findCommunity(communityId);
    if (c == null) return;
    if (session is! AuthSession) {
      showLoginSnackBar(context, message: l10n.chatSignInToChat);
      return;
    }
    if (c.viewerStatus != CommunityViewerStatus.approved) {
      showInfoSnackBar(context, l10n.communityMembersOnlyChat);
      return;
    }
    final thread = repo.openOrCreateCommunityThread(c.id, nameFallback: l10n.communityTitle, usernameFallback: 'group');
    Navigator.of(context).pushNamed(
      Routes.chat,
      arguments: ChatArgs(
        threadId: thread.id,
        peerName: c.name,
        peerUsername: 'group',
        peerIsVerified: false,
        communityId: c.id,
      ),
    );
  }

  Future<void> _openGlobalPrayer(BuildContext context, {required DemoRepository repo}) async {
    if (repo.isOffline) {
      showErrorSnackBar(context, onRetry: () {});
      return;
    }
    var locationId = await repo.locationIdByPath('world');
    if (!context.mounted) return;
    if (locationId == null || locationId.trim().isEmpty) {
      showInfoSnackBar(context, 'Local indisponível');
      return;
    }
    final meta = await repo.locationMetaById(locationId);
    if (!context.mounted) return;
    final locationName = meta?['name'] ?? 'Mundo';
    final locationLevel = meta?['level'] ?? 'world';
    final locationPath = meta?['path'] ?? 'world';
    Navigator.of(context).pushNamed(
      Routes.regionPrayer,
      arguments: RegionPrayerArgs(
        locationId: locationId,
        locationName: locationName,
        locationLevel: locationLevel,
        locationPath: locationPath,
        contextBreadcrumb: 'Oração global',
      ),
    );
  }

  void _togglePrayerHeatmap() {
    final repo = RepoScope.of(context);
    final enabled = !_showPrayerHeatmap;
    repo.trackEvent('map_heatmap_toggle', <String, Object?>{'enabled': enabled});
    setState(() => _showPrayerHeatmap = enabled);
    if (enabled) _scheduleEngineRun(immediate: true);
  }
  int _engineToken = 0;
  var _enginePrimed = false;
  static const double _disableCityClusteringAtZoom = 11.0;

  Set<String> _cityIdsWithStories = const <String>{};
  String? _storyPresenceKey;
  int _storyPresenceToken = 0;

  List<RegionRef> _fallbackRegionsForEmptyRemote() {
    final visible = _visibleRegionsFor(_mapZoom);
    final parentPaths = visible.map((r) => r.path).toSet();
    final result = <RegionRef>[];
    for (final parentPath in parentPaths) {
      final parentDepth = parentPath.split('/').length;
      for (final candidate in _mapRegions) {
        if (!candidate.path.startsWith('$parentPath/')) continue;
        final candidateDepth = candidate.path.split('/').length;
        if (candidateDepth != parentDepth + 1) continue;
        result.add(candidate);
      }
    }
    if (result.isNotEmpty) return result;
    return _mapRegions.where((r) => r.path != 'world').toList(growable: false);
  }

  @override
  void initState() {
    super.initState();
    _activeCommunityId = _looksLikeUuid(widget.initialCommunityId) ? widget.initialCommunityId : null;
    if (_activeCommunityId != null) {
      WidgetsBinding.instance.addPostFrameCallback((_) {
        widget.onCommunityContextChanged?.call();
      });
    }
  }

  @override
  void didChangeDependencies() {
    super.didChangeDependencies();
    if (_mapOpenTracked) return;
    _mapOpenTracked = true;
    final repo = RepoScope.of(context);
    repo.trackEvent('map_open', const <String, Object?>{});
    if (!_enginePrimed) {
      _enginePrimed = true;
      WidgetsBinding.instance.addPostFrameCallback((_) {
        _mapController.move(const LatLng(0, 0), 2.3);
        _scheduleEngineRun(immediate: true);
      });
    }
  }

  @override
  void dispose() {
    _moveEndDebounce?.cancel();
    _communitySearch.dispose();
    super.dispose();
  }

  void _maybeTrackZoom(double zoom) {
    final bucket = (zoom * 2).round();
    if (_lastTrackedZoomBucket == bucket) return;
    _lastTrackedZoomBucket = bucket;
    RepoScope.of(context).trackEvent('map_zoom_level', <String, Object?>{'zoom': bucket / 2});
  }

  void _setCommunityFilter(String? communityId) {
    setState(() {
      _activeCommunityId = communityId;
      _selectedLocation = null;
      _aggKey = null;
      _aggFuture = null;
      _lastLoggedAggKey = null;
      _storyPresenceKey = null;
      _cityIdsWithStories = const <String>{};
    });
    _scheduleEngineRun(immediate: true);
    widget.onCommunityContextChanged?.call();
  }

  Widget _buildMarkerBubble(
    BuildContext context, {
    required String label,
    Color? background,
    Color? foreground,
  }) {
    final scheme = Theme.of(context).colorScheme;
    return Container(
      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
      decoration: BoxDecoration(
        color: background ?? scheme.primary,
        borderRadius: BorderRadius.circular(999),
        boxShadow: const [BoxShadow(color: Colors.black26, blurRadius: 8, offset: Offset(0, 2))],
      ),
      child: Text(
        label,
        style: TextStyle(color: foreground ?? scheme.onPrimary, fontWeight: FontWeight.w900),
      ),
    );
  }

  Color _alertMarkerColor(BuildContext context, AlertUrgency urgency) {
    final cs = Theme.of(context).colorScheme;
    return switch (urgency) {
      AlertUrgency.critical => const Color(0xFFC62828),
      AlertUrgency.high => const Color(0xFFEF6C00),
      AlertUrgency.medium => const Color(0xFFF9A825),
      AlertUrgency.low => cs.primary,
    };
  }

  Widget _buildAlertBadge(BuildContext context, {required int count, required AlertUrgency urgency}) {
    if (count <= 0) return const SizedBox.shrink();
    final text = count >= 99 ? '99+' : '$count';
    return DecoratedBox(
      decoration: BoxDecoration(
        color: _alertMarkerColor(context, urgency),
        borderRadius: BorderRadius.circular(999),
        boxShadow: const [BoxShadow(color: Colors.black26, blurRadius: 6, offset: Offset(0, 2))],
      ),
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
        child: Text(
          text,
          style: const TextStyle(color: Colors.white, fontWeight: FontWeight.w900, fontSize: 11, height: 1.0),
        ),
      ),
    );
  }

  Widget _buildNewsBadge(BuildContext context, {required int count, required AlertUrgency urgency}) {
    if (count <= 0) return const SizedBox.shrink();
    final cs = Theme.of(context).colorScheme;
    final text = count >= 99 ? '99+' : '$count';
    return DecoratedBox(
      decoration: BoxDecoration(
        color: cs.primary,
        borderRadius: BorderRadius.circular(999),
        boxShadow: const [BoxShadow(color: Colors.black26, blurRadius: 6, offset: Offset(0, 2))],
      ),
      child: Padding(
        padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
        child: Text(
          text,
          style: TextStyle(color: cs.onPrimary, fontWeight: FontWeight.w900, fontSize: 11, height: 1.0),
        ),
      ),
    );
  }

  Widget _buildMapVitalsPill(
    BuildContext context, {
    required int postsCount,
    required int alertsCount,
    required int newsCount,
    required int momentsCount,
  }) {
    if (postsCount <= 0 && alertsCount <= 0 && newsCount <= 0 && momentsCount <= 0) {
      return const SizedBox.shrink();
    }
    final cs = Theme.of(context).colorScheme;

    Widget pill({
      required IconData icon,
      required String label,
      Color? fg,
      Color? bg,
    }) {
      return DecoratedBox(
        decoration: BoxDecoration(
          color: bg ?? cs.surfaceContainerHighest,
          borderRadius: BorderRadius.circular(999),
          border: Border.all(color: cs.outlineVariant),
        ),
        child: Padding(
          padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
          child: Row(
            mainAxisSize: MainAxisSize.min,
            children: [
              Icon(icon, size: 15, color: fg ?? cs.onSurfaceVariant),
              const SizedBox(width: 6),
              Text(
                label,
                style: TextStyle(
                  color: fg ?? cs.onSurfaceVariant,
                  fontWeight: FontWeight.w800,
                  height: 1.0,
                ),
              ),
            ],
          ),
        ),
      );
    }

    final items = <Widget>[];
    if (momentsCount > 0) {
      items.add(pill(icon: Icons.auto_awesome_outlined, label: t(context).mapMomentsCount(momentsCount.toString())));
    }
    if (postsCount > 0) {
      items.add(pill(icon: Icons.volunteer_activism_outlined, label: t(context).mapRequestsCount(postsCount.toString())));
    }
    if (alertsCount > 0) {
      items.add(
        pill(
          icon: Icons.warning_amber_outlined,
          label: t(context).mapAlertsCount(alertsCount.toString()),
          fg: cs.onErrorContainer,
          bg: cs.errorContainer,
        ),
      );
    }
    if (newsCount > 0) {
      items.add(pill(icon: Icons.bolt_outlined, label: t(context).mapNewsCount(newsCount.toString())));
    }

    return Material(
      color: cs.surface,
      elevation: 1,
      borderRadius: BorderRadius.circular(16),
      child: Padding(
        padding: const EdgeInsets.fromLTRB(12, 10, 12, 10),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text(t(context).mapActiveTitle, style: const TextStyle(fontWeight: FontWeight.w900)),
            const SizedBox(height: 8),
            Wrap(spacing: 8, runSpacing: 8, children: items),
          ],
        ),
      ),
    );
  }

  String _desiredLevelForZoom(double zoom) {
    const continentToCountryIn = 3.9;
    const countryToContinentOut = 3.6;
    const countryToStateIn = 6.8;
    const stateToCountryOut = 6.5;
    const stateToCityIn = 10.8;
    const cityToStateOut = 10.5;
    if (_currentLevel == 'city') return zoom <= cityToStateOut ? 'state' : 'city';
    if (_currentLevel == 'state') {
      if (zoom >= stateToCityIn) return 'city';
      return zoom <= stateToCountryOut ? 'country' : 'state';
    }
    if (_currentLevel == 'country') {
      if (zoom >= countryToStateIn) return 'state';
      if (zoom <= countryToContinentOut) return 'continent';
      return 'country';
    }
    return zoom >= continentToCountryIn ? 'country' : 'continent';
  }

  String? _parentLevelFor(String level) {
    return switch (level) {
      'world' => null,
      'continent' => 'world',
      'country' => 'continent',
      'state' => 'country',
      'city' => 'state',
      _ => null,
    };
  }

  double _targetZoomFor(String level) {
    return switch (level) {
      'world' => 2.3,
      'continent' => 4.2,
      'country' => 6.9,
      'state' => 6.9,
      'city' => 12.0,
      _ => 10.6,
    };
  }

  RegionRef _regionFromAgg(_MapLocationAgg agg) {
    return RegionRef(
      path: agg.locationPath,
      name: agg.name,
      center: agg.center,
      targetZoom: _targetZoomFor(agg.level),
    );
  }

  List<LatLng> _normalizeRingPoints(List<dynamic> rawPoints) {
    final points = <LatLng>[];
    for (final p in rawPoints) {
      if (p is! List) continue;
      if (p.length < 2) continue;
      final lng = (p[0] as num?)?.toDouble();
      final lat = (p[1] as num?)?.toDouble();
      if (lat == null || lng == null) continue;
      points.add(LatLng(lat, lng));
    }
    if (points.length >= 2) {
      final a = points.first;
      final b = points.last;
      if (a.latitude == b.latitude && a.longitude == b.longitude) {
        points.removeLast();
      }
    }
    return points;
  }

  List<List<LatLng>> _outerRingsFromGeoJson(String geoJson) {
    final rootAny = jsonDecode(geoJson);
    if (rootAny is! Map<String, dynamic>) return const [];
    final type = rootAny['type']?.toString();
    if (type == 'Feature') {
      final geom = rootAny['geometry'];
      if (geom is Map<String, dynamic>) {
        return _outerRingsFromGeoJson(jsonEncode(geom));
      }
      return const [];
    }
    if (type == 'FeatureCollection') {
      final features = rootAny['features'];
      if (features is! List) return const [];
      final rings = <List<LatLng>>[];
      for (final f in features) {
        if (f is! Map<String, dynamic>) continue;
        final geom = f['geometry'];
        if (geom is! Map<String, dynamic>) continue;
        rings.addAll(_outerRingsFromGeoJson(jsonEncode(geom)));
      }
      return rings;
    }
    final coords = rootAny['coordinates'];
    if (coords is! List) return const [];
    if (type == 'Polygon') {
      if (coords.isEmpty) return const [];
      final outer = coords.first;
      if (outer is! List) return const [];
      final ring = _normalizeRingPoints(outer);
      return ring.length >= 3 ? [ring] : const [];
    }
    if (type == 'MultiPolygon') {
      final rings = <List<LatLng>>[];
      for (final poly in coords) {
        if (poly is! List) continue;
        if (poly.isEmpty) continue;
        final outer = poly.first;
        if (outer is! List) continue;
        final ring = _normalizeRingPoints(outer);
        if (ring.length >= 3) rings.add(ring);
      }
      return rings;
    }
    return const [];
  }

  List<Polygon> _polygonsFromShapes(
    BuildContext context,
    List<_MapLocationShape> shapes, {
    String? selectedLocationId,
  }) {
    final cs = Theme.of(context).colorScheme;
    final polygons = <Polygon>[];
    for (final s in shapes) {
      final rings = _outerRingsFromGeoJson(s.geomGeoJson);
      final isSelected = selectedLocationId != null && s.locationId == selectedLocationId;
      for (final ring in rings) {
        polygons.add(
          Polygon(
            points: ring,
            color: (isSelected ? cs.primary : cs.primaryContainer).withValues(alpha: isSelected ? 0.28 : 0.18),
            borderColor: (isSelected ? cs.primary : cs.outline).withValues(alpha: isSelected ? 0.85 : 0.45),
            borderStrokeWidth: isSelected ? 1.7 : 1.0,
          ),
        );
      }
    }
    return polygons;
  }

  LocationRef _locationWithName(LocationRef base, String name) {
    return LocationRef(
      id: base.id,
      name: name,
      level: base.level,
      path: base.path,
      center: base.center,
      postsCount: base.postsCount,
      prayersCount: base.prayersCount,
    );
  }

  Future<void> _handleMapTapSelect(
    BuildContext context, {
    required DemoRepository repo,
    required SessionState session,
    required LatLng point,
  }) async {
    if (!mounted) return;
    if (repo.supabase == null) return;
    if (repo.isOffline) return;

    final desiredLevel = _currentLevel;
    final parentLevel = _parentLevelFor(desiredLevel);
    final levelsToTry = <String>[
      desiredLevel,
      if (parentLevel != null) parentLevel,
    ];

    _ResolvedLocation? resolved;
    for (final lvl in levelsToTry) {
      resolved = await repo.resolveLocationByPointGeom(level: lvl, lat: point.latitude, lng: point.longitude);
      if (!mounted) return;
      if (resolved != null) break;
    }
    if (resolved == null) return;

    if (_isRegionSheetOpen) {
      Navigator.of(context).pop(false);
    }

    _MapLocationAgg? agg;
    for (final a in _lastAggItems) {
      if (a.locationId == resolved.locationId) {
        agg = a;
        break;
      }
    }
    final location = agg != null
        ? LocationRef.fromAgg(agg)
        : LocationRef(
            id: resolved.locationId,
            name: resolved.name,
            level: resolved.level,
            path: resolved.path,
            center: point,
            postsCount: 0,
            prayersCount: 0,
          );

    repo.trackEvent('map_region_select_tap', <String, Object?>{
      'regionPath': location.path,
      'level': location.level,
      'zoom': (_mapZoom * 2).round() / 2,
    });

    setState(() {
      _selectedLocation = location;
    });
    unawaited(
      _openRegionSheet(
        context,
        repo: repo,
        session: session,
        location: location,
        agg: agg,
        communityId: _activeCommunityId,
      ),
    );
  }

  Future<void> _openSponsoredPin(
    BuildContext context, {
    required DemoRepository repo,
    required SponsoredMapPinModel pin,
  }) async {
    repo.trackAdClick(
      slotId: 'map_pin:${pin.id}',
      placement: 'map_pin',
      provider: 'atalaia_ads',
      campaignId: pin.campaignId,
      creativeId: pin.creativeId,
    );

    final uri = Uri.tryParse(pin.targetUrl);
    if (uri == null) {
      showInfoSnackBar(context, t(context).commonInvalidLink);
      return;
    }
    final ok = await launchUrl(uri, mode: LaunchMode.inAppBrowserView);
    if (!context.mounted) return;
    if (!ok) {
      await Clipboard.setData(ClipboardData(text: uri.toString()));
      if (!context.mounted) return;
      showInfoSnackBar(context, t(context).commonLinkCopied);
    }
  }

  void _scheduleEngineRun({bool immediate = false}) {
    _moveEndDebounce?.cancel();
    if (immediate) {
      unawaited(_runEngine());
      return;
    }
    _moveEndDebounce = Timer(const Duration(milliseconds: 300), () {
      if (!mounted) return;
      unawaited(_runEngine());
    });
  }

  Future<void> _runEngine() async {
    if (!mounted) return;
    final repo = RepoScope.of(context);
    if (repo.supabase == null) return;
    if (repo.isOffline) return;

    final token = ++_engineToken;
    final center = _mapController.camera.center;
    final zoom = _mapController.camera.zoom;
    var nextLevel = _desiredLevelForZoom(zoom);
    var parentLevel = _parentLevelFor(nextLevel);

    String? nextParentId;
    if (parentLevel != null) {
      if (nextLevel == 'continent') {
        nextParentId = _lastValidParentIdByLevel['world'] ?? await repo.locationIdByPath('world');
        if (!mounted || token != _engineToken) return;
        if (nextParentId != null) _lastValidParentIdByLevel['world'] = nextParentId;
      } else {
        nextParentId = await repo.resolveLocationIdByPoint(
          level: parentLevel,
          lat: center.latitude,
          lng: center.longitude,
        );
        if (!mounted || token != _engineToken) return;
        if (nextParentId == null) nextParentId = _lastValidParentIdByLevel[parentLevel];
        if (nextParentId != null) _lastValidParentIdByLevel[parentLevel] = nextParentId;
      }

      if (nextLevel == 'city' && nextParentId == null && parentLevel == 'state') {
        final fallbackParentId = await repo.resolveLocationIdByPoint(
          level: 'country',
          lat: center.latitude,
          lng: center.longitude,
        );
        if (!mounted || token != _engineToken) return;
        if (fallbackParentId != null) {
          parentLevel = 'country';
          nextParentId = fallbackParentId;
          _lastValidParentIdByLevel['country'] = fallbackParentId;
        }
      }

      if (nextParentId == null) {
        nextLevel = 'continent';
        parentLevel = 'world';
        nextParentId = _lastValidParentIdByLevel['world'] ?? await repo.locationIdByPath('world') ?? _currentParentId;
        if (!mounted || token != _engineToken) return;
      }
    }

    assert(() {
      if (nextLevel == 'continent') {
        debugPrint('[map] desiredLevel=continent worldId=$nextParentId');
      } else if (nextLevel == 'country') {
        debugPrint(
          '[map] desiredLevel=country center=(${center.latitude}, ${center.longitude}) continentId=$nextParentId',
        );
      } else if (nextLevel == 'state') {
        debugPrint(
          '[map] desiredLevel=state center=(${center.latitude}, ${center.longitude}) countryId=$nextParentId',
        );
      } else if (nextLevel == 'city') {
        debugPrint(
          '[map] desiredLevel=city center=(${center.latitude}, ${center.longitude}) ${parentLevel == 'country' ? 'countryId' : 'stateId'}=$nextParentId',
        );
      }
      return true;
    }());

    final nextContextLocation = switch (nextLevel) {
      'continent' => LocationRef.world(id: nextParentId ?? ''),
      'country' => LocationRef(
        id: nextParentId ?? '',
        name: nextParentId == null ? '…' : (_locationNameById[nextParentId] ?? '…'),
        level: 'continent',
        path: '',
        center: center,
        postsCount: 0,
        prayersCount: 0,
      ),
      'state' => LocationRef(
        id: nextParentId ?? '',
        name: nextParentId == null ? '…' : (_locationNameById[nextParentId] ?? '…'),
        level: 'country',
        path: '',
        center: center,
        postsCount: 0,
        prayersCount: 0,
      ),
      'city' => LocationRef(
        id: nextParentId ?? '',
        name: nextParentId == null ? '…' : (_locationNameById[nextParentId] ?? '…'),
        level: parentLevel ?? 'state',
        path: '',
        center: center,
        postsCount: 0,
        prayersCount: 0,
      ),
      _ => _contextLocation,
    };

    final communityId = _activeCommunityId;
    final nextKey = '$nextLevel|${nextParentId ?? ''}|${communityId ?? ''}';
    if (nextParentId != null) {
      unawaited(
        repo.refreshCampaignsForCurrentFeed(
          locationPath: 'world',
          locationId: nextParentId,
          communityId: communityId,
          lat: center.latitude,
          lng: center.longitude,
        ),
      );
      unawaited(repo.refreshSponsoredPinsForMap(locationId: nextParentId, communityId: communityId));
    }
    unawaited(repo.refreshPrayerChallengePinsForMap(communityId: communityId));
    if (_showPrayerHeatmap) {
      unawaited(repo.refreshPrayerHeatmapForMap(windowHours: 24, communityId: communityId));
    }
    final shapesTolerance = switch (nextLevel) {
      'continent' => 1.5,
      'country' => 0.35,
      'state' => 0.08,
      _ => 0.0,
    };
    final shouldLoadShapes = nextLevel == 'continent' || nextLevel == 'country' || nextLevel == 'state';
    final nextShapesKey = shouldLoadShapes ? '$nextLevel|${nextParentId ?? ''}' : null;
    if (_aggKey == nextKey && _aggFuture != null) {
      if (_currentLevel != nextLevel || _currentParentId != nextParentId) {
        setState(() {
          if (_currentLevel != nextLevel) _selectedLocation = null;
          _currentLevel = nextLevel;
          _currentParentId = nextParentId;
          _contextLocation = nextContextLocation;
          if (_shapesKey != nextShapesKey) {
            _shapesKey = nextShapesKey;
            _shapesFuture = shouldLoadShapes && nextParentId != null
                ? repo.fetchMapLocationShapes(
                    level: nextLevel,
                    parentId: nextParentId,
                    simplifyTolerance: shapesTolerance,
                  )
                : Future.value(const <_MapLocationShape>[]);
          }
        });
      }
      return;
    }

    final requestLimit = switch (nextLevel) {
      'continent' => 50,
      'country' => 500,
      'state' => 800,
      'city' => 1400,
      _ => 250,
    };
    final future = repo
        .fetchMapLocationsAggregateByParentId(
          level: nextLevel,
          parentId: nextParentId,
          communityId: communityId,
          limit: requestLimit,
        )
        .then((locations) async {
          final alerts = await repo.fetchMapAlertsAggregateByParentId(
            level: nextLevel,
            parentId: nextParentId,
            communityId: communityId,
            limit: requestLimit,
          );
          final news = await repo.fetchMapNewsEventsAggregateByParentId(
            level: nextLevel,
            parentId: nextParentId,
            limit: requestLimit,
          );
          if (alerts.isEmpty && news.isEmpty) return locations;
          final alertsById = <String, _MapAlertsAgg>{
            for (final a in alerts) a.locationId: a,
          };
          final newsById = <String, _MapNewsEventsAgg>{
            for (final n in news) n.locationId: n,
          };
          final merged = <_MapLocationAgg>[];
          for (final l in locations) {
            final a = alertsById[l.locationId];
            final n = newsById[l.locationId];
            if (a == null && n == null) {
              merged.add(l);
              continue;
            }
            merged.add(
              _MapLocationAgg(
                locationId: l.locationId,
                locationPath: l.locationPath,
                name: l.name,
                level: l.level,
                center: l.center,
                postsCount: l.postsCount,
                prayersCount: l.prayersCount,
                alertsCount: a?.alertsCount ?? 0,
                maxAlertUrgency: a?.maxUrgency,
                newsEventsCount: n?.eventsCount ?? 0,
                maxNewsUrgency: n?.maxUrgency,
              ),
            );
          }
          return merged;
        });
    final shapesFuture = nextShapesKey == null
        ? null
        : (shouldLoadShapes && nextParentId != null
            ? repo.fetchMapLocationShapes(
                level: nextLevel,
                parentId: nextParentId,
                simplifyTolerance: shapesTolerance,
              )
            : Future.value(const <_MapLocationShape>[]));

    setState(() {
      if (_currentLevel != nextLevel) _selectedLocation = null;
      _currentLevel = nextLevel;
      _currentParentId = nextParentId;
      _aggKey = nextKey;
      _aggFuture = future;
      _shapesKey = nextShapesKey;
      _shapesFuture = shapesFuture;
      _contextLocation = nextContextLocation;
    });

    final parentId = nextParentId;
    if ((nextLevel == 'country' || nextLevel == 'state' || nextLevel == 'city') && parentId != null && _locationNameById[parentId] == null) {
      unawaited(
        repo.locationNameById(parentId).then((name) {
          if (!mounted || token != _engineToken) return;
          if (name == null || name.isEmpty) return;
          setState(() {
            _locationNameById[parentId] = name;
            final currentContext = _contextLocation;
            if ((_currentLevel == 'country' || _currentLevel == 'state' || _currentLevel == 'city') && currentContext != null && currentContext.id == parentId) {
              _contextLocation = _locationWithName(currentContext, name);
            }
          });
        }),
      );
    }

    unawaited(
      future
          .then((rows) {
            if (!mounted || token != _engineToken) return;
            assert(() {
              if (_currentLevel == 'continent') {
                debugPrint('[map] continent rows=${rows.length}');
                for (final r in rows) {
                  debugPrint('[map] ${r.name} (${r.center.latitude}, ${r.center.longitude}) ${r.locationPath}');
                }
              } else if (_currentLevel == 'country') {
                debugPrint(
                  '[map] country rows=${rows.length} continentId=${_currentParentId ?? ''} continentName=${_contextLocation?.name ?? ''}',
                );
              }
              return true;
            }());
            final names = <String, String>{};
            for (final r in rows) {
              names[r.locationId] = r.name;
            }
            setState(() {
              _locationNameById.addAll(names);
              _lastAggItems = rows;
              final currentContext = _contextLocation;
              if ((_currentLevel == 'country' || _currentLevel == 'state' || _currentLevel == 'city') && currentContext != null) {
                final n = _locationNameById[currentContext.id];
                if (n != null && n.isNotEmpty && currentContext.name != n) {
                  _contextLocation = _locationWithName(currentContext, n);
                }
              }
            });
          })
          .catchError((_) {
            if (!mounted || token != _engineToken) return;
            setState(() {});
          }),
    );
  }

  List<RegionRef> _visibleRegionsFor(double zoom) {
    if (zoom < 3.2) return [_mapRegions[0]];
    if (zoom < 4.3) return [_mapRegions[1]];
    if (zoom < 5.6) return [_mapRegions[2]];
    if (zoom < 8.6) return [_mapRegions[3], _mapRegions[5]];
    return [_mapRegions[4], _mapRegions[6]];
  }

  void _animateToRegion(RegionRef region) {
    _mapController.move(region.center, region.targetZoom);
  }

  int _hashCityIds(Iterable<String> ids) {
    var h = 0;
    for (final id in ids) {
      h = 0x1fffffff & (h + id.hashCode);
      h = 0x1fffffff & (h + ((0x0007ffff & h) << 10));
      h ^= (h >> 6);
    }
    h = 0x1fffffff & (h + ((0x03ffffff & h) << 3));
    h ^= (h >> 11);
    h = 0x1fffffff & (h + ((0x00003fff & h) << 15));
    return h;
  }

  void _ensureStoryPresence(Set<String> cityIds) {
    if (cityIds.isEmpty) return;
    final ids = cityIds.toList(growable: false)..sort();
    final nextKey = '${_activeCommunityId ?? ''}|${_currentLevel}|${_currentParentId ?? ''}|${_hashCityIds(ids)}|${ids.length}';
    if (_storyPresenceKey == nextKey) return;
    _storyPresenceKey = nextKey;
    final token = ++_storyPresenceToken;
    final repo = RepoScope.of(context);
    final filterCommunityId = _activeCommunityId;
    unawaited(
      (filterCommunityId == null
              ? repo.fetchCityIdsWithActiveStories(cityIds)
              : repo.fetchCityIdsWithActiveStoriesInCommunity(cityIds, filterCommunityId))
          .then((idsWithStory) {
        if (!mounted || token != _storyPresenceToken) return;
        setState(() => _cityIdsWithStories = idsWithStory);
      }),
    );
  }

  Future<void> _openStoryViewer(
    BuildContext context, {
    required DemoRepository repo,
    required String cityId,
    required String cityName,
    String? communityId,
    String? communityName,
  }) async {
    final stories = communityId == null ? await repo.fetchStoriesForCity(cityId) : await repo.fetchStoriesForCityInCommunity(cityId: cityId, communityId: communityId);
    if (!context.mounted) return;
    if (stories.isEmpty) {
      showInfoSnackBar(context, 'Sem stories agora.');
      return;
    }
    final title = (communityName == null || communityName.trim().isEmpty) ? cityName : '${communityName.trim()} • $cityName';
    await Navigator.of(context).push(
      MaterialPageRoute<void>(
        fullscreenDialog: true,
        builder: (_) => _StoryViewerScreen(
          cityName: title,
          stories: stories,
        ),
      ),
    );
  }

  String? _inferContentType(String ext, {required bool isVideo}) {
    final e = ext.toLowerCase();
    if (!isVideo) {
      if (e == 'jpg' || e == 'jpeg') return 'image/jpeg';
      if (e == 'png') return 'image/png';
      if (e == 'webp') return 'image/webp';
      return 'image/jpeg';
    }
    if (e == 'mp4') return 'video/mp4';
    if (e == 'mov') return 'video/quicktime';
    if (e == 'm4v') return 'video/x-m4v';
    return 'video/mp4';
  }

  String _extensionFromPath(String path) {
    final i = path.lastIndexOf('.');
    if (i < 0 || i == path.length - 1) return '';
    return path.substring(i + 1).toLowerCase();
  }

  Future<String?> _resolveCityIdForCurrentMapCenter(DemoRepository repo) async {
    final c = _mapController.camera.center;
    return repo.resolveLocationIdByPoint(level: 'city', lat: c.latitude, lng: c.longitude);
  }

  Future<void> _tryAttachCityToStoryInBackground({
    required DemoRepository repo,
    required AuthSession session,
    required String storyId,
    String? communityId,
  }) async {
    await Future<void>.delayed(const Duration(milliseconds: 450));
    if (!mounted) return;
    final resolved = await _resolveCityIdForCurrentMapCenter(repo);
    if (!mounted) return;
    if (resolved == null || resolved.isEmpty) return;
    final ok = await repo.updateStoryCityId(session: session, storyId: storyId, cityId: resolved);
    if (!mounted || !ok) return;
    final name = _locationNameById[resolved] ?? '';
    if (name.isEmpty) {
      final fetched = await repo.locationNameById(resolved);
      if (!mounted) return;
      if (fetched != null && fetched.trim().isNotEmpty) {
        setState(() => _locationNameById[resolved] = fetched.trim());
      }
    }
    setState(() => _cityIdsWithStories = {..._cityIdsWithStories, resolved});
    _storyPresenceKey = null;
  }

  Future<void> _handleCreateStory(
    BuildContext context, {
    required DemoRepository repo,
    required SessionState session,
  }) async {
    if (!session.isAuthenticated) {
      unawaited(showAuthGate(context));
      return;
    }
    if (repo.isOffline) {
      showErrorSnackBar(
        context,
        message: t(context).commonNoConnection,
        onRetry: () => unawaited(_handleCreateStory(context, repo: repo, session: session)),
      );
      return;
    }
    final authSession = session is AuthSession ? session : null;
    if (authSession == null) return;

    final activeCommunityId = _activeCommunityId;
    final activeCommunityName = activeCommunityId == null ? null : repo.findCommunity(activeCommunityId)?.name;

    XFile? picked;
    if (!kIsWeb) {
      try {
        picked = await _imagePicker.pickImage(source: ImageSource.gallery);
      } catch (_) {
        picked = null;
      }
    }
    if (!context.mounted || picked == null) return;
    final mediaBytes = await picked.readAsBytes();
    if (!context.mounted || mediaBytes.isEmpty) return;

    final path = picked.path;
    final rawExt = _extensionFromPath(path);
    final ext = rawExt.isEmpty ? 'jpg' : rawExt;

    final caption = TextEditingController();
    var shareTarget = 'social';
    final published = await showAtalaiaBottomSheet<StoryModel?>(
      context,
      isScrollControlled: true,
      builder: (ctx) {
        var busy = false;
        return StatefulBuilder(
          builder: (ctx, setLocalState) {
            Future<void> publish() async {
              if (busy) return;
              setLocalState(() => busy = true);
              final trimmed = caption.text.trim();
              String? cityId;
              String? communityId;
              if (shareTarget == 'community') {
                communityId = activeCommunityId;
              } else if (shareTarget == 'regional') {
                cityId = await _resolveCityIdForCurrentMapCenter(repo);
                if (!ctx.mounted) return;
              }
              final story = await repo.createStory(
                session: authSession,
                cityId: cityId,
                mediaType: 'image',
                communityId: communityId,
                mediaBytes: mediaBytes,
                contentType: _inferContentType(ext, isVideo: false),
                fileExtension: ext,
                text: trimmed.isEmpty ? null : trimmed,
              );
              if (!ctx.mounted) return;
              Navigator.of(ctx).pop(story);
            }

            final l10n = t(ctx);
            final cName = (activeCommunityName ?? '').trim();
            return SafeArea(
              child: Padding(
                padding: EdgeInsets.only(
                  left: 16,
                  right: 16,
                  top: 12,
                  bottom: 16 + MediaQuery.viewInsetsOf(ctx).bottom,
                ),
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  crossAxisAlignment: CrossAxisAlignment.stretch,
                  children: [
                    Text(l10n.storiesShareSheetTitle, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 16)),
                    const SizedBox(height: 12),
                    ClipRRect(
                      borderRadius: BorderRadius.circular(16),
                      child: Image.memory(
                        mediaBytes,
                        fit: BoxFit.cover,
                        height: 220,
                      ),
                    ),
                    const SizedBox(height: 10),
                    TextField(
                      controller: caption,
                      maxLines: 2,
                      decoration: InputDecoration(
                        hintText: l10n.storiesCaptionHintOptional,
                        border: const OutlineInputBorder(),
                      ),
                    ),
                    const SizedBox(height: 12),
                    Text(l10n.storiesShareIn, style: const TextStyle(fontWeight: FontWeight.w900)),
                    const SizedBox(height: 6),
                    RadioGroup<String>(
                      groupValue: shareTarget,
                      onChanged: (v) {
                        if (busy) return;
                        setLocalState(() => shareTarget = v ?? shareTarget);
                      },
                      child: Column(
                        mainAxisSize: MainAxisSize.min,
                        children: [
                          RadioListTile<String>(
                            value: 'social',
                            title: Text(l10n.storiesShareTargetMyStory),
                            contentPadding: EdgeInsets.zero,
                            dense: true,
                          ),
                          if (activeCommunityId != null)
                            RadioListTile<String>(
                              value: 'community',
                              title: Text(cName.isEmpty ? l10n.mainTitleCommunity : cName),
                              contentPadding: EdgeInsets.zero,
                              dense: true,
                            ),
                          RadioListTile<String>(
                            value: 'regional',
                            title: Text(l10n.storiesShareTargetCurrentRegion),
                            contentPadding: EdgeInsets.zero,
                            dense: true,
                          ),
                        ],
                      ),
                    ),
                    const SizedBox(height: 10),
                    FilledButton(
                      onPressed: busy ? null : () => unawaited(publish()),
                      child: Text(busy ? l10n.storiesPublishing : l10n.storiesPublish),
                    ),
                  ],
                ),
              ),
            );
          },
        );
      },
    );
    caption.dispose();
    if (!context.mounted) return;

    Future<void> finish(StoryModel? story, {required String share}) async {
      if (!context.mounted) return;
      if (story == null) {
        showErrorSnackBar(
          context,
          message: repo.lastStoryCreateError ?? t(context).commonSomethingWentWrong,
          onRetry: () => unawaited(_handleCreateStory(context, repo: repo, session: session)),
        );
        return;
      }
      final c = (activeCommunityName ?? '').trim();
      final cityId = (story.cityId ?? '').trim();
      if (cityId.isNotEmpty) {
        var name = (_locationNameById[cityId] ?? '').trim();
        if (name.isEmpty) {
          final fetched = await repo.locationNameById(cityId);
          if (!context.mounted) return;
          if (fetched != null && fetched.trim().isNotEmpty) {
            name = fetched.trim();
            setState(() => _locationNameById[cityId] = name);
          } else {
            name = t(context).storiesPlaceFallbackCity;
          }
        }
        setState(() => _cityIdsWithStories = {..._cityIdsWithStories, cityId});
        _storyPresenceKey = null;
        showInfoSnackBar(
          context,
          c.isEmpty ? t(context).storiesPublishedInPlace(name) : t(context).storiesPublishedWithCommunityAndPlace(c, name),
        );
        return;
      }
      _storyPresenceKey = null;
      if (share == 'community') {
        showInfoSnackBar(context, c.isEmpty ? t(context).storiesPublished : t(context).storiesPublishedWithCommunity(c));
        return;
      }
      showInfoSnackBar(context, t(context).storiesPublished);
      if (share == 'regional') {
        unawaited(_tryAttachCityToStoryInBackground(repo: repo, session: authSession, storyId: story.id, communityId: activeCommunityId));
      }
    }
    await finish(published, share: shareTarget);
  }

  Future<void> _openCommunitiesSheet(
    BuildContext context, {
    required DemoRepository repo,
    required SessionState session,
  }) async {
    if (repo.supabase != null && !repo.isOffline) {
      unawaited(repo.refreshCommunitiesForViewer(force: true));
    }
    _communitySearch.text = '';
    await showAtalaiaBottomSheet<void>(
      context,
      builder: (ctx) {
        return _CommunitiesSheet(
          search: _communitySearch,
          session: session,
          repo: repo,
          activeCommunityId: _activeCommunityId,
          onOpenCommunity: (communityId) {
            Navigator.of(ctx).pop();
            unawaited(() async {
              await Navigator.of(context).pushNamed(
                Routes.communityDetail,
                arguments: CommunityArgs(communityId: communityId),
              );
              if (!context.mounted) return;
              if (repo.supabase != null && !repo.isOffline) {
                await repo.refreshCommunitiesForViewer(force: true);
              }
              if (!context.mounted) return;
              final c = repo.findCommunity(communityId);
              if (c != null && c.viewerStatus == CommunityViewerStatus.approved) {
                repo.trackEvent('map_community_filter_set', <String, Object?>{'communityId': communityId});
                _setCommunityFilter(communityId);
              }
            }());
          },
          onSelectFilter: (communityId) {
            Navigator.of(ctx).pop();
            repo.trackEvent('map_community_filter_set', <String, Object?>{'communityId': communityId ?? ''});
            _setCommunityFilter(communityId);
          },
          onCreateCommunity: session is! AuthSession
              ? null
              : () async {
                  final AuthSession s = session;
                  final id = await showAtalaiaBottomSheet<String?>(
                    context,
                    builder: (_) => _CreateCommunitySheet(repo: repo, session: s),
                  );
                  if (!context.mounted) return;
                  if (id == null || id.isEmpty) return;
                  repo.trackEvent('map_community_filter_set', <String, Object?>{'communityId': id});
                  _setCommunityFilter(id);
                  Navigator.of(context).pushNamed(
                    Routes.communityDetail,
                    arguments: CommunityArgs(communityId: id),
                  );
                },
        );
      },
    );
  }

  Future<void> _openRegionSheet(
    BuildContext context, {
    required DemoRepository repo,
    required SessionState session,
    required LocationRef location,
    _MapLocationAgg? agg,
    String? communityId,
  }) async {
    final posts =
        communityId == null ? repo.postsForRegion(session, location.path) : repo.postsForRegionInCommunity(session, location.path, communityId);

    final requestCount = posts.where((p) => p.kind == PostKind.request).length;
    final prayerSum = posts.fold<int>(0, (sum, p) => sum + p.prayerCount);
    final prayersCount = prayerSum > location.prayersCount ? prayerSum : location.prayersCount;

    final breadcrumb = switch (location.level) {
      'continent' => 'Mundo • Continente',
      'country' => '${_contextLocation?.name ?? '…'} • País',
      'state' => '${_contextLocation?.name ?? '…'} • Estado',
      'city' => '${_contextLocation?.name ?? '…'} • Cidade',
      _ => location.level,
    };

    setState(() => _isRegionSheetOpen = true);
    unawaited(
      Navigator.of(context)
          .pushNamed(
            Routes.regionDetail,
            arguments: RegionDetailArgs(
              location: location,
              breadcrumb: breadcrumb,
              requestCount: requestCount,
              prayerCount: prayersCount,
              communityId: communityId,
            ),
          )
          .then((_) {
        if (!mounted) return;
        setState(() {
          _isRegionSheetOpen = false;
          _selectedLocation = null;
        });
      }),
    );
  }

  void _handleRegionTap(
    BuildContext context, {
    required DemoRepository repo,
    required SessionState session,
    required RegionRef region,
    _MapLocationAgg? agg,
  }) {
    repo.trackEvent('map_region_select', <String, Object?>{
      'regionPath': region.path,
      'zoom': (_mapZoom * 2).round() / 2,
    });
    final location = agg == null ? LocationRef.fromRegion(region, level: _currentLevel) : LocationRef.fromAgg(agg);
    setState(() => _selectedLocation = location);
    _mapController.move(region.center, _mapZoom);
    final openSheetImmediately = agg != null && (agg.level == 'continent' || agg.level == 'country' || agg.level == 'state' || agg.level == 'city');
    if (!openSheetImmediately) {
      if (_mapZoom + 0.5 < region.targetZoom) {
        _animateToRegion(region);
        return;
      }
    }
    unawaited(
      _openRegionSheet(
        context,
        repo: repo,
        session: session,
        location: location,
        agg: agg,
        communityId: _activeCommunityId,
      ),
    );
  }

  Future<void> _openCityClusterSheet(
    BuildContext context, {
    required DemoRepository repo,
    required SessionState session,
    required List<_MapLocationAgg> group,
  }) async {
    final sorted = group.toList(growable: false)..sort((a, b) => a.name.compareTo(b.name));
    await showAtalaiaBottomSheet<void>(
      context,
      builder: (sheetContext) {
        return SafeArea(
          child: SizedBox(
            height: MediaQuery.sizeOf(context).height * 0.7,
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                Padding(
                  padding: const EdgeInsets.fromLTRB(16, 0, 16, 10),
                  child: Text(
                    '${sorted.length} cidades aqui',
                    style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 18),
                  ),
                ),
                const Divider(height: 1),
                Expanded(
                  child: ListView.separated(
                    itemCount: sorted.length,
                    separatorBuilder: (_, __) => const Divider(height: 1),
                    itemBuilder: (rowContext, index) {
                      final agg = sorted[index];
                      return ListTile(
                        title: Text(agg.name, style: const TextStyle(fontWeight: FontWeight.w800)),
                        trailing: const Icon(Icons.chevron_right),
                        onTap: () {
                          Navigator.of(sheetContext).pop();
                          Future<void>.delayed(const Duration(milliseconds: 1)).then((_) {
                            if (!mounted) return;
                            final region = _regionFromAgg(agg);
                            _handleRegionTap(context, repo: repo, session: session, region: region, agg: agg);
                          });
                        },
                      );
                    },
                  ),
                ),
              ],
            ),
          ),
        );
      },
    );
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        return Column(
          children: [
            if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
            Expanded(child: _buildMapStack(context, repo: repo, session: session.value)),
          ],
        );
      },
    );
  }

  Widget _buildMapStack(
    BuildContext context, {
    required DemoRepository repo,
    required SessionState session,
  }) {
    final visibleRegions = _visibleRegionsFor(_mapZoom);
    final useRemote = repo.supabase != null && !repo.isOffline;

    if (useRemote) {
      if (_aggFuture == null) {
        WidgetsBinding.instance.addPostFrameCallback((_) => _scheduleEngineRun(immediate: true));
      }
      return FutureBuilder<List<_MapLocationAgg>>(
        future: _aggFuture,
        builder: (context, snapshot) {
          final items = snapshot.data ?? const <_MapLocationAgg>[];
          final showEmptyRemoteFallback = snapshot.connectionState == ConnectionState.done && items.isEmpty;
            final totalPostsCount = items.fold<int>(0, (sum, a) => sum + a.postsCount);
            final totalAlertsCount = items.fold<int>(0, (sum, a) => sum + a.alertsCount);
            final totalNewsCount = items.fold<int>(0, (sum, a) => sum + a.newsEventsCount);
            final momentsCount = _currentLevel == 'city' ? _cityIdsWithStories.length : 0;
          if (_currentLevel == 'city') {
            final ids = <String>{};
            for (final a in items) {
              final id = a.locationId;
              if (_looksLikeUuid(id)) ids.add(id);
            }
            _ensureStoryPresence(ids);
          }
          final markers = <Marker>[];
          var clusterCount = 0;
          if (showEmptyRemoteFallback) {
            final fallbackRegions = _fallbackRegionsForEmptyRemote();
            for (final r in fallbackRegions) {
              markers.add(
                Marker(
                  point: r.center,
                  width: 68,
                  height: 44,
                  child: GestureDetector(
                    behavior: HitTestBehavior.opaque,
                    onTap: () => _handleRegionTap(context, repo: repo, session: session, region: r),
                    child: const Center(child: Icon(Icons.place, size: 34)),
                  ),
                ),
              );
            }
          }
          final disableCityClustering = _currentLevel == 'city' && _mapZoom >= _disableCityClusteringAtZoom;
          if (!disableCityClustering && (_currentLevel == 'country' || _currentLevel == 'state' || _currentLevel == 'city')) {
            final cellDeg = switch (_currentLevel) {
              'country' => _mapZoom < 4.6 ? 6.0 : (_mapZoom < 5.4 ? 4.0 : 2.5),
              'state' => _mapZoom < 7.4 ? 2.5 : (_mapZoom < 8.2 ? 1.6 : 1.0),
              _ => _mapZoom < 10.9 ? 0.6 : (_mapZoom < 11.6 ? 0.35 : 0.22),
            };
            final buckets = <String, List<_MapLocationAgg>>{};
            for (final agg in items) {
              final key = '${(agg.center.latitude / cellDeg).floor()}|${(agg.center.longitude / cellDeg).floor()}';
              (buckets[key] ??= <_MapLocationAgg>[]).add(agg);
            }
            clusterCount = buckets.values.where((g) => g.length > 1).length;
            for (final group in buckets.values) {
              if (group.length == 1) {
                final agg = group.first;
                final region = _regionFromAgg(agg);
                final label = agg.postsCount > 0 ? '${agg.postsCount}' : '•';
                final hasStory = _currentLevel == 'city' && _cityIdsWithStories.contains(agg.locationId);
                final urgency = agg.maxAlertUrgency ?? AlertUrgency.medium;
                final newsUrgency = agg.maxNewsUrgency ?? AlertUrgency.medium;
                final markerChild = _currentLevel == 'city'
                    ? Stack(
                        clipBehavior: Clip.none,
                        children: [
                          _CityPinMarker(label: label, hasStory: hasStory),
                          if (agg.newsEventsCount > 0)
                            Positioned(
                              left: 0,
                              top: 0,
                              child: _buildNewsBadge(context, count: agg.newsEventsCount, urgency: newsUrgency),
                            ),
                          if (agg.alertsCount > 0)
                            Positioned(
                              right: 0,
                              top: 0,
                              child: _buildAlertBadge(context, count: agg.alertsCount, urgency: urgency),
                            ),
                        ],
                      )
                    : Stack(
                        clipBehavior: Clip.none,
                        children: [
                          _buildMarkerBubble(
                            context,
                            label: label,
                            background: agg.alertsCount > 0 ? _alertMarkerColor(context, urgency) : null,
                            foreground: agg.alertsCount > 0 ? Colors.white : null,
                          ),
                          if (agg.newsEventsCount > 0)
                            Positioned(
                              left: -6,
                              top: -8,
                              child: _buildNewsBadge(context, count: agg.newsEventsCount, urgency: newsUrgency),
                            ),
                          if (agg.alertsCount > 0)
                            Positioned(
                              right: -6,
                              top: -8,
                              child: _buildAlertBadge(context, count: agg.alertsCount, urgency: urgency),
                            ),
                        ],
                      );
                markers.add(
                  Marker(
                    point: agg.center,
                    width: _currentLevel == 'city' ? 72 : 68,
                    height: _currentLevel == 'city' ? 72 : 44,
                    child: GestureDetector(
                      behavior: HitTestBehavior.opaque,
                      onTap: () {
                        if (hasStory) {
                          final communityId = _activeCommunityId;
                          final communityName = communityId == null ? null : repo.findCommunity(communityId)?.name;
                          unawaited(
                            _openStoryViewer(
                              context,
                              repo: repo,
                              cityId: agg.locationId,
                              cityName: agg.name,
                              communityId: communityId,
                              communityName: communityName,
                            ),
                          );
                          return;
                        }
                        _handleRegionTap(context, repo: repo, session: session, region: region, agg: agg);
                      },
                      child: Center(child: markerChild),
                    ),
                  ),
                );
                continue;
              }

              var sumLat = 0.0;
              var sumLng = 0.0;
              var sumAlerts = 0;
              AlertUrgency? maxUrgency;
              var sumNews = 0;
              AlertUrgency? maxNewsUrgency;
              for (final m in group) {
                sumLat += m.center.latitude;
                sumLng += m.center.longitude;
                sumAlerts += m.alertsCount;
                final u = m.maxAlertUrgency;
                if (u != null) {
                  if (maxUrgency == null || u.index > maxUrgency.index) maxUrgency = u;
                }
                sumNews += m.newsEventsCount;
                final nu = m.maxNewsUrgency;
                if (nu != null) {
                  if (maxNewsUrgency == null || nu.index > maxNewsUrgency.index) maxNewsUrgency = nu;
                }
              }
              final center = LatLng(sumLat / group.length, sumLng / group.length);
              markers.add(
                Marker(
                  point: center,
                  width: 72,
                  height: 52,
                  child: GestureDetector(
                    behavior: HitTestBehavior.opaque,
                    onTap: () {
                      if (_currentLevel == 'city') {
                        unawaited(_openCityClusterSheet(context, repo: repo, session: session, group: group));
                        return;
                      }
                      _mapController.move(
                        center,
                        _mapZoom + (_currentLevel == 'country' ? 1.2 : 0.9),
                      );
                    },
                    child: Center(
                      child: Stack(
                        clipBehavior: Clip.none,
                        children: [
                          _buildMarkerBubble(
                            context,
                            label: '${group.length}',
                            background: sumAlerts > 0 && maxUrgency != null ? _alertMarkerColor(context, maxUrgency) : null,
                            foreground: sumAlerts > 0 && maxUrgency != null ? Colors.white : null,
                          ),
                          if (sumNews > 0 && maxNewsUrgency != null)
                            Positioned(
                              left: -6,
                              top: -8,
                              child: _buildNewsBadge(context, count: sumNews, urgency: maxNewsUrgency),
                            ),
                          if (sumAlerts > 0 && maxUrgency != null)
                            Positioned(
                              right: -6,
                              top: -8,
                              child: _buildAlertBadge(context, count: sumAlerts, urgency: maxUrgency),
                            ),
                        ],
                      ),
                    ),
                  ),
                ),
              );
            }
          } else {
            for (final agg in items) {
              final region = _regionFromAgg(agg);
              final label = agg.postsCount > 0 ? '${agg.postsCount}' : '•';
              final hasStory = _currentLevel == 'city' && _cityIdsWithStories.contains(agg.locationId);
              final urgency = agg.maxAlertUrgency ?? AlertUrgency.medium;
              final newsUrgency = agg.maxNewsUrgency ?? AlertUrgency.medium;
              final markerChild = _currentLevel == 'city'
                  ? Stack(
                      clipBehavior: Clip.none,
                      children: [
                        _CityPinMarker(label: label, hasStory: hasStory),
                        if (agg.newsEventsCount > 0)
                          Positioned(
                            left: 0,
                            top: 0,
                            child: _buildNewsBadge(context, count: agg.newsEventsCount, urgency: newsUrgency),
                          ),
                        if (agg.alertsCount > 0)
                          Positioned(
                            right: 0,
                            top: 0,
                            child: _buildAlertBadge(context, count: agg.alertsCount, urgency: urgency),
                          ),
                      ],
                    )
                  : Stack(
                      clipBehavior: Clip.none,
                      children: [
                        _buildMarkerBubble(
                          context,
                          label: label,
                          background: agg.alertsCount > 0 ? _alertMarkerColor(context, urgency) : null,
                          foreground: agg.alertsCount > 0 ? Colors.white : null,
                        ),
                        if (agg.newsEventsCount > 0)
                          Positioned(
                            left: -6,
                            top: -8,
                            child: _buildNewsBadge(context, count: agg.newsEventsCount, urgency: newsUrgency),
                          ),
                        if (agg.alertsCount > 0)
                          Positioned(
                            right: -6,
                            top: -8,
                            child: _buildAlertBadge(context, count: agg.alertsCount, urgency: urgency),
                          ),
                      ],
                    );
              markers.add(
                Marker(
                  point: agg.center,
                  width: _currentLevel == 'city' ? 72 : 68,
                  height: _currentLevel == 'city' ? 72 : 44,
                  child: GestureDetector(
                    behavior: HitTestBehavior.opaque,
                    onTap: () {
                      if (hasStory) {
                        final communityId = _activeCommunityId;
                        final communityName = communityId == null ? null : repo.findCommunity(communityId)?.name;
                        unawaited(
                          _openStoryViewer(
                            context,
                            repo: repo,
                            cityId: agg.locationId,
                            cityName: agg.name,
                            communityId: communityId,
                            communityName: communityName,
                          ),
                        );
                        return;
                      }
                      _handleRegionTap(context, repo: repo, session: session, region: region, agg: agg);
                    },
                    child: Center(child: markerChild),
                  ),
                ),
              );
            }
          }

          final showCampaignPins = _mapZoom >= 9.5;
          if (showCampaignPins) {
            final centerPoint = _mapController.camera.center;
            final maxDistanceKm = _mapZoom >= 12.2 ? 70.0 : (_mapZoom >= 11.2 ? 120.0 : 220.0);
            final filterCommunityId = _activeCommunityId;
            final candidates = repo
                .visibleCampaignsFor(session)
                .where((c) => c.status == CampaignStatus.active)
                .where((c) => filterCommunityId == null ? true : c.communityId == filterCommunityId)
                .toList(growable: false);
            final scored = <({CampaignModel campaign, double distance})>[];
            for (final c in candidates) {
              final p = _campaignCenter(c);
              if (p == null) continue;
              final d = _distanceKm(centerPoint, p);
              if (d > maxDistanceKm) continue;
              scored.add((campaign: c, distance: d));
            }
            scored.sort((a, b) => a.distance.compareTo(b.distance));
            for (final item in scored.take(18)) {
              final p = _campaignCenter(item.campaign);
              if (p == null) continue;
              markers.add(
                Marker(
                  point: p,
                  width: 52,
                  height: 52,
                  child: GestureDetector(
                    behavior: HitTestBehavior.opaque,
                    onTap: () {
                      Navigator.of(context).pushNamed(
                        Routes.campaignDetail,
                        arguments: CampaignDetailArgs(campaignId: item.campaign.id),
                      );
                    },
                    child: Center(child: _CampaignPinMarker(progress: item.campaign.progress, isUrgent: item.campaign.isUrgent)),
                  ),
                ),
              );
            }
          }

          final showChallengePins = _mapZoom >= 5.0;
          if (showChallengePins) {
            final now = DateTime.now().toUtc();
            final centerPoint = _mapController.camera.center;
            final maxDistanceKm = _mapZoom >= 10.8 ? 650.0 : (_mapZoom >= 7.6 ? 1500.0 : 5000.0);
            final sponsoredPins = repo.sponsoredPinsForMap(session, communityId: _activeCommunityId);
            final sponsoredScored = <({SponsoredMapPinModel pin, double distance})>[];
            for (final pin in sponsoredPins) {
              final d = _distanceKm(centerPoint, pin.center);
              if (d > maxDistanceKm) continue;
              sponsoredScored.add((pin: pin, distance: d));
            }
            sponsoredScored.sort((a, b) => a.distance.compareTo(b.distance));
            for (final item in sponsoredScored.take(8)) {
              repo.markAdImpression(
                slotId: 'map_pin:${item.pin.id}',
                placement: 'map_pin',
                provider: 'atalaia_ads',
                campaignId: item.pin.campaignId,
                creativeId: item.pin.creativeId,
              );
              markers.add(
                Marker(
                  point: item.pin.center,
                  width: 54,
                  height: 54,
                  child: GestureDetector(
                    behavior: HitTestBehavior.opaque,
                    onTap: () => unawaited(_openSponsoredPin(context, repo: repo, pin: item.pin)),
                    child: const Center(child: _SponsoredPinMarker()),
                  ),
                ),
              );
            }
            final candidates = repo.prayerChallengePinsForMap(session, communityId: _activeCommunityId);
            final scored = <({PrayerChallengeMapPinModel pin, double distance})>[];
            for (final pin in candidates) {
              if (now.isBefore(pin.startDate.toUtc()) || now.isAfter(pin.endDate.toUtc())) continue;
              final d = _distanceKm(centerPoint, pin.center);
              if (d > maxDistanceKm) continue;
              scored.add((pin: pin, distance: d));
            }
            scored.sort((a, b) => a.distance.compareTo(b.distance));
            for (final item in scored.take(14)) {
              markers.add(
                Marker(
                  point: item.pin.center,
                  width: 56,
                  height: 56,
                  child: GestureDetector(
                    behavior: HitTestBehavior.opaque,
                    onTap: () {
                      Navigator.of(context).pushNamed(
                        Routes.prayerChallengeDetail,
                        arguments: PrayerChallengeDetailArgs(challengeId: item.pin.id),
                      );
                    },
                    child: Center(
                      child: _PrayerChallengePinMarker(
                        participantsCount: item.pin.participantsCount,
                        isCommunity: item.pin.communityId != null,
                      ),
                    ),
                  ),
                ),
              );
            }
          }

          assert(() {
            if (snapshot.connectionState == ConnectionState.done && snapshot.hasError == false) {
              final key = _aggKey;
              if (key != null && key != _lastLoggedAggKey) {
                if (_currentLevel == 'country') {
                  debugPrint(
                    '[map] render desiredLevel=country rows=${items.length} markers=${markers.length} clusters=$clusterCount context=${_contextLocation?.name ?? ''}',
                  );
                } else if (_currentLevel == 'state') {
                  debugPrint(
                    '[map] render desiredLevel=state rows=${items.length} markers=${markers.length} clusters=$clusterCount context=${_contextLocation?.name ?? ''}',
                  );
                } else if (_currentLevel == 'city') {
                  debugPrint(
                    '[map] render desiredLevel=city rows=${items.length} markers=${markers.length} clusters=$clusterCount context=${_contextLocation?.name ?? ''}',
                  );
                } else if (_currentLevel == 'continent') {
                  debugPrint('[map] render desiredLevel=continent rows=${items.length} markers=${markers.length}');
                } else {
                  debugPrint('[map] render desiredLevel=$_currentLevel rows=${items.length} markers=${markers.length}');
                }
                _lastLoggedAggKey = key;
              }
            }
            return true;
          }());

          return Stack(
            children: [
              _buildMapSurface(
                context,
                repo: repo,
                session: session,
                markers: markers,
                postsCount: totalPostsCount,
                alertsCount: totalAlertsCount,
                newsCount: totalNewsCount,
                momentsCount: momentsCount,
              ),
              if (showEmptyRemoteFallback)
                Positioned(
                  left: 12,
                  top: 12,
                  child: SafeArea(
                    minimum: const EdgeInsets.only(top: 8),
                    child: Material(
                      color: Theme.of(context).colorScheme.surface,
                      borderRadius: BorderRadius.circular(12),
                      elevation: 1,
                      child: Padding(
                        padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 8),
                        child: Row(
                          mainAxisSize: MainAxisSize.min,
                          children: [
                            const Icon(Icons.info_outline, size: 16),
                            const SizedBox(width: 8),
                            Text(
                              'Sem dados do mapa no Supabase',
                              style: TextStyle(
                                color: Theme.of(context).colorScheme.onSurface,
                                fontWeight: FontWeight.w800,
                              ),
                            ),
                            const SizedBox(width: 10),
                            AtalaiaTextButton(
                              label: 'Recarregar',
                              onPressed: () => _scheduleEngineRun(immediate: true),
                            ),
                          ],
                        ),
                      ),
                    ),
                  ),
                ),
              if (snapshot.connectionState != ConnectionState.done)
                const Positioned(
                  left: 12,
                  top: 12,
                  child: SizedBox(width: 18, height: 18, child: CircularProgressIndicator(strokeWidth: 2)),
                ),
            ],
          );
        },
      );
    }

    final markers = <Marker>[];
    var postsCount = 0;
    for (final r in visibleRegions) {
      final filterCommunityId = _activeCommunityId;
      final regionPosts = filterCommunityId == null
          ? repo.postsForRegion(session, r.path)
          : repo.postsForRegionInCommunity(session, r.path, filterCommunityId);
      final requestCount = regionPosts.where((p) => p.kind == PostKind.request).length;
      if (requestCount <= 0) continue;
      postsCount += requestCount;
      markers.add(
        Marker(
          point: r.center,
          width: 68,
          height: 44,
          child: GestureDetector(
            behavior: HitTestBehavior.opaque,
            onTap: () => _handleRegionTap(context, repo: repo, session: session, region: r),
            child: const Center(child: Icon(Icons.place, size: 34)),
          ),
        ),
      );
    }

    if (_mapZoom >= 5.0) {
      final now = DateTime.now().toUtc();
      final centerPoint = _mapController.camera.center;
      final maxDistanceKm = _mapZoom >= 10.8 ? 650.0 : (_mapZoom >= 7.6 ? 1500.0 : 5000.0);
      final sponsoredPins = repo.sponsoredPinsForMap(session, communityId: _activeCommunityId);
      final sponsoredScored = <({SponsoredMapPinModel pin, double distance})>[];
      for (final pin in sponsoredPins) {
        final d = _distanceKm(centerPoint, pin.center);
        if (d > maxDistanceKm) continue;
        sponsoredScored.add((pin: pin, distance: d));
      }
      sponsoredScored.sort((a, b) => a.distance.compareTo(b.distance));
      for (final item in sponsoredScored.take(8)) {
        repo.markAdImpression(
          slotId: 'map_pin:${item.pin.id}',
          placement: 'map_pin',
          provider: 'atalaia_ads',
          campaignId: item.pin.campaignId,
          creativeId: item.pin.creativeId,
        );
        markers.add(
          Marker(
            point: item.pin.center,
            width: 54,
            height: 54,
            child: GestureDetector(
              behavior: HitTestBehavior.opaque,
              onTap: () => unawaited(_openSponsoredPin(context, repo: repo, pin: item.pin)),
              child: const Center(child: _SponsoredPinMarker()),
            ),
          ),
        );
      }
      final pins = repo.prayerChallengePinsForMap(session, communityId: _activeCommunityId);
      final scored = <({PrayerChallengeMapPinModel pin, double distance})>[];
      for (final pin in pins) {
        if (now.isBefore(pin.startDate.toUtc()) || now.isAfter(pin.endDate.toUtc())) continue;
        final d = _distanceKm(centerPoint, pin.center);
        if (d > maxDistanceKm) continue;
        scored.add((pin: pin, distance: d));
      }
      scored.sort((a, b) => a.distance.compareTo(b.distance));
      for (final item in scored.take(14)) {
        markers.add(
          Marker(
            point: item.pin.center,
            width: 56,
            height: 56,
            child: GestureDetector(
              behavior: HitTestBehavior.opaque,
              onTap: () {
                Navigator.of(context).pushNamed(
                  Routes.prayerChallengeDetail,
                  arguments: PrayerChallengeDetailArgs(challengeId: item.pin.id),
                );
              },
              child: Center(
                child: _PrayerChallengePinMarker(
                  participantsCount: item.pin.participantsCount,
                  isCommunity: item.pin.communityId != null,
                ),
              ),
            ),
          ),
        );
      }
    }

    final momentsCount = _currentLevel == 'city' ? _cityIdsWithStories.length : 0;
    return _buildMapSurface(
      context,
      repo: repo,
      session: session,
      markers: markers,
      postsCount: postsCount,
      momentsCount: momentsCount,
    );
  }

  Widget _buildMapSurface(
    BuildContext context, {
    required DemoRepository repo,
    required SessionState session,
    required List<Marker> markers,
    int postsCount = 0,
    int alertsCount = 0,
    int newsCount = 0,
    int momentsCount = 0,
  }) {
    final heatMarkers = <Marker>[];
    if (_showPrayerHeatmap) {
      final points = repo.prayerHeatmapPointsForMap(session, communityId: _activeCommunityId);
      for (final p in points) {
        final intensity = (p.urgencyScore / 40.0).clamp(0.0, 1.0);
        final countFactor = (p.prayerCount / 40.0).clamp(0.0, 1.0);
        final size = 20.0 + 46.0 * (0.55 * intensity + 0.45 * countFactor);

        final color = intensity >= 0.70
            ? const Color(0xFFD32F2F)
            : intensity >= 0.35
                ? const Color(0xFFF9A825)
                : const Color(0xFF2E7D32);
        final fill = color.withValues(alpha: (0.10 + 0.35 * intensity).clamp(0.10, 0.45));
        final stroke = color.withValues(alpha: (0.20 + 0.50 * intensity).clamp(0.20, 0.70));

        heatMarkers.add(
          Marker(
            point: p.center,
            width: size,
            height: size,
            child: IgnorePointer(
              child: DecoratedBox(
                decoration: BoxDecoration(
                  shape: BoxShape.circle,
                  color: fill,
                  border: Border.all(color: stroke, width: 1.0),
                ),
              ),
            ),
          ),
        );
      }
    }

    return Stack(
      children: [
        Positioned(
          left: 12,
          top: 12,
          child: SafeArea(
            minimum: const EdgeInsets.only(top: 8),
            child: _buildMapVitalsPill(
              context,
              postsCount: postsCount,
              alertsCount: alertsCount,
              newsCount: newsCount,
              momentsCount: momentsCount,
            ),
          ),
        ),
        FlutterMap(
          mapController: _mapController,
          options: MapOptions(
            initialCenter: const LatLng(0, 0),
            initialZoom: 2.3,
            onPositionChanged: (pos, _) {
              final z = pos.zoom;
              setState(() => _mapZoom = z);
              _maybeTrackZoom(z);
            },
            onMapEvent: (event) {
              if (event is MapEventMoveEnd) {
                final z = _mapController.camera.zoom;
                final nextLevel = _desiredLevelForZoom(z);
                if (mounted) {
                  setState(() {
                    _mapZoom = z;
                    if (_currentLevel != nextLevel) {
                      _selectedLocation = null;
                      _currentLevel = nextLevel;
                    }
                  });
                }
                _scheduleEngineRun();
              }
            },
            onTap: (_, __) {
              unawaited(_handleMapTapSelect(context, repo: repo, session: session, point: __));
            },
          ),
          children: [
            TileLayer(
              urlTemplate: 'https://tile.openstreetmap.org/{z}/{x}/{y}.png',
              userAgentPackageName: 'atalaia_social',
            ),
            if (_shapesFuture != null && (_currentLevel == 'continent' || _currentLevel == 'country' || _currentLevel == 'state'))
              FutureBuilder<List<_MapLocationShape>>(
                future: _shapesFuture,
                builder: (context, snapshot) {
                  final shapes = snapshot.data ?? const <_MapLocationShape>[];
                  final polygons = _polygonsFromShapes(context, shapes, selectedLocationId: _selectedLocation?.id);
                  if (polygons.isEmpty) return const SizedBox.shrink();
                  return PolygonLayer(polygons: polygons);
                },
              ),
            if (heatMarkers.isNotEmpty) MarkerLayer(markers: heatMarkers),
            MarkerLayer(markers: markers),
          ],
        ),
        if (_selectedLocation != null)
          Positioned(
            left: 12,
            top: 66,
            child: Material(
              color: Theme.of(context).colorScheme.surface,
              borderRadius: BorderRadius.circular(999),
              elevation: 1,
              child: Padding(
                padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
                child: Text(
                  _selectedLocation!.name,
                  style: const TextStyle(fontWeight: FontWeight.w800),
                ),
              ),
            ),
          ),
        Positioned(
          left: 12,
          bottom: 12,
          child: SafeArea(
            minimum: const EdgeInsets.only(bottom: 8),
            child: FilledButton.tonalIcon(
              onPressed: _togglePrayerHeatmap,
              icon: Icon(_showPrayerHeatmap ? Icons.whatshot : Icons.whatshot_outlined, size: 18),
              label: const Text('Heat map'),
            ),
          ),
        ),
        if (_activeCommunityId != null)
          Positioned(
            right: 12,
            bottom: 12,
            child: SafeArea(
              minimum: const EdgeInsets.only(bottom: 8),
              child: FilledButton.icon(
                onPressed: () => unawaited(_openGlobalPrayer(context, repo: repo)),
                icon: const Icon(Icons.public, size: 18),
                label: const Text('Oração global'),
              ),
            ),
          ),
      ],
    );
  }
}

class _CommunitiesSheet extends StatefulWidget {
  const _CommunitiesSheet({
    required this.search,
    required this.session,
    required this.repo,
    required this.activeCommunityId,
    required this.onOpenCommunity,
    required this.onSelectFilter,
    required this.onCreateCommunity,
  });

  final TextEditingController search;
  final SessionState session;
  final DemoRepository repo;
  final String? activeCommunityId;
  final void Function(String communityId) onOpenCommunity;
  final void Function(String? communityId) onSelectFilter;
  final Future<void> Function()? onCreateCommunity;

  @override
  State<_CommunitiesSheet> createState() => _CommunitiesSheetState();
}

class _CommunitiesSheetState extends State<_CommunitiesSheet> {
  @override
  void initState() {
    super.initState();
    widget.search.addListener(_onSearchChanged);
  }

  @override
  void dispose() {
    widget.search.removeListener(_onSearchChanged);
    super.dispose();
  }

  void _onSearchChanged() {
    if (!mounted) return;
    setState(() {});
  }

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final list = widget.repo.communitiesFor(widget.session, query: widget.search.text);

    return SafeArea(
      child: Padding(
        padding: EdgeInsets.only(bottom: 12 + MediaQuery.viewInsetsOf(context).bottom),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          children: [
            Padding(
              padding: const EdgeInsets.fromLTRB(16, 0, 16, 10),
              child: Row(
                children: [
                  Expanded(
                    child: Text(t(context).mainActionCommunities, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 18)),
                  ),
                  if (widget.onCreateCommunity != null)
                    AtalaiaTextButton(
                      label: t(context).commonCreate,
                      onPressed: () => unawaited(widget.onCreateCommunity!.call()),
                    ),
                ],
              ),
            ),
            Padding(
              padding: const EdgeInsets.symmetric(horizontal: 16),
              child: SearchField(
                controller: widget.search,
                hintText: t(context).communitiesSearchHint,
                onChanged: (_) {},
              ),
            ),
            const SizedBox(height: 10),
            Flexible(
              child: RefreshIndicator(
                onRefresh: () async {
                  await widget.repo.refreshCommunitiesForViewer(force: true);
                },
                child: list.isEmpty
                    ? ListView(
                        physics: const AlwaysScrollableScrollPhysics(),
                        children: [
                          SizedBox(height: MediaQuery.sizeOf(context).height * 0.10),
                          EmptyState(
                            icon: Icons.groups_outlined,
                            title: widget.search.text.trim().isEmpty ? t(context).communitiesEmpty : t(context).communitiesEmptySearch,
                          ),
                        ],
                      )
                    : ListView.separated(
                        shrinkWrap: true,
                        physics: const AlwaysScrollableScrollPhysics(),
                        itemCount: list.length + 1,
                        separatorBuilder: (_, __) => const Divider(height: 1),
                        itemBuilder: (context, index) {
                          if (index == 0) {
                            final isActive = widget.activeCommunityId == null;
                            return ListTile(
                              leading: const Icon(Icons.public),
                              title: Text(t(context).communitiesGlobalFilterTitle, style: const TextStyle(fontWeight: FontWeight.w800)),
                              subtitle: Text(t(context).communitiesGlobalFilterSubtitle, style: TextStyle(color: cs.outline)),
                              trailing: isActive ? const Icon(Icons.check) : null,
                              onTap: () => widget.onSelectFilter(null),
                            );
                          }

                          final c = list[index - 1];
                          final statusLabel = switch (c.viewerStatus) {
                            CommunityViewerStatus.none => c.isClosed ? t(context).communityPrivacyClosed : t(context).communityPrivacyOpen,
                            CommunityViewerStatus.pending => t(context).communityStatusPending,
                            CommunityViewerStatus.approved => t(context).communityStatusMember,
                          };
                          final loc = (c.locationName ?? '').trim();
                          final subtitle = loc.isEmpty ? statusLabel : '$statusLabel • $loc';
                          final isActive = widget.activeCommunityId == c.id;
                          final canSelect = c.viewerStatus == CommunityViewerStatus.approved;
                          return ListTile(
                            leading: Avatar(name: c.name, imageUrl: c.imageUrl, size: AvatarSize.s44),
                            title: Text(c.name, style: const TextStyle(fontWeight: FontWeight.w800)),
                            subtitle: Text(subtitle, style: TextStyle(color: cs.outline)),
                            trailing: isActive ? const Icon(Icons.check) : const Icon(Icons.chevron_right),
                            onTap: () => canSelect ? widget.onSelectFilter(c.id) : widget.onOpenCommunity(c.id),
                            onLongPress: canSelect ? () => widget.onOpenCommunity(c.id) : null,
                          );
                        },
                      ),
              ),
            ),
          ],
        ),
      ),
    );
  }
}

class _CreateCommunitySheet extends StatefulWidget {
