}

class _CreateCommunitySheetState extends State<_CreateCommunitySheet> {
  final _name = TextEditingController();
  final _description = TextEditingController();
  final _imageUrl = TextEditingController();
  final _locationPath = TextEditingController();

  var _type = 'church';
  var _visibility = 'public';
  var _joinMode = 'request';
  var _loading = false;

  @override
  void dispose() {
    _name.dispose();
    _description.dispose();
    _imageUrl.dispose();
    _locationPath.dispose();
    super.dispose();
  }

  bool get _valid => _name.text.trim().isNotEmpty;

  @override
  Widget build(BuildContext context) {
    return SafeArea(
      child: Padding(
        padding: EdgeInsets.only(
          left: 16,
          right: 16,
          top: 4,
          bottom: 16 + MediaQuery.viewInsetsOf(context).bottom,
        ),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            Text(t(context).communityCreateTitle, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 18)),
            const SizedBox(height: 12),
            AtalaiaTextField(
              controller: _name,
              labelText: t(context).communityCreateNameLabel,
              hintText: t(context).communityCreateNameHint,
              textInputAction: TextInputAction.next,
              onChanged: (_) => setState(() {}),
            ),
            const SizedBox(height: 10),
            AtalaiaTextField(
              controller: _description,
              labelText: t(context).communityDescription,
              hintText: t(context).communityCreateDescriptionHint,
              maxLines: 4,
              minLines: 2,
              textInputAction: TextInputAction.newline,
            ),
            const SizedBox(height: 10),
            AtalaiaTextField(
              controller: _locationPath,
              labelText: t(context).communityCreateLocationPathLabel,
              hintText: t(context).communityCreateLocationPathHint,
              textInputAction: TextInputAction.next,
            ),
            const SizedBox(height: 10),
            AtalaiaTextField(
              controller: _imageUrl,
              labelText: t(context).communityCreateImageUrlLabel,
              hintText: t(context).communityCreateImageUrlHint,
              textInputAction: TextInputAction.done,
            ),
            const SizedBox(height: 10),
            Row(
              children: [
                Expanded(
                  child: DropdownButtonFormField<String>(
                    initialValue: _joinMode,
                    items: [
                      DropdownMenuItem(value: 'public', child: Text(t(context).communityCreateJoinModePublic)),
                      DropdownMenuItem(value: 'request', child: Text(t(context).communityCreateJoinModeRequest)),
                      DropdownMenuItem(value: 'invite', child: Text(t(context).communityCreateJoinModeInvite)),
                    ],
                    onChanged: _loading ? null : (v) => setState(() => _joinMode = v ?? 'request'),
                    decoration: InputDecoration(labelText: t(context).communityCreateJoinModeLabel),
                  ),
                ),
                const SizedBox(width: 10),
                Expanded(
                  child: DropdownButtonFormField<String>(
                    initialValue: _visibility,
                    items: [
                      DropdownMenuItem(value: 'public', child: Text(t(context).communityCreateVisibilityPublic)),
                      DropdownMenuItem(value: 'private', child: Text(t(context).communityCreateVisibilityPrivate)),
                      DropdownMenuItem(value: 'unlisted', child: Text(t(context).communityCreateVisibilityUnlisted)),
                    ],
                    onChanged: _loading ? null : (v) => setState(() => _visibility = v ?? 'public'),
                    decoration: InputDecoration(labelText: t(context).communityPrivacyLabel),
                  ),
                ),
              ],
            ),
            const SizedBox(height: 10),
            DropdownButtonFormField<String>(
              initialValue: _type,
              items: [
                DropdownMenuItem(value: 'church', child: Text(t(context).communityCreateTypeChurch)),
                DropdownMenuItem(value: 'ministry', child: Text(t(context).communityCreateTypeMinistry)),
                DropdownMenuItem(value: 'prayer', child: Text(t(context).communityCreateTypePrayer)),
              ],
              onChanged: _loading ? null : (v) => setState(() => _type = v ?? 'church'),
              decoration: InputDecoration(labelText: t(context).communityCreateTypeLabel),
            ),
            const SizedBox(height: 14),
            PrimaryButton(
              label: t(context).commonCreate,
              loading: _loading,
              onPressed: _loading || !_valid
                  ? null
                  : () async {
                      if (widget.repo.isOffline) {
                        showErrorSnackBar(context, onRetry: () {});
                        return;
                      }
                      setState(() => _loading = true);
                      final id = await widget.repo.createCommunity(
                        session: widget.session,
                        name: _name.text,
                        description: _description.text,
                        imageUrl: _imageUrl.text.trim().isEmpty ? null : _imageUrl.text.trim(),
                        locationPath: _locationPath.text.trim().isEmpty ? null : _locationPath.text.trim(),
                        type: _type,
                        visibility: _visibility,
                        joinMode: _joinMode,
                      );
                      if (!mounted) return;
                      setState(() => _loading = false);
                      if (id == null) {
                        showErrorSnackBar(context, onRetry: () {});
                        return;
                      }
                      Navigator.of(context).pop(id);
                    },
            ),
          ],
        ),
      ),
    );
  }
}

class _CityPinMarker extends StatefulWidget {
  const _CityPinMarker({required this.label, required this.hasStory});

  final String label;
  final bool hasStory;

  @override
  State<_CityPinMarker> createState() => _CityPinMarkerState();
}

class _CityPinMarkerState extends State<_CityPinMarker> with SingleTickerProviderStateMixin {
  AnimationController? _controller;

  @override
  void initState() {
    super.initState();
    _syncAnimation();
  }

  @override
  void didUpdateWidget(covariant _CityPinMarker oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (oldWidget.hasStory != widget.hasStory) _syncAnimation();
  }

  void _syncAnimation() {
    if (widget.hasStory) {
      _controller ??= AnimationController(vsync: this, duration: const Duration(milliseconds: 1500))..repeat();
    } else {
      _controller?.stop();
    }
  }

  @override
  void dispose() {
    _controller?.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    const green = Color(0xFF2E7D32);
    final ringColor = cs.brightness == Brightness.dark ? green.withValues(alpha: 0.95) : green;

    final ring = _controller == null
        ? const SizedBox.shrink()
        : AnimatedBuilder(
            animation: _controller!,
            builder: (context, _) {
              final t1 = _controller!.value;
              final t2 = (_controller!.value + 0.5) % 1.0;
              Widget wave(double t) {
                final scale = 1.0 + (t * 0.38);
                final opacity = (1.0 - t).clamp(0.0, 1.0);
                return Transform.scale(
                  scale: scale,
                  child: Container(
                    width: 44,
                    height: 44,
                    decoration: BoxDecoration(
                      shape: BoxShape.circle,
                      border: Border.all(
                        color: ringColor.withValues(alpha: (0.70 * opacity).clamp(0.0, 0.70)),
                        width: 2,
                      ),
                    ),
                  ),
                );
              }

              return Stack(
                alignment: Alignment.center,
                children: [wave(t1), wave(t2)],
              );
            },
          );

    final badgeText = widget.label.trim();
    final showBadge = badgeText.isNotEmpty && badgeText != '•';

    return SizedBox(
      width: 72,
      height: 72,
      child: Stack(
        alignment: Alignment.center,
        children: [
          if (widget.hasStory) ring,
          const Icon(Icons.location_on, size: 42, color: green),
          if (showBadge)
            Positioned(
              bottom: 6,
              child: DecoratedBox(
                decoration: BoxDecoration(
                  color: cs.surface.withValues(alpha: 0.92),
                  borderRadius: BorderRadius.circular(999),
                  boxShadow: const [
                    BoxShadow(color: Colors.black26, blurRadius: 8, offset: Offset(0, 2)),
                  ],
                ),
                child: Padding(
                  padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 3),
                  child: Text(
                    badgeText,
                    style: TextStyle(
                      color: cs.onSurface,
                      fontWeight: FontWeight.w900,
                      fontSize: 12,
                      height: 1.0,
                    ),
                  ),
                ),
              ),
            ),
        ],
      ),
    );
  }
}

