class CommunityFeedScreen extends StatefulWidget {
  const CommunityFeedScreen({required this.args, super.key});

  final CommunityFeedArgs args;

  @override
  State<CommunityFeedScreen> createState() => _CommunityFeedScreenState();
}

class _CommunityFeedScreenState extends State<CommunityFeedScreen> {
  late bool _onlyRequests;
  final _scrollController = ScrollController();
  var _loading = true;
  var _loadingMore = false;
  var _hasMore = true;
  DateTime? _cursorCreatedAt;
  List<PostModel> _remotePosts = const [];

  @override
  void initState() {
    super.initState();
    _onlyRequests = widget.args.initialOnlyRequests;
    _scrollController.addListener(_maybeLoadMore);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_loadInitial());
    });
  }

  @override
  void dispose() {
    _scrollController.dispose();
    super.dispose();
  }

  PostKind? get _kindFilter => _onlyRequests ? PostKind.request : null;

  void _maybeLoadMore() {
    if (!_hasMore || _loading || _loadingMore) return;
    if (!_scrollController.hasClients) return;
    final pos = _scrollController.position;
    if (pos.maxScrollExtent <= 0) return;
    if (pos.pixels < pos.maxScrollExtent - 320) return;
    unawaited(_loadMore());
  }

  Future<void> _loadInitial() async {
    if (!mounted) return;
    setState(() {
      _loading = true;
      _loadingMore = false;
      _hasMore = true;
      _cursorCreatedAt = null;
      _remotePosts = const [];
    });

    final repo = RepoScope.of(context);
    final useRemote = repo.supabase != null && !repo.isOffline;
    if (!useRemote) {
      if (!mounted) return;
      setState(() => _loading = false);
      return;
    }

    final items = await repo.fetchCommunityFeedPosts(
      widget.args.communityId,
      limit: 24,
      kind: _kindFilter,
    );
    if (!mounted) return;
    setState(() {
      _loading = false;
      _remotePosts = items;
      _cursorCreatedAt = items.isEmpty ? null : items.last.createdAt;
      _hasMore = items.length >= 24;
    });
  }

  Future<void> _loadMore() async {
    final repo = RepoScope.of(context);
    final useRemote = repo.supabase != null && !repo.isOffline;
    if (!useRemote) return;
    final cursor = _cursorCreatedAt;
    if (cursor == null) {
      setState(() => _hasMore = false);
      return;
    }
    setState(() => _loadingMore = true);
    final items = await repo.fetchCommunityFeedPosts(
      widget.args.communityId,
      cursorCreatedAt: cursor,
      limit: 24,
      kind: _kindFilter,
    );
    if (!mounted) return;
    final existingIds = _remotePosts.map((p) => p.id).toSet();
    final next = [..._remotePosts, ...items.where((p) => !existingIds.contains(p.id))];
    setState(() {
      _loadingMore = false;
      _remotePosts = List.unmodifiable(next);
      _cursorCreatedAt = items.isEmpty ? _cursorCreatedAt : items.last.createdAt;
      _hasMore = items.length >= 24;
    });
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final l10n = t(context);
        final s = session.value;
        final c = repo.findCommunity(widget.args.communityId);
        if (c == null) {
          return Scaffold(
            appBar: AppBar(title: Text(l10n.communityFeedTitle)),
            body: Center(child: Text(l10n.communityNotFound)),
          );
        }

        if (s is! AuthSession) {
          return Scaffold(
            appBar: AppBar(title: Text(c.name)),
            body: Center(
              child: PrimaryButton(
                label: l10n.communitySignInToSeeFeed,
                onPressed: () => showLoginSnackBar(context, message: l10n.communitySignInToSeeFeed),
              ),
            ),
          );
        }

        if (c.isClosed && c.viewerStatus != CommunityViewerStatus.approved) {
          final title = c.viewerStatus == CommunityViewerStatus.pending
              ? l10n.communityRequestSent
              : l10n.communityMembersOnlyFeed;
          final ctaLabel = c.viewerStatus == CommunityViewerStatus.pending ? null : l10n.communityRequestEntry;
          return Scaffold(
            appBar: AppBar(title: Text(c.name)),
            body: ListView(
              physics: const AlwaysScrollableScrollPhysics(),
              children: [
                SizedBox(height: MediaQuery.sizeOf(context).height * 0.18),
                EmptyState(
                  icon: Icons.lock_outline,
                  title: title,
                  ctaLabel: ctaLabel,
                  onCta: ctaLabel == null
                      ? null
                      : () {
                          if (repo.isOffline) {
                            showErrorSnackBar(
                              context,
                              onRetry: () {
                                if (RepoScope.of(context).isOffline) return;
                                RepoScope.of(context).requestCommunityJoin(c.id, isAuthenticated: true);
                              showInfoSnackBar(context, l10n.communityRequestSent);
                              },
                            );
                            return;
                          }
                          RepoScope.of(context).requestCommunityJoin(c.id, isAuthenticated: true);
                        showInfoSnackBar(context, l10n.communityRequestSent);
                        },
                ),
              ],
            ),
          );
        }

        final useRemote = repo.supabase != null && !repo.isOffline;
        final all = useRemote ? _remotePosts : repo.postsForCommunity(s, c.id);
        final posts = useRemote
            ? all
            : (_onlyRequests ? all.where((p) => p.kind == PostKind.request).toList() : all);

        return Scaffold(
          appBar: AppBar(
            title: Text(c.name),
            actions: [
              if (c.viewerStatus == CommunityViewerStatus.approved)
                IconButton(
                  tooltip: l10n.communityCreatePost,
                  icon: const Icon(Icons.edit_outlined),
                  onPressed: repo.isOffline
                      ? null
                      : () {
                          Navigator.of(context).push(
                            MaterialPageRoute<void>(
                              builder: (_) => PostComposerScreen(draft: ComposerDraft(initialCommunityId: c.id)),
                            ),
                          );
                        },
                ),
            ],
          ),
          body: Column(
            children: [
              if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
              Padding(
                padding: const EdgeInsets.fromLTRB(
                  AtalaiaSpacing.md,
                  AtalaiaSpacing.sm,
                  AtalaiaSpacing.md,
                  AtalaiaSpacing.sm,
                ),
                child: SizedBox.shrink(),
              ),
              Expanded(
                child: RefreshIndicator(
                  onRefresh: () async => _loadInitial(),
                  child: _loading
                      ? ListView.builder(
                          controller: _scrollController,
                          physics: const AlwaysScrollableScrollPhysics(),
                          itemCount: 6,
                          itemBuilder: (context, index) {
                            return PostCardSkeleton(
                              hasMedia: index.isEven,
                              margin: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
                            );
                          },
                        )
                      : posts.isEmpty
                          ? ListView(
                              controller: _scrollController,
                              physics: const AlwaysScrollableScrollPhysics(),
                              children: [
                                SizedBox(height: MediaQuery.sizeOf(context).height * 0.18),
                                EmptyState(
                                  icon: Icons.feed_outlined,
                                  title: l10n.communityNoPostsYet,
                                ),
                              ],
                            )
                          : ListView.builder(
                              controller: _scrollController,
                              padding: const EdgeInsets.only(top: 8, bottom: 8),
                              physics: const AlwaysScrollableScrollPhysics(),
                              itemCount: posts.length + (_loadingMore ? 1 : 0),
                              itemBuilder: (context, index) {
                                if (index >= posts.length) {
                                  return const Padding(
                                    padding: EdgeInsets.fromLTRB(12, 12, 12, 18),
                                    child: Center(child: CircularProgressIndicator()),
                                  );
                                }
                                final post = posts[index];
                                return PostCard(
                                  post: post,
                                  isAuthenticated: true,
                                  onOpenPost: () {
                                    Navigator.of(context).pushNamed(
                                      Routes.postDetail,
                                      arguments: PostDetailArgs(postId: post.id),
                                    );
                                  },
                                  onLike: () {
                                    if (!useRemote) {
                                      repo.toggleLike(post.id, isAuthenticated: true);
                                      return;
                                    }
                                    final idx = _remotePosts.indexWhere((p) => p.id == post.id);
                                    if (idx < 0) return;
                                    final p = _remotePosts[idx];
                                    final nextLiked = !p.viewerHasLiked;
                                    if (nextLiked) {
                                      repo.trackEvent('like_add', <String, Object?>{
                                        'postId': p.id,
                                        'kind': p.kind.analyticsValue,
                                        'visibility': p.visibility.analyticsValue,
                                      });
                                    }
                                    final list = _remotePosts.toList(growable: true);
                                    list[idx] = p.copyWith(
                                      viewerHasLiked: nextLiked,
                                      likeCount: nextLiked ? p.likeCount + 1 : (p.likeCount - 1).clamp(0, 1 << 30),
                                    );
                                    setState(() => _remotePosts = List.unmodifiable(list));
                                    unawaited(repo.setLikeOnPostSupabase(postId: p.id, shouldLike: nextLiked));
                                  },
                                  onPray: () {
                                    if (!useRemote) {
                                      repo.togglePrayer(post.id, isAuthenticated: true);
                                      showInfoSnackBar(context, t(context).prayerRegisteredSnack);
                                      return;
                                    }
                                    final idx = _remotePosts.indexWhere((p) => p.id == post.id);
                                    if (idx < 0) return;
                                    final p = _remotePosts[idx];
                                    if (p.viewerHasPrayed) return;
                                    repo.trackEvent('prayer_add', <String, Object?>{
                                      'postId': p.id,
                                      'kind': p.kind.analyticsValue,
                                      'visibility': p.visibility.analyticsValue,
                                    });
                                    final list = _remotePosts.toList(growable: true);
                                    list[idx] = p.copyWith(viewerHasPrayed: true, prayerCount: p.prayerCount + 1);
                                    setState(() => _remotePosts = List.unmodifiable(list));
                                    unawaited(repo.addPrayerOnPostSupabase(postId: p.id));
                                    showInfoSnackBar(context, t(context).prayerRegisteredSnack);
                                  },
                                  onComment: () {
                                    Navigator.of(context).pushNamed(
                                      Routes.postComments,
                                      arguments: CommentsArgs(postId: post.id),
                                    );
                                  },
                                  onShare: () async {
                                    await showShareSheet(context, post: post, isAuthenticated: true);
                                  },
                                  onSave: () {
                                    if (!useRemote) {
                                      final willSave = !post.viewerHasSaved;
                                      repo.toggleSave(post.id, isAuthenticated: true);
                                      if (willSave) showInfoSnackBar(context, t(context).commonSaved);
                                      return;
                                    }
                                    final idx = _remotePosts.indexWhere((p) => p.id == post.id);
                                    if (idx < 0) return;
                                    final p = _remotePosts[idx];
                                    final list = _remotePosts.toList(growable: true);
                                    list[idx] = p.copyWith(viewerHasSaved: !p.viewerHasSaved);
                                    setState(() => _remotePosts = List.unmodifiable(list));
                                    if (!p.viewerHasSaved) showInfoSnackBar(context, t(context).commonSaved);
                                  },
                                );
                              },
                            ),
                ),
              ),
            ],
          ),
        );
      },
    );
  }
}

class CommunityMembersScreen extends StatefulWidget {
  const CommunityMembersScreen({required this.args, super.key});

  final CommunityMembersArgs args;

  @override
  State<CommunityMembersScreen> createState() => _CommunityMembersScreenState();
}

class _CommunityMembersScreenState extends State<CommunityMembersScreen> {
  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      final repo = RepoScope.of(context);
      if (repo.supabase == null || repo.isOffline) return;
      unawaited(repo.refreshCommunityMembers(widget.args.communityId, force: true));
      final s = SessionScope.of(context).value;
      if (s is! AuthSession) return;
      if (repo.canModerateCommunity(widget.args.communityId, s.userId)) {
        unawaited(repo.refreshCommunityJoinRequests(widget.args.communityId, force: true));
      }
    });
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final s = session.value;
        final c = repo.findCommunity(widget.args.communityId);
        if (c == null) {
          return Scaffold(
            appBar: AppBar(title: Text(t(context).communityMembersTitle)),
            body: Center(child: Text(t(context).communityNotFound)),
          );
        }

        if (s is! AuthSession || c.viewerStatus != CommunityViewerStatus.approved) {
          return Scaffold(
            appBar: AppBar(title: Text(t(context).communityMembersTitle)),
            body: ListView(
              physics: const AlwaysScrollableScrollPhysics(),
              children: [
                SizedBox(height: MediaQuery.sizeOf(context).height * 0.18),
                EmptyState(icon: Icons.lock_outline, title: t(context).communityMembersOnly),
              ],
            ),
          );
        }

        final canModerate = repo.canModerateCommunity(c.id, s.userId);
        final canManageRoles = c.ownerId == s.userId;
        final showRequests = c.isClosed && canModerate;
        final members = repo.membersForCommunity(c.id);
        final requests = showRequests ? repo.joinRequestsForCommunity(c.id) : const <ProfileModel>[];

        return DefaultTabController(
          length: showRequests ? 2 : 1,
          child: Scaffold(
            appBar: AppBar(
              title: Text(c.name),
              bottom: TabBar(
                tabs: [
                  Tab(text: t(context).communityMembersTabMembers),
                  if (showRequests) Tab(text: t(context).communityMembersTabRequests(requests.length)),
                ],
              ),
            ),
            body: TabBarView(
              children: [
                members.isEmpty
                    ? EmptyState(icon: Icons.people_outline, title: t(context).communityMembersEmptyDemo)
                    : ListView.separated(
                        physics: const AlwaysScrollableScrollPhysics(),
                        itemCount: members.length,
                        separatorBuilder: (_, __) => const Divider(height: 1),
                        itemBuilder: (context, index) {
                          final p = members[index];
                          final displayName = _displayNameForProfile(p, userFallback: t(context).commonUserFallback);
                          final displayUsername = _usernameForProfile(p, userId: p.userId);
                          final isAdmin = repo.isCommunityAdmin(c.id, p.userId);
                          final isMod = repo.isCommunityModerator(c.id, p.userId);
                          final badge = isAdmin ? 'Admin' : (isMod ? 'Mod' : null);
                          return ListTile(
                            leading: Avatar(name: displayName, imageUrl: p.avatarUrl, size: AvatarSize.s44),
                            title: Row(
                              children: [
                                Flexible(
                                  child: Text(
                                    displayName,
                                    style: const TextStyle(fontWeight: FontWeight.w800),
                                    overflow: TextOverflow.ellipsis,
                                  ),
                                ),
                                if (p.isVerified) ...[
                                  const SizedBox(width: 6),
                                  Icon(Icons.verified, size: 18, color: context.brand.verifiedBlue),
                                ],
                                if (badge != null) ...[
                                  const SizedBox(width: 10),
                                  Chip(label: Text(badge), visualDensity: VisualDensity.compact),
                                ],
                              ],
                            ),
                            subtitle: Text('@$displayUsername'),
                            trailing: (!canManageRoles || p.userId == c.ownerId)
                                ? null
                                : PopupMenuButton<String>(
                                    itemBuilder: (context) {
                                      return <PopupMenuEntry<String>>[
                                        PopupMenuItem<String>(
                                          value: isMod ? 'demote' : 'promote',
                                          child: Text(
                                            isMod
                                                ? t(context).communityMemberActionDemoteToMember
                                                : t(context).communityMemberActionPromoteToAdmin,
                                          ),
                                        ),
                                        PopupMenuItem<String>(
                                          value: 'transfer',
                                          child: Text(t(context).communityMemberActionTransferOwnership),
                                        ),
                                      ];
                                    },
                                    onSelected: (action) async {
                                      if (repo.isOffline) {
                                        showErrorSnackBar(context, onRetry: () {});
                                        return;
                                      }
                                      if (action == 'promote') {
                                        await repo.setCommunityMemberRole(
                                          communityId: c.id,
                                          targetUserId: p.userId,
                                          role: 'admin',
                                        );
                                        if (!context.mounted) return;
                                        showInfoSnackBar(context, t(context).communityMemberPromotedSnack);
                                        return;
                                      }
                                      if (action == 'demote') {
                                        await repo.setCommunityMemberRole(
                                          communityId: c.id,
                                          targetUserId: p.userId,
                                          role: 'member',
                                        );
                                        if (!context.mounted) return;
                                        showInfoSnackBar(context, t(context).communityMemberDemotedSnack);
                                        return;
                                      }
                                      if (action == 'transfer') {
                                        final ok = await showDialog<bool>(
                                          context: context,
                                          builder: (ctx) => AlertDialog(
                                            title: Text(t(context).communityOwnershipTransferConfirmTitle),
                                            content: Text(t(context).communityOwnershipTransferConfirmBody(p.name)),
                                            actions: [
                                              TextButton(
                                                onPressed: () => Navigator.of(ctx).pop(false),
                                                child: Text(t(context).commonCancel),
                                              ),
                                              FilledButton(
                                                onPressed: () => Navigator.of(ctx).pop(true),
                                                child: Text(t(context).communityMemberActionTransferOwnership),
                                              ),
                                            ],
                                          ),
                                        );
                                        if (ok != true) return;
                                        await repo.transferCommunityOwnership(
                                          communityId: c.id,
                                          newOwnerId: p.userId,
                                        );
                                        if (!context.mounted) return;
                                        showInfoSnackBar(context, t(context).communityOwnershipTransferredSnack);
                                      }
                                    },
                                  ),
                            onTap: () {
                              Navigator.of(context).pushNamed(
                                Routes.userProfile,
                                arguments: UserProfileArgs(userId: p.userId),
                              );
                            },
                          );
                        },
                      ),
                if (showRequests)
                  requests.isEmpty
                      ? EmptyState(icon: Icons.inbox_outlined, title: t(context).communityRequestsEmpty)
                      : ListView.separated(
                          physics: const AlwaysScrollableScrollPhysics(),
                          itemCount: requests.length,
                          separatorBuilder: (_, __) => const Divider(height: 1),
                          itemBuilder: (context, index) {
                            final p = requests[index];
                            final displayName = _displayNameForProfile(p, userFallback: t(context).commonUserFallback);
                            final displayUsername = _usernameForProfile(p, userId: p.userId);
                            return ListTile(
                              leading: Avatar(name: displayName, imageUrl: p.avatarUrl, size: AvatarSize.s44),
                              title: Text(displayName, style: const TextStyle(fontWeight: FontWeight.w800)),
                              subtitle: Text('@$displayUsername'),
                              trailing: Wrap(
                                spacing: 8,
                                children: [
                                  SecondaryButton(
                                    label: t(context).communityRequestApproveAction,
                                    onPressed: () {
                                      if (repo.isOffline) {
                                        showErrorSnackBar(
                                          context,
                                          onRetry: () {
                                            if (RepoScope.of(context).isOffline) return;
                                            RepoScope.of(context).approveCommunityJoinRequest(c.id, p.userId);
                                            showInfoSnackBar(context, t(context).communityRequestApprovedSnack);
                                          },
                                        );
                                        return;
                                      }
                                      RepoScope.of(context).approveCommunityJoinRequest(c.id, p.userId);
                                      showInfoSnackBar(context, t(context).communityRequestApprovedSnack);
                                    },
                                  ),
                                  AtalaiaTextButton(
                                    label: t(context).communityRequestRejectAction,
                                    onPressed: () {
                                      if (repo.isOffline) {
                                        showErrorSnackBar(
                                          context,
                                          onRetry: () {
                                            if (RepoScope.of(context).isOffline) return;
                                            RepoScope.of(context).refuseCommunityJoinRequest(c.id, p.userId);
                                            showInfoSnackBar(context, t(context).communityRequestRejectedSnack);
                                          },
                                        );
                                        return;
                                      }
                                      RepoScope.of(context).refuseCommunityJoinRequest(c.id, p.userId);
                                      showInfoSnackBar(context, t(context).communityRequestRejectedSnack);
                                    },
                                  ),
                                ],
                              ),
                            );
                          },
                        ),
              ],
            ),
          ),
        );
      },
    );
  }
}

