class CommunityPrayerScalesScreen extends StatefulWidget {
  const CommunityPrayerScalesScreen({required this.args, super.key});

  final CommunityArgs args;

  @override
  State<CommunityPrayerScalesScreen> createState() => _CommunityPrayerScalesScreenState();
}

class _CommunityPrayerScalesScreenState extends State<CommunityPrayerScalesScreen> {
  var _loadingRuns = true;
  var _loadingReport = false;
  int _reportLoadToken = 0;
  Timer? _reportLoadingFailsafe;
  List<_CommunityPrayerRunRow> _runs = const [];
  int _dashTotalDurationSeconds = 0;
  int _dashTotalSessions = 0;
  int _dashTotalScalesCompleted = 0;
  int _dashTotalScalesMissed = 0;
  List<_CommunityPrayerMemberReportRow> _memberReport = const [];
  List<_CommunityPrayerOccurrenceReportRow> _occurrenceReport = const [];

  bool _isSameDay(DateTime a, DateTime b) => a.year == b.year && a.month == b.month && a.day == b.day;

  _CommunityPrayerRunRow? _nextRunForUser({required String userId}) {
    final now = DateTime.now();
    _CommunityPrayerRunRow? best;
    for (final r in _runs) {
      if ((r.assignedUserId ?? '').trim() != userId.trim()) continue;
      if (r.status == 'cancelled' || r.status == 'completed' || r.status == 'missed') continue;
      if (!r.endsAt.isAfter(now)) continue;
      final b = best;
      if (b == null || r.startsAt.isBefore(b.startsAt)) best = r;
    }
    return best;
  }

  ({List<_CommunityPrayerRunRow> today, List<_CommunityPrayerRunRow> upcoming, List<_CommunityPrayerRunRow> recent}) _groupRuns() {
    final now = DateTime.now();
    final today = <_CommunityPrayerRunRow>[];
    final upcoming = <_CommunityPrayerRunRow>[];
    final recent = <_CommunityPrayerRunRow>[];
    for (final r in _runs) {
      if (_isSameDay(r.startsAt, now)) {
        today.add(r);
        continue;
      }
      if (r.startsAt.isAfter(now)) {
        upcoming.add(r);
        continue;
      }
      recent.add(r);
    }
    recent.sort((a, b) => b.startsAt.compareTo(a.startsAt));
    return (today: List.unmodifiable(today), upcoming: List.unmodifiable(upcoming), recent: List.unmodifiable(recent));
  }

  String _weekdayLabel(int weekday) {
    return switch (weekday) {
      DateTime.monday => t(context).commonWeekdayMonday,
      DateTime.tuesday => t(context).commonWeekdayTuesday,
      DateTime.wednesday => t(context).commonWeekdayWednesday,
      DateTime.thursday => t(context).commonWeekdayThursday,
      DateTime.friday => t(context).commonWeekdayFriday,
      DateTime.saturday => t(context).commonWeekdaySaturday,
      _ => t(context).commonWeekdaySunday,
    };
  }

  String _formatShortTime(DateTime dt) {
    final two = (int v) => v.toString().padLeft(2, '0');
    return '${two(dt.hour)}:${two(dt.minute)}';
  }

  String _formatCompactDate(DateTime dt) {
    final two = (int v) => v.toString().padLeft(2, '0');
    return '${two(dt.day)}/${two(dt.month)}';
  }

  String _formatDateLine({required DateTime start, required DateTime end}) {
    return '${_formatCompactDate(start)} • ${_formatShortTime(start)} — ${_formatShortTime(end)}';
  }

  String _statusLabelForRun(_CommunityPrayerRunRow r) {
    final now = DateTime.now();
    final isActiveWindow = r.startsAt.isBefore(now) && r.endsAt.isAfter(now);
    if (r.status == 'cancelled') return t(context).prayerRunStatusCancelled;
    if (r.status == 'completed') return t(context).prayerRunStatusCompleted;
    if (r.status == 'missed') return t(context).prayerRunStatusMissed;
    if (isActiveWindow) return t(context).prayerRunStatusInProgress;
    return t(context).prayerRunStatusScheduled;
  }

  ({Color bg, Color fg, Color? border, Color stripe}) _statusColors({required ColorScheme cs, required _CommunityPrayerRunRow r, required bool isMine}) {
    final now = DateTime.now();
    final isActiveWindow = r.startsAt.isBefore(now) && r.endsAt.isAfter(now);
    final isSoon = r.startsAt.isAfter(now) && r.startsAt.difference(now) <= const Duration(minutes: 30);
    if (r.status == 'cancelled') return (bg: cs.surfaceContainerHighest, fg: cs.onSurfaceVariant, border: null, stripe: cs.outlineVariant);
    if (r.status == 'completed') return (bg: cs.primaryContainer, fg: cs.onPrimaryContainer, border: null, stripe: cs.primary);
    if (r.status == 'missed') return (bg: cs.errorContainer, fg: cs.onErrorContainer, border: null, stripe: cs.error);
    if (isMine && (isActiveWindow || isSoon)) return (bg: cs.tertiaryContainer, fg: cs.onTertiaryContainer, border: null, stripe: cs.tertiary);
    if (isActiveWindow) return (bg: cs.secondaryContainer, fg: cs.onSecondaryContainer, border: null, stripe: cs.secondary);
    return (bg: cs.surfaceContainerHighest, fg: cs.onSurface, border: cs.outlineVariant, stripe: cs.primary);
  }

  Future<void> _showRunDetailsSheet({
    required DemoRepository repo,
    required CommunityModel c,
    required _CommunityPrayerRunRow run,
    required ProfileModel? assigned,
    required bool canModerate,
    required String viewerUserId,
  }) async {
    final cs = Theme.of(context).colorScheme;
    final title = (run.title == null || run.title!.trim().isEmpty) ? t(context).prayerRunDefaultTitle : run.title!.trim();
    final displayName = assigned == null ? t(context).commonUserFallback : _profileDisplayLabel(assigned, userFallback: t(context).commonUserFallback);
    final isMine = (run.assignedUserId ?? '') == viewerUserId;
    final statusLabel = _statusLabelForRun(run);
    final statusColors = _statusColors(cs: cs, r: run, isMine: isMine);
    final whenLine = _formatDateLine(start: run.startsAt, end: run.endsAt);
    final durationMins = run.endsAt.difference(run.startsAt).inMinutes.clamp(1, 24 * 60);
    final canStart = run.status != 'completed' && run.status != 'cancelled';

    await showAtalaiaBottomSheet<void>(
      context,
      builder: (context) {
        return SafeArea(
          child: Padding(
            padding: EdgeInsets.only(
              left: 16,
              right: 16,
              top: 12,
              bottom: 16 + MediaQuery.viewInsetsOf(context).bottom,
            ),
            child: Column(
              mainAxisSize: MainAxisSize.min,
              crossAxisAlignment: CrossAxisAlignment.stretch,
              children: [
                Row(
                  children: [
                    Avatar(
                      name: assigned == null ? displayName : _normalizeDisplayUsername(assigned.username, fallback: assigned.userId),
                      imageUrl: assigned?.avatarUrl,
                      size: AvatarSize.s44,
                    ),
                    const SizedBox(width: 12),
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          Text(title, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 16)),
                          const SizedBox(height: 4),
                          Text(displayName, style: TextStyle(color: cs.onSurfaceVariant)),
                        ],
                      ),
                    ),
                    Container(
                      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
                      decoration: BoxDecoration(
                        color: statusColors.bg,
                        borderRadius: BorderRadius.circular(999),
                      ),
                      child: Text(statusLabel, style: TextStyle(color: statusColors.fg, fontWeight: FontWeight.w800)),
                    ),
                  ],
                ),
                const SizedBox(height: 14),
                Container(
                  padding: const EdgeInsets.all(12),
                  decoration: BoxDecoration(
                    color: cs.surfaceContainer,
                    borderRadius: BorderRadius.circular(14),
                    border: Border.all(color: cs.outlineVariant),
                  ),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Text(whenLine, style: const TextStyle(fontWeight: FontWeight.w900)),
                      const SizedBox(height: 6),
                      Text(t(context).prayerRunDetailsDurationLine(durationMins), style: TextStyle(color: cs.onSurfaceVariant)),
                      const SizedBox(height: 6),
                      Text(t(context).prayerRunDetailsCommunityLine(c.name), style: TextStyle(color: cs.onSurfaceVariant)),
                      if (canModerate) ...[
                        const SizedBox(height: 6),
                        Text(t(context).prayerRunDetailsIdLine(run.id), style: TextStyle(color: cs.onSurfaceVariant)),
                      ],
                    ],
                  ),
                ),
                const SizedBox(height: 14),
                PrimaryButton(
                  label: canStart ? t(context).prayerRunDetailsStartPrayer : t(context).commonClose,
                  onPressed: () {
                    Navigator.of(context).pop();
                    if (canStart) {
                      unawaited(_startPrayerFromRun(repo: repo, c: c, run: run));
                    }
                  },
                ),
              ],
            ),
          ),
        );
      },
    );
  }

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_loadRuns());
      final repo = RepoScope.of(context);
      final session = SessionScope.of(context).value;
      final c = repo.findCommunity(widget.args.communityId);
      if (c == null) return;
      if (session is! AuthSession) return;
      final canModerate = repo.canModerateCommunity(c.id, session.userId);
      if (canModerate) {
        unawaited(_loadReportIfAllowed(repo: repo, canModerate: canModerate));
      }
    });
  }

  @override
  void dispose() {
    _reportLoadingFailsafe?.cancel();
    super.dispose();
  }

  Future<void> _loadRuns() async {
    final repo = RepoScope.of(context);
    final sb = repo.supabase;
    if (sb == null) {
      if (!mounted) return;
      setState(() {
        _runs = const [];
        _loadingRuns = false;
      });
      return;
    }
    if (repo.isOffline) {
      if (!mounted) return;
      setState(() => _loadingRuns = false);
      return;
    }
    setState(() => _loadingRuns = true);
    final now = DateTime.now().toUtc();
    final from = now.subtract(const Duration(days: 7)).toIso8601String();
    final to = now.add(const Duration(days: 14)).toIso8601String();
    try {
      final rows = await sb
          .from('community_prayer_schedule_runs')
          .select('id,community_id,starts_at,ends_at,assigned_user_id,status,community_prayer_schedules(title)')
          .eq('community_id', widget.args.communityId)
          .gte('starts_at', from)
          .lte('starts_at', to)
          .order('starts_at', ascending: true)
          .limit(200);
      final list = <_CommunityPrayerRunRow>[];
      for (final raw in (rows as List<dynamic>)) {
        final r = raw as Map<String, dynamic>;
        final id = r['id']?.toString() ?? '';
        final communityId = r['community_id']?.toString() ?? '';
        if (id.isEmpty || communityId.isEmpty) continue;
        final startsAt = DateTime.tryParse(r['starts_at']?.toString() ?? '')?.toLocal();
        final endsAt = DateTime.tryParse(r['ends_at']?.toString() ?? '')?.toLocal();
        if (startsAt == null || endsAt == null) continue;
        final status = r['status']?.toString() ?? 'scheduled';
        final assignedUserId = r['assigned_user_id']?.toString();
        String? title;
        final schedule = r['community_prayer_schedules'];
        if (schedule is Map<String, dynamic>) {
          title = schedule['title']?.toString();
        }
        list.add(
          _CommunityPrayerRunRow(
            id: id,
            communityId: communityId,
            startsAt: startsAt,
            endsAt: endsAt,
            status: status,
            title: title,
            assignedUserId: assignedUserId,
          ),
        );
      }
      if (!mounted) return;
      setState(() {
        _runs = List.unmodifiable(list);
        _loadingRuns = false;
      });
    } catch (_) {
      if (!mounted) return;
      setState(() => _loadingRuns = false);
    }
  }

  Future<void> _loadReportIfAllowed({required DemoRepository repo, required bool canModerate}) async {
    if (!canModerate) return;
    final sb = repo.supabase;
    if (sb == null) return;
    if (repo.isOffline) return;
    if (_loadingReport) return;
    final token = ++_reportLoadToken;
    _reportLoadingFailsafe?.cancel();
    _reportLoadingFailsafe = Timer(const Duration(seconds: 25), () {
      if (!mounted) return;
      if (!_loadingReport) return;
      if (token != _reportLoadToken) return;
      setState(() => _loadingReport = false);
      showErrorSnackBar(
        context,
        message: 'Relatório demorou para responder. Tente novamente.',
        onRetry: () => unawaited(_loadReportIfAllowed(repo: repo, canModerate: canModerate)),
      );
    });
    setState(() => _loadingReport = true);
    final nowUtc = DateTime.now().toUtc();
    final todayUtc = DateTime.utc(nowUtc.year, nowUtc.month, nowUtc.day);
    final fromAllTime = DateTime.utc(2000, 1, 1);
    final occurrencesFrom = nowUtc.subtract(const Duration(days: 30));
    final occurrencesTo = nowUtc.add(const Duration(days: 14));
    try {
      const rpcTimeout = Duration(seconds: 20);
      final dashRows = await sb.rpc('get_community_prayer_dashboard', params: <String, Object?>{
        'p_community_id': widget.args.communityId,
        'p_from': '${fromAllTime.year}-${fromAllTime.month.toString().padLeft(2, '0')}-${fromAllTime.day.toString().padLeft(2, '0')}',
        'p_to': '${todayUtc.year}-${todayUtc.month.toString().padLeft(2, '0')}-${todayUtc.day.toString().padLeft(2, '0')}',
      }).timeout(rpcTimeout);

      int totalDurationSeconds = 0;
      int totalSessions = 0;
      int totalScalesCompleted = 0;
      int totalScalesMissed = 0;
      var membersRaw = const <dynamic>[];

      if (dashRows is List && dashRows.isNotEmpty) {
        final r = (dashRows.first as Map<String, dynamic>);
        totalDurationSeconds = (r['total_duration_seconds'] as num?)?.toInt() ?? 0;
        totalSessions = (r['total_sessions'] as num?)?.toInt() ?? 0;
        totalScalesCompleted = (r['total_scales_completed'] as num?)?.toInt() ?? 0;
        totalScalesMissed = (r['total_scales_missed'] as num?)?.toInt() ?? 0;
        final m = r['members'];
        if (m is List) {
          membersRaw = m;
        } else if (m is String) {
          final decoded = jsonDecode(m);
          if (decoded is List) membersRaw = decoded;
        }
      }

      final members = <_CommunityPrayerMemberReportRow>[];
      for (final raw in membersRaw) {
        if (raw is! Map<String, dynamic>) continue;
        final userId = raw['user_id']?.toString() ?? '';
        if (userId.isEmpty) continue;
        members.add(
          _CommunityPrayerMemberReportRow(
            userId: userId,
            name: raw['name']?.toString() ?? 'Usuário',
            totalDurationSeconds: (raw['total_duration_seconds'] as num?)?.toInt() ?? 0,
            totalSessions: (raw['total_sessions'] as num?)?.toInt() ?? 0,
            scalesCompleted: (raw['scales_completed'] as num?)?.toInt() ?? 0,
            scalesMissed: (raw['scales_missed'] as num?)?.toInt() ?? 0,
          ),
        );
      }

      final occurrenceRows = await sb.rpc('get_community_schedule_report', params: <String, Object?>{
        'p_community_id': widget.args.communityId,
        'p_from': occurrencesFrom.toIso8601String(),
        'p_to': occurrencesTo.toIso8601String(),
        'p_limit': 200,
        'p_offset': 0,
      }).timeout(rpcTimeout);

      final occurrences = <_CommunityPrayerOccurrenceReportRow>[];
      for (final raw in (occurrenceRows as List<dynamic>)) {
        final r = raw as Map<String, dynamic>;
        final runId = r['run_id']?.toString() ?? '';
        if (runId.isEmpty) continue;
        final scheduledStartAt = DateTime.tryParse(r['scheduled_start_at']?.toString() ?? '')?.toLocal();
        final scheduledEndAt = DateTime.tryParse(r['scheduled_end_at']?.toString() ?? '')?.toLocal();
        if (scheduledStartAt == null || scheduledEndAt == null) continue;
        occurrences.add(
          _CommunityPrayerOccurrenceReportRow(
            runId: runId,
            scheduledStartAt: scheduledStartAt,
            scheduledEndAt: scheduledEndAt,
            status: r['status']?.toString() ?? 'scheduled',
            plannedDurationSeconds: (r['planned_duration_seconds'] as num?)?.toInt() ?? 0,
            actualStartAt: DateTime.tryParse(r['actual_start_at']?.toString() ?? '')?.toLocal(),
            actualEndAt: DateTime.tryParse(r['actual_end_at']?.toString() ?? '')?.toLocal(),
            actualDurationSeconds: (r['actual_duration_seconds'] as num?)?.toInt(),
            prayerNote: r['prayer_note']?.toString(),
            assignedUserId: r['assigned_user_id']?.toString(),
            assignedUserName: r['assigned_user_name']?.toString(),
            scheduleTitle: r['schedule_title']?.toString(),
          ),
        );
      }

      if (!mounted) return;
      if (token != _reportLoadToken) return;
      _reportLoadingFailsafe?.cancel();
      setState(() {
        _dashTotalDurationSeconds = totalDurationSeconds;
        _dashTotalSessions = totalSessions;
        _dashTotalScalesCompleted = totalScalesCompleted;
        _dashTotalScalesMissed = totalScalesMissed;
        _memberReport = List.unmodifiable(members);
        _occurrenceReport = List.unmodifiable(occurrences);
        _loadingReport = false;
      });
    } catch (_) {
      if (!mounted) return;
      if (token != _reportLoadToken) return;
      _reportLoadingFailsafe?.cancel();
      setState(() => _loadingReport = false);
      showErrorSnackBar(
        context,
        message: 'Falha ao carregar relatório (pode haver lock/migration aberta no BD).',
        onRetry: () => unawaited(_loadReportIfAllowed(repo: repo, canModerate: canModerate)),
      );
    }
  }

  Future<void> _createRunSheet({required DemoRepository repo, required CommunityModel c}) async {
    final session = SessionScope.of(context).value;
    if (session is! AuthSession) return;
    final members = repo.membersForCommunity(c.id);
    final runId = await showAtalaiaBottomSheet<String?>(
      context,
      builder: (_) => _CreateCommunityPrayerRunSheet(
        repo: repo,
        community: c,
        members: members,
      ),
    );
    if (!mounted) return;
    if (runId == null) return;
    await _loadRuns();
  }

  Future<void> _startPrayerFromRun({required DemoRepository repo, required CommunityModel c, required _CommunityPrayerRunRow run}) async {
    if (repo.isOffline) {
      showErrorSnackBar(context, onRetry: () {});
      return;
    }
    var locationId = c.locationId;
    if (locationId == null || locationId.trim().isEmpty) {
      locationId = await repo.locationIdByPath('world');
    }
    if (locationId == null || locationId.trim().isEmpty) {
      if (!mounted) return;
      showInfoSnackBar(context, 'Local indisponível');
      return;
    }
    final meta = await repo.locationMetaById(locationId);
    if (!mounted) return;
    final locationName = meta?['name'] ?? 'Mundo';
    final locationLevel = meta?['level'] ?? 'world';
    final locationPath = meta?['path'] ?? 'world';
    Navigator.of(context).pushNamed(
      Routes.regionPrayer,
      arguments: RegionPrayerArgs(
        locationId: locationId,
        locationName: locationName,
        locationLevel: locationLevel,
        locationPath: locationPath,
        contextBreadcrumb: '${c.name} • Escala de oração',
        communityId: c.id,
        scheduleRunId: run.id,
      ),
    );
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final c = repo.findCommunity(widget.args.communityId);
        if (c == null) {
          return Scaffold(
            appBar: AppBar(title: Text(t(context).prayerRunsTitleShort)),
            body: Center(child: Text(t(context).communityNotFound)),
          );
        }
        final s = session.value;
        if (s is! AuthSession || c.viewerStatus != CommunityViewerStatus.approved) {
          return Scaffold(
            appBar: AppBar(title: Text(t(context).prayerRunsTitleShort)),
            body: ListView(
              physics: const AlwaysScrollableScrollPhysics(),
              children: [
                SizedBox(height: MediaQuery.sizeOf(context).height * 0.18),
                EmptyState(icon: Icons.lock_outline, title: t(context).prayerRunsMembersOnly),
              ],
            ),
          );
        }

        final canModerate = repo.canModerateCommunity(c.id, s.userId);
        final tabs = canModerate ? 3 : 2;

        return DefaultTabController(
          length: tabs,
          child: Scaffold(
            appBar: AppBar(
              title: Column(
                crossAxisAlignment: CrossAxisAlignment.start,
                children: [
                  Text(t(context).prayerRunsTitle, style: const TextStyle(fontWeight: FontWeight.w900)),
                  Text(
                    t(context).prayerRunsSubtitle,
                    style: TextStyle(fontSize: 12, color: Theme.of(context).colorScheme.onSurfaceVariant),
                  ),
                ],
              ),
              actions: [
                if (canModerate)
                  Padding(
                    padding: const EdgeInsets.only(right: 10),
                    child: Builder(
                      builder: (context) {
                        final w = MediaQuery.sizeOf(context).width;
                        final label = w >= 420 ? t(context).prayerRunsNew : null;
                        if (label == null) {
                          return IconButton(
                            icon: const Icon(Icons.add),
                            onPressed: repo.isOffline ? null : () => unawaited(_createRunSheet(repo: repo, c: c)),
                          );
                        }
                        return FilledButton.icon(
                          onPressed: repo.isOffline ? null : () => unawaited(_createRunSheet(repo: repo, c: c)),
                          icon: const Icon(Icons.add),
                          label: Text(label, style: const TextStyle(fontWeight: FontWeight.w800)),
                        );
                      },
                    ),
                  ),
              ],
              bottom: TabBar(
                tabs: [
                  Tab(text: t(context).prayerRunsTabSchedule),
                  Tab(text: t(context).prayerRunsTabMyShift),
                  if (canModerate) Tab(text: t(context).prayerRunsTabReport),
                ],
              ),
            ),
            body: TabBarView(
              children: [
                RefreshIndicator(
                  onRefresh: _loadRuns,
                  child: _loadingRuns
                      ? ListView(
                          physics: const AlwaysScrollableScrollPhysics(),
                          children: const [
                            SizedBox(height: 18),
                            Center(child: CircularProgressIndicator()),
                          ],
                        )
                      : _buildAgendaTab(repo: repo, c: c, viewerUserId: s.userId, canModerate: canModerate),
                ),
                RefreshIndicator(
                  onRefresh: _loadRuns,
                  child: _loadingRuns
                      ? ListView(
                          physics: const AlwaysScrollableScrollPhysics(),
                          children: const [
                            SizedBox(height: 18),
                            Center(child: CircularProgressIndicator()),
                          ],
                        )
                      : _buildMyTurnTab(repo: repo, c: c, viewerUserId: s.userId, canModerate: canModerate),
                ),
                if (canModerate)
                  RefreshIndicator(
                    onRefresh: () async {
                      setState(() {
                        _dashTotalDurationSeconds = 0;
                        _dashTotalSessions = 0;
                        _dashTotalScalesCompleted = 0;
                        _dashTotalScalesMissed = 0;
                        _memberReport = const [];
                        _occurrenceReport = const [];
                      });
                      await _loadReportIfAllowed(repo: repo, canModerate: canModerate);
                    },
                    child: _loadingReport
                        ? ListView(
                            physics: const AlwaysScrollableScrollPhysics(),
                            children: const [
                              SizedBox(height: 18),
                              Center(child: CircularProgressIndicator()),
                            ],
                          )
                        : _dashTotalSessions <= 0 && _memberReport.isEmpty && _occurrenceReport.isEmpty
                            ? ListView(
                                physics: const AlwaysScrollableScrollPhysics(),
                                children: [
                                  SizedBox(height: MediaQuery.sizeOf(context).height * 0.18),
                                  EmptyState(icon: Icons.bar_chart_outlined, title: t(context).prayerRunsReportEmpty),
                                ],
                              )
                            : ListView(
                                physics: const AlwaysScrollableScrollPhysics(),
                                padding: const EdgeInsets.fromLTRB(12, 12, 12, 12),
                                children: [
                                  Card(
                                    child: Padding(
                                      padding: const EdgeInsets.all(14),
                                      child: Column(
                                        crossAxisAlignment: CrossAxisAlignment.start,
                                        children: [
                                          Text(t(context).prayerRunsReportDashboardTitle, style: const TextStyle(fontWeight: FontWeight.w900)),
                                          const SizedBox(height: 10),
                                          Wrap(
                                            spacing: 10,
                                            runSpacing: 10,
                                            children: [
                                              _StatPill(
                                                label: t(context).prayerRunsReportPrayedTime,
                                                value: _formatTotalDuration(_dashTotalDurationSeconds),
                                                cs: Theme.of(context).colorScheme,
                                              ),
                                              _StatPill(
                                                label: t(context).prayerRunsReportSessions,
                                                value: _dashTotalSessions.toString(),
                                                cs: Theme.of(context).colorScheme,
                                              ),
                                              _StatPill(
                                                label: t(context).prayerRunsReportCompleted,
                                                value: _dashTotalScalesCompleted.toString(),
                                                cs: Theme.of(context).colorScheme,
                                              ),
                                              _StatPill(
                                                label: t(context).prayerRunsReportMissed,
                                                value: _dashTotalScalesMissed.toString(),
                                                cs: Theme.of(context).colorScheme,
                                              ),
                                            ],
                                          ),
                                        ],
                                      ),
                                    ),
                                  ),
                                  const SizedBox(height: 12),
                                  Text(t(context).prayerRunsReportByMember, style: const TextStyle(fontWeight: FontWeight.w900)),
                                  const SizedBox(height: 6),
                                  if (_memberReport.isEmpty)
                                    Text(t(context).prayerRunsReportEmptyByMember, style: TextStyle(color: Theme.of(context).colorScheme.outline))
                                  else
                                    ..._memberReport.map((m) {
                                      final minutes = (m.totalDurationSeconds / 60).floor();
                                      final subtitle = t(context).prayerRunsReportMemberSubtitle(
                                        minutes,
                                        m.totalSessions,
                                        m.scalesCompleted,
                                        m.scalesMissed,
                                      );
                                      return ListTile(
                                        contentPadding: EdgeInsets.zero,
                                        leading: Avatar(name: m.name, size: AvatarSize.s44),
                                        title: Text(m.name, style: const TextStyle(fontWeight: FontWeight.w800)),
                                        subtitle: Text(subtitle),
                                        onTap: () {
                                          Navigator.of(context).pushNamed(
                                            Routes.userProfile,
                                            arguments: UserProfileArgs(userId: m.userId),
                                          );
                                        },
                                      );
                                    }),
                                  const Divider(height: 24),
                                  Text(t(context).prayerRunsReportByOccurrence, style: const TextStyle(fontWeight: FontWeight.w900)),
                                  const SizedBox(height: 6),
                                  if (_occurrenceReport.isEmpty)
                                    Text(t(context).prayerRunsReportEmptyByOccurrence, style: TextStyle(color: Theme.of(context).colorScheme.outline))
                                  else
                                    ..._occurrenceReport.map((o) {
                                      final expected = '${_formatShortDateTime(o.scheduledStartAt)} – ${_formatShortDateTime(o.scheduledEndAt)}';
                                      final actual = (o.actualStartAt == null || o.actualEndAt == null)
                                          ? t(context).prayerRunsReportActualEmpty
                                          : t(context).prayerRunsReportActualRange(
                                              _formatShortDateTime(o.actualStartAt!),
                                              _formatShortDateTime(o.actualEndAt!),
                                            );
                                      final plannedMin = (o.plannedDurationSeconds / 60).floor();
                                      final actualMin = o.actualDurationSeconds == null ? null : (o.actualDurationSeconds! / 60).floor();
                                      final actualPart =
                                          actualMin == null ? '' : t(context).prayerRunsReportActualDurationPart(actualMin);
                                      final statusLabel = switch (o.status) {
                                        'completed' => t(context).prayerRunsReportStatusCompleted,
                                        'missed' => t(context).prayerRunsReportStatusMissed,
                                        'cancelled' => t(context).prayerRunsReportStatusCancelled,
                                        _ => t(context).prayerRunsReportStatusScheduled,
                                      };
                                      final parts = <String>[
                                        expected,
                                        actual,
                                        t(context).prayerRunsReportStatusLine(statusLabel, plannedMin, actualPart),
                                        if ((o.prayerNote ?? '').trim().isNotEmpty) t(context).prayerRunsReportNoteLine(o.prayerNote!.trim()),
                                        if ((o.assignedUserName ?? '').trim().isNotEmpty)
                                          t(context).prayerRunsReportAssigneeLine(o.assignedUserName!.trim()),
                                      ];
                                      return ListTile(
                                        contentPadding: EdgeInsets.zero,
                                        leading: const Icon(Icons.event_note_outlined),
                                        title: Text(
                                          (o.scheduleTitle == null || o.scheduleTitle!.trim().isEmpty)
                                              ? t(context).prayerRunDefaultTitle
                                              : o.scheduleTitle!.trim(),
                                          style: const TextStyle(fontWeight: FontWeight.w800),
                                        ),
                                        subtitle: Text(parts.join('\n')),
                                        isThreeLine: true,
                                      );
                                    }),
                                ],
                              ),
                  ),
              ],
            ),
          ),
        );
      },
    );
  }

  Widget _buildAgendaTab({
    required DemoRepository repo,
    required CommunityModel c,
    required String viewerUserId,
    required bool canModerate,
  }) {
    final cs = Theme.of(context).colorScheme;
    final groups = _groupRuns();
    final now = DateTime.now();
    final nextMine = _nextRunForUser(userId: viewerUserId);
    final completedCount = _runs.where((r) => r.status == 'completed').length;
    final todayCount = groups.today.length;
    final upcomingCount = groups.upcoming.length;

    final header = Padding(
      padding: const EdgeInsets.fromLTRB(16, 14, 16, 8),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Text(t(context).prayerRunsAgendaTitle, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 22)),
          const SizedBox(height: 6),
          Text(
            t(context).prayerRunsAgendaCommunityLine(c.name),
            style: TextStyle(color: cs.onSurfaceVariant, fontWeight: FontWeight.w700),
          ),
        ],
      ),
    );

    final summary = Padding(
      padding: const EdgeInsets.fromLTRB(12, 4, 12, 12),
      child: SingleChildScrollView(
        scrollDirection: Axis.horizontal,
        child: Row(
          children: [
            _SummaryCard(label: t(context).prayerRunsSummaryToday, value: todayCount.toString(), cs: cs),
            const SizedBox(width: 10),
            _SummaryCard(label: t(context).prayerRunsSummaryUpcoming, value: upcomingCount.toString(), cs: cs),
            const SizedBox(width: 10),
            _SummaryCard(label: t(context).prayerRunsSummaryCompleted, value: completedCount.toString(), cs: cs),
            if (canModerate && _dashTotalDurationSeconds > 0) ...[
              const SizedBox(width: 10),
              _SummaryCard(label: t(context).prayerRunsSummaryPrayedTime, value: _formatTotalDuration(_dashTotalDurationSeconds), cs: cs),
            ],
          ],
        ),
      ),
    );

    final children = <Widget>[header, summary];

    if (nextMine != null) {
      children.add(
        Padding(
          padding: const EdgeInsets.fromLTRB(12, 0, 12, 14),
          child: _HighlightRunCard(
            cs: cs,
            label: t(context).prayerRunsHighlightMyNextShift,
            title: (nextMine.title == null || nextMine.title!.trim().isEmpty) ? t(context).prayerRunDefaultTitle : nextMine.title!.trim(),
            subtitle: _formatDateLine(start: nextMine.startsAt, end: nextMine.endsAt),
            statusLabel: _statusLabelForRun(nextMine),
            stripeColor: _statusColors(cs: cs, r: nextMine, isMine: true).stripe,
            onTap: () {
              final assigned = nextMine.assignedUserId == null ? null : repo.findProfile(nextMine.assignedUserId!);
              unawaited(
                _showRunDetailsSheet(
                  repo: repo,
                  c: c,
                  run: nextMine,
                  assigned: assigned,
                  canModerate: canModerate,
                  viewerUserId: viewerUserId,
                ),
              );
            },
          ),
        ),
      );
    }

    if (_runs.isEmpty) {
      children.add(
        Padding(
          padding: EdgeInsets.only(top: MediaQuery.sizeOf(context).height * 0.12),
          child: EmptyState(icon: Icons.event_outlined, title: t(context).prayerRunsEmptyNoSchedules),
        ),
      );
      return ListView(
        physics: const AlwaysScrollableScrollPhysics(),
        children: children,
      );
    }

    void addSection(String title, List<_CommunityPrayerRunRow> runs, {bool compact = false}) {
      if (runs.isEmpty) return;
      children.add(_SectionHeader(title: title));
      children.add(
        Padding(
          padding: const EdgeInsets.fromLTRB(12, 0, 12, 14),
          child: Column(
            children: [
              for (final r in runs)
                Padding(
                  padding: const EdgeInsets.only(bottom: 10),
                  child: _PrayerRunSocialCard(
                    cs: cs,
                    run: r,
                    viewerUserId: viewerUserId,
                    assigned: r.assignedUserId == null ? null : repo.findProfile(r.assignedUserId!),
                    title: (r.title == null || r.title!.trim().isEmpty) ? t(context).prayerRunDefaultTitle : r.title!.trim(),
                    badgeLabel: _isSameDay(r.startsAt, now) ? t(context).prayerRunsSummaryToday : _weekdayLabel(r.startsAt.weekday),
                    whenLine: _formatDateLine(start: r.startsAt, end: r.endsAt),
                    statusLabel: _statusLabelForRun(r),
                    statusColors: _statusColors(cs: cs, r: r, isMine: (r.assignedUserId ?? '') == viewerUserId),
                    compact: compact,
                    onDetails: () {
                      unawaited(
                        _showRunDetailsSheet(
                          repo: repo,
                          c: c,
                          run: r,
                          assigned: r.assignedUserId == null ? null : repo.findProfile(r.assignedUserId!),
                          canModerate: canModerate,
                          viewerUserId: viewerUserId,
                        ),
                      );
                    },
                    onStart: () => unawaited(_startPrayerFromRun(repo: repo, c: c, run: r)),
                  ),
                ),
            ],
          ),
        ),
      );
    }

    addSection(t(context).prayerRunsSummaryToday, groups.today);
    addSection(t(context).prayerRunsSummaryUpcoming, groups.upcoming);
    addSection(t(context).prayerRunsSectionRecentHistory, groups.recent.take(6).toList(growable: false), compact: true);

    return ListView(
      physics: const AlwaysScrollableScrollPhysics(),
      children: children,
    );
  }

  Widget _buildMyTurnTab({
    required DemoRepository repo,
    required CommunityModel c,
    required String viewerUserId,
    required bool canModerate,
  }) {
    final cs = Theme.of(context).colorScheme;
    final mine = _runs.where((r) => (r.assignedUserId ?? '') == viewerUserId).toList();
    mine.sort((a, b) => a.startsAt.compareTo(b.startsAt));
    final now = DateTime.now();
    final next = _nextRunForUser(userId: viewerUserId);
    final upcoming = mine.where((r) => r.endsAt.isAfter(now) && r.status != 'cancelled').toList();
    final recent = mine.where((r) => r.startsAt.isBefore(now)).toList()..sort((a, b) => b.startsAt.compareTo(a.startsAt));

    final children = <Widget>[
      Padding(
        padding: EdgeInsets.fromLTRB(16, 14, 16, 8),
        child: Text(t(context).prayerRunsTabMyShift, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 22)),
      ),
      Padding(
        padding: const EdgeInsets.fromLTRB(16, 0, 16, 12),
        child: Text(
          t(context).prayerRunsMyShiftSubtitle,
          style: TextStyle(color: cs.onSurfaceVariant, fontWeight: FontWeight.w700),
        ),
      ),
    ];

    if (mine.isEmpty) {
      children.add(
        Padding(
          padding: EdgeInsets.only(top: MediaQuery.sizeOf(context).height * 0.12),
          child: EmptyState(icon: Icons.person_outline, title: t(context).prayerRunsMyShiftEmptyAssigned),
        ),
      );
      return ListView(physics: const AlwaysScrollableScrollPhysics(), children: children);
    }

    if (next != null) {
      children.add(
        Padding(
          padding: const EdgeInsets.fromLTRB(12, 0, 12, 14),
          child: _HighlightRunCard(
            cs: cs,
            label: t(context).prayerRunsHighlightMyNextShift,
            title: (next.title == null || next.title!.trim().isEmpty) ? t(context).prayerRunDefaultTitle : next.title!.trim(),
            subtitle: _formatDateLine(start: next.startsAt, end: next.endsAt),
            statusLabel: _statusLabelForRun(next),
            stripeColor: _statusColors(cs: cs, r: next, isMine: true).stripe,
            onTap: () {
              unawaited(
                _showRunDetailsSheet(
                  repo: repo,
                  c: c,
                  run: next,
                  assigned: next.assignedUserId == null ? null : repo.findProfile(next.assignedUserId!),
                  canModerate: canModerate,
                  viewerUserId: viewerUserId,
                ),
              );
            },
          ),
        ),
      );
    }

    void addSection(String title, List<_CommunityPrayerRunRow> runs, {bool compact = false}) {
      if (runs.isEmpty) return;
      children.add(_SectionHeader(title: title));
      children.add(
        Padding(
          padding: const EdgeInsets.fromLTRB(12, 0, 12, 14),
          child: Column(
            children: [
              for (final r in runs)
                Padding(
                  padding: const EdgeInsets.only(bottom: 10),
                  child: _PrayerRunSocialCard(
                    cs: cs,
                    run: r,
                    viewerUserId: viewerUserId,
                    assigned: r.assignedUserId == null ? null : repo.findProfile(r.assignedUserId!),
                    title: (r.title == null || r.title!.trim().isEmpty) ? t(context).prayerRunDefaultTitle : r.title!.trim(),
                    badgeLabel: _isSameDay(r.startsAt, now) ? t(context).prayerRunsSummaryToday : _weekdayLabel(r.startsAt.weekday),
                    whenLine: _formatDateLine(start: r.startsAt, end: r.endsAt),
                    statusLabel: _statusLabelForRun(r),
                    statusColors: _statusColors(cs: cs, r: r, isMine: true),
                    compact: compact,
                    onDetails: () {
                      unawaited(
                        _showRunDetailsSheet(
                          repo: repo,
                          c: c,
                          run: r,
                          assigned: r.assignedUserId == null ? null : repo.findProfile(r.assignedUserId!),
                          canModerate: canModerate,
                          viewerUserId: viewerUserId,
                        ),
                      );
                    },
                    onStart: () => unawaited(_startPrayerFromRun(repo: repo, c: c, run: r)),
                  ),
                ),
            ],
          ),
        ),
      );
    }

    addSection(t(context).prayerRunsSectionUpcomingMyShift, upcoming);
    addSection(t(context).prayerRunsSectionRecentHistory, recent.take(8).toList(growable: false), compact: true);

    return ListView(
      physics: const AlwaysScrollableScrollPhysics(),
      children: children,
    );
  }

  String _formatShortDateTime(DateTime dt) {
    final two = (int v) => v.toString().padLeft(2, '0');
    return '${two(dt.day)}/${two(dt.month)}/${dt.year} ${two(dt.hour)}:${two(dt.minute)}';
  }

  String _formatTotalDuration(int seconds) {
    final s = seconds.clamp(0, 1 << 30);
    final h = (s / 3600).floor();
    final m = ((s % 3600) / 60).floor();
    if (h <= 0) return '${m}m';
    if (m <= 0) return '${h}h';
    return '${h}h ${m}m';
  }
}

