class _PrayerRunSocialCard extends StatelessWidget {
  const _PrayerRunSocialCard({
    required this.cs,
    required this.run,
    required this.viewerUserId,
    required this.assigned,
    required this.title,
    required this.badgeLabel,
    required this.whenLine,
    required this.statusLabel,
    required this.statusColors,
    required this.onDetails,
    required this.onStart,
    this.compact = false,
  });

  final ColorScheme cs;
  final _CommunityPrayerRunRow run;
  final String viewerUserId;
  final ProfileModel? assigned;
  final String title;
  final String badgeLabel;
  final String whenLine;
  final String statusLabel;
  final ({Color bg, Color fg, Color? border, Color stripe}) statusColors;
  final VoidCallback onDetails;
  final VoidCallback onStart;
  final bool compact;

  @override
  Widget build(BuildContext context) {
    final assignedProfile = assigned;
    final displayName = assignedProfile == null ? t(context).commonUserFallback : _profileDisplayLabel(assignedProfile, userFallback: t(context).commonUserFallback);
    final avatarName =
        assignedProfile == null ? displayName : _normalizeDisplayUsername(assignedProfile.username, fallback: assignedProfile.userId);
    final durationMins = run.endsAt.difference(run.startsAt).inMinutes.clamp(1, 24 * 60);
    final isMine = (run.assignedUserId ?? '') == viewerUserId;
    final now = DateTime.now();
    final isActiveWindow = run.startsAt.isBefore(now) && run.endsAt.isAfter(now);
    final isSoon = run.startsAt.isAfter(now) && run.startsAt.difference(now) <= const Duration(minutes: 30);
    final canStart = (run.status != 'completed' && run.status != 'cancelled') && (isActiveWindow || isSoon);

    final badge = Container(
      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
      decoration: BoxDecoration(
        color: cs.surfaceContainerHighest,
        borderRadius: BorderRadius.circular(999),
        border: Border.all(color: cs.outlineVariant),
      ),
      child: Text(badgeLabel, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 12)),
    );

    final durationChip = Container(
      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
      decoration: BoxDecoration(
        color: cs.surfaceContainerHighest,
        borderRadius: BorderRadius.circular(999),
        border: Border.all(color: cs.outlineVariant),
      ),
      child: Text('${durationMins} min', style: TextStyle(fontWeight: FontWeight.w900, fontSize: 12, color: cs.onSurfaceVariant)),
    );

    final statusPill = Container(
      padding: const EdgeInsets.symmetric(horizontal: 10, vertical: 6),
      decoration: BoxDecoration(
        color: statusColors.bg,
        borderRadius: BorderRadius.circular(999),
        border: statusColors.border == null ? null : Border.all(color: statusColors.border!),
      ),
      child: Text(statusLabel, style: TextStyle(fontWeight: FontWeight.w900, fontSize: 12, color: statusColors.fg)),
    );

    return Material(
      color: cs.surfaceContainer,
      borderRadius: BorderRadius.circular(18),
      child: InkWell(
        borderRadius: BorderRadius.circular(18),
        onTap: onDetails,
        child: Container(
          decoration: BoxDecoration(
            borderRadius: BorderRadius.circular(18),
            border: Border.all(color: cs.outlineVariant),
          ),
          child: Row(
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Container(
                width: 6,
                height: compact ? 122 : 146,
                decoration: BoxDecoration(
                  color: statusColors.stripe,
                  borderRadius: const BorderRadius.horizontal(left: Radius.circular(18)),
                ),
              ),
              Expanded(
                child: Padding(
                  padding: EdgeInsets.fromLTRB(12, compact ? 10 : 12, 12, compact ? 10 : 12),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      Row(
                        children: [
                          Avatar(
                            name: avatarName,
                            imageUrl: assigned?.avatarUrl,
                            size: compact ? AvatarSize.s32 : AvatarSize.s44,
                          ),
                          const SizedBox(width: 10),
                          Expanded(
                            child: Column(
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                                Text(
                                  displayName,
                                  maxLines: 1,
                                  overflow: TextOverflow.ellipsis,
                                  style: const TextStyle(fontWeight: FontWeight.w900),
                                ),
                                const SizedBox(height: 2),
                                Text(
                                  isMine ? 'Seu turno' : 'Turno da comunidade',
                                  style: TextStyle(color: cs.onSurfaceVariant, fontWeight: FontWeight.w700, fontSize: 12),
                                ),
                              ],
                            ),
                          ),
                          const SizedBox(width: 10),
                          badge,
                        ],
                      ),
                      const SizedBox(height: 10),
                      Text(title, style: TextStyle(fontWeight: FontWeight.w900, fontSize: compact ? 14 : 16)),
                      const SizedBox(height: 8),
                      Row(
                        children: [
                          Expanded(child: Text(whenLine, style: TextStyle(color: cs.onSurfaceVariant, fontWeight: FontWeight.w800))),
                          const SizedBox(width: 10),
                          durationChip,
                        ],
                      ),
                      const SizedBox(height: 10),
                      Wrap(
                        spacing: 10,
                        runSpacing: 8,
                        crossAxisAlignment: WrapCrossAlignment.center,
                        children: [
                          statusPill,
                          TextButton(
                            onPressed: onDetails,
                            child: Text(t(context).commonViewDetails),
                          ),
                          if (canStart)
                            FilledButton(
                              onPressed: onStart,
                              child: Text(t(context).prayerStart),
                            ),
                        ],
                      ),
                    ],
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

class _CreateCommunityPrayerRunSheet extends StatefulWidget {
  const _CreateCommunityPrayerRunSheet({
    required this.repo,
    required this.community,
    required this.members,
  });

  final DemoRepository repo;
  final CommunityModel community;
  final List<ProfileModel> members;

  @override
  State<_CreateCommunityPrayerRunSheet> createState() => _CreateCommunityPrayerRunSheetState();
}

class _CreateCommunityPrayerRunSheetState extends State<_CreateCommunityPrayerRunSheet> {
  final _title = TextEditingController();
  DateTime _start = DateTime.now().add(const Duration(hours: 2));
  var _weeklyFixed = false;
  late TimeOfDay _weeklyTime = TimeOfDay.fromDateTime(_start);
  late int _weeklyWeekday = _start.weekday % 7;
  int _durationMinutes = 60;
  String? _assignedUserId;
  var _loading = false;

  @override
  void dispose() {
    _title.dispose();
    super.dispose();
  }

  Future<DateTime?> _pickDateTime(DateTime initial) async {
    final date = await showDatePicker(
      context: context,
      initialDate: initial,
      firstDate: DateTime.now().subtract(const Duration(days: 1)),
      lastDate: DateTime.now().add(const Duration(days: 365 * 2)),
    );
    if (!mounted || date == null) return null;
    final time = await showTimePicker(context: context, initialTime: TimeOfDay.fromDateTime(initial));
    if (!mounted || time == null) return null;
    return DateTime(date.year, date.month, date.day, time.hour, time.minute);
  }

  bool _isMissingRpcFunction(Object e, String functionName) {
    if (e is! PostgrestException) return false;
    final hay = [
      e.message,
      (e.details ?? '').toString(),
      (e.hint ?? '').toString(),
    ].join(' ').toLowerCase();
    return hay.contains('could not find the function') && hay.contains(functionName.toLowerCase());
  }

  Future<String?> _createWeeklyRunsFallback({
    required SupabaseClient sb,
    required String communityId,
    required String title,
    required int weekday0Sunday,
    required TimeOfDay time,
    required int durationMinutes,
    required String assignedUserId,
    required int weeks,
    required String? timezoneName,
  }) async {
    tz.Location loc = tz.local;
    final tzName = timezoneName?.trim();
    if (tzName != null && tzName.isNotEmpty) {
      try {
        loc = tz.getLocation(tzName);
      } catch (_) {}
    }

    final now = tz.TZDateTime.now(loc);
    final targetWeekday = weekday0Sunday == 0 ? DateTime.sunday : weekday0Sunday;
    var candidate = tz.TZDateTime(loc, now.year, now.month, now.day, time.hour, time.minute);
    var diffDays = (targetWeekday - candidate.weekday) % 7;
    if (diffDays == 0 && !candidate.isAfter(now)) diffDays = 7;
    candidate = candidate.add(Duration(days: diffDays));

    String? firstId;
    var created = 0;
    for (var i = 0; i < weeks; i++) {
      final dt = candidate.add(Duration(days: i * 7));
      final res = await sb.rpc('create_community_prayer_run_simple', params: <String, Object?>{
        'p_community_id': communityId,
        'p_title': title,
        'p_starts_at': dt.toUtc().toIso8601String(),
        'p_duration_minutes': durationMinutes,
        'p_assigned_user_id': assignedUserId,
      });
      created += 1;
      final v = res?.toString().trim();
      if (firstId == null && v != null && v.isNotEmpty && v != 'null') {
        firstId = v;
      }
    }

    if (created <= 0) return null;
    return firstId ?? 'created';
  }

  @override
  Widget build(BuildContext context) {
    String weekdayLabel(int value) {
      return switch (value) {
        0 => t(context).commonWeekdaySunday,
        1 => t(context).commonWeekdayMonday,
        2 => t(context).commonWeekdayTuesday,
        3 => t(context).commonWeekdayWednesday,
        4 => t(context).commonWeekdayThursday,
        5 => t(context).commonWeekdayFriday,
        _ => t(context).commonWeekdaySaturday,
      };
    }

    return SafeArea(
      child: Padding(
        padding: EdgeInsets.only(
          left: 16,
          right: 16,
          top: 4,
          bottom: 16 + MediaQuery.viewInsetsOf(context).bottom,
        ),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            Text(t(context).prayerRunsCreateSheetTitle, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 18)),
            const SizedBox(height: 12),
            AtalaiaTextField(
              controller: _title,
              labelText: t(context).prayerRunsCreateTitleLabel,
              hintText: t(context).prayerRunsCreateTitleHint,
              onChanged: (_) => setState(() {}),
            ),
            const SizedBox(height: 10),
            SwitchListTile(
              contentPadding: EdgeInsets.zero,
              title: Text(t(context).prayerRunsCreateWeeklyFixedTitle),
              subtitle: Text(t(context).prayerRunsCreateWeeklyFixedSubtitle),
              value: _weeklyFixed,
              onChanged: _loading
                  ? null
                  : (v) {
                      setState(() {
                        _weeklyFixed = v;
                        _weeklyTime = TimeOfDay.fromDateTime(_start);
                        _weeklyWeekday = _start.weekday % 7;
                      });
                    },
            ),
            const SizedBox(height: 8),
            DropdownButtonFormField<String?>(
              initialValue: _assignedUserId,
              items: [
                ...widget.members.map(
                  (m) => DropdownMenuItem<String?>(
                    value: m.userId,
                    child: Text(_profileDisplayLabel(m, userFallback: t(context).commonUserFallback)),
                  ),
                ),
              ],
              onChanged: _loading ? null : (v) => setState(() => _assignedUserId = v),
              decoration: InputDecoration(labelText: t(context).prayerRunsCreateAssigneeLabel),
            ),
            const SizedBox(height: 10),
            if (!_weeklyFixed)
              ListTile(
                contentPadding: EdgeInsets.zero,
                leading: const Icon(Icons.schedule),
                title: Text(t(context).prayerRunsCreateStartLabel),
                subtitle: Text(_formatShort(_start)),
                onTap: _loading
                    ? null
                    : () async {
                        final next = await _pickDateTime(_start);
                        if (!mounted || next == null) return;
                        setState(() => _start = next);
                      },
              )
            else
              Row(
                children: [
                  Expanded(
                    child: DropdownButtonFormField<int>(
                      initialValue: _weeklyWeekday,
                      items: [
                        ...List.generate(
                          7,
                          (value) => DropdownMenuItem<int>(value: value, child: Text(weekdayLabel(value))),
                        ),
                      ],
                      onChanged: _loading ? null : (v) => setState(() => _weeklyWeekday = v ?? (_start.weekday % 7)),
                      decoration: InputDecoration(labelText: t(context).prayerRunsCreateDayLabel),
                    ),
                  ),
                  const SizedBox(width: 12),
                  Expanded(
                    child: ListTile(
                      contentPadding: EdgeInsets.zero,
                      leading: const Icon(Icons.access_time),
                      title: Text(t(context).prayerRunsCreateTimeLabel),
                      subtitle: Text(_formatTimeOfDay(_weeklyTime)),
                      onTap: _loading
                          ? null
                          : () async {
                              final picked = await showTimePicker(context: context, initialTime: _weeklyTime);
                              if (!mounted || picked == null) return;
                              setState(() => _weeklyTime = picked);
                            },
                    ),
                  ),
                ],
              ),
            const SizedBox(height: 8),
            DropdownButtonFormField<int>(
              initialValue: _durationMinutes,
              items: const [
                DropdownMenuItem<int>(value: 15, child: Text('15 min')),
                DropdownMenuItem<int>(value: 30, child: Text('30 min')),
                DropdownMenuItem<int>(value: 60, child: Text('60 min')),
              ],
              onChanged: _loading ? null : (v) => setState(() => _durationMinutes = v ?? 60),
              decoration: InputDecoration(labelText: t(context).prayerRunsCreateDurationLabel),
            ),
            const SizedBox(height: 14),
            PrimaryButton(
              label: t(context).commonCreate,
              loading: _loading,
              onPressed: _loading
                  ? null
                  : () async {
                      final repo = widget.repo;
                      final sb = repo.supabase;
                      if (sb == null) return;
                      if (repo.isOffline) {
                        showErrorSnackBar(context, onRetry: () {});
                        return;
                      }
                      final assignedId = _assignedUserId;
                      if (assignedId == null || assignedId.trim().isEmpty) {
                        showInfoSnackBar(context, t(context).prayerRunsCreateSelectAssignee);
                        return;
                      }
                      setState(() => _loading = true);
                      try {
                        final title = _title.text.trim().isEmpty ? t(context).prayerRunDefaultTitle : _title.text.trim();
                        final tzName = (UserLocalePrefsScope.of(context).value.timezoneName ?? '').trim();
                        final timezone = tzName.isEmpty ? 'UTC' : tzName;
                        dynamic result;
                        if (_weeklyFixed) {
                          try {
                            result = await sb.rpc('create_community_prayer_weekly_schedule_and_runs', params: <String, Object?>{
                              'p_community_id': widget.community.id,
                              'p_title': title,
                              'p_weekday': _weeklyWeekday,
                              'p_start_time': '${_weeklyTime.hour.toString().padLeft(2, '0')}:${_weeklyTime.minute.toString().padLeft(2, '0')}:00',
                              'p_duration_minutes': _durationMinutes,
                              'p_assigned_user_id': assignedId,
                              'p_weeks': 8,
                              'p_timezone': timezone,
                            });
                          } catch (e) {
                            if (_isMissingRpcFunction(e, 'create_community_prayer_weekly_schedule_and_runs')) {
                              result = await _createWeeklyRunsFallback(
                                sb: sb,
                                communityId: widget.community.id,
                                title: title,
                                weekday0Sunday: _weeklyWeekday,
                                time: _weeklyTime,
                                durationMinutes: _durationMinutes,
                                assignedUserId: assignedId,
                                weeks: 8,
                                timezoneName: tzName.isEmpty ? null : tzName,
                              );
                            } else {
                              rethrow;
                            }
                          }
                        } else {
                          result = await sb.rpc('create_community_prayer_run_simple', params: <String, Object?>{
                            'p_community_id': widget.community.id,
                            'p_title': title,
                            'p_starts_at': _userWallTimeToUtc(_start, tzName.isEmpty ? null : tzName).toIso8601String(),
                            'p_duration_minutes': _durationMinutes,
                            'p_assigned_user_id': assignedId,
                          });
                        }
                        if (!mounted) return;
                        setState(() => _loading = false);
                        Navigator.of(context).pop(result?.toString());
                      } catch (e, st) {
                        assert(() {
                          debugPrint('[prayer:run] create run failed: $e');
                          debugPrintStack(stackTrace: st);
                          return true;
                        }());
                        if (!mounted) return;
                        setState(() => _loading = false);
                        final short = _shortSupabaseError(e).trim();
                        if (short.isEmpty) {
                          showErrorSnackBar(context, onRetry: () {});
                          return;
                        }
                        showAtalaiaSnackBar(
                          context,
                          t(context).commonSomethingWentWrongWithReason(short),
                          kind: AtalaiaSnackKind.error,
                        );
                      }
                    },
            ),
          ],
        ),
      ),
    );
  }

  String _formatShort(DateTime dt) {
    final two = (int v) => v.toString().padLeft(2, '0');
    return '${two(dt.day)}/${two(dt.month)}/${dt.year} ${two(dt.hour)}:${two(dt.minute)}';
  }

  String _formatTimeOfDay(TimeOfDay t) {
    final h = t.hour.toString().padLeft(2, '0');
    final m = t.minute.toString().padLeft(2, '0');
    return '$h:$m';
  }
}

class CommunityEventsScreen extends StatefulWidget {
  const CommunityEventsScreen({required this.args, super.key});

  final CommunityArgs args;

  @override
  State<CommunityEventsScreen> createState() => _CommunityEventsScreenState();
}

class _CommunityEventsScreenState extends State<CommunityEventsScreen> {
  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      final repo = RepoScope.of(context);
      if (repo.supabase == null || repo.isOffline) return;
      unawaited(repo.refreshCommunityEvents(widget.args.communityId, force: true));
    });
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final c = repo.findCommunity(widget.args.communityId);
        if (c == null) {
          return Scaffold(
            appBar: AppBar(title: Text(t(context).communityEventsTitle)),
            body: Center(child: Text(t(context).communityNotFound)),
          );
        }

        final s = session.value;
        final canCreate = s is AuthSession && c.viewerStatus == CommunityViewerStatus.approved;
        final events = repo.eventsForCommunity(c.id);

        return Scaffold(
          appBar: AppBar(
            title: Text(t(context).communityEventsTitleWithCommunity(c.name)),
            actions: [
              if (canCreate)
                IconButton(
                  icon: const Icon(Icons.add),
                  onPressed: () async {
                    await showAtalaiaBottomSheet<void>(
                      context,
                      builder: (_) => _CreateCommunityEventSheet(
                        repo: repo,
                        session: s,
                        communityId: c.id,
                      ),
                    );
                  },
                ),
            ],
          ),
          body: RefreshIndicator(
            onRefresh: () async {
              await repo.refreshCommunityEvents(c.id, force: true);
            },
            child: events.isEmpty
                ? ListView(
                    physics: const AlwaysScrollableScrollPhysics(),
                    children: [
                      SizedBox(height: MediaQuery.sizeOf(context).height * 0.18),
                      EmptyState(icon: Icons.event_outlined, title: t(context).communityEventsEmpty),
                    ],
                  )
                : ListView.separated(
                    physics: const AlwaysScrollableScrollPhysics(),
                    itemCount: events.length,
                    separatorBuilder: (_, __) => const Divider(height: 1),
                    itemBuilder: (context, index) {
                      final e = events[index];
                      final when = '${_formatShortDateTime(e.startTime)}${e.endTime.isAfter(e.startTime) ? ' – ${_formatShortDateTime(e.endTime)}' : ''}';
                      final where = e.location.trim().isEmpty ? null : e.location.trim();
                      return ListTile(
                        leading: const Icon(Icons.event_outlined),
                        title: Text(e.title, style: const TextStyle(fontWeight: FontWeight.w800)),
                        subtitle: Text([when, if (where != null) where].join('\n')),
                        isThreeLine: where != null,
                      );
                    },
                  ),
          ),
        );
      },
    );
  }

  String _formatShortDateTime(DateTime dt) {
    final two = (int v) => v.toString().padLeft(2, '0');
    return '${two(dt.day)}/${two(dt.month)}/${dt.year} ${two(dt.hour)}:${two(dt.minute)}';
  }
}

class _CreateCommunityEventSheet extends StatefulWidget {
  const _CreateCommunityEventSheet({
    required this.repo,
    required this.session,
    required this.communityId,
  });

  final DemoRepository repo;
  final AuthSession session;
  final String communityId;

  @override
  State<_CreateCommunityEventSheet> createState() => _CreateCommunityEventSheetState();
}

class _CreateCommunityEventSheetState extends State<_CreateCommunityEventSheet> {
  final _title = TextEditingController();
  final _description = TextEditingController();
  final _location = TextEditingController();

  DateTime _start = DateTime.now().add(const Duration(days: 1));
  DateTime? _end;
  var _loading = false;

  @override
  void dispose() {
    _title.dispose();
    _description.dispose();
    _location.dispose();
    super.dispose();
  }

  bool get _valid => _title.text.trim().isNotEmpty;

  Future<DateTime?> _pickDateTime(DateTime initial) async {
    final date = await showDatePicker(
      context: context,
      initialDate: initial,
      firstDate: DateTime.now().subtract(const Duration(days: 1)),
      lastDate: DateTime.now().add(const Duration(days: 365 * 3)),
    );
    if (!mounted || date == null) return null;
    final time = await showTimePicker(context: context, initialTime: TimeOfDay.fromDateTime(initial));
    if (!mounted || time == null) return null;
    return DateTime(date.year, date.month, date.day, time.hour, time.minute);
  }

  @override
  Widget build(BuildContext context) {
    return SafeArea(
      child: Padding(
        padding: EdgeInsets.only(
          left: 16,
          right: 16,
          top: 4,
          bottom: 16 + MediaQuery.viewInsetsOf(context).bottom,
        ),
        child: Column(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.stretch,
          children: [
            Text(t(context).communityEventCreateSheetTitle, style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 18)),
            const SizedBox(height: 12),
            AtalaiaTextField(
              controller: _title,
              labelText: t(context).communityEventCreateTitleLabel,
              hintText: t(context).communityEventCreateTitleHint,
              onChanged: (_) => setState(() {}),
            ),
            const SizedBox(height: 10),
            AtalaiaTextField(
              controller: _description,
              labelText: t(context).communityEventCreateDescriptionLabel,
              hintText: t(context).communityEventCreateDescriptionHint,
              maxLines: 4,
              minLines: 2,
            ),
            const SizedBox(height: 10),
            AtalaiaTextField(
              controller: _location,
              labelText: t(context).communityEventCreateLocationLabel,
              hintText: t(context).communityEventCreateLocationHint,
            ),
            const SizedBox(height: 10),
            ListTile(
              contentPadding: EdgeInsets.zero,
              leading: const Icon(Icons.schedule),
              title: Text(t(context).communityEventCreateStartLabel),
              subtitle: Text(_formatShort(_start)),
              onTap: _loading
                  ? null
                  : () async {
                      final next = await _pickDateTime(_start);
                      if (!mounted || next == null) return;
                      setState(() => _start = next);
                    },
            ),
            ListTile(
              contentPadding: EdgeInsets.zero,
              leading: const Icon(Icons.schedule_outlined),
              title: Text(t(context).communityEventCreateEndOptionalLabel),
              subtitle: Text(_end == null ? '—' : _formatShort(_end!)),
              onTap: _loading
                  ? null
                  : () async {
                      final base = _end ?? _start.add(const Duration(hours: 1));
                      final next = await _pickDateTime(base);
                      if (!mounted) return;
                      setState(() => _end = next);
                    },
              trailing: _end == null || _loading
                  ? null
                  : IconButton(
                      icon: const Icon(Icons.close),
                      onPressed: () => setState(() => _end = null),
                    ),
            ),
            const SizedBox(height: 14),
            PrimaryButton(
              label: t(context).communityEventCreateSubmit,
              loading: _loading,
              onPressed: _loading || !_valid
                  ? null
                  : () async {
                      if (widget.repo.isOffline) {
                        showErrorSnackBar(context, onRetry: () {});
                        return;
                      }
                      setState(() => _loading = true);
                      await widget.repo.createCommunityEvent(
                        session: widget.session,
                        communityId: widget.communityId,
                        title: _title.text,
                        description: _description.text,
                        location: _location.text,
                        startTime: _start,
                        endTime: _end,
                      );
                      if (!mounted) return;
                      setState(() => _loading = false);
                      Navigator.of(context).pop();
                    },
            ),
          ],
        ),
      ),
    );
  }

  String _formatShort(DateTime dt) {
    final two = (int v) => v.toString().padLeft(2, '0');
    return '${two(dt.day)}/${two(dt.month)}/${dt.year} ${two(dt.hour)}:${two(dt.minute)}';
  }
}

class CommunityDetailScreen extends StatefulWidget {
  const CommunityDetailScreen({required this.args, super.key});

  final CommunityArgs args;

  @override
  State<CommunityDetailScreen> createState() => _CommunityDetailScreenState();
}

class _CommunityDetailScreenState extends State<CommunityDetailScreen> {
  final _scrollController = ScrollController();
  var _feedLoading = true;
  var _feedLoadingMore = false;
  var _feedHasMore = true;
  DateTime? _feedCursorCreatedAt;
  List<PostModel> _feedRemotePosts = const [];

  Future<void> _openCommunitySwitcherSheet() async {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context).value;
    if (repo.supabase != null && !repo.isOffline) {
      unawaited(repo.refreshCommunitiesForViewer(force: true));
    }

    final search = TextEditingController();
    try {
      await showAtalaiaBottomSheet<void>(
        context,
        builder: (sheetContext) {
          return _CommunitiesSheet(
            search: search,
            session: session,
            repo: repo,
            activeCommunityId: widget.args.communityId,
            onOpenCommunity: (communityId) {
              Navigator.of(sheetContext).pop();
              Future<void>.delayed(const Duration(milliseconds: 1)).then((_) {
                if (!mounted) return;
                Navigator.of(context).pop(communityId);
              });
            },
            onSelectFilter: (communityId) {
              Navigator.of(sheetContext).pop();
              Future<void>.delayed(const Duration(milliseconds: 1)).then((_) {
                if (!mounted) return;
                if (communityId == null) {
                  Navigator.of(context).pop(true);
                  return;
                }
                Navigator.of(context).pop(communityId);
              });
            },
            onCreateCommunity: null,
          );
        },
      );
    } finally {
      search.dispose();
    }
  }

  @override
  void initState() {
    super.initState();
    _scrollController.addListener(_maybeLoadMore);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_loadFeedInitial());
    });
  }

  @override
  void dispose() {
    _scrollController.dispose();
    super.dispose();
  }

  void _maybeLoadMore() {
    if (!_feedHasMore || _feedLoading || _feedLoadingMore) return;
    if (!_scrollController.hasClients) return;
    final pos = _scrollController.position;
    if (pos.maxScrollExtent <= 0) return;
    if (pos.pixels < pos.maxScrollExtent - 320) return;
    unawaited(_loadFeedMore());
  }

  Future<void> _loadFeedInitial() async {
    if (!mounted) return;
    setState(() {
      _feedLoading = true;
      _feedLoadingMore = false;
      _feedHasMore = true;
      _feedCursorCreatedAt = null;
      _feedRemotePosts = const [];
    });

    final repo = RepoScope.of(context);
    final useRemote = repo.supabase != null && !repo.isOffline;
    if (!useRemote) {
      if (!mounted) return;
      setState(() => _feedLoading = false);
      return;
    }

    final c = repo.findCommunity(widget.args.communityId);
    if (c == null) {
      if (!mounted) return;
      setState(() => _feedLoading = false);
      return;
    }

    final items = await repo.fetchCommunityFeedPosts(c.id, limit: 24);
    if (!mounted) return;
    setState(() {
      _feedLoading = false;
      _feedRemotePosts = items;
      _feedCursorCreatedAt = items.isEmpty ? null : items.last.createdAt;
      _feedHasMore = items.length >= 24;
    });
  }

  Future<void> _loadFeedMore() async {
    final repo = RepoScope.of(context);
    final useRemote = repo.supabase != null && !repo.isOffline;
    if (!useRemote) return;
    final cursor = _feedCursorCreatedAt;
    if (cursor == null) {
      setState(() => _feedHasMore = false);
      return;
    }
    setState(() => _feedLoadingMore = true);
    final items = await repo.fetchCommunityFeedPosts(
      widget.args.communityId,
      cursorCreatedAt: cursor,
      limit: 24,
    );
    if (!mounted) return;
    final existingIds = _feedRemotePosts.map((p) => p.id).toSet();
    final next = [..._feedRemotePosts, ...items.where((p) => !existingIds.contains(p.id))];
    setState(() {
      _feedLoadingMore = false;
      _feedRemotePosts = List.unmodifiable(next);
      _feedCursorCreatedAt = items.isEmpty ? _feedCursorCreatedAt : items.last.createdAt;
      _feedHasMore = items.length >= 24;
    });
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final c = repo.findCommunity(widget.args.communityId);
        if (c == null) {
          final l10n = t(context);
          return Scaffold(
            appBar: AppBar(title: Text(l10n.communityTitle)),
            body: Center(child: Text(l10n.communityNotFound)),
          );
        }

        final s = session.value;
        final isAuthenticated = s.isAuthenticated;
        final cs = Theme.of(context).colorScheme;
        final l10n = t(context);
        final viewerId = s is AuthSession ? s.userId : null;
        if (viewerId != null && repo.supabase != null && !repo.isOffline) {
          unawaited(repo.refreshCommunityMembers(c.id));
        }
        final role = (c.viewerRole ?? '').trim().toLowerCase();
        final canEdit = viewerId != null && (c.ownerId == viewerId || role == 'admin' || role == 'moderator' || role == 'founder');

        final posts = repo.postsForCommunity(s, c.id);
        final prayerSum = posts.fold<int>(0, (sum, p) => sum + p.prayerCount);

        final primaryLabel = switch (c.viewerStatus) {
          CommunityViewerStatus.none => c.isClosed ? l10n.communityRequestEntry : l10n.communityJoin,
          CommunityViewerStatus.pending => l10n.communityRequestSent,
          CommunityViewerStatus.approved => null,
        };

        return Scaffold(
          appBar: AppBar(
            title: Text(c.name),
            actions: [
              if (c.viewerStatus == CommunityViewerStatus.approved && s is AuthSession && !repo.isOffline)
                IconButton(
                  icon: const Icon(Icons.add),
                  tooltip: l10n.communityCreatePost,
                  onPressed: () {
                    Navigator.of(context).push(
                      MaterialPageRoute<void>(
                        builder: (_) => PostComposerScreen(draft: ComposerDraft(initialCommunityId: c.id)),
                      ),
                    );
                  },
                ),
            ],
          ),
          body: RefreshIndicator(
            onRefresh: _loadFeedInitial,
            child: CustomScrollView(
              controller: _scrollController,
              physics: const AlwaysScrollableScrollPhysics(),
              slivers: [
                SliverPadding(
                  padding: const EdgeInsets.all(12),
                  sliver: SliverList(
                    delegate: SliverChildListDelegate(
                      [
                        if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
                        Card(
                          child: Padding(
                            padding: const EdgeInsets.all(14),
                            child: Column(
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                                Row(
                                  crossAxisAlignment: CrossAxisAlignment.start,
                                  children: [
                                    Avatar(name: c.name, imageUrl: c.imageUrl, size: AvatarSize.s96),
                                    const SizedBox(width: 14),
                                    Expanded(
                                      child: Column(
                                        crossAxisAlignment: CrossAxisAlignment.start,
                                        children: [
                                          Row(
                                            children: [
                                              Flexible(
                                                child: Text(
                                                  c.name,
                                                  style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 18),
                                                  maxLines: 1,
                                                  overflow: TextOverflow.ellipsis,
                                                ),
                                              ),
                                              if (c.isVerified) ...[
                                                const SizedBox(width: 6),
                                                Icon(Icons.verified, size: 18, color: context.brand.verifiedBlue),
                                              ],
                                            ],
                                          ),
                                          const SizedBox(height: 10),
                                          Row(
                                            children: [
                                              Expanded(
                                                child: _StatPill(
                                                  label: t(context).communityMembersTitle,
                                                  value: c.memberCount.toString(),
                                                  cs: cs,
                                                  onTap: () {
                                                    Navigator.of(context).pushNamed(
                                                      Routes.communityMembers,
                                                      arguments: CommunityMembersArgs(communityId: c.id),
                                                    );
                                                  },
                                                ),
                                              ),
                                              const SizedBox(width: 10),
                                              Expanded(
                                                child: _StatPill(
                                                  label: t(context).regionPrayersTitleShort,
                                                  value: prayerSum.toString(),
                                                  cs: cs,
                                                  onTap: () {
                                                    Navigator.of(context).pushNamed(
                                                      Routes.communityPrayerScales,
                                                      arguments: CommunityArgs(communityId: c.id),
                                                    );
                                                  },
                                                ),
                                              ),
                                            ],
                                          ),
                                        ],
                                      ),
                                    ),
                                  ],
                                ),
                                if (canEdit) ...[
                                  const SizedBox(height: 12),
                                  SizedBox(
                                    width: double.infinity,
                                    child: SecondaryButton(
                                      label: t(context).communityEditTitle,
                                      onPressed: () {
                                        Navigator.of(context).pushNamed(
                                          Routes.editCommunity,
                                          arguments: EditCommunityArgs(communityId: c.id),
                                        );
                                      },
                                    ),
                                  ),
                                ],
                              ],
                            ),
                          ),
                        ),
                        const SizedBox(height: 12),
                        if (c.description.trim().isNotEmpty) ...[
                          Card(
                            elevation: 0,
                            color: cs.surfaceContainerHighest.withValues(alpha: 0.35),
                            child: Padding(
                              padding: const EdgeInsets.all(14),
                              child: Column(
                                crossAxisAlignment: CrossAxisAlignment.start,
                                children: [
                                  Row(
                                    children: [
                                      const Icon(Icons.info_outline, size: 18),
                                      const SizedBox(width: 8),
                                      Text(t(context).communityDescription, style: const TextStyle(fontWeight: FontWeight.w800)),
                                    ],
                                  ),
                                  const SizedBox(height: 10),
                                  _ExpandableText(text: c.description, maxLines: 4),
                                ],
                              ),
                            ),
                          ),
                          const SizedBox(height: 12),
                        ],
                        Card(
                          elevation: 0,
                          color: cs.surfaceContainerHighest.withValues(alpha: 0.35),
                          child: Padding(
                            padding: const EdgeInsets.all(14),
                            child: Column(
                              crossAxisAlignment: CrossAxisAlignment.start,
                              children: [
                                Row(
                                  children: [
                                    const Icon(Icons.rule_outlined, size: 18),
                                    const SizedBox(width: 8),
                                    Text(t(context).communityRules, style: const TextStyle(fontWeight: FontWeight.w800)),
                                  ],
                                ),
                                const SizedBox(height: 10),
                                if (c.rules.isEmpty)
                                  Text(t(context).communityNoRulesYet, style: TextStyle(color: cs.outline))
                                else
                                  ...c.rules.map(
                                    (r) => Padding(
                                      padding: const EdgeInsets.only(bottom: 6),
                                      child: Text('• $r'),
                                    ),
                                  ),
                              ],
                            ),
                          ),
                        ),
                        if (primaryLabel != null) ...[
                          const SizedBox(height: 12),
                          PrimaryButton(
                            label: primaryLabel,
                            onPressed: c.viewerStatus == CommunityViewerStatus.pending
                                ? null
                                : () {
                                    if (!isAuthenticated) {
                                      showLoginSnackBar(context, message: t(context).settingsSignInToContinue);
                                      return;
                                    }

                                    if (repo.isOffline) {
                                      showErrorSnackBar(
                                        context,
                                        onRetry: () {
                                          if (RepoScope.of(context).isOffline) return;
                                          RepoScope.of(context).requestCommunityJoin(c.id, isAuthenticated: true);
                                          showInfoSnackBar(
                                            context,
                                            c.isClosed ? t(context).communityRequestSent : t(context).communityJoinedMessage,
                                          );
                                        },
                                      );
                                      return;
                                    }

                                    RepoScope.of(context).requestCommunityJoin(c.id, isAuthenticated: true);
                                    showInfoSnackBar(
                                      context,
                                      c.isClosed ? t(context).communityRequestSent : t(context).communityJoinedMessage,
                                    );
                                  },
                          ),
                        ],
                        if (c.viewerStatus == CommunityViewerStatus.pending) ...[
                          const SizedBox(height: 10),
                          SecondaryButton(
                            label: t(context).communityCancelRequest,
                            onPressed: () {
                              if (!isAuthenticated) {
                                showLoginSnackBar(context, message: t(context).settingsSignInToContinue);
                                return;
                              }
                              RepoScope.of(context).cancelCommunityJoinRequest(c.id, isAuthenticated: true);
                              showInfoSnackBar(context, t(context).communityRequestCanceled);
                            },
                          ),
                        ] else if (c.viewerStatus == CommunityViewerStatus.none && c.isClosed) ...[
                          const SizedBox(height: 10),
                          SecondaryButton(
                            label: t(context).communityMessageAdmin,
                            onPressed: () {
                              if (!isAuthenticated) {
                                showLoginSnackBar(context, message: t(context).communitySignInToMessage);
                                return;
                              }
                              final l10n = t(context);
                              final admin = RepoScope.of(context).findProfile(c.ownerId);
                              if (admin == null) {
                                showInfoSnackBar(context, l10n.communityAdminUnavailableDemo);
                                return;
                              }
                              final thread = RepoScope.of(context).openOrCreateThreadWith(admin);
                              Navigator.of(context).pushNamed(
                                Routes.chat,
                                arguments: ChatArgs(
                                  threadId: thread.id,
                                  peerName: thread.peerName,
                                  peerUsername: thread.peerUsername,
                                  peerIsVerified: thread.peerIsVerified,
                                  peerAvatarUrl: admin.avatarUrl,
                                ),
                              );
                            },
                          ),
                        ],
                        const SizedBox(height: 12),
                        Row(
                          children: [
                            Expanded(
                              child: SecondaryButton(
                                label: t(context).communitySwitch,
                                onPressed: _openCommunitySwitcherSheet,
                              ),
                            ),
                            const SizedBox(width: 10),
                            Expanded(
                              child: SecondaryButton(
                                label: t(context).communityLeave,
                                onPressed: () {
                                  if (!isAuthenticated) {
                                    showLoginSnackBar(context, message: t(context).settingsSignInToContinue);
                                    return;
                                  }
                                  if (repo.isOffline) {
                                    showErrorSnackBar(
                                      context,
                                      onRetry: () {
                                        if (RepoScope.of(context).isOffline) return;
                                        unawaited(RepoScope.of(context).leaveCommunity(c.id, isAuthenticated: true));
                                      },
                                    );
                                    return;
                                  }
                                  unawaited(RepoScope.of(context).leaveCommunity(c.id, isAuthenticated: true));
                                  Navigator.of(context).pop(true);
                                },
                              ),
                            ),
                          ],
                        ),
                        const SizedBox(height: 14),
                        Row(
                          children: [
                            Expanded(
                              child: Text(
                                t(context).communityFeedSectionTitle,
                                style: const TextStyle(fontWeight: FontWeight.w900, fontSize: 16),
                              ),
                            ),
                          ],
                        ),
                        const SizedBox(height: 8),
                      ],
                    ),
                  ),
                ),
                Builder(
                  builder: (context) {
                    if (s is! AuthSession) {
                      return SliverToBoxAdapter(
                        child: Padding(
                          padding: const EdgeInsets.fromLTRB(12, 0, 12, 18),
                          child: Center(
                            child: PrimaryButton(
                              label: t(context).communitySignInToSeeFeed,
                              onPressed: () => showLoginSnackBar(context, message: t(context).communitySignInToSeeFeed),
                            ),
                          ),
                        ),
                      );
                    }

                    if (c.isClosed && c.viewerStatus != CommunityViewerStatus.approved) {
                      return SliverToBoxAdapter(
                        child: Padding(
                          padding: const EdgeInsets.fromLTRB(12, 0, 12, 18),
                          child: Column(
                            children: [
                              SizedBox(height: MediaQuery.sizeOf(context).height * 0.04),
                              EmptyState(icon: Icons.lock_outline, title: t(context).communityMembersOnlyFeed),
                            ],
                          ),
                        ),
                      );
                    }

                    final useRemote = repo.supabase != null && !repo.isOffline;
                    final posts = useRemote ? _feedRemotePosts : repo.postsForCommunity(s, c.id);

                    if (_feedLoading) {
                      return SliverList(
                        delegate: SliverChildBuilderDelegate(
                          (context, index) {
                            return PostCardSkeleton(
                              hasMedia: index.isEven,
                              margin: const EdgeInsets.symmetric(horizontal: 12, vertical: 8),
                            );
                          },
                          childCount: 6,
                        ),
                      );
                    }

                    if (posts.isEmpty) {
                      return SliverToBoxAdapter(
                        child: Padding(
                          padding: const EdgeInsets.fromLTRB(12, 24, 12, 18),
                          child: Column(
                            children: [
                              SizedBox(height: MediaQuery.sizeOf(context).height * 0.06),
                              EmptyState(icon: Icons.feed_outlined, title: t(context).communityNoPostsYet),
                            ],
                          ),
                        ),
                      );
                    }

                    return SliverList(
                      delegate: SliverChildBuilderDelegate(
                        (context, index) {
                          if (index >= posts.length) {
                            return const Padding(
                              padding: EdgeInsets.fromLTRB(12, 12, 12, 18),
                              child: Center(child: CircularProgressIndicator()),
                            );
                          }

                          final post = posts[index];
                          return PostCard(
                            post: post,
                            isAuthenticated: true,
                            onOpenPost: () {
                              Navigator.of(context).pushNamed(
                                Routes.postDetail,
                                arguments: PostDetailArgs(postId: post.id),
                              );
                            },
                            onLike: () {
                              if (!useRemote) {
                                repo.toggleLike(post.id, isAuthenticated: true);
                                return;
                              }
                              final idx = _feedRemotePosts.indexWhere((p) => p.id == post.id);
                              if (idx < 0) return;
                              final p = _feedRemotePosts[idx];
                              final nextLiked = !p.viewerHasLiked;
                              if (nextLiked) {
                                repo.trackEvent('like_add', <String, Object?>{
                                  'postId': p.id,
                                  'kind': p.kind.analyticsValue,
                                  'visibility': p.visibility.analyticsValue,
                                });
                              }
                              final list = _feedRemotePosts.toList(growable: true);
                              list[idx] = p.copyWith(
                                viewerHasLiked: nextLiked,
                                likeCount: nextLiked ? p.likeCount + 1 : (p.likeCount - 1).clamp(0, 1 << 30),
                              );
                              setState(() => _feedRemotePosts = List.unmodifiable(list));
                              unawaited(repo.setLikeOnPostSupabase(postId: p.id, shouldLike: nextLiked));
                            },
                            onPray: () {
                              if (!useRemote) {
                                repo.togglePrayer(post.id, isAuthenticated: true);
                    showInfoSnackBar(context, t(context).prayerRegisteredSnack);
                                return;
                              }
                              final idx = _feedRemotePosts.indexWhere((p) => p.id == post.id);
                              if (idx < 0) return;
                              final p = _feedRemotePosts[idx];
                              if (p.viewerHasPrayed) return;
                              repo.trackEvent('prayer_add', <String, Object?>{
                                'postId': p.id,
                                'kind': p.kind.analyticsValue,
                                'visibility': p.visibility.analyticsValue,
                              });
                              final list = _feedRemotePosts.toList(growable: true);
                              list[idx] = p.copyWith(viewerHasPrayed: true, prayerCount: p.prayerCount + 1);
                              setState(() => _feedRemotePosts = List.unmodifiable(list));
                              unawaited(repo.addPrayerOnPostSupabase(postId: p.id));
                  showInfoSnackBar(context, t(context).prayerRegisteredSnack);
                            },
                            onComment: () {
                              Navigator.of(context).pushNamed(
                                Routes.postComments,
                                arguments: CommentsArgs(postId: post.id),
                              );
                            },
                            onShare: () async {
                              await showShareSheet(context, post: post, isAuthenticated: true);
                            },
                            onSave: () {
                              if (!useRemote) {
                                final willSave = !post.viewerHasSaved;
                                repo.toggleSave(post.id, isAuthenticated: true);
                    if (willSave) showInfoSnackBar(context, t(context).commonSaved);
                                return;
                              }
                              final idx = _feedRemotePosts.indexWhere((p) => p.id == post.id);
                              if (idx < 0) return;
                              final p = _feedRemotePosts[idx];
                              final list = _feedRemotePosts.toList(growable: true);
                              list[idx] = p.copyWith(viewerHasSaved: !p.viewerHasSaved);
                              setState(() => _feedRemotePosts = List.unmodifiable(list));
                  if (!p.viewerHasSaved) showInfoSnackBar(context, t(context).commonSaved);
                            },
                          );
                        },
                        childCount: posts.length + (_feedLoadingMore ? 1 : 0),
                      ),
                    );
                  },
                ),
                const SliverToBoxAdapter(child: SizedBox(height: 8)),
              ],
            ),
          ),
        );
      },
    );
  }
}

class CommunityMapScreen extends StatefulWidget {
  const CommunityMapScreen({required this.args, super.key});

  final CommunityArgs args;

  @override
  State<CommunityMapScreen> createState() => _CommunityMapScreenState();
}

enum _CommunityRequestTriageFilter { all, reported, hidden }

enum _CommunityRequestTriageSort { newest, leastPrayed, mostPrayed, mostCommented }

class _CommunityMapScreenState extends State<CommunityMapScreen> {
  final TextEditingController _triageSearch = TextEditingController();
  var _triageFilter = _CommunityRequestTriageFilter.all;
  var _triageSort = _CommunityRequestTriageSort.newest;

  @override
  void dispose() {
    _triageSearch.dispose();
    super.dispose();
  }

  Future<void> _openTriageActionsSheet(
    BuildContext context, {
    required DemoRepository repo,
    required PostModel post,
    required int reportCount,
    required List<ReportModel> reportsForPost,
  }) async {
    final isHidden = repo.isPostHidden(post.id);
    final choice = await showAtalaiaBottomSheet<String>(
      context,
      builder: (ctx) {
        return SafeArea(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              ListTile(
                leading: const Icon(Icons.open_in_new),
                title: Text(t(ctx).prayerRequestActionOpen),
                onTap: () => Navigator.of(ctx).pop('open'),
              ),
              ListTile(
                leading: const Icon(Icons.volunteer_activism_outlined),
                title: Text(t(ctx).prayerRequestActionPray),
                onTap: () => Navigator.of(ctx).pop('pray'),
              ),
              ListTile(
                leading: Icon(isHidden ? Icons.visibility_outlined : Icons.visibility_off_outlined),
                title: Text(isHidden ? t(ctx).commonUnhide : t(ctx).commonHide),
                onTap: () => Navigator.of(ctx).pop(isHidden ? 'unhide' : 'hide'),
              ),
              if (reportCount > 0)
                ListTile(
                  leading: const Icon(Icons.flag_outlined),
                  title: Text(t(ctx).reportsViewCount(reportCount)),
                  onTap: () => Navigator.of(ctx).pop('reports'),
                ),
              const Divider(height: 18),
              ListTile(
                leading: const Icon(Icons.copy_all_outlined),
                title: Text(t(ctx).prayerRequestCopyId),
                onTap: () => Navigator.of(ctx).pop('copy'),
              ),
              const SizedBox(height: 8),
            ],
          ),
        );
      },
    );

    if (!context.mounted) return;

    switch (choice) {
      case 'open':
        Navigator.of(context).pushNamed(
          Routes.postDetail,
          arguments: PostDetailArgs(postId: post.id),
        );
      case 'pray':
        repo.togglePrayer(post.id, isAuthenticated: true);
        showInfoSnackBar(context, t(context).prayerRegisteredSnack);
      case 'hide':
        repo.hidePost(post.id);
        showAtalaiaSnackBar(
          context,
          t(context).postSnackPostHidden,
          actionLabel: t(context).postSnackUndo,
          onAction: () => repo.unhidePost(post.id),
        );
      case 'unhide':
        repo.unhidePost(post.id);
        showInfoSnackBar(context, t(context).postSnackPostUnhidden);
      case 'reports':
        if (reportsForPost.isEmpty) return;
        unawaited(
          showAtalaiaBottomSheet<void>(
            context,
            builder: (ctx) {
              final l10n = t(ctx);
              return SafeArea(
                child: Column(
                  mainAxisSize: MainAxisSize.min,
                  children: [
                    ListTile(
                      title: Text(l10n.reportsTitle, style: const TextStyle(fontWeight: FontWeight.w900)),
                    ),
                    ...reportsForPost.map(
                      (r) {
                        final statusLabel = switch (r.status) {
                          ReportStatus.open => l10n.reportsStatusOpen,
                          ReportStatus.reviewing => l10n.reportsStatusReviewing,
                          ReportStatus.resolved => l10n.reportsStatusResolved,
                          ReportStatus.dismissed => l10n.reportsStatusDismissed,
                        };
                        final desc = (r.description ?? '').trim();
                        return ListTile(
                          leading: const Icon(Icons.flag_outlined),
                          title: Text(r.reason.isEmpty ? l10n.reportsNoReason : r.reason),
                          subtitle: Text(
                            '${l10n.reportsStatus(statusLabel)}${desc.isEmpty ? '' : '\n$desc'}',
                            maxLines: 3,
                            overflow: TextOverflow.ellipsis,
                          ),
                        );
                      },
                    ),
                    const SizedBox(height: 10),
                  ],
                ),
              );
            },
          ),
        );
      case 'copy':
        await Clipboard.setData(ClipboardData(text: post.id));
        if (!context.mounted) return;
        showInfoSnackBar(context, t(context).commonIdCopied);
      default:
        return;
    }
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final s = session.value;
        final c = repo.findCommunity(widget.args.communityId);
        if (c == null) {
          return Scaffold(
            appBar: AppBar(title: Text(t(context).communityMapTitle)),
            body: Center(child: Text(t(context).communityNotFound)),
          );
        }

        if (s is! AuthSession || c.viewerStatus != CommunityViewerStatus.approved) {
          return CommunityDetailScreen(args: CommunityArgs(communityId: c.id));
        }

        final posts = repo.postsForCommunity(s, c.id);
        final requestPosts = posts.where((p) => p.kind == PostKind.request).toList(growable: false);
        final map = MapScreen(key: ValueKey('community_map:${c.id}'), initialCommunityId: c.id);
        final canModerate = repo.canModerateCommunity(c.id, s.userId);

        return DefaultTabController(
          length: canModerate ? 3 : 2,
          child: Scaffold(
            appBar: AppBar(
              title: Text(c.name),
              actions: [
                Padding(
                  padding: const EdgeInsets.only(right: 6),
                  child: IconButton(
                    tooltip: t(context).communityRequestsScreenNewRequestTooltip,
                    icon: const Icon(Icons.add),
                    onPressed: repo.isOffline
                        ? null
                        : () {
                            Navigator.of(context).push(
                              MaterialPageRoute<void>(
                                builder: (_) => PostComposerScreen(draft: ComposerDraft(initialCommunityId: c.id)),
                              ),
                            );
                          },
                  ),
                ),
              ],
              bottom: TabBar(
                tabs: [
                  Tab(text: t(context).communityRequestsScreenTabMap),
                  Tab(
                    text: requestPosts.isEmpty
                        ? t(context).communityRequestsScreenTabRequests
                        : t(context).communityRequestsScreenTabRequestsWithCount(requestPosts.length),
                  ),
                  if (canModerate) Tab(text: t(context).communityRequestsScreenTabTriage),
                ],
              ),
            ),
            body: TabBarView(
              children: [
                map,
                requestPosts.isEmpty
                    ? Center(
                        child: Text(
                          t(context).communityRequestsTriageEmptyCommunity,
                          style: TextStyle(color: Theme.of(context).colorScheme.outline),
                        ),
                      )
                    : ListView.builder(
                        padding: const EdgeInsets.only(top: 8, bottom: 8),
                        itemCount: requestPosts.length,
                        itemBuilder: (context, index) {
                          final post = requestPosts[index];
                          return PostCard(
                            post: post,
                            isAuthenticated: true,
                            onOpenPost: () {
                              Navigator.of(context).pushNamed(
                                Routes.postDetail,
                                arguments: PostDetailArgs(postId: post.id),
                              );
                            },
                            onLike: () => repo.toggleLike(post.id, isAuthenticated: true),
                            onPray: () {
                              repo.togglePrayer(post.id, isAuthenticated: true);
                              showInfoSnackBar(context, t(context).prayerRegisteredSnack);
                            },
                            onComment: () {
                              Navigator.of(context).pushNamed(
                                Routes.postComments,
                                arguments: CommentsArgs(postId: post.id),
                              );
                            },
                            onShare: () async {
                              await showShareSheet(context, post: post, isAuthenticated: true);
                            },
                            onSave: () {
                              final willSave = !post.viewerHasSaved;
                              repo.toggleSave(post.id, isAuthenticated: true);
                              if (willSave) showInfoSnackBar(context, t(context).commonSaved);
                            },
                          );
                        },
                      ),
                if (canModerate)
                  Builder(
                    builder: (context) {
                      final activeReports = repo
                          .reportsForModeration()
                          .where((r) => r.entityType == ReportEntityType.post)
                          .where((r) => r.status == ReportStatus.open || r.status == ReportStatus.reviewing)
                          .toList(growable: false);
                      final reportCountByPostId = <String, int>{};
                      for (final r in activeReports) {
                        reportCountByPostId.update(r.entityId, (v) => v + 1, ifAbsent: () => 1);
                      }

                      final q = _triageSearch.text.trim().toLowerCase();
                      final filtered = requestPosts.where((p) {
                        if (_triageFilter == _CommunityRequestTriageFilter.reported) {
                          if ((reportCountByPostId[p.id] ?? 0) <= 0) return false;
                        } else if (_triageFilter == _CommunityRequestTriageFilter.hidden) {
                          if (!repo.isPostHidden(p.id)) return false;
                        }
                        if (q.isEmpty) return true;
                        final body = p.body.toLowerCase();
                        final user = p.username.toLowerCase();
                        return body.contains(q) || user.contains(q);
                      }).toList(growable: true);

                      filtered.sort((a, b) {
                        int byNum(int a, int b) => a.compareTo(b);
                        int byDate(DateTime a, DateTime b) => b.compareTo(a);
                        return switch (_triageSort) {
                          _CommunityRequestTriageSort.newest => byDate(a.createdAt, b.createdAt),
                          _CommunityRequestTriageSort.leastPrayed =>
                            byNum(a.prayerCount, b.prayerCount) != 0 ? byNum(a.prayerCount, b.prayerCount) : byDate(a.createdAt, b.createdAt),
                          _CommunityRequestTriageSort.mostPrayed =>
                            byNum(b.prayerCount, a.prayerCount) != 0 ? byNum(b.prayerCount, a.prayerCount) : byDate(a.createdAt, b.createdAt),
                          _CommunityRequestTriageSort.mostCommented =>
                            byNum(b.commentCount, a.commentCount) != 0 ? byNum(b.commentCount, a.commentCount) : byDate(a.createdAt, b.createdAt),
                        };
                      });

                      String labelForSort(_CommunityRequestTriageSort s) {
                        return switch (s) {
                          _CommunityRequestTriageSort.newest => t(context).communityRequestsTriageSortNewest,
                          _CommunityRequestTriageSort.leastPrayed => t(context).communityRequestsTriageSortLeastPrayed,
                          _CommunityRequestTriageSort.mostPrayed => t(context).communityRequestsTriageSortMostPrayed,
                          _CommunityRequestTriageSort.mostCommented => t(context).communityRequestsTriageSortMostCommented,
                        };
                      }

                      return Column(
                        children: [
                          Padding(
                            padding: const EdgeInsets.fromLTRB(12, 10, 12, 8),
                            child: SearchField(
                              controller: _triageSearch,
                              hintText: t(context).communityRequestsTriageSearchHint,
                              onChanged: (_) => setState(() {}),
                            ),
                          ),
                          Padding(
                            padding: const EdgeInsets.fromLTRB(12, 0, 12, 10),
                            child: Row(
                              children: [
                                Expanded(
                                  child: SegmentedButton<_CommunityRequestTriageFilter>(
                                    segments: [
                                      ButtonSegment(value: _CommunityRequestTriageFilter.all, label: Text(t(context).communityRequestsTriageFilterAll)),
                                      ButtonSegment(
                                        value: _CommunityRequestTriageFilter.reported,
                                        label: Text(t(context).communityRequestsTriageFilterReported),
                                      ),
                                      ButtonSegment(
                                        value: _CommunityRequestTriageFilter.hidden,
                                        label: Text(t(context).communityRequestsTriageFilterHidden),
                                      ),
                                    ],
                                    selected: {_triageFilter},
                                    onSelectionChanged: (s) => setState(() => _triageFilter = s.first),
                                  ),
                                ),
                                const SizedBox(width: 8),
                                PopupMenuButton<_CommunityRequestTriageSort>(
                                  tooltip: t(context).communityRequestsTriageSortTooltip,
                                  icon: const Icon(Icons.sort),
                                  initialValue: _triageSort,
                                  onSelected: (v) => setState(() => _triageSort = v),
                                  itemBuilder: (_) => [
                                    for (final v in _CommunityRequestTriageSort.values)
                                      PopupMenuItem(value: v, child: Text(labelForSort(v))),
                                  ],
                                ),
                              ],
                            ),
                          ),
                          Expanded(
                            child: filtered.isEmpty
                                ? Center(
                                    child: Text(
                                      _triageFilter == _CommunityRequestTriageFilter.reported
                                          ? t(context).communityRequestsTriageEmptyReported
                                          : _triageFilter == _CommunityRequestTriageFilter.hidden
                                              ? t(context).communityRequestsTriageEmptyHidden
                                              : t(context).communityRequestsTriageEmptyCommunity,
                                      style: TextStyle(color: Theme.of(context).colorScheme.outline),
                                    ),
                                  )
                                : ListView.separated(
                                    padding: const EdgeInsets.fromLTRB(12, 6, 12, 12),
                                    itemCount: filtered.length,
                                    separatorBuilder: (_, __) => const SizedBox(height: 10),
                                    itemBuilder: (context, index) {
                                      final post = filtered[index];
                                      final firstLine = post.body.trim().split('\n').first.trim();
                                      final title = firstLine.isEmpty ? t(context).communityRequestsTriagePrayerRequestFallback : firstLine;
                                      final shortTitle = title.length > 120 ? '${title.substring(0, 120)}…' : title;
                                      final when = _formatRelativeTimeForUser(context, post.createdAt);
                                      final reportCount = reportCountByPostId[post.id] ?? 0;
                                      final isHidden = repo.isPostHidden(post.id);
                                      final reportsForPost = activeReports.where((r) => r.entityId == post.id).toList(growable: false);
                                      final cs = Theme.of(context).colorScheme;
                                      final p = repo.profileForUserId(post.userId);
                                      final displayUsername = _usernameForProfile(p, userId: post.userId);

                                      return Card(
                                        child: ListTile(
                                          title: Text(shortTitle, maxLines: 2, overflow: TextOverflow.ellipsis),
                                          subtitle: Column(
                                            crossAxisAlignment: CrossAxisAlignment.start,
                                            children: [
                                              const SizedBox(height: 4),
                                              Text(
                                                '@$displayUsername • $when',
                                                style: TextStyle(color: cs.onSurfaceVariant),
                                              ),
                                              const SizedBox(height: 8),
                                              Wrap(
                                                spacing: 6,
                                                runSpacing: 6,
                                                children: [
                                                  _TriageMetricChip(
                                                    icon: Icons.volunteer_activism_outlined,
                                                    label: '${post.prayerCount}',
                                                  ),
                                                  _TriageMetricChip(
                                                    icon: Icons.mode_comment_outlined,
                                                    label: '${post.commentCount}',
                                                  ),
                                                  if (reportCount > 0)
                                                    _TriageMetricChip(
                                                      icon: Icons.flag_outlined,
                                                      label: '$reportCount',
                                                      fg: cs.onErrorContainer,
                                                      bg: cs.errorContainer,
                                                    ),
                                                  if (isHidden)
                                                    _TriageMetricChip(
                                                      icon: Icons.visibility_off_outlined,
                                                      label: t(context).communityRequestsTriageHiddenChip,
                                                      fg: cs.onSurfaceVariant,
                                                      bg: cs.surfaceContainerHighest,
                                                    ),
                                                ],
                                              ),
                                            ],
                                          ),
                                          isThreeLine: true,
                                          onTap: () {
                                            Navigator.of(context).pushNamed(
                                              Routes.postDetail,
                                              arguments: PostDetailArgs(postId: post.id),
                                            );
                                          },
                                          trailing: IconButton(
                                            icon: const Icon(Icons.more_horiz),
                                            onPressed: () => unawaited(
                                              _openTriageActionsSheet(
                                                context,
                                                repo: repo,
                                                post: post,
                                                reportCount: reportCount,
                                                reportsForPost: reportsForPost,
                                              ),
                                            ),
                                          ),
                                        ),
                                      );
                                    },
                                  ),
                          ),
                        ],
                      );
                    },
                  ),
              ],
            ),
          ),
        );
      },
    );
  }
}

