class _ExpandableText extends StatefulWidget {
  const _ExpandableText({required this.text, required this.maxLines});

  final String text;
  final int maxLines;

  @override
  State<_ExpandableText> createState() => _ExpandableTextState();
}

class _ExpandableTextState extends State<_ExpandableText> {
  var _expanded = false;

  @override
  Widget build(BuildContext context) {
    final l10n = t(context);
    return LayoutBuilder(
      builder: (context, constraints) {
        final tp = TextPainter(
          text: TextSpan(text: widget.text, style: DefaultTextStyle.of(context).style),
          maxLines: widget.maxLines,
          textDirection: Directionality.of(context),
        )..layout(maxWidth: constraints.maxWidth);
        final overflow = tp.didExceedMaxLines;

        return Column(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Text(
              widget.text,
              maxLines: _expanded ? null : widget.maxLines,
              overflow: _expanded ? TextOverflow.visible : TextOverflow.ellipsis,
            ),
            if (overflow) ...[
              const SizedBox(height: 6),
              Align(
                alignment: Alignment.centerLeft,
                child: AtalaiaTextButton(
                  label: _expanded ? l10n.commonSeeLess : l10n.commonSeeMore,
                  onPressed: () => setState(() => _expanded = !_expanded),
                ),
              ),
            ],
          ],
        );
      },
    );
  }
}

class ProfileScreen extends StatelessWidget {
  const ProfileScreen({this.embedded = false, super.key});

  final bool embedded;

  @override
  Widget build(BuildContext context) {
    final session = SessionScope.of(context);

    return ValueListenableBuilder(
      valueListenable: session,
      builder: (context, value, _) {
        if (value is! AuthSession) {
          final content = Center(
            child: PrimaryButton(label: t(context).profileSignInToView, onPressed: () => showCtaSnackBar(context)),
          );
          if (embedded) return content;
          return Scaffold(
            appBar: AppBar(title: Text(t(context).profileTitle, style: const TextStyle(fontWeight: FontWeight.w800))),
            body: content,
          );
        }

        return _AnalyticsOnce(
          eventName: 'profile_view',
          fieldsBuilder: (_) => <String, Object?>{'userId': value.userId},
          child: UserProfileScreen(
            args: UserProfileArgs(userId: value.userId),
            showBack: false,
            embedded: embedded,
          ),
        );
      },
    );
  }
}

class UserProfileScreen extends StatelessWidget {
  const UserProfileScreen({
    required this.args,
    this.showBack = true,
    this.embedded = false,
    super.key,
  });

  final UserProfileArgs args;
  final bool showBack;
  final bool embedded;

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final l10n = t(context);
        final profile = repo.profileForUserId(args.userId);
        if (profile == null) {
          if (embedded) return Center(child: Text(l10n.profileNotFound));
          return Scaffold(
            appBar: AppBar(
              leading: showBack
                  ? AtalaiaIconButton(
                      icon: Icons.arrow_back,
                      label: l10n.commonBack,
                      onPressed: () => Navigator.of(context).maybePop(),
                    )
                  : null,
              title: Text(l10n.profileTitle),
            ),
            body: Center(child: Text(l10n.profileNotFound)),
          );
        }

        final s = session.value;
        final isAuthenticated = s.isAuthenticated;
        final isMe = s is AuthSession && s.userId == profile.userId;
        final cs = Theme.of(context).colorScheme;
        final posts = repo.visiblePostsFor(s).where((p) => p.userId == profile.userId).toList(growable: false);
        final mediaPosts = posts.where((p) => p.mediaKind != null).toList(growable: false);
        final prayerReceived = posts.fold<int>(0, (acc, p) => acc + p.prayerCount);

        Future<void> onMenuSelected(String v) async {
          switch (v) {
            case 'settings':
              Navigator.of(context).pushNamed(Routes.settings);
            case 'verification':
              final s = session.value;
              if (s is! AuthSession) {
                showAuthGate(context);
                return;
              }
              final userId = s.userId;
              final repo = RepoScope.of(context);
              final active =
                  repo.hasActiveVerification(userId) || (repo.profileForUserId(userId)?.isVerified ?? false);
              Navigator.of(context).pushNamed(active ? Routes.verificationStatus : Routes.verificationPaywall);
            case 'logout':
              showLogoutConfirmDialog(context);
            case 'report':
              final s = session.value;
              if (s is! AuthSession) {
                showAuthGate(context);
                return;
              }
              final selected = await showReportReasonSheet(context);
              if (!context.mounted) return;
              if (selected != null) {
                await RepoScope.of(context).submitReport(
                  reporterId: s.userId,
                  entityType: ReportEntityType.user,
                  entityId: profile.userId,
                  reason: selected.reason.name,
                  description: selected.otherText,
                  reportedUserId: profile.userId,
                );
                if (!context.mounted) return;
                showInfoSnackBar(context, l10n.postSnackReportSent);
              }
            case 'copy':
              showInfoSnackBar(context, l10n.commonLinkCopied);
          }
        }

        List<PopupMenuEntry<String>> menuItems() {
          if (isMe) {
            return [
              PopupMenuItem(value: 'settings', child: Text(l10n.profileSettings)),
              PopupMenuItem(value: 'verification', child: Text(l10n.profileVerification)),
              PopupMenuItem(value: 'logout', child: Text(l10n.profileLogout)),
            ];
          }
          return [
            PopupMenuItem(value: 'report', child: Text(l10n.profileReport)),
            PopupMenuItem(value: 'copy', child: Text(l10n.profileCopyProfileLink)),
          ];
        }

        final profileBody = DefaultTabController(
          length: 2,
          child: ListView(
            padding: const EdgeInsets.all(12),
            children: [
              if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
              _ProfileHeader(
                profile: profile,
                isMe: isMe,
                isAuthenticated: isAuthenticated,
                isFollowing: repo.isFollowingUser(profile.userId),
                followLoading: repo.isFollowTogglingUser(profile.userId),
                onToggleFollow: () {
                  if (!isAuthenticated) {
                    return showLoginSnackBar(context, message: l10n.profileFollowToggleSignIn);
                  }
                  if (repo.isFollowTogglingUser(profile.userId)) return;
                  unawaited(() async {
                    final ok = await repo.toggleFollowUser(profile.userId, isAuthenticated: true);
                    if (!context.mounted) return;
                    if (!ok) {
                      final msg = repo.lastFollowToggleError?.trim();
                      showAtalaiaSnackBar(
                        context,
                        msg == null || msg.isEmpty ? t(context).commonSomethingWentWrong : msg,
                        kind: AtalaiaSnackKind.error,
                      );
                      return;
                    }
                    showInfoSnackBar(
                      context,
                      repo.isFollowingUser(profile.userId) ? l10n.profileSnackFollowing : l10n.profileSnackUnfollowed,
                    );
                  }());
                },
                onMessage: () {
                  if (!isAuthenticated) {
                    return showLoginSnackBar(context, message: l10n.profileFollowToggleSignIn);
                  }
                  final t = repo.openOrCreateThreadWith(profile);
                  Navigator.of(context).pushNamed(
                    Routes.chat,
                    arguments: ChatArgs(
                      threadId: t.id,
                      peerName: t.peerName,
                      peerUsername: t.peerUsername,
                      peerIsVerified: t.peerIsVerified,
                      peerAvatarUrl: profile.avatarUrl,
                    ),
                  );
                },
                onEditProfile: () {
                  Navigator.of(context).pushNamed(
                    Routes.editProfile,
                    arguments: EditProfileArgs(userId: profile.userId),
                  );
                },
              ),
              const SizedBox(height: 12),
              _ProfileStatsRow(
                postsCount: posts.length,
                followersCount: repo.followersCountForUser(profile.userId),
                followingCount: repo.followingCountForUser(profile.userId),
                prayersReceivedCount: prayerReceived,
                onTapFollowers: () {
                  Navigator.of(context).pushNamed(
                    Routes.followersFollowing,
                    arguments: FollowersFollowingArgs(userId: profile.userId, initialTab: 0),
                  );
                },
                onTapFollowing: () {
                  Navigator.of(context).pushNamed(
                    Routes.followersFollowing,
                    arguments: FollowersFollowingArgs(userId: profile.userId, initialTab: 1),
                  );
                },
              ),
              const SizedBox(height: 12),
              Builder(
                builder: (context) {
                  final controller = DefaultTabController.of(context);
                  return AnimatedBuilder(
                    animation: controller,
                    builder: (context, _) {
                      final idx = controller.index;
                      return TabBar(
                        labelColor: cs.onSurface,
                        unselectedLabelColor: cs.onSurfaceVariant,
                        dividerColor: Colors.transparent,
                        indicatorSize: TabBarIndicatorSize.label,
                        indicator: BoxDecoration(
                          color: cs.primary.withValues(alpha: 0.14),
                          borderRadius: BorderRadius.circular(999),
                        ),
                        indicatorPadding: const EdgeInsets.symmetric(horizontal: 6, vertical: 6),
                        overlayColor: WidgetStatePropertyAll(cs.onSurface.withValues(alpha: 0.06)),
                        tabs: [
                          Tab(
                            icon: Padding(
                              padding: const EdgeInsets.symmetric(horizontal: 18, vertical: 10),
                              child: Icon(idx == 0 ? Icons.view_agenda : Icons.view_agenda_outlined),
                            ),
                          ),
                          Tab(
                            icon: Padding(
                              padding: const EdgeInsets.symmetric(horizontal: 18, vertical: 10),
                              child: Icon(idx == 1 ? Icons.grid_on : Icons.grid_on_outlined),
                            ),
                          ),
                        ],
                      );
                    },
                  );
                },
              ),
              const SizedBox(height: 12),
              SizedBox(
                height: MediaQuery.sizeOf(context).height * 0.62,
                child: TabBarView(
                  children: [
                    _ProfilePostsList(
                      posts: posts,
                      isAuthenticated: isAuthenticated,
                      canCreate: isMe,
                      onCreate: () => Navigator.of(context).pushNamed(Routes.createPost),
                    ),
                    _ProfileMediaGrid(posts: mediaPosts),
                  ],
                ),
              ),
            ],
          ),
        );

        if (embedded) return profileBody;

        return Scaffold(
          appBar: AppBar(
            leading: showBack
                ? AtalaiaIconButton(
                    icon: Icons.arrow_back,
                    label: t(context).commonBack,
                    onPressed: () => Navigator.of(context).maybePop(),
                  )
                : null,
            title: Text(
              '@${_usernameForProfile(profile, userId: profile.userId)}',
              style: const TextStyle(fontWeight: FontWeight.w800),
            ),
            actions: [
              if (isMe)
                AtalaiaIconButton(
                  icon: Icons.add,
                  label: 'Criar post',
                  onPressed: () => Navigator.of(context).pushNamed(Routes.createPost),
                ),
              PopupMenuButton<String>(
                icon: const Icon(Icons.more_horiz),
                onSelected: (v) => unawaited(onMenuSelected(v)),
                itemBuilder: (_) => menuItems(),
              ),
            ],
          ),
          body: profileBody,
        );
      },
    );
  }
}

