class _ProfilePostsList extends StatefulWidget {
  const _ProfilePostsList({
    required this.posts,
    required this.isAuthenticated,
    required this.canCreate,
    required this.onCreate,
  });

  final List<PostModel> posts;
  final bool isAuthenticated;
  final bool canCreate;
  final VoidCallback onCreate;

  @override
  State<_ProfilePostsList> createState() => _ProfilePostsListState();
}

class _ProfilePostsListState extends State<_ProfilePostsList> {
  var _refreshing = false;

  Future<void> _onRefresh() async {
    setState(() => _refreshing = true);
    await Future<void>.delayed(const Duration(milliseconds: 450));
    if (!mounted) return;
    setState(() => _refreshing = false);
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    return RefreshIndicator(
      onRefresh: _onRefresh,
      child: _refreshing
          ? ListView.builder(
              physics: const AlwaysScrollableScrollPhysics(),
              padding: EdgeInsets.zero,
              itemCount: 6,
              itemBuilder: (context, index) => PostCardSkeleton(
                hasMedia: index.isEven,
                margin: const EdgeInsets.fromLTRB(0, 0, 0, 12),
              ),
            )
          : widget.posts.isEmpty
              ? ListView(
                  physics: const AlwaysScrollableScrollPhysics(),
                  children: [
                    SizedBox(height: MediaQuery.sizeOf(context).height * 0.14),
                    EmptyState(
                      icon: Icons.inbox_outlined,
                                      title: t(context).feedEmptyPosts,
                                      ctaLabel: widget.canCreate ? t(context).feedCreatePost : null,
                      onCta: widget.canCreate ? widget.onCreate : null,
                    ),
                  ],
                )
              : ListView.builder(
                  physics: const AlwaysScrollableScrollPhysics(),
                  padding: EdgeInsets.zero,
                  itemCount: widget.posts.length,
                  itemBuilder: (context, i) {
                    final post = widget.posts[i];
                    return PostCard(
                      post: post,
                      isAuthenticated: widget.isAuthenticated,
                      margin: const EdgeInsets.fromLTRB(0, 0, 0, 12),
                      compact: true,
                      onOpenPost: () {
                        Navigator.of(context).pushNamed(
                          Routes.postDetail,
                          arguments: PostDetailArgs(postId: post.id),
                        );
                      },
                      onLike: () {
                        if (!widget.isAuthenticated) return showCtaSnackBar(context);
                        repo.toggleLike(post.id, isAuthenticated: true);
                      },
                      onPray: () {
                        if (!widget.isAuthenticated) return showCtaSnackBar(context);
                        repo.togglePrayer(post.id, isAuthenticated: true);
                        showInfoSnackBar(context, t(context).prayerRegisteredSnack);
                      },
                      onComment: () {
                        Navigator.of(context).pushNamed(
                          Routes.postComments,
                          arguments: CommentsArgs(postId: post.id),
                        );
                      },
                      onShare: () async {
                        await showShareSheet(context, post: post, isAuthenticated: widget.isAuthenticated);
                      },
                      onSave: () {
                        if (!widget.isAuthenticated) return showCtaSnackBar(context);
                        final willSave = !post.viewerHasSaved;
                        repo.toggleSave(post.id, isAuthenticated: true);
                        if (willSave) showInfoSnackBar(context, t(context).commonSaved);
                      },
                    );
                  },
                ),
    );
  }
}

class _ProfileMediaGrid extends StatelessWidget {
  const _ProfileMediaGrid({required this.posts});

  final List<PostModel> posts;

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    if (posts.isEmpty) {
      return Center(
        child: Text(
          'Sem mídia ainda.',
          style: TextStyle(color: cs.outline),
        ),
      );
    }
    return GridView.builder(
      padding: EdgeInsets.zero,
      gridDelegate: const SliverGridDelegateWithFixedCrossAxisCount(
        crossAxisCount: 3,
        crossAxisSpacing: 3,
        mainAxisSpacing: 3,
      ),
      itemCount: posts.length,
      itemBuilder: (context, i) {
        final post = posts[i];
        final url = (post.mediaUrl ?? '').trim();
        final hasNetwork = url.isNotEmpty && (url.startsWith('https://') || url.startsWith('http://'));
        return ClipRRect(
          borderRadius: BorderRadius.circular(12),
          child: Material(
            color: cs.surfaceContainerHighest,
            child: InkWell(
              onTap: () {
                Navigator.of(context).pushNamed(
                  Routes.postDetail,
                  arguments: PostDetailArgs(postId: post.id),
                );
              },
              child: Stack(
                children: [
                  Positioned.fill(
                    child: hasNetwork
                        ? Image.network(
                            url,
                            fit: BoxFit.cover,
                            errorBuilder: (_, __, ___) => Center(child: Icon(Icons.image_outlined, color: cs.outline)),
                          )
                        : Center(child: Icon(Icons.image_outlined, color: cs.outline)),
                  ),
                  if (post.mediaKind == 'video')
                    Align(
                      alignment: Alignment.topRight,
                      child: Padding(
                        padding: const EdgeInsets.all(6),
                        child: Container(
                          padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 6),
                          decoration: BoxDecoration(
                            color: cs.surface.withValues(alpha: 0.82),
                            borderRadius: BorderRadius.circular(999),
                          ),
                          child: Icon(Icons.videocam, size: 16, color: cs.onSurface),
                        ),
                      ),
                    ),
                ],
              ),
            ),
          ),
        );
      },
    );
  }
}

class FollowersFollowingScreen extends StatefulWidget {
  const FollowersFollowingScreen({required this.args, super.key});

  final FollowersFollowingArgs args;

  @override
  State<FollowersFollowingScreen> createState() => _FollowersFollowingScreenState();
}

class _FollowersFollowingScreenState extends State<FollowersFollowingScreen> with SingleTickerProviderStateMixin {
  late final TabController _tabController;
  final _search = TextEditingController();
  var _query = '';
  var _loading = true;

  @override
  void initState() {
    super.initState();
    _tabController = TabController(length: 2, vsync: this, initialIndex: widget.args.initialTab);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(() async {
        final startedAt = DateTime.now();
        final repo = RepoScope.of(context);
        await repo.refreshFollowsForUser(widget.args.userId);
        final elapsed = DateTime.now().difference(startedAt);
        final minWait = const Duration(milliseconds: 260);
        if (elapsed < minWait) {
          await Future<void>.delayed(minWait - elapsed);
        }
        if (!mounted) return;
        setState(() => _loading = false);
      }());
    });
  }

  @override
  void dispose() {
    _tabController.dispose();
    _search.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final isAuthenticated = session.value.isAuthenticated;
        final profile = repo.profileForUserId(widget.args.userId);
        final title = profile == null
            ? t(context).profileFollowers
            : '@${_usernameForProfile(profile, userId: profile.userId)}';

        final followers = repo.followersForUser(widget.args.userId, query: _query);
        final following = repo.followingForUser(widget.args.userId, query: _query);

        return Scaffold(
          appBar: AppBar(
            leading: AtalaiaIconButton(
              icon: Icons.arrow_back,
              label: t(context).commonBack,
              onPressed: () => Navigator.of(context).maybePop(),
            ),
            title: Text(title, style: const TextStyle(fontWeight: FontWeight.w800)),
            bottom: TabBar(
              controller: _tabController,
              tabs: [
                Tab(text: t(context).profileFollowers),
                Tab(text: t(context).profileFollowingLabel),
              ],
            ),
          ),
          body: Column(
            children: [
              if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
              Padding(
                padding: const EdgeInsets.all(AtalaiaSpacing.md),
                child: SearchField(
                  controller: _search,
                  hintText: t(context).commonSearch,
                  onChanged: (v) => setState(() => _query = v),
                ),
              ),
              Expanded(
                child: TabBarView(
                  controller: _tabController,
                  children: [
                    _PeopleList(
                      people: followers,
                      isAuthenticated: isAuthenticated,
                      emptyLabel: t(context).followersEmptyFollowers,
                      loading: _loading,
                    ),
                    _PeopleList(
                      people: following,
                      isAuthenticated: isAuthenticated,
                      emptyLabel: t(context).followersEmptyFollowing,
                      loading: _loading,
                    ),
                  ],
                ),
              ),
            ],
          ),
        );
      },
    );
  }
}

class _PeopleList extends StatelessWidget {
  const _PeopleList({
    required this.people,
    required this.isAuthenticated,
    required this.emptyLabel,
    required this.loading,
  });

  final List<ProfileModel> people;
  final bool isAuthenticated;
  final String emptyLabel;
  final bool loading;

  @override
  Widget build(BuildContext context) {
    if (loading) {
      return ListView.separated(
        padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
        itemCount: 8,
        separatorBuilder: (_, __) => const SizedBox(height: 10),
        itemBuilder: (_, __) => const RowSkeleton(),
      );
    }
    if (people.isEmpty) {
      return ListView(
        physics: const AlwaysScrollableScrollPhysics(),
        children: [
          SizedBox(height: MediaQuery.sizeOf(context).height * 0.18),
          EmptyState(
            icon: Icons.person_outline,
            title: emptyLabel,
          ),
        ],
      );
    }
    return ListView.separated(
      padding: const EdgeInsets.symmetric(horizontal: 12, vertical: 6),
      itemCount: people.length,
      separatorBuilder: (_, __) => const SizedBox(height: 2),
      itemBuilder: (context, i) {
        return PeopleResultRow(profile: people[i], isAuthenticated: isAuthenticated);
      },
    );
  }
}

class EditProfileScreen extends StatefulWidget {
  const EditProfileScreen({required this.args, super.key});

  final EditProfileArgs args;

  @override
  State<EditProfileScreen> createState() => _EditProfileScreenState();
}

class _EditProfileScreenState extends State<EditProfileScreen> {
  final _name = TextEditingController();
  final _bio = TextEditingController();
  final _church = TextEditingController();

  var _saving = false;
  double? _savingProgress;
  var _loaded = false;

  @override
  void dispose() {
    _name.dispose();
    _bio.dispose();
    _church.dispose();
    super.dispose();
  }

  bool _isValid() {
    return _name.text.trim().length >= 2;
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final s = session.value;
        final isMe = s is AuthSession && s.userId == widget.args.userId;
        if (!isMe) {
          return Scaffold(
            appBar: AppBar(
              leading: AtalaiaIconButton(
                icon: Icons.arrow_back,
                label: t(context).commonBack,
                onPressed: () => Navigator.of(context).maybePop(),
              ),
              title: Text(t(context).profileEditProfile),
            ),
            body: Center(
              child: PrimaryButton(label: t(context).settingsSignInToContinue, onPressed: () => showCtaSnackBar(context)),
            ),
          );
        }

        final profile = repo.profileForUserId(widget.args.userId);
        if (profile == null) {
          return Scaffold(
            appBar: AppBar(
              leading: AtalaiaIconButton(
                icon: Icons.arrow_back,
                label: t(context).commonBack,
                onPressed: () => Navigator.of(context).maybePop(),
              ),
              title: Text(t(context).profileEditProfile),
            ),
            body: Center(child: Text(t(context).profileNotFound)),
          );
        }

        if (!_loaded) {
          _name.text = profile.name;
          _bio.text = profile.bio;
          _church.text = profile.churchName ?? '';
          _loaded = true;
        }

        final canSave = _isValid() && !_saving;
        final cs = Theme.of(context).colorScheme;
        final displayName = _displayNameForProfile(profile, userFallback: t(context).commonUserFallback);
        final displayUsername = _usernameForProfile(profile, userId: profile.userId);

        Future<void> onSave() async {
          if (!canSave) return;
          setState(() {
            _saving = true;
            _savingProgress = null;
          });
          await Future<void>.delayed(const Duration(milliseconds: 520));
          if (repo.isOffline) {
            setState(() {
              _saving = false;
              _savingProgress = null;
            });
            showErrorSnackBar(context, onRetry: onSave);
            return;
          }

          repo.updateProfile(
            widget.args.userId,
            name: _name.text.trim(),
            bio: _bio.text.trim(),
            churchName: _church.text.trim().isEmpty ? null : _church.text.trim(),
          );
          setState(() {
            _saving = false;
            _savingProgress = null;
          });
          showInfoSnackBar(context, t(context).profileEditUpdated);
          Navigator.of(context).maybePop();
        }

        return Scaffold(
          appBar: AppBar(
            leading: AtalaiaIconButton(
              icon: Icons.arrow_back,
              label: t(context).commonBack,
              onPressed: _saving ? null : () => Navigator.of(context).maybePop(),
            ),
            title: Text(t(context).profileEditProfile, style: const TextStyle(fontWeight: FontWeight.w800)),
            actions: [
              AtalaiaTextButton(label: t(context).commonSave, onPressed: canSave ? onSave : null),
            ],
          ),
          body: ListView(
            padding: const EdgeInsets.all(12),
            children: [
              if (_saving) LinearProgressIndicator(value: _savingProgress),
              const SizedBox(height: 12),
              Card(
                child: Padding(
                  padding: const EdgeInsets.all(12),
                  child: Row(
                    children: [
                      Avatar(name: displayName, imageUrl: profile.avatarUrl, size: AvatarSize.s72),
                      const SizedBox(width: 12),
                      Expanded(
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Text(displayName, style: const TextStyle(fontWeight: FontWeight.w900)),
                            Text('@$displayUsername', style: TextStyle(color: cs.outline)),
                          ],
                        ),
                      ),
                      SecondaryButton(
                        label: t(context).profileEditChangePhoto,
                        onPressed: _saving
                            ? null
                            : () => _changeAvatar(
                                  profile: profile,
                                  repo: repo,
                                ),
                      ),
                    ],
                  ),
                ),
              ),
              const SizedBox(height: 12),
              AtalaiaTextField(
                controller: _name,
                labelText: t(context).profileEditNameLabel,
                hintText: t(context).profileEditNameHint,
                textInputAction: TextInputAction.next,
                onChanged: (_) => setState(() {}),
              ),
              const SizedBox(height: 12),
              AtalaiaTextField(
                controller: _bio,
                labelText: t(context).profileEditBioLabel,
                hintText: t(context).profileEditBioHint,
                errorText: null,
                minLines: 3,
                maxLines: 6,
                textInputAction: TextInputAction.newline,
                keyboardType: TextInputType.multiline,
              ),
              const SizedBox(height: 12),
              AtalaiaTextField(
                controller: _church,
                labelText: t(context).profileEditChurchOptionalLabel,
                hintText: t(context).profileEditChurchHint,
                textInputAction: TextInputAction.done,
                onChanged: (_) => setState(() {}),
              ),
              const SizedBox(height: 18),
              SizedBox(
                width: double.infinity,
                child: PrimaryButton(
                  label: t(context).commonSave,
                  onPressed: canSave ? onSave : null,
                  loading: _saving,
                ),
              ),
            ],
          ),
        );
      },
    );
  }

  Future<void> _changeAvatar({
    required ProfileModel profile,
    required DemoRepository repo,
  }) async {
    if (_saving) return;
    if (repo.isOffline) {
      showErrorSnackBar(context, onRetry: () => _changeAvatar(profile: profile, repo: repo));
      return;
    }
    if (repo.supabase == null) {
      showInfoSnackBar(context, t(context).uploadSupabaseOnly);
      return;
    }

    final choice = await showAtalaiaBottomSheet<String>(
      context,
      isScrollControlled: false,
      builder: (context) {
        final l10n = t(context);
        return SafeArea(
          child: Column(
            mainAxisSize: MainAxisSize.min,
            children: [
              ListTile(
                leading: const Icon(Icons.photo_camera_outlined),
                title: Text(l10n.commonCamera),
                onTap: () => Navigator.of(context).pop('camera'),
              ),
              ListTile(
                leading: const Icon(Icons.photo_library_outlined),
                title: Text(l10n.commonGallery),
                onTap: () => Navigator.of(context).pop('gallery'),
              ),
              const SizedBox(height: 8),
            ],
          ),
        );
      },
    );
    if (!mounted) return;
    if (choice == null) return;

    final picked = await FilePicker.platform.pickFiles(
      type: FileType.image,
      allowMultiple: false,
      withData: true,
    );
    if (!mounted) return;
    final file = (picked == null || picked.files.isEmpty) ? null : picked.files.first;
    if (file == null) return;

    final originalBytes = await _bytesFromPlatformFile(file);
    if (!mounted) return;
    if (originalBytes == null || originalBytes.isEmpty) {
      showInfoSnackBar(context, t(context).imageReadFailed);
      return;
    }

    if (originalBytes.lengthInBytes > 10 * 1024 * 1024) {
      showInfoSnackBar(context, t(context).photoTooLargeMax10mb);
      return;
    }

    Uint8List processed;
    try {
      processed = _prepareProfileAvatarJpeg(originalBytes);
    } catch (_) {
      showInfoSnackBar(context, t(context).imageInvalid);
      return;
    }

    setState(() {
      _saving = true;
      _savingProgress = 0.35;
    });

    try {
      setState(() => _savingProgress = 0.6);
      String? url;
      try {
        url = await repo.uploadProfileAvatar(userId: profile.userId, jpegBytes: processed);
      } on StorageException catch (e) {
        if (!mounted) return;
        setState(() {
          _saving = false;
          _savingProgress = null;
        });
        final code = e.statusCode == null ? '' : ' (${e.statusCode})';
        showAtalaiaSnackBar(
          context,
          t(context).uploadFailedWithCode(code, e.message),
          kind: AtalaiaSnackKind.error,
        );
        return;
      } catch (_) {
        url = null;
      }
      if (!mounted) return;
      if (url == null) {
        setState(() {
          _saving = false;
          _savingProgress = null;
        });
        showErrorSnackBar(context, onRetry: () => _changeAvatar(profile: profile, repo: repo));
        return;
      }
      setState(() => _savingProgress = 1);
      showInfoSnackBar(context, t(context).photoUpdated);
    } finally {
      if (!mounted) return;
      setState(() {
        _saving = false;
        _savingProgress = null;
      });
    }
  }

  Future<Uint8List?> _bytesFromPlatformFile(PlatformFile file) async {
    final bytes = file.bytes;
    if (bytes != null) return bytes;
    final stream = file.readStream;
    if (stream == null) return null;
    final list = <int>[];
    await for (final chunk in stream) {
      list.addAll(chunk);
    }
    return Uint8List.fromList(list);
  }

  Uint8List _prepareProfileAvatarJpeg(Uint8List input) {
    final decoded = img.decodeImage(input);
    if (decoded == null) throw StateError('invalid_image');
    final side = math.min(decoded.width, decoded.height);
    final x = ((decoded.width - side) / 2).round();
    final y = ((decoded.height - side) / 2).round();
    final cropped = img.copyCrop(decoded, x: x, y: y, width: side, height: side);
    final resized = img.copyResize(
      cropped,
      width: 1080,
      height: 1080,
      interpolation: img.Interpolation.cubic,
    );
    final encoded = img.encodeJpg(resized, quality: 85);
    return Uint8List.fromList(encoded);
  }
}

class EditCommunityScreen extends StatefulWidget {
  const EditCommunityScreen({required this.args, super.key});

  final EditCommunityArgs args;

  @override
  State<EditCommunityScreen> createState() => _EditCommunityScreenState();
}

class _EditCommunityScreenState extends State<EditCommunityScreen> {
  final _name = TextEditingController();
  final _description = TextEditingController();
  final _rules = TextEditingController();

  var _saving = false;
  double? _savingProgress;
  var _loaded = false;

  @override
  void dispose() {
    _name.dispose();
    _description.dispose();
    _rules.dispose();
    super.dispose();
  }

  bool _isValid() {
    return _name.text.trim().length >= 2;
  }

  List<String> _parseRules() {
    return _rules.text
        .split('\n')
        .map((s) => s.trim())
        .where((s) => s.isNotEmpty)
        .toList(growable: false);
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final s = session.value;
        final viewerId = s is AuthSession ? s.userId : null;
        if (viewerId == null) {
          return Scaffold(
            appBar: AppBar(
              leading: AtalaiaIconButton(
                icon: Icons.arrow_back,
                label: t(context).commonBack,
                onPressed: () => Navigator.of(context).maybePop(),
              ),
              title: Text(t(context).communityEditTitle),
            ),
            body: Center(
              child: PrimaryButton(label: t(context).settingsSignInToContinue, onPressed: () => showCtaSnackBar(context)),
            ),
          );
        }

        final c = repo.findCommunity(widget.args.communityId);
        if (c == null) {
          return Scaffold(
            appBar: AppBar(
              leading: AtalaiaIconButton(
                icon: Icons.arrow_back,
                label: t(context).commonBack,
                onPressed: () => Navigator.of(context).maybePop(),
              ),
              title: Text(t(context).communityEditTitle),
            ),
            body: Center(child: Text(t(context).communityNotFound)),
          );
        }

        if (repo.supabase != null && !repo.isOffline) {
          unawaited(repo.refreshCommunityMembers(c.id));
        }
        final role = (c.viewerRole ?? '').trim().toLowerCase();
        final canModerate = c.ownerId == viewerId || role == 'admin' || role == 'moderator' || role == 'founder';
        if (!canModerate) {
          return Scaffold(
            appBar: AppBar(
              leading: AtalaiaIconButton(
                icon: Icons.arrow_back,
                label: t(context).commonBack,
                onPressed: () => Navigator.of(context).maybePop(),
              ),
              title: Text(t(context).communityEditTitle),
            ),
            body: Center(child: Text(t(context).communityEditNoPermission)),
          );
        }

        if (!_loaded) {
          _name.text = c.name;
          _description.text = c.description;
          _rules.text = c.rules.join('\n');
          _loaded = true;
        }

        final canSave = _isValid() && !_saving;
        final cs = Theme.of(context).colorScheme;

        Future<void> onSave() async {
          if (!canSave) return;
          setState(() {
            _saving = true;
            _savingProgress = null;
          });
          try {
            await Future<void>.delayed(const Duration(milliseconds: 520));
            if (repo.isOffline) {
              showErrorSnackBar(context, onRetry: onSave);
              return;
            }

            final ok = await repo.updateCommunity(
              c.id,
              name: _name.text,
              description: _description.text,
              rules: _parseRules(),
            );
            if (!mounted) return;
            if (!ok) {
              final msg = (repo.lastCommunityUpdateError ?? '').trim();
              if (msg.isEmpty) {
                showErrorSnackBar(context, onRetry: onSave);
              } else {
                showAtalaiaSnackBar(
                  context,
                  msg,
                  kind: AtalaiaSnackKind.error,
                  actionLabel: 'Tentar',
                  onAction: onSave,
                );
              }
              return;
            }
            showInfoSnackBar(context, 'Comunidade atualizada');
            Navigator.of(context).maybePop();
          } finally {
            if (!mounted) return;
            setState(() {
              _saving = false;
              _savingProgress = null;
            });
          }
        }

        return Scaffold(
          appBar: AppBar(
            leading: AtalaiaIconButton(
              icon: Icons.arrow_back,
              label: t(context).commonBack,
              onPressed: _saving ? null : () => Navigator.of(context).maybePop(),
            ),
            title: Text(t(context).communityEditTitle, style: const TextStyle(fontWeight: FontWeight.w800)),
            actions: [
              AtalaiaTextButton(label: t(context).commonSave, onPressed: canSave ? onSave : null),
            ],
          ),
          body: ListView(
            padding: const EdgeInsets.all(12),
            children: [
              if (_saving) LinearProgressIndicator(value: _savingProgress),
              const SizedBox(height: 12),
              Card(
                child: Padding(
                  padding: const EdgeInsets.all(12),
                  child: Row(
                    children: [
                      Avatar(name: c.name, imageUrl: c.imageUrl, size: AvatarSize.s72),
                      const SizedBox(width: 12),
                      Expanded(
                        child: Column(
                          crossAxisAlignment: CrossAxisAlignment.start,
                          children: [
                            Text(c.name, style: const TextStyle(fontWeight: FontWeight.w900)),
                            Text(t(context).communityEditSubtitle, style: TextStyle(color: cs.outline)),
                          ],
                        ),
                      ),
                      SecondaryButton(
                        label: t(context).communityEditChangePhoto,
                        onPressed: _saving ? null : () => _changeAvatar(repo: repo, communityId: c.id),
                      ),
                    ],
                  ),
                ),
              ),
              const SizedBox(height: 12),
              AtalaiaTextField(
                controller: _name,
                hintText: t(context).communityEditNameHint,
                textInputAction: TextInputAction.next,
                onChanged: (_) => setState(() {}),
              ),
              const SizedBox(height: 12),
              MultiLineComposer(
                controller: _description,
                hintText: t(context).communityEditDescriptionHint,
                errorText: null,
              ),
              const SizedBox(height: 12),
              MultiLineComposer(
                controller: _rules,
                hintText: t(context).communityEditRulesHint,
                errorText: null,
              ),
              const SizedBox(height: 18),
              SizedBox(
                width: double.infinity,
                child: PrimaryButton(
                  label: t(context).commonSave,
                  onPressed: canSave ? onSave : null,
                  loading: _saving,
                ),
              ),
            ],
          ),
        );
      },
    );
  }

  Future<void> _changeAvatar({
    required DemoRepository repo,
    required String communityId,
  }) async {
    if (_saving) return;
    if (repo.isOffline) {
      showErrorSnackBar(context, onRetry: () => _changeAvatar(repo: repo, communityId: communityId));
      return;
    }
    if (repo.supabase == null) {
      showInfoSnackBar(context, t(context).uploadSupabaseOnly);
