    if (!mounted) return;
    if (choice == null) return;

    final picked = await FilePicker.platform.pickFiles(
      type: FileType.image,
      allowMultiple: false,
      withData: true,
    );
    if (!mounted) return;
    final file = (picked == null || picked.files.isEmpty) ? null : picked.files.first;
    if (file == null) return;

    final originalBytes = await _bytesFromPlatformFile(file);
    if (!mounted) return;
    if (originalBytes == null || originalBytes.isEmpty) {
      showInfoSnackBar(context, t(context).imageReadFailed);
      return;
    }

    if (originalBytes.lengthInBytes > 10 * 1024 * 1024) {
      showInfoSnackBar(context, t(context).photoTooLargeMax10mb);
      return;
    }

    Uint8List processed;
    try {
      processed = _prepareCommunityAvatarJpeg(originalBytes);
    } catch (_) {
      showInfoSnackBar(context, t(context).imageInvalid);
      return;
    }

    setState(() {
      _saving = true;
      _savingProgress = 0.35;
    });

    try {
      setState(() => _savingProgress = 0.6);
      String? url;
      try {
        url = await repo.uploadCommunityAvatar(communityId: communityId, jpegBytes: processed);
      } on StorageException catch (e) {
        if (!mounted) return;
        setState(() {
          _saving = false;
          _savingProgress = null;
        });
        final code = e.statusCode == null ? '' : ' (${e.statusCode})';
        showAtalaiaSnackBar(
          context,
          t(context).uploadFailedWithCode(code, e.message),
          kind: AtalaiaSnackKind.error,
        );
        return;
      } catch (_) {
        url = null;
      }
      if (!mounted) return;
      if (url == null) {
        setState(() {
          _saving = false;
          _savingProgress = null;
        });
        final msg = (repo.lastCommunityAvatarError ?? '').trim();
        final retry = () => _changeAvatar(repo: repo, communityId: communityId);
        if (msg.isEmpty) {
          showErrorSnackBar(context, onRetry: retry);
        } else {
          showAtalaiaSnackBar(
            context,
            msg,
            kind: AtalaiaSnackKind.error,
            actionLabel: t(context).commonRetry,
            onAction: retry,
          );
        }
        return;
      }
      setState(() => _savingProgress = 1);
      showInfoSnackBar(context, t(context).photoUpdated);
    } finally {
      if (!mounted) return;
      setState(() {
        _saving = false;
        _savingProgress = null;
      });
    }
  }

  Future<Uint8List?> _bytesFromPlatformFile(PlatformFile file) async {
    final bytes = file.bytes;
    if (bytes != null) return bytes;
    final stream = file.readStream;
    if (stream == null) return null;
    final list = <int>[];
    await for (final chunk in stream) {
      list.addAll(chunk);
    }
    return Uint8List.fromList(list);
  }

  Uint8List _prepareCommunityAvatarJpeg(Uint8List input) {
    final decoded = img.decodeImage(input);
    if (decoded == null) throw StateError('invalid_image');
    final side = math.min(decoded.width, decoded.height);
    final x = ((decoded.width - side) / 2).round();
    final y = ((decoded.height - side) / 2).round();
    final cropped = img.copyCrop(decoded, x: x, y: y, width: side, height: side);
    final resized = img.copyResize(
      cropped,
      width: 1080,
      height: 1080,
      interpolation: img.Interpolation.cubic,
    );
    final encoded = img.encodeJpg(resized, quality: 85);
    return Uint8List.fromList(encoded);
  }
}

class SearchScreen extends StatefulWidget {
  const SearchScreen({super.key});

  @override
  State<SearchScreen> createState() => _SearchScreenState();
}

class _SearchScreenState extends State<SearchScreen> with SingleTickerProviderStateMixin {
  final _text = TextEditingController();
  final _focusNode = FocusNode();

  late final TabController _tabController;

  var _query = '';
  var _loading = false;
  Timer? _analyticsDebounce;
  var _lastTrackedQuery = '';

  @override
  void initState() {
    super.initState();
    _tabController = TabController(length: 4, vsync: this);
    WidgetsBinding.instance.addPostFrameCallback((_) {
      if (!mounted) return;
      _focusNode.requestFocus();
    });
  }

  @override
  void dispose() {
    _analyticsDebounce?.cancel();
    _tabController.dispose();
    _text.dispose();
    _focusNode.dispose();
    super.dispose();
  }

  void _setQuery(String v) {
    final next = v;
    setState(() {
      _query = next;
      _loading = true;
    });
    _analyticsDebounce?.cancel();
    _analyticsDebounce = Timer(const Duration(milliseconds: 450), () {
      if (!mounted) return;
      final trimmed = _query.trim();
      if (trimmed.isEmpty) {
        _lastTrackedQuery = '';
        return;
      }
      if (trimmed == _lastTrackedQuery) return;

      final repo = RepoScope.of(context);
      final session = SessionScope.of(context).value;
      final safeQuery = trimmed.length > 64 ? trimmed.substring(0, 64) : trimmed;
      final scope = switch (_tabController.index) {
        0 => 'all',
        1 => 'people',
        2 => 'posts',
        _ => 'communities',
      };

      final peopleCount = repo.searchProfiles(trimmed).length;
      final postsCount = repo.searchPosts(session, trimmed).length;
      final communitiesCount = repo.searchCommunities(trimmed).length;
      final resultsCount = switch (scope) {
        'all' => peopleCount + postsCount + communitiesCount,
        'people' => peopleCount,
        'posts' => postsCount,
        _ => communitiesCount,
      };

      repo.trackEvent('search_query', <String, Object?>{
        'query': safeQuery,
        'scope': scope,
        'resultsCount': resultsCount,
      });
      _lastTrackedQuery = trimmed;
    });
    Future<void>.delayed(const Duration(milliseconds: 280)).then((_) {
      if (!mounted) return;
      setState(() => _loading = false);
    });
  }

  Future<void> _onRefresh() async {
    setState(() => _loading = true);
    await Future<void>.delayed(const Duration(milliseconds: 280));
    if (!mounted) return;
    setState(() => _loading = false);
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final isAuthenticated = session.value.isAuthenticated;
        final query = _query.trim();
        final hasQuery = query.isNotEmpty;

        final people = hasQuery ? repo.searchProfiles(query) : const <ProfileModel>[];
        final posts = hasQuery ? repo.searchPosts(session.value, query) : const <PostModel>[];
        final communities = hasQuery ? repo.searchCommunities(query) : const <CommunityModel>[];

        final topics = [
          t(context).searchTopicHealing,
          t(context).searchTopicFamily,
          t(context).searchTopicWork,
          t(context).searchTopicAnxiety,
          t(context).searchTopicGratitude,
          t(context).searchTopicFinances,
        ];

        return Scaffold(
          appBar: AppBar(
            leading: AtalaiaIconButton(
              icon: Icons.arrow_back,
              label: t(context).commonBack,
              onPressed: () => Navigator.of(context).maybePop(),
            ),
            titleSpacing: 0,
            title: AtalaiaTextField(
              controller: _text,
              focusNode: _focusNode,
              hintText: t(context).commonSearch,
              prefixIcon: Icons.search,
              textInputAction: TextInputAction.search,
              onChanged: _setQuery,
              suffixIcon: _text.text.isEmpty
                  ? null
                  : AtalaiaIconButton(
                      icon: Icons.close,
                      label: t(context).commonClearSearch,
                      onPressed: () {
                        _text.clear();
                        _setQuery('');
                        _focusNode.requestFocus();
                      },
                    ),
            ),
            bottom: TabBar(
              controller: _tabController,
              isScrollable: true,
              tabs: [
                Tab(text: t(context).searchTabAll),
                Tab(text: t(context).searchTabPeople),
                Tab(text: t(context).searchTabPosts),
                Tab(text: t(context).searchTabCommunities),
              ],
            ),
          ),
          body: Column(
            children: [
              if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
              Expanded(
                child: TabBarView(
                  controller: _tabController,
                  children: [
                    _SearchTabAll(
                      isAuthenticated: isAuthenticated,
                      loading: _loading,
                      query: query,
                      people: people,
                      posts: posts,
                      communities: communities,
                      suggestions: repo.suggestions(),
                      topics: topics,
                      onRefresh: _onRefresh,
                      onPickTopic: (topic) {
                        final q = '#$topic';
                        _text.value = _text.value.copyWith(
                          text: q,
                          selection: TextSelection.collapsed(offset: q.length),
                          composing: TextRange.empty,
                        );
                        _tabController.index = 2;
                        _setQuery(q);
                      },
                    ),
                    _SearchTabPeople(
                      isAuthenticated: isAuthenticated,
                      loading: _loading,
                      query: query,
                      results: people,
                      onRefresh: _onRefresh,
                    ),
                    _SearchTabPosts(
                      isAuthenticated: isAuthenticated,
                      loading: _loading,
                      query: query,
                      results: posts,
                      onRefresh: _onRefresh,
                    ),
                    _SearchTabCommunities(
                      isAuthenticated: isAuthenticated,
                      loading: _loading,
                      query: query,
                      results: communities,
                      onRefresh: _onRefresh,
                    ),
                  ],
                ),
              ),
            ],
          ),
        );
      },
    );
  }
}

class _SearchTabAll extends StatelessWidget {
  const _SearchTabAll({
    required this.isAuthenticated,
    required this.loading,
    required this.query,
    required this.people,
    required this.posts,
    required this.communities,
    required this.suggestions,
    required this.topics,
    required this.onRefresh,
    required this.onPickTopic,
  });

  final bool isAuthenticated;
  final bool loading;
  final String query;
  final List<ProfileModel> people;
  final List<PostModel> posts;
  final List<CommunityModel> communities;
  final List<ProfileModel> suggestions;
  final List<String> topics;
  final Future<void> Function() onRefresh;
  final void Function(String topic) onPickTopic;

  @override
  Widget build(BuildContext context) {
    final hasQuery = query.trim().isNotEmpty;
    if (!hasQuery) {
      return ListView(
        physics: const AlwaysScrollableScrollPhysics(),
        padding: const EdgeInsets.all(12),
        children: [
          Row(
            children: [
              Expanded(
                child: Text(t(context).searchSuggestionsTitle, style: const TextStyle(fontWeight: FontWeight.w900)),
              ),
              AtalaiaTextButton(
                label: t(context).searchMapButton,
                onPressed: () {
                  Navigator.of(context).push(
                    MaterialPageRoute<void>(
                      builder: (_) => Scaffold(
                        appBar: AppBar(title: Text(t(context).searchMapButton)),
                        body: const MapScreen(),
                      ),
                    ),
                  );
                },
              ),
            ],
          ),
          const SizedBox(height: 8),
          ...suggestions.map((p) => PeopleResultRow(profile: p, isAuthenticated: isAuthenticated)),
          const SizedBox(height: 18),
          Text(t(context).searchTopicsTitle, style: const TextStyle(fontWeight: FontWeight.w900)),
          const SizedBox(height: 8),
          Wrap(
            spacing: 8,
            runSpacing: 8,
            children: topics
                .map(
                  (t) => ActionChip(
                    label: Text('#$t'),
                    onPressed: () => onPickTopic(t),
                  ),
                )
                .toList(growable: false),
          ),
        ],
      );
    }

    return RefreshIndicator(
      onRefresh: onRefresh,
      child: loading
          ? const _SearchSkeletonList()
          : (people.isEmpty && posts.isEmpty && communities.isEmpty)
              ? ListView(
                  physics: const AlwaysScrollableScrollPhysics(),
                  children: [
                    SizedBox(height: MediaQuery.sizeOf(context).height * 0.18),
                    EmptyState(
                      icon: Icons.search_off_outlined,
                      title: t(context).searchNoResults(query),
                    ),
                  ],
                )
              : ListView(
                  physics: const AlwaysScrollableScrollPhysics(),
                  padding: const EdgeInsets.all(12),
                  children: [
                    if (people.isNotEmpty) ...[
                      Text(t(context).searchSectionPeople, style: const TextStyle(fontWeight: FontWeight.w900)),
                      const SizedBox(height: 8),
                      ...people.take(4).map((p) => PeopleResultRow(profile: p, isAuthenticated: isAuthenticated)),
                      const SizedBox(height: 14),
                    ],
                    if (posts.isNotEmpty) ...[
                      Text(t(context).searchSectionPosts, style: const TextStyle(fontWeight: FontWeight.w900)),
                      const SizedBox(height: 8),
                      ...posts.take(6).map((p) => PostResultRow(post: p)),
                    ],
                    if (communities.isNotEmpty) ...[
                      const SizedBox(height: 14),
                      Text(t(context).searchSectionCommunities, style: const TextStyle(fontWeight: FontWeight.w900)),
                      const SizedBox(height: 8),
                      ...communities
                          .take(4)
                          .map((c) => CommunityResultRow(community: c, isAuthenticated: isAuthenticated)),
                    ],
                  ],
                ),
    );
  }
}

