class _SearchTabPosts extends StatelessWidget {
  const _SearchTabPosts({
    required this.isAuthenticated,
    required this.loading,
    required this.query,
    required this.results,
    required this.onRefresh,
  });

  final bool isAuthenticated;
  final bool loading;
  final String query;
  final List<PostModel> results;
  final Future<void> Function() onRefresh;

  @override
  Widget build(BuildContext context) {
    final hasQuery = query.trim().isNotEmpty;
    if (!hasQuery) {
      return Center(child: Text(t(context).searchHintPosts));
    }
    return RefreshIndicator(
      onRefresh: onRefresh,
      child: loading
          ? ListView.builder(
              physics: const AlwaysScrollableScrollPhysics(),
              itemCount: 6,
              itemBuilder: (context, index) {
                return PostCardSkeleton(
                  hasMedia: index.isEven,
                  margin: const EdgeInsets.fromLTRB(12, 12, 12, 0),
                );
              },
            )
          : results.isEmpty
              ? ListView(
                  physics: const AlwaysScrollableScrollPhysics(),
                  children: [
                    SizedBox(height: MediaQuery.sizeOf(context).height * 0.18),
                    EmptyState(
                      icon: Icons.search_off_outlined,
                      title: t(context).searchNoResults(query),
                    ),
                  ],
                )
              : ListView.builder(
                  physics: const AlwaysScrollableScrollPhysics(),
                  padding: const EdgeInsets.all(12),
                  itemCount: results.length + (results.length ~/ 15),
                  itemBuilder: (context, index) {
                    final i = index;
                    final isAdSlot = i != 0 && i % 16 == 15;
                    if (isAdSlot) {
                      final slot = (i + 1) ~/ 16;
                      final slotId = 'explore_slot_$slot';
                      return AdCard(
                        key: ValueKey(slotId),
                        slotId: slotId,
                        placement: 'explore',
                        margin: const EdgeInsets.symmetric(vertical: 8),
                      );
                    }

                    final realIndex = i - (i ~/ 16);
                    if (realIndex < 0 || realIndex >= results.length) return const SizedBox.shrink();
                    return PostResultRow(post: results[realIndex]);
                  },
                ),
    );
  }
}

