Future<void> _openPostFromNotification(BuildContext context, DemoRepository repo, String postId) async {
  final cached = repo.findPost(postId);
  if (cached != null) {
    Navigator.of(context).pushNamed(
      Routes.postDetail,
      arguments: PostDetailArgs(postId: postId),
    );
    return;
  }

  if (repo.supabase != null) {
    if (repo.isOffline) {
      showErrorSnackBar(
        context,
        onRetry: () => unawaited(_openPostFromNotification(context, repo, postId)),
      );
      return;
    }
    final ok = await repo.hydratePostById(postId);
    if (!context.mounted) return;
    if (!ok) {
      showPermissionSnackBar(context);
      return;
    }
    Navigator.of(context).pushNamed(
      Routes.postDetail,
      arguments: PostDetailArgs(postId: postId),
    );
    return;
  }

  showPermissionSnackBar(context);
}

Future<void> _openCommunityPrayerRunFromNotification(BuildContext context, DemoRepository repo, String runId) async {
  final sb = repo.supabase;
  if (sb == null) {
    showPermissionSnackBar(context);
    return;
  }
  if (repo.isOffline) {
    showErrorSnackBar(
      context,
      onRetry: () => unawaited(_openCommunityPrayerRunFromNotification(context, repo, runId)),
    );
    return;
  }
  try {
    final row = await sb.from('community_prayer_schedule_runs').select('community_id').eq('id', runId).maybeSingle();
    if (!context.mounted) return;
    final communityId = row?['community_id']?.toString();
    if (communityId == null || communityId.isEmpty) {
      showPermissionSnackBar(context);
      return;
    }
    Navigator.of(context).pushNamed(
      Routes.communityPrayerScales,
      arguments: CommunityArgs(communityId: communityId),
    );
  } catch (_) {
    if (!context.mounted) return;
    showErrorSnackBar(
      context,
      onRetry: () => unawaited(_openCommunityPrayerRunFromNotification(context, repo, runId)),
    );
  }
}

Future<void> _openAlertFromNotification(BuildContext context, DemoRepository repo, String alertId) async {
  final cached = repo.findAlert(alertId);
  if (cached != null) {
    Navigator.of(context).pushNamed(
      Routes.alertDetail,
      arguments: AlertDetailArgs(alertId: alertId),
    );
    return;
  }

  if (repo.supabase != null) {
    if (repo.isOffline) {
      showErrorSnackBar(
        context,
        onRetry: () => unawaited(_openAlertFromNotification(context, repo, alertId)),
      );
      return;
    }
    final ok = await repo.hydrateAlertById(alertId);
    if (!context.mounted) return;
    if (!ok) {
      showPermissionSnackBar(context);
      return;
    }
    Navigator.of(context).pushNamed(
      Routes.alertDetail,
      arguments: AlertDetailArgs(alertId: alertId),
    );
    return;
  }

  showPermissionSnackBar(context);
}

Future<void> _openStoryFromNotification(
  BuildContext context,
  DemoRepository repo, {
  required String cityId,
}) async {
  if (repo.isOffline) {
    showErrorSnackBar(
      context,
      onRetry: () => unawaited(_openStoryFromNotification(context, repo, cityId: cityId)),
    );
    return;
  }
  final stories = await repo.fetchStoriesForCity(cityId);
  if (!context.mounted) return;
  if (stories.isEmpty) {
    showInfoSnackBar(context, 'Sem stories agora.');
    return;
  }
  final cityName = await repo.locationNameById(cityId) ?? 'Cidade';
  if (!context.mounted) return;
  await Navigator.of(context).push(
    MaterialPageRoute<void>(
      fullscreenDialog: true,
      builder: (_) => _StoryViewerScreen(
        cityName: cityName,
        stories: stories,
      ),
    ),
  );
}

class NotificationsScreen extends StatefulWidget {
  const NotificationsScreen({required this.showBack, super.key});

  final bool showBack;

  @override
  State<NotificationsScreen> createState() => _NotificationsScreenState();
}

final class _NotificationGroup {
  _NotificationGroup(this.latest, this.items);

  NotificationModel latest;
  final List<NotificationModel> items;
}

class _NotificationsScreenState extends State<NotificationsScreen> {
  var _loading = true;

  @override
  void initState() {
    super.initState();
    WidgetsBinding.instance.addPostFrameCallback((_) {
      unawaited(_loadInitial());
    });
  }

  Future<void> _loadInitial() async {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    final s = session.value;
    final viewerId = s is AuthSession ? s.userId : null;
    if (viewerId != null && repo.supabase != null && !repo.isOffline) {
      await repo.refreshNotificationsForViewer(viewerId);
    }
    await Future<void>.delayed(const Duration(milliseconds: 320));
    if (!mounted) return;
    setState(() => _loading = false);
  }

  Future<void> _onRefresh() async {
    setState(() => _loading = true);
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);
    final s = session.value;
    final viewerId = s is AuthSession ? s.userId : null;
    if (viewerId != null && repo.supabase != null && !repo.isOffline) {
      await repo.refreshNotificationsForViewer(viewerId);
    } else {
      await Future<void>.delayed(const Duration(milliseconds: 320));
    }
    if (!mounted) return;
    setState(() => _loading = false);
  }

  @override
  Widget build(BuildContext context) {
    final repo = RepoScope.of(context);
    final session = SessionScope.of(context);

    return AnimatedBuilder(
      animation: Listenable.merge([repo, session]),
      builder: (context, _) {
        final s = session.value;
        final viewerId = s is AuthSession ? s.userId : null;
        final isAuthenticated = viewerId != null;

        final notifs = viewerId == null ? const <NotificationModel>[] : repo.notificationsFor(viewerId);
        final cs = Theme.of(context).colorScheme;

        return Scaffold(
          appBar: AppBar(
            leading: widget.showBack
                ? AtalaiaIconButton(
                    icon: Icons.arrow_back,
                    label: t(context).commonBack,
                    onPressed: () => Navigator.of(context).maybePop(),
                  )
                : null,
            title: Text(t(context).notificationsTitle),
            actions: [
              PopupMenuButton<String>(
                icon: const Icon(Icons.more_horiz),
                onSelected: (v) {
                  final l10n = t(context);
                  if (v == 'markAll') {
                    if (!isAuthenticated) {
                      showCtaSnackBar(context);
                      return;
                    }
                    if (repo.isOffline) {
                      showErrorSnackBar(context, onRetry: () => repo.markAllNotificationsRead(viewerId));
                      return;
                    }
                    repo.markAllNotificationsRead(viewerId);
                    showInfoSnackBar(context, l10n.notificationsMarkedAllReadSnack);
                    return;
                  }
                  if (v == 'settings') {
                    Navigator.of(context).pushNamed(Routes.settings);
                  }
                },
                itemBuilder: (context) {
                  final l10n = t(context);
                  return [
                    PopupMenuItem(value: 'markAll', child: Text(l10n.notificationsMarkAllRead)),
                    PopupMenuItem(value: 'settings', child: Text(l10n.settingsTitle)),
                  ];
                },
              ),
            ],
          ),
          body: Column(
            children: [
              if (repo.isOffline) OfflineBanner(onRetry: () => repo.setOffline(false)),
              Expanded(
                child: !isAuthenticated
                    ? Center(
                        child: PrimaryButton(
                          label: t(context).notificationsSignInToSee,
                          onPressed: () => showCtaSnackBar(context),
                        ),
                      )
                    : RefreshIndicator(
                        onRefresh: _onRefresh,
                        child: _loading
                            ? ListView.separated(
                                physics: const AlwaysScrollableScrollPhysics(),
                                padding: const EdgeInsets.all(12),
                                itemCount: 8,
                                separatorBuilder: (_, __) => const SizedBox(height: 10),
                                itemBuilder: (context, index) => const _NotificationRowSkeleton(),
                              )
                            : notifs.isEmpty
                                ? ListView(
                                    physics: const AlwaysScrollableScrollPhysics(),
                                    children: [
                                      SizedBox(height: MediaQuery.sizeOf(context).height * 0.18),
                                      EmptyState(
                                        icon: Icons.volunteer_activism_outlined,
                                        title: t(context).notificationsEmptyAll,
                                      ),
                                    ],
                                  )
                                : ListView(
                                    physics: const AlwaysScrollableScrollPhysics(),
                                    padding: const EdgeInsets.all(12),
                                    children: _buildNotificationSections(
                                      context,
                                      repo: repo,
                                      viewerId: viewerId,
                                      notifications: notifs,
                                      cs: cs,
                                    ),
                                  ),
                      ),
              ),
            ],
          ),
        );
      },
    );
  }

  List<Widget> _buildNotificationSections(
    BuildContext context, {
    required DemoRepository repo,
    required String viewerId,
    required List<NotificationModel> notifications,
    required ColorScheme cs,
  }) {
    final out = <Widget>[];
    final l10n = t(context);

    final buckets = <String, Map<String, Map<String, _NotificationGroup>>>{};
    for (final n in notifications) {
      final header = _notificationBucketLabel(l10n, n.createdAt);
      final category = _notificationCategoryLabel(l10n, n);
      final byCategory = buckets.putIfAbsent(header, () => <String, Map<String, _NotificationGroup>>{});
      final groups = byCategory.putIfAbsent(category, () => <String, _NotificationGroup>{});
      final key = _notificationGroupKey(n);
      final existing = groups[key];
      if (existing == null) {
        groups[key] = _NotificationGroup(n, [n]);
      } else {
        existing.items.add(n);
        if (n.createdAt.isAfter(existing.latest.createdAt)) {
          existing.latest = n;
        }
      }
    }

    for (final bucketEntry in buckets.entries) {
      out.add(
        Padding(
          padding: EdgeInsets.only(top: out.isEmpty ? 0 : 12, bottom: 8),
          child: Text(bucketEntry.key, style: const TextStyle(fontWeight: FontWeight.w900)),
        ),
      );

      final showCategoryHeaders = bucketEntry.value.length > 1;
      for (final catEntry in bucketEntry.value.entries) {
        if (showCategoryHeaders) {
          out.add(
            Padding(
              padding: const EdgeInsets.only(bottom: 8),
              child: Text(
                catEntry.key,
                style: TextStyle(color: cs.outline, fontWeight: FontWeight.w900),
              ),
            ),
          );
        }

        for (final g in catEntry.value.values) {
          final n = g.latest;
          final actorId = n.actorId;
          final actor = actorId == null ? null : repo.profileForUserId(actorId);
          final postId = (n.entityType == 'post') ? n.entityId : null;
          final post = postId == null ? null : repo.findPost(postId);
          final count = g.items.length;

          out.add(
            Padding(
              padding: const EdgeInsets.only(bottom: 10),
              child: NotificationRow(
                notification: n,
                actor: actor,
                post: post,
                groupCount: count,
                isFollowingActor: actorId == null ? false : repo.isFollowingUser(actorId),
                followBackLoading: actorId == null ? false : repo.isFollowTogglingUser(actorId),
                onTap: () {
                  for (final it in g.items) {
                    repo.markNotificationRead(it.id, viewerId: viewerId);
                  }
                  if (actorId != null && n.type == NotificationType.follow) {
                    Navigator.of(context).pushNamed(
                      Routes.userProfile,
                      arguments: UserProfileArgs(userId: actorId),
                    );
                    return;
                  }
                  if (n.entityType == 'community_prayer_run' && n.entityId != null) {
                    unawaited(_openCommunityPrayerRunFromNotification(context, repo, n.entityId!));
                    return;
                  }
                  if (n.entityType == 'story' && n.locationId != null) {
                    unawaited(_openStoryFromNotification(context, repo, cityId: n.locationId!));
                    return;
                  }
                  final entityAlertId = (n.entityType == 'alert') ? n.entityId : null;
                  if (entityAlertId != null) {
                    unawaited(_openAlertFromNotification(context, repo, entityAlertId));
                    return;
                  }
                  final entityPostId = (n.entityType == 'post') ? n.entityId : null;
                  if (entityPostId != null) {
                    unawaited(_openPostFromNotification(context, repo, entityPostId));
                  }
                },
                onFollowBack: () {
                  if (actorId == null) return;
                  if (repo.isOffline) {
                    showErrorSnackBar(
                      context,
                      onRetry: () {
                        if (repo.isFollowTogglingUser(actorId)) return;
                        unawaited(() async {
                          final ok = await repo.toggleFollowUser(actorId, isAuthenticated: true);
                          if (!context.mounted) return;
                          if (!ok) {
                            final msg = repo.lastFollowToggleError?.trim();
                            showAtalaiaSnackBar(
                              context,
                              msg == null || msg.isEmpty ? t(context).commonSomethingWentWrong : msg,
                              kind: AtalaiaSnackKind.error,
                            );
                            return;
                          }
                          showInfoSnackBar(context, t(context).profileSnackFollowing);
                        }());
                      },
                    );
                    return;
                  }
                  if (repo.isFollowTogglingUser(actorId)) return;
                  unawaited(() async {
                    final ok = await repo.toggleFollowUser(actorId, isAuthenticated: true);
                    if (!context.mounted) return;
                    if (!ok) {
                      final msg = repo.lastFollowToggleError?.trim();
                      showAtalaiaSnackBar(
                        context,
                        msg == null || msg.isEmpty ? t(context).commonSomethingWentWrong : msg,
                        kind: AtalaiaSnackKind.error,
                      );
                      return;
                    }
                    showInfoSnackBar(context, t(context).profileSnackFollowing);
                  }());
                },
                onHide: () {
                  if (repo.isOffline) {
                    showErrorSnackBar(
                      context,
                      onRetry: () {
                        repo.hideNotification(n.id, viewerId: viewerId);
                        showInfoSnackBar(context, t(context).notificationsHiddenSnack);
                      },
                    );
                    return;
                  }
                  repo.hideNotification(n.id, viewerId: viewerId);
                  showInfoSnackBar(context, t(context).notificationsHiddenSnack);
                },
              ),
            ),
          );
        }
      }
    }
    return out;
  }
}

String _notificationCategoryLabel(AppLocalizations l10n, NotificationModel n) {
  if (n.entityType == 'community_prayer_run') return l10n.notificationsFilterScales;
  return switch (n.type) {
    NotificationType.follow ||
    NotificationType.reaction ||
    NotificationType.comment ||
    NotificationType.postNew ||
    NotificationType.storyNew =>
      l10n.notificationsFilterSocial,
    NotificationType.prayed || NotificationType.prayerRequest => l10n.notificationsFilterPrayer,
    NotificationType.alertNew => l10n.notificationsFilterAlerts,
    NotificationType.scaleReminder24h || NotificationType.scaleReminder1h => l10n.notificationsFilterScales,
  };
}

String _notificationGroupKey(NotificationModel n) {
  final entity = '${n.entityType ?? ''}:${n.entityId ?? ''}:${n.locationId ?? ''}';
  if (n.type == NotificationType.follow) {
    return 'follow:${n.actorId ?? ''}';
  }
  if (n.type == NotificationType.reaction || n.type == NotificationType.comment || n.type == NotificationType.prayed) {
    return '${n.type.name}:$entity';
  }
  if (n.type == NotificationType.scaleReminder24h || n.type == NotificationType.scaleReminder1h || n.entityType == 'community_prayer_run') {
    return 'scale:$entity';
  }
  return '${n.type.name}:${n.actorId ?? ''}:$entity';
}

String _notificationBucketLabel(AppLocalizations l10n, DateTime dt) {
  final diff = DateTime.now().difference(dt);
  if (diff.inDays < 1) return l10n.notificationsBucketToday;
  if (diff.inDays < 7) return l10n.notificationsBucketThisWeek;
  if (diff.inDays < 31) return l10n.notificationsBucketThisMonth;
  return l10n.notificationsBucketEarlier;
}

class NotificationRow extends StatelessWidget {
  const NotificationRow({
    required this.notification,
    required this.actor,
    required this.post,
    required this.isFollowingActor,
    this.followBackLoading = false,
    required this.onTap,
    required this.onFollowBack,
    required this.onHide,
    this.groupCount = 1,
    super.key,
  });

  final NotificationModel notification;
  final ProfileModel? actor;
  final PostModel? post;
  final bool isFollowingActor;
  final bool followBackLoading;
  final VoidCallback onTap;
  final VoidCallback onFollowBack;
  final VoidCallback onHide;
  final int groupCount;

  @override
  Widget build(BuildContext context) {
    final cs = Theme.of(context).colorScheme;
    final actorId = notification.actorId ?? 'user';
    final actorUsername = _normalizeDisplayUsername(actor?.username ?? actorId, fallback: actorId);
    final l10n = t(context);
    final actorName = groupCount <= 1 ? '@$actorUsername' : l10n.notificationActorAndMore(actorUsername, groupCount - 1);
    final text = _notificationText(context, notification, post, groupCount: groupCount);
    final time = _relativeTime(context, notification.createdAt);
    final isUnread = !notification.isRead;

    final trailing = switch (notification.type) {
      NotificationType.follow => SizedBox(
          height: 34,
          child: SecondaryButton(
            label: isFollowingActor ? l10n.profileFollowing : l10n.notificationFollowBack,
            loading: followBackLoading,
            onPressed: (followBackLoading || isFollowingActor) ? null : onFollowBack,
          ),
        ),
      _ => SizedBox(
          height: 34,
          child: SecondaryButton(
            label: _notificationCtaLabel(context, notification),
            onPressed: _notificationCanOpen(notification, post) ? onTap : null,
          ),
        ),
    };

    return InkWell(
      borderRadius: BorderRadius.circular(16),
      onTap: onTap,
      onLongPress: onHide,
      child: Container(
        padding: const EdgeInsets.all(12),
        decoration: BoxDecoration(
          color: isUnread ? cs.surfaceContainerHighest : cs.surface,
          borderRadius: BorderRadius.circular(16),
          border: Border.all(color: cs.outlineVariant),
        ),
        child: Row(
          crossAxisAlignment: CrossAxisAlignment.start,
          children: [
            Avatar(name: actorUsername, size: AvatarSize.s44),
            const SizedBox(width: 12),
            Expanded(
              child: Text.rich(
                TextSpan(
                  children: [
                    TextSpan(text: '$actorName ', style: const TextStyle(fontWeight: FontWeight.w900)),
                    TextSpan(text: text),
                  ],
                ),
                maxLines: 2,
                overflow: TextOverflow.ellipsis,
              ),
            ),
            const SizedBox(width: 10),
            Column(
              crossAxisAlignment: CrossAxisAlignment.end,
              children: [
                Text(time, style: TextStyle(color: cs.outline, fontWeight: FontWeight.w600)),
                const SizedBox(height: 8),
                trailing,
              ],
            ),
          ],
        ),
      ),
    );
  }
}

bool _notificationCanOpen(NotificationModel n, PostModel? post) {
  if (n.type == NotificationType.follow) return (n.actorId ?? '').trim().isNotEmpty;
  if (n.entityType == 'community_prayer_run') return (n.entityId ?? '').trim().isNotEmpty;
  if (n.entityType == 'story') return (n.locationId ?? '').trim().isNotEmpty;
  if (n.entityType == 'alert') return (n.entityId ?? '').trim().isNotEmpty;
  if (n.entityType == 'post') return (n.entityId ?? '').trim().isNotEmpty;
  return false;
}

String _notificationCtaLabel(BuildContext context, NotificationModel n) {
  final l10n = t(context);
  if (n.type == NotificationType.comment) return l10n.notificationCtaReply;
  if (n.type == NotificationType.follow) return l10n.notificationCtaView;
  if (n.type == NotificationType.scaleReminder24h || n.type == NotificationType.scaleReminder1h || n.entityType == 'community_prayer_run') {
    return l10n.notificationCtaOpen;
  }
  return l10n.notificationCtaView;
}

String _notificationText(BuildContext context, NotificationModel n, PostModel? post, {int groupCount = 1}) {
  final l10n = t(context);
  final body = (n.body ?? '').trim();
  final isMany = groupCount > 1;
  return switch (n.type) {
    NotificationType.follow => isMany ? l10n.notificationFollowMany : l10n.notificationFollowOne,
    NotificationType.reaction => isMany ? l10n.notificationReactionMany : l10n.notificationReactionOne,
    NotificationType.comment => isMany
        ? (body.isEmpty ? l10n.notificationCommentManyNoBody : l10n.notificationCommentManyWithBody(body))
        : (body.isEmpty ? l10n.notificationCommentOneNoBody : l10n.notificationCommentOneWithBody(body)),
    NotificationType.prayed =>
      (post?.kind == PostKind.request)
          ? (isMany ? l10n.notificationPrayedRequestMany : l10n.notificationPrayedRequestOne)
          : (isMany ? l10n.notificationPrayedPostMany : l10n.notificationPrayedPostOne),
    NotificationType.postNew => isMany
        ? (body.isEmpty ? l10n.notificationPostNewManyNoBody : l10n.notificationPostNewManyWithBody(body))
        : (body.isEmpty ? l10n.notificationPostNewOneNoBody : l10n.notificationPostNewOneWithBody(body)),
    NotificationType.storyNew => l10n.notificationStoryNew,
    NotificationType.alertNew => isMany
        ? (body.isEmpty ? l10n.notificationAlertNewManyNoBody : l10n.notificationAlertNewManyWithBody(body))
        : (body.isEmpty ? l10n.notificationAlertNewOneNoBody : l10n.notificationAlertNewOneWithBody(body)),
    NotificationType.prayerRequest => isMany
        ? (body.isEmpty ? l10n.notificationPrayerRequestManyNoBody : l10n.notificationPrayerRequestManyWithBody(body))
        : (body.isEmpty ? l10n.notificationPrayerRequestOneNoBody : l10n.notificationPrayerRequestOneWithBody(body)),
    NotificationType.scaleReminder24h =>
      body.isEmpty ? l10n.notificationScaleReminder24hNoBody : l10n.notificationScaleReminder24hWithBody(body),
    NotificationType.scaleReminder1h => body.isEmpty ? l10n.notificationScaleReminder1hNoBody : l10n.notificationScaleReminder1hWithBody(body),
  };
}

class _NotificationRowSkeleton extends StatelessWidget {
  const _NotificationRowSkeleton();

  @override
  Widget build(BuildContext context) {
    return const RowSkeleton(primaryWidth: 220, secondaryWidth: 160);
  }
}

String _relativeTime(BuildContext context, DateTime dt) {
  final l10n = t(context);
  final diff = DateTime.now().difference(dt);
  if (diff.inMinutes < 1) return l10n.timeNow;
  if (diff.inMinutes < 60) return l10n.timeAgoMinutes(diff.inMinutes);
  if (diff.inHours < 24) return l10n.timeAgoHours(diff.inHours);
  return l10n.timeAgoDays(diff.inDays);
}

String _formatTimestamp(DateTime dt) {
  String two(int v) => v.toString().padLeft(2, '0');
  return '${two(dt.day)}/${two(dt.month)}/${dt.year} • ${two(dt.hour)}:${two(dt.minute)}';
}
